                        try { com.lifecyclebot.v3.scoring.BehaviorAI.recordTradeForAsset(pnlPct = _fanoutPnlPct, reason = _fanoutReason, mint = _fanoutMint, isPaperMode = _fanoutIsPaper, assetClass = _behAsset) } catch (_: Exception) {}
