                        val _fluidTm = _fanoutTradingMode
                        val isMemeBaseClose = _fluidTm.isBlank() || _fluidTm !in setOf(
                            "SHITCOIN", "SHITCOIN_EXPRESS", "SHITCOINEXPRESS", "EXPRESS", "CYCLIC",
                            "QUALITY", "BLUECHIP", "BLUE_CHIP", "MOONSHOT", "TREASURY", "CASHGEN",
