                            "EXPRESS"                                         -> "EXPRESS"
                            "CYCLIC"                                          -> "CYCLIC"
                            "QUALITY"                                         -> "QUALITY"
                            "BLUECHIP", "BLUE_CHIP"                           -> "BLUECHIP"
