                        runtimeGeneration = try { BotRuntimeController.currentGeneration() } catch (_: Throwable) { 0L },
                    )
                } catch (_: Throwable) {}
                try {
                    ForensicLogger.lifecycle("PROFIT_PRESSURE_SELL_RECOVERY_ENQUEUED_4384", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$recoveryReason kind=profit_lock wallet_null pendingSell=true balanceProofWait=true")
                    PipelineHealthCollector.labelInc("PROFIT_PRESSURE_SELL_RECOVERY_ENQUEUED_4384")
                } catch (_: Throwable) {}
                return false
            }
            if (pos.isPaperPosition) {
                val newQty = pos.qtyToken - sellQty
                val newCost = pos.costSol * (1.0 - sellFraction)
                val pnlSol = sellSol - pos.costSol * sellFraction
                
                ts.position = pos.copy(
                    qtyToken = newQty,
                    costSol = newCost,
                    profitLocked = true,
                    profitLockedSol = sellSol,
                    lockedProfitFloor = pos.lockedProfitFloor + sellSol,
                    partialSoldPct = (pos.partialSoldPct + sellFraction * 100.0).coerceAtMost(100.0),
                )
                
                val trade = Trade("PARTIAL_SELL", "paper", sellSol, actualPrice,
                    System.currentTimeMillis(), "profit_lock_${gainMultiple.fmt(1)}x",
                    pnlSol, gainPct)
                // V5.0.3683 — ACCOUNTING LEDGER FIX — canonical cost-basis row.
                @Suppress("UNUSED_VARIABLE") val _legacyPLTrade = trade
                val paperPLCostBasis = pos.costSol * sellFraction
                val paperPLFee = paperPLCostBasis * MEME_TRADING_FEE_PERCENT
                val paperPLNetPnl = pnlSol - paperPLFee
                val paperPLLegPct = pct(paperPLCostBasis, sellSol)
                val tradeRow = Trade(
                    "PARTIAL_SELL", "paper", paperPLCostBasis, actualPrice,
                    System.currentTimeMillis(), "profit_lock_${gainMultiple.fmt(1)}x",
                    pnlSol, paperPLLegPct,
                    feeSol = paperPLFee, netPnlSol = paperPLNetPnl,
                )
                recordTrade(ts, tradeRow)
                security.recordTrade(tradeRow)
                onPaperBalanceChange?.invoke(sellSol)
                
                val solPrice = WalletManager.lastKnownSolPrice
                TreasuryManager.recordProfitLockEvent(
                    TreasuryEventType.PROFIT_LOCK_SELL,
                    sellSol,
                    ts.symbol,
                    gainMultiple,
                    solPrice
                )
                
                if (pnlSol > 0) {
                    TreasuryManager.lockRealizedProfit(pnlSol, solPrice)
                }
                
                onLog("📄 PAPER PROFIT LOCK: Sold ${sellSol.fmt(4)} SOL @ ${gainMultiple.fmt(1)}x — letting rest ride free!", ts.mint)
            } else {
                // V5.9.751b — wallet guaranteed non-null by PROFIT_LOCK_DEFERRED guard.
                executeProfitLockSell(ts, wallet!!, sellFraction, "profit_lock_${gainMultiple.fmt(1)}x", walletSol)
            }
            return true
        }
        
        return false
    }

    /**
     * V5.0.6072 — PAPER-OR-LIVE PROFIT LOCK ENTRY POINT.
     *
     * The three big runner-harvest paths (PROTECTIVE_PEAK_PARTIAL_6064,
     * ULTRA_RUNNER_LIVE_BANK, WALLET_GROWTH_HARVEST_6028) historically fired
     * live-only via `executeProfitLockSell(...)`, so paper positions with
     * genuine +100%/+500% runners never had their partial-bank exit rows
     * recorded. The AI's learning stack (FluidLearningAI, UnifiedPolicyHead,
     * StrategyTruthLedger) then never saw a "banked at +Nx%" outcome for
     * paper trades — a huge blind spot given the operator's directive that
     * paper and live must learn symmetrically.
     *
     * This helper routes to `executeProfitLockSell` for live positions
     * (unchanged), and mirrors the same paper-branch bookkeeping used by
     * the capital_recovery / profit_lock paths for paper positions (partial
     * qty/cost update, canonical PARTIAL_SELL trade row into recordTrade,
     * TreasuryManager profit-lock event, onPaperBalanceChange invoke, log).
     */
    private fun executeProfitLockSellPaperOrLive(
        ts: TokenState,
        wallet: SolanaWallet?,
        sellFraction: Double,
        reason: String,
        walletSol: Double,
        pos: Position,
        actualPrice: Double,
        gainMultiple: Double,
        gainPct: Double,
    ) {
        if (!pos.isPaperPosition) {
            if (wallet == null) return
            executeProfitLockSell(ts, wallet, sellFraction, reason, walletSol)
            return
        }
        // Paper branch — mirror the capital_recovery / profit_lock paper accounting.
        val sellQty = pos.qtyToken * sellFraction
        val sellSol = sellQty * actualPrice
        val newQty = pos.qtyToken - sellQty
        val newCost = pos.costSol * (1.0 - sellFraction)
        val pnlSol = sellSol - pos.costSol * sellFraction
        ts.position = pos.copy(
            qtyToken = newQty,
            costSol = newCost,
            partialSoldPct = (pos.partialSoldPct + sellFraction * 100.0).coerceAtMost(100.0),
            lockedProfitFloor = pos.lockedProfitFloor + sellSol.coerceAtLeast(0.0),
        )
        val paperCostBasis = pos.costSol * sellFraction
        val paperFee = paperCostBasis * MEME_TRADING_FEE_PERCENT
        val paperNetPnl = pnlSol - paperFee
        val paperLegPct = pct(paperCostBasis, sellSol)
        val tradeRow = Trade(
            "PARTIAL_SELL", "paper", paperCostBasis, actualPrice,
            System.currentTimeMillis(), reason,
            pnlSol, paperLegPct,
            feeSol = paperFee, netPnlSol = paperNetPnl,
        )
        recordTrade(ts, tradeRow)
        security.recordTrade(tradeRow)
        onPaperBalanceChange?.invoke(sellSol)
        val solPrice = WalletManager.lastKnownSolPrice
        try {
            TreasuryManager.recordProfitLockEvent(
                TreasuryEventType.PROFIT_LOCK_SELL,
                sellSol,
                ts.symbol,
                gainMultiple,
                solPrice,
            )
        } catch (_: Throwable) {}
        if (pnlSol > 0) {
            try { TreasuryManager.lockRealizedProfit(pnlSol, solPrice) } catch (_: Throwable) {}
        }
        try {
            ForensicLogger.lifecycle(
                "PAPER_PROFIT_LOCK_PARITY_FIRED_6072",
                "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason gain=${gainMultiple.fmt(2)}x sellPct=${(sellFraction*100).toInt()} sellSol=${sellSol.fmt(4)} pnlSol=${pnlSol.fmt(4)}",
            )
            PipelineHealthCollector.labelInc("PAPER_PROFIT_LOCK_PARITY_FIRED_6072")
        } catch (_: Throwable) {}
        onLog("📄💰 PAPER PARITY LOCK: ${ts.symbol} @ ${gainMultiple.fmt(1)}x — banked ${sellSol.fmt(4)} SOL (${(sellFraction*100).toInt()}%) reason=$reason", ts.mint)
    }

    
    private fun executeProfitLockSell(
        ts: TokenState,
        wallet: SolanaWallet,
        sellFraction: Double,
        reason: String,
        walletSol: Double,
    ) {
        val c = cfg()
        beginMemeExecutionStack(
            side = com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Side.SELL,
            ts = ts,
            amountIn = sellFraction,
            amountInRaw = "fraction=$sellFraction",
            slippageBps = com.lifecyclebot.engine.sell.SellSafetyPolicy.initialSlippageBps(reason),
            reason = reason,
            urgency = if (reason.contains("profit", ignoreCase = true)) com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Urgency.PROFIT_LOCK else com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Urgency.PARTIAL,
            walletSol = walletSol,
            tokenBalanceAuthority = "SELL_AMOUNT_AUTHORITY_PENDING",
            callSite = "executeProfitLockSell",
        )
        // V5.9.475 — rehydrate ts.position from sub-trader maps if it's
        // empty. Sub-traders (Treasury, ShitCoin, etc.) keep positions in
        // private maps and don't always mirror to ts.position. Without
        // this, profit-lock sells would compute sellQty = 0 * fraction =
        // 0 and silently no-op the entire sell.
        rehydratePositionFromSubTraders(ts)
        val pos = ts.position
        
        // V5.9.495y — DUPLICATE-EXIT GUARD (spec item 9). Refuse to start a
        // second sell if there's already a verified-pending sig in flight
        // for this mint. Prevents stacked broadcasts when the previous sell
        // is in INCONCLUSIVE_PENDING.
        TradeVerifier.activeSellSig(ts.mint)?.let { existingSig ->
            onLog("⏳ SELL DEDUPE: ${ts.symbol} — existing sell sig=${existingSig.take(16)}… still verifying. Skipping new $reason exit attempt.", ts.mint)
            return
        }
        
        if (!security.verifyKeypairIntegrity(wallet.publicKeyB58,
                c.walletAddress.ifBlank { wallet.publicKeyB58 })) {
            onLog("🛑 Keypair check failed — aborting profit lock sell", ts.mint)
            return
        }
        
        // V5.9.495z47 — outer vars so PartialSellMismatchDetector can verify
        // post-sell wallet drop ≤ expected after broadcast confirms.
        var preSellRawForAudit: java.math.BigInteger = java.math.BigInteger.ZERO
        var expectedConsumedRawForAudit: java.math.BigInteger = java.math.BigInteger.ZERO
        var decimalsForAudit: Int = 0
        var liveBalanceSource: com.lifecyclebot.engine.sell.SellAmountAuthority.BalanceSource =
            com.lifecyclebot.engine.sell.SellAmountAuthority.BalanceSource.UNKNOWN
        val sellQty = run {
            // V5.9.495z46 P0 — operator spec items C/E (forensics 0508_143519):
            // replace `pos.qtyToken * sellFraction` ad-hoc math with the
            // verified-remaining clamp from PartialSellSizer + SellAmountAuthority.
            // pos.qtyToken can be stale (cached from initial buy result);
            // the wallet's chain-confirmed remaining balance is the truth.
            val resolution = try {
                com.lifecyclebot.engine.sell.SellAmountAuthority.resolveForExit(ts.mint, wallet, reason)
            } catch (_: Throwable) { null }
            liveBalanceSource = com.lifecyclebot.engine.sell.SellAmountAuthority.balanceSource(resolution)
            val confirmed = resolution as? com.lifecyclebot.engine.sell.SellAmountAuthority.Resolution.Confirmed
            if (confirmed != null) {
                preSellRawForAudit = confirmed.rawAmount
                decimalsForAudit = confirmed.decimals
                val sized = com.lifecyclebot.engine.sell.PartialSellSizer.size(
                    intendedFraction = sellFraction,
                    verifiedRemainingRaw = confirmed.rawAmount,
                )
                if (sized != null) {
                    expectedConsumedRawForAudit = sized.rawAmount
                    val ui = java.math.BigDecimal(sized.rawAmount)
                        .movePointLeft(confirmed.decimals)
                        .toDouble()
                    onLog("📐 PartialSellSizer ${ts.symbol}: " +
                          "verifiedRaw=${confirmed.rawAmount} fraction=${sellFraction} " +
                          "→ rawAmount=${sized.rawAmount} (${"%.6f".format(ui)} ui) " +
                          "vs cached pos.qtyToken=${pos.qtyToken}", ts.mint)
                    ui
                } else {
                    onLog("⏸️ SELL_WAITING_BALANCE_PROOF: ${ts.symbol} dust-rejected by verified raw amount — no cached qty sell.", ts.mint)
                    try { ForensicLogger.lifecycle("SELL_WAITING_BALANCE_PROOF", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${reason}_DUST_REJECTED") } catch (_: Throwable) {}
                    try { com.lifecyclebot.engine.sell.CloseLease.release(ts.mint, "BALANCE_DUST_NO_SIGNATURE") } catch (_: Throwable) {}
                    try { HostWalletTokenTracker.markSellWaitingBalanceProof(ts.mint, ts.symbol, "BALANCE_DUST") } catch (_: Throwable) {}
                    return
                }
            } else {
                onLog("⏸️ SELL_WAITING_BALANCE_PROOF: ${ts.symbol} RPC empty/unknown — no cached qty sell.", ts.mint)
                try { ForensicLogger.lifecycle("SELL_WAITING_BALANCE_PROOF", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason") } catch (_: Throwable) {}
                try { com.lifecyclebot.engine.sell.CloseLease.release(ts.mint, "BALANCE_UNKNOWN_NO_SIGNATURE") } catch (_: Throwable) {}
                try { HostWalletTokenTracker.markSellWaitingBalanceProof(ts.mint, ts.symbol, "BALANCE_UNKNOWN") } catch (_: Throwable) {}
                // V5.0.3746 — profit-lock BALANCE_UNKNOWN must also hand off to
                // BalanceProofPoller so the next tick does NOT re-acquire a
                // close lease (operator spec items 1, 4, 7).
                try {
                    com.lifecyclebot.engine.sell.BalanceProofWaitState.markWaiting(
                        ts.mint, ts.symbol, "PROFIT_LOCK_BALANCE_UNKNOWN",
                        runtimeGeneration = try { BotRuntimeController.currentGeneration() } catch (_: Throwable) { 0L },
                    )
                } catch (_: Throwable) {}
                return
            }
        }
        val initialProcessorPlan = recalcSellPlanForProcessor(
            ts = ts,
            wallet = wallet,
            processor = "INITIAL_SELL_PLAN",
            requestedUiQty = sellQty,
            exitReason = reason,
            sellTradeKey = null,
            traderTag = "MEME",
        ) ?: return
        val sellUnits = initialProcessorPlan.rawAmount
        // V5.9.1533 — spec item 5: LIVE sell broadcasts ONLY on on-chain confirmed
        // balance (RPC_CONFIRMED / WALLET_SCAN_CONFIRMED). TX_PARSE-only / UNKNOWN =>
        // queue recovery, do not broadcast a sell sized off a guess. Paper unaffected.
        if (!pos.isPaperPosition) {
            val cb = com.lifecyclebot.engine.sell.SellAmountAuthority.canBroadcastLiveOrEmergency(
                resolution = try { com.lifecyclebot.engine.sell.SellAmountAuthority.resolveForExit(ts.mint, wallet, reason) } catch (_: Throwable) { null },
                reason = reason,
                mint = ts.mint,
                requestedRawAmount = java.math.BigInteger.valueOf(sellUnits),
            )
            if (!cb) {
                try { ForensicLogger.lifecycle("SELL_BROADCAST_BLOCKED_UNCONFIRMED_BALANCE",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} balanceSource=$liveBalanceSource action=queue_recovery_not_broadcast") } catch (_: Throwable) {}
                onLog("⏸️ SELL_WAITING_BALANCE_PROOF: ${ts.symbol} balance not on-chain confirmed (src=$liveBalanceSource) — no broadcast, no blocking lease.", ts.mint)
                try { com.lifecyclebot.engine.sell.CloseLease.release(ts.mint, "BALANCE_UNKNOWN_NO_SIGNATURE") } catch (_: Throwable) {}
                try { HostWalletTokenTracker.markSellWaitingBalanceProof(ts.mint, ts.symbol, "BALANCE_UNKNOWN") } catch (_: Throwable) {}
                // V5.0.3746 — profit-lock balance-not-on-chain-confirmed must hand
                // off to BalanceProofPoller (operator spec items 1, 4, 7).
                try {
                    com.lifecyclebot.engine.sell.BalanceProofWaitState.markWaiting(
                        ts.mint, ts.symbol, "PROFIT_LOCK_BROADCAST_BLOCKED",
                        runtimeGeneration = try { BotRuntimeController.currentGeneration() } catch (_: Throwable) { 0L },
                    )
                } catch (_: Throwable) {}
                return
            }
        }

        // V5.9.495z29 — operator spec item 4: ExecutableQuoteGate.
        // Profit-lock is only allowed when a fresh executable Jupiter quote
        // for the EXACT wallet token amount produces a slippage-adjusted
        // net SOL output above the entry basis recorded in
        // TokenLifecycleTracker. Refuses on stale price / zero balance /
        // missing entry basis / extreme price impact / route-not-found.
        // Capital-recovery exits (which run at the same call site for
        // 'capital_recovery_*' reasons) DELIBERATELY skip the gate — they
        // exit on risk grounds even at a small loss. So we only gate
        // pure profit-lock paths.
        val isProfitLockReason = reason.startsWith("profit_lock") ||
                                 reason.startsWith("partial_profit_lock") ||
                                 reason.startsWith("take_profit")
        if (isProfitLockReason && sellUnits > 0L) {
            val lifecycle = TokenLifecycleTracker.get(ts.mint)
            val entryBasis = lifecycle?.entrySolSpent ?: 0.0
            // entryBasis falls back to 0 if the lifecycle tracker hasn't
            // been populated yet (older positions pre-z28). In that case
            // we let the profit-lock proceed (operator spec: 'do not
            // block on missing data, log clearly').
            if (entryBasis > 0.0) {
                val gateSlip = SellSlippageProfile.forTier(
                    SellSlippageProfile.Tier.NORMAL_PROFIT_LOCK
                ).initialBps
                val verdict = ExecutableQuoteGate.evaluate(
                    tokenMint = ts.mint,
                    currentWalletTokenRaw = sellUnits,
                    entrySolSpent = entryBasis,
                    minNetProfitFraction = 0.10,   // ≥10% net required
                    slippageBps = gateSlip,
                    jupiter = jupiter,
                )
                when (verdict) {
                    is ExecutableQuoteGate.Verdict.Rejected -> {
                        onLog(
                            "🚫 PROFIT_LOCK_BLOCKED ${ts.symbol} " +
                            "${verdict.code}: ${verdict.reason}", ts.mint,
                        )
                        LiveTradeLogStore.log(
                            LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                            ts.mint, ts.symbol, "INFO",
                            LiveTradeLogStore.Phase.WARNING,
                            "Profit-lock blocked: ${verdict.code} | ${verdict.reason}",
                            traderTag = "MEME",
                        )
                        return
                    }
                    is ExecutableQuoteGate.Verdict.Approved -> {
                        ErrorLogger.info("Executor",
                            "✅ PROFIT_LOCK_APPROVED ${ts.symbol} " +
                            "netSol=${"%.6f".format(verdict.expectedSolOutNet)} " +
                            "impact=${"%.2f".format(verdict.priceImpactPct)}%")
                    }
                }
            }
        }

        // V5.9.474 — full forensics + V5.9.468 binding-order + V5.9.472 cap removal
        // for the profit-lock / capital-recovery sell path. Operator's screenshot
        // showed sells labelled 'profit_lock_86.2x' / 'capital_recovery_86.2x'
        // executing but never appearing in Live Trade Forensics — this entire
        // function was emitting onLog only and bypassed LiveTradeLogStore.
        val sellTradeKey = LiveTradeLogStore.keyFor(ts.mint, pos.entryTime)
        if (blockIfSellInFlight(ts, reason, sellTradeKey)) return
        if (!com.lifecyclebot.engine.sell.SellExecutionLocks.tryAcquire(ts.mint)) {
            // V5.9.967 — z43-D SellSpamGuard wrap.
            if (com.lifecyclebot.engine.sell.SellSpamGuard.shouldLogBlocked(ts.mint, reason))
            LiveTradeLogStore.log(
                sellTradeKey, ts.mint, ts.symbol, "SELL",
                LiveTradeLogStore.Phase.SELL_VERIFY_INCONCLUSIVE_PENDING,
                "SELL_BLOCKED_ALREADY_IN_PROGRESS profit-lock reason=$reason",
                traderTag = "MEME",
            )
            return
        }
        val sellSlippage = com.lifecyclebot.engine.sell.SellSafetyPolicy.initialSlippageBps(reason)
            .coerceAtMost(com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)) // V5.9.1533 hard 500bps cap

        // V5.9.479 — DRAIN-EXIT detection + in-line slippage ladder mirroring
        // V5.9.478 in liveSell. Profit-lock sells previously did a single
        // broadcast attempt and on 0x1788 only escalated across ticks (slow).
        // Now: a profit-lock fail at 200bps immediately re-tries at the next
        // tier in this same call.
        // V5.9.495v — operator triage 06 May 2026: WCOR capital_recovery_85.1x
        // failed every slippage tier 200/400/600/1000/2000bps because the
        // reason string didn't match any drain keyword and got the
        // CONSERVATIVE ladder. (Re-evaluated below — see z38.)
        // V5.9.495z38 — operator-reported real-money safety bug:
        // PROFIT-LOCK sell ran at 75% slippage and consumed ~3.6× the
        // intended quantity. Root cause: profit_lock and
        // capital_recovery were being treated as DRAIN-EXIT, allowing
        // the 5000→7500→9999bps escalation. This is wrong: those
        // exits are "we've already made our money, want out cleanly",
        // NOT "rug emergency". Per operator spec:
        //   - PROFIT_LOCK         max 500–800 bps
        //   - CAPITAL_RECOVERY    max 1000–1500 bps
        //   - 7500/9999 bps is RUG_DRAIN territory only.
        val isDrainExit = com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason) > 1200 &&
                          (com.lifecyclebot.engine.sell.SellSafetyPolicy.isHardRug(reason) ||
                           com.lifecyclebot.engine.sell.SellSafetyPolicy.isManualEmergency(reason))
        val isProfitLock      = reason.contains("profit_lock", ignoreCase = true)
        val isCapitalRecovery = reason.contains("capital_recovery", ignoreCase = true)
        val broadcastSlipLadder = com.lifecyclebot.engine.sell.SellSafetyPolicy.ladder(reason)
        // Forensic guard — if we ever try to take a profit_lock/cap_rec
        // sell with slippage above its cap, surface a SELL_AMOUNT_VIOLATION
        // event so the operator sees it in forensics.
        run {
            val maxAllowed = when {
                isProfitLock      -> com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)
                isCapitalRecovery -> com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)
                isDrainExit       -> com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)
                else              -> com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)
            }
            // V5.9.1533 — spec item 2: HARD 500bps cap for non-emergency live sells.
            // A path attempting >cap must FAIL-CLOSED and queue, not broadcast at a
            // silently-raised slippage. Emergency exits log the override in the policy.
            val isEmergency = com.lifecyclebot.engine.sell.SellSafetyPolicy.isEmergencyExit(reason)
            if (sellSlippage > maxAllowed) {
                ForensicLogger.lifecycle("SELL_SLIPPAGE_CAP_ENFORCED",
                    "mint=${ts.mint.take(10)} reason=$reason attemptedBps=$sellSlippage slippageCapBps=$maxAllowed emergency=$isEmergency action=clamp_to_cap")
                ErrorLogger.warn("Executor",
                    "🚨 SLIPPAGE_CAP_VIOLATION: ${ts.symbol} reason=$reason slippage=${sellSlippage}bps > max=${maxAllowed}bps — clamping to cap.")
            } else {
                ForensicLogger.lifecycle("SELL_SLIPPAGE_WITHIN_CAP",
                    "mint=${ts.mint.take(10)} slippageCapBps=$maxAllowed attemptedBps=$sellSlippage")
            }
        }
        // Tail-clamp the ladder so the broadcast loop physically cannot
        // escalate past the cap.
        val maxLadderBps = when {
            isDrainExit       -> com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)
            isCapitalRecovery -> com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)
            isProfitLock      -> com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)
            else              -> com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason)
        }
        val broadcastSlipLadderCapped = broadcastSlipLadder.map { it.coerceAtMost(maxLadderBps) }.distinct()

        LiveTradeLogStore.log(
            sellTradeKey, ts.mint, ts.symbol, "SELL",
            LiveTradeLogStore.Phase.SELL_START,
            "executeProfitLockSell: $reason | sellFraction=${(sellFraction*100).toInt()}% | qty=$sellUnits | slip=${sellSlippage}bps | ladder=${broadcastSlipLadderCapped.joinToString(",")}${if (isDrainExit) " [DRAIN-EXIT]" else if (isProfitLock) " [PROFIT-LOCK]" else if (isCapitalRecovery) " [CAPITAL-RECOVERY]" else ""}",
            tokenAmount = sellQty,
            slippageBps = sellSlippage,
            traderTag = "MEME",
        )

        try {
            LiveTradeLogStore.log(
                sellTradeKey, ts.mint, ts.symbol, "SELL",
                LiveTradeLogStore.Phase.SELL_QUOTE_TRY,
                "Quote try @ ${sellSlippage}bps",
                slippageBps = sellSlippage,
                traderTag = "MEME",
            )
            // V5.9.468 — pass wallet pubkey as taker so the quote is a binding
            // Ultra-v2 order. RFQ rejections surface here, not silently in build.
            var jupiterPlan = recalcSellPlanForProcessor(
                ts = ts,
                wallet = wallet,
                processor = "JUPITER_ULTRA_METIS",
                requestedUiQty = sellQty,
                exitReason = reason,
                sellTradeKey = sellTradeKey,
                traderTag = "MEME",
            ) ?: return
            var quote = getQuoteWithSlippageGuard(ts.mint, JupiterApi.SOL_MINT, jupiterPlan.rawAmount,
                                                   sellSlippage, isBuy = false,
                                                   sellTaker = wallet.publicKeyB58)
            LiveTradeLogStore.log(
                sellTradeKey, ts.mint, ts.symbol, "SELL",
                LiveTradeLogStore.Phase.SELL_QUOTE_OK,
                "Quote OK | out=${quote.outAmount} | impact=${"%.2f".format(quote.priceImpactPct)}% | router=${quote.router}${if (quote.isRfqRoute) " (RFQ)" else ""}${if (quote.ultraRejectedReason.isNotBlank()) " ⚠ Ultra REJECTED → Metis fallback (${quote.ultraRejectedReason.take(60)})" else ""}",
                slippageBps = sellSlippage,
                traderTag = "MEME",
            )

            // V5.9.479 — IN-LINE broadcast escalation loop (matches V5.9.478 in liveSell)
            var sig: String? = null
            var lastBroadcastException: Exception? = null
            var broadcastAttempts = 0

            // V5.9.495 — PUMP-FIRST routing for profit-lock partial sells.
            // Same universal-auto routing as liveSell: try PumpPortal direct
            // FIRST (fast path), fall through to Jupiter ladder on failure;
            // a final PUMP-RESCUE retry at higher slip fires after Jupiter
            // exhaustion if PUMP-FIRST was rejected the first time.
            //
            // Inlined (no `run { }` lambda) so Kotlin smart-cast on `sig`
            // still works downstream — closures break flow analysis.
            // V5.9.1542 — slip is QUOTE-DERIVED, not a flat 5% ceiling. The old
            // hardcoded 5 authorized PumpPortal to fill against the curve up to 5%
            // on EVERY sell, so we ate ~5% even on liquid profit-locks. Start at the
            // reason-aware ladder floor (profit-lock/partial/cap-rec = 2%; only
            // rug/SL/emergency = 5%); the broadcast ladder still widens to 5% ONLY
            // if this tight attempt fails to land. sellSlippage is bps -> /100 for %.
            val pfPumpSlip = (sellSlippage / 100).coerceIn(1, 5)
            val pfPumpJito = c.jitoEnabled
            val pfPumpTip = effectiveJitoTipLamports(c, urgent = isDrainExit)
            // V5.9.1533 — spec item 7: skip Pump-direct when this mint's pump route was
            // invalidated by a prior 0x1787; let the Jupiter/venue ladder re-resolve.
            sig = if (com.lifecyclebot.engine.sell.MemeVenueRouter.isPumpRouteInvalid(ts.mint)) {
                try { ForensicLogger.lifecycle("PUMP_DIRECT_SKIPPED_RERESOLVE",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} label=PROFIT-LOCK reason=pump_route_invalid") } catch (_: Throwable) {}
                null
            } else tryPumpPortalSell(
                ts = ts,
                wallet = wallet,
                tokenUnits = recalcSellPlanForProcessor(
                    ts = ts,
                    wallet = wallet,
                    processor = "PUMPPORTAL",
                    requestedUiQty = sellQty,
                    exitReason = reason,
                    sellTradeKey = sellTradeKey,
                    traderTag = "MEME",
                )?.rawAmount ?: return,
                slipPct = pfPumpSlip,
                priorityFeeSol = if (isDrainExit) 0.0005 else 0.0001,
                useJito = pfPumpJito,
                jitoTipLamports = pfPumpTip,
                sellTradeKey = sellTradeKey,
                traderTag = "MEME",
                labelTag = "PROFIT-LOCK",
            )
            // V5.9.495 — skip Jupiter ladder if PumpPortal already landed.
            // V5.9.495d — Ultra-first fallback signal. liveSell uses
            // getQuoteWithTaker which prefers Jupiter Ultra v2 then v6
            // Metis on RFQ rejection. Log the intent so operator sees the
            // escalation chain end-to-end on the forensics tile.
            if (sig == null) {
                LiveTradeLogStore.log(
                    sellTradeKey, ts.mint, ts.symbol, "SELL",
                    LiveTradeLogStore.Phase.INFO,
                    "↩ FALLBACK → Jupiter Ultra (v2) primary, v6 Metis secondary | ladder=${broadcastSlipLadder.joinToString("/")}bps",
                    traderTag = "MEME",
                )
            }
            for (currentSlip in if (sig != null) emptyList() else broadcastSlipLadder) {
                broadcastAttempts++
                try {
                    if (broadcastAttempts > 1) {
                        LiveTradeLogStore.log(
                            sellTradeKey, ts.mint, ts.symbol, "SELL",
                            LiveTradeLogStore.Phase.SELL_QUOTE_TRY,
                            "⚡ ESCALATION re-quote @ ${currentSlip}bps (attempt $broadcastAttempts)${if (isDrainExit) " [DRAIN-EXIT]" else ""}",
                            slippageBps = currentSlip, traderTag = "MEME",
                        )
                        try {
                            jupiterPlan = recalcSellPlanForProcessor(
                                ts = ts,
                                wallet = wallet,
                                processor = "JUPITER_ULTRA_METIS",
                                requestedUiQty = sellQty,
                                exitReason = reason,
                                sellTradeKey = sellTradeKey,
                                traderTag = "MEME",
                            ) ?: return
                            quote = getQuoteWithSlippageGuard(
                                ts.mint, JupiterApi.SOL_MINT, jupiterPlan.rawAmount, currentSlip,
                                isBuy = false, sellTaker = wallet.publicKeyB58)
                            // V5.9.495u — operator triage 06 May 2026: "are
                            // we using ultra the way its meant to be?". We
                            // ARE — getQuoteWithTaker double-taps Ultra
                            // before falling to v6 Metis on every escalation
                            // — but the previous log line dropped the
                            // ultraRejectedReason suffix, so forensics
                            // looked like we'd silently abandoned Ultra.
                            // Log it explicitly here on every re-quote so
                            // the operator can see Ultra-vs-Metis routing
                            // each tier of the slippage ladder.
                            LiveTradeLogStore.log(
                                sellTradeKey, ts.mint, ts.symbol, "SELL",
                                LiveTradeLogStore.Phase.SELL_QUOTE_OK,
                                "Re-quote OK @ ${currentSlip}bps | out=${quote.outAmount} | router=${quote.router}${if (quote.isRfqRoute) " (RFQ)" else ""}${if (quote.ultraRejectedReason.isNotBlank()) " ⚠ Ultra REJECTED → Metis (${quote.ultraRejectedReason.take(60)})" else if (quote.isUltra) " ✅ ULTRA accepted" else ""}",
                                slippageBps = currentSlip, traderTag = "MEME",
                            )
                        } catch (qex: Exception) {
                            lastBroadcastException = qex
                            LiveTradeLogStore.log(
                                sellTradeKey, ts.mint, ts.symbol, "SELL",
                                LiveTradeLogStore.Phase.SELL_QUOTE_FAIL,
                                "Re-quote ${currentSlip}bps FAILED: ${qex.message?.take(80) ?: "?"}",
                                slippageBps = currentSlip, traderTag = "MEME",
                            )
                            continue
                        }
                    }
                    val dynSlipCap = com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason).coerceAtLeast(currentSlip)
                    val txResult = buildTxWithRetry(
                        quote, wallet.publicKeyB58, dynamicSlippageMaxBps = dynSlipCap,
                        senderTipLamports = effectiveJitoTipLamports(c, urgent = isDrainExit),
                    )
                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_TX_BUILT,
                        "Tx built | router=${txResult.router} rfq=${txResult.isRfqRoute} | slip=${currentSlip}bps (attempt $broadcastAttempts)" + (if (txResult.dynSlipPickedBps >= 0) " | dyn-slip picked=${txResult.dynSlipPickedBps}bps incurred=${txResult.dynSlipIncurredBps}bps" else ""),
                        traderTag = "MEME",
                    )
                    security.enforceSignDelay()

                    val useJito = c.jitoEnabled && !quote.isUltra
                    // V5.9.483 — dynamic Jito tip from bundles.jito.wtf 75th percentile.
                    // Static c.jitoTipLamports (10_000) was too low during congestion;
                    // drain-exit doubles the tip so we don't lose the position to a slow land.
                    val jitoTip = effectiveJitoTipLamports(c, urgent = isDrainExit)
                    val ultraReqId = if (quote.isUltra) txResult.requestId else null

                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_BROADCAST,
                        "Broadcasting @ ${currentSlip}bps | route=${if (quote.isUltra) "ULTRA" else if (useJito) "JITO" else "RPC"} (attempt $broadcastAttempts)",
                        traderTag = "MEME",
                    )
                    sig = wallet.signSendAndConfirm(txResult.txBase64, useJito, jitoTip, ultraReqId, c.jupiterApiKey, txResult.isRfqRoute, txResult.senderCompatible)
                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_CONFIRMED,
                        "✅ Sig confirmed @ ${currentSlip}bps (attempt $broadcastAttempts): ${sig.take(20)}…",
                        sig = sig, traderTag = "MEME",
                    )
                    break
                } catch (broadcastEx: Exception) {
                    lastBroadcastException = broadcastEx
                    val safe = security.sanitiseForLog(broadcastEx.message ?: "unknown")
                    val isSlippage = safe.contains("0x1788", ignoreCase = true) ||
                                     safe.contains("0x1789", ignoreCase = true) ||
                                     safe.contains("TooLittleSolReceived", ignoreCase = true) ||
                                     safe.contains("Slippage", ignoreCase = true) ||
                                     safe.contains("SlippageToleranceExceeded", ignoreCase = true)
                    if (!isSlippage) throw broadcastEx
                    val brc = zeroBalanceRetries.merge(ts.mint + "_broadcast", 1) { old, _ -> old + 1 } ?: 1
                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_FAILED,
                        "SLIPPAGE @ ${currentSlip}bps (in-line attempt $broadcastAttempts) — escalating${if (isDrainExit) " [DRAIN-EXIT]" else ""} (lifetime=$brc)",
                        slippageBps = currentSlip, traderTag = "MEME",
                    )
                }
            }
            if (sig == null) {
                // V5.9.495 — PUMP DIRECT FALLBACK after Jupiter ladder
                // exhausted. Profit-lock always tries PUMP-FIRST at moderate
                // slip; this final attempt bumps slippage so a tighter market
                // gets a second shot via PumpPortal at e.g. 75% (drain) or
                // 50% (normal).
                val pumpSlip = 5  // V5.9.1524 — 5% live sell cap (was 90/50; builder also caps)
                val pumpJito = c.jitoEnabled
                val pumpTip = effectiveJitoTipLamports(c, urgent = isDrainExit)
                sig = tryPumpPortalSell(
                    ts = ts,
                    wallet = wallet,
                    tokenUnits = recalcSellPlanForProcessor(
                        ts = ts,
                        wallet = wallet,
                        processor = "PUMPPORTAL_PROFIT_RESCUE",
                        requestedUiQty = sellQty,
                        sellTradeKey = sellTradeKey,
                        traderTag = "MEME",
                    )?.rawAmount ?: return,
                    slipPct = pumpSlip,
                    priorityFeeSol = if (isDrainExit) 0.0008 else 0.0003,
                    useJito = pumpJito,
                    jitoTipLamports = pumpTip,
                    sellTradeKey = sellTradeKey,
                    traderTag = "MEME",
                    labelTag = "PROFIT-LOCK-RESCUE",
                )
            }
            if (sig == null) {
                throw lastBroadcastException ?: RuntimeException(
                    "${ts.symbol}: profit-lock in-line broadcast retries exhausted at ${broadcastSlipLadder.last()}bps")
            }
            // Reset broadcast retry counter on success
            zeroBalanceRetries.remove(ts.mint + "_broadcast")
            // V5.9.479 — capture non-null sig for downstream Trade record + log calls
            val finalSig: String = sig!!
            // V5.9.495y — register with TradeVerifier dedupe guard immediately after broadcast accepts.
            if (!finalSig.startsWith("PHANTOM_")) TradeVerifier.beginSell(ts.mint, finalSig, reason)

            // V5.9.495z47 — operator P0 (forensics 0508_143519):
            // PARTIAL_SELL_AMOUNT_MISMATCH detection. If the wallet drop
            // exceeds the expected consumed raw by >5%, the detector locks
            // the mint via SellAmountAuditor (which executor.liveSell early-
            // returns on). Fail-soft: never block the success path.
            if (!finalSig.startsWith("PHANTOM_")) {
                try {
                    if (decimalsForAudit > 0 &&
                        expectedConsumedRawForAudit.signum() > 0 &&
                        preSellRawForAudit.signum() > 0) {
                        com.lifecyclebot.engine.sell.PartialSellMismatchDetector.verifyAndMaybeLock(
                            mint = ts.mint,
                            symbol = ts.symbol,
                            decimals = decimalsForAudit,
                            expectedConsumedRaw = expectedConsumedRawForAudit,
                            preSellWalletRaw = preSellRawForAudit,
                            wallet = wallet,
                        )
                    }
                } catch (_: Throwable) { /* fail-soft */ }
            }

            // V5.9.495s — POST-BROADCAST SELL VERIFY. Operator (06 May 2026):
            // "the capital recovery/profit lock sells in live in memes aren't
            // working correctly. its assuming it sells then leaving the full
            // amount in the host wallet". Previously this path trusted the
            // PumpPortal/Jupiter signature and reduced ts.position.qtyToken
            // immediately, even if the broadcast never settled on-chain
            // (slippage, no liq, MEV bundle dropped). Now: read the wallet
            // token balance for up to 12s after broadcast; require ≥60% of
            // sellQty to actually leave the wallet before we mutate the
            // position record. Synthetic PHANTOM_ sentinels (dust/local
            // closes) skip this gate. Real sigs that didn't settle now
            // bail out cleanly with a SELL_FAILED forensics entry and the
            // position stays intact for the next exit attempt.
            // V5.9.495y/z — TRADE-VERIFIER AUTHORITATIVE SELL VERIFY (spec
            // items 6, 8). Replaces the V5.9.495s/t wallet-token-poll
            // heuristic — which was producing false SELL_FAILED on
            // RPC empty-map even when the chain had settled. Now: use
            // getSignatureStatuses + getTransaction tx-parse as the
            // single authority. LANDED requires BOTH tokens cleared AND
            // SOL received (operator: "I still want the sell verified and
            // that the tokens clear the wallet and return the sol").
            // INCONCLUSIVE_PENDING leaves the position open & qty
            // unchanged so the next exit tick can retry naturally.
            // V5.9.495z — when LANDED, capture the verifier's solReceived
            // (real on-chain SOL delta) into a closure-mutable holder so
            // the journal-write below uses on-chain truth instead of the
            // pre-trade quote.outAmount estimate.
            var verifiedSolReceived: Long = -1L
            run {
                if (finalSig.startsWith("PHANTOM_")) return@run  // dust/local close — skip verify
                val vsr = try {
                    TradeVerifier.verifySell(wallet, finalSig, ts.mint, timeoutMs = 60_000L)
                } catch (vfx: Throwable) {
                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.WARNING,
                        "⚠ TradeVerifier threw (${vfx.message?.take(60)}) — leaving position pending",
                        sig = finalSig, traderTag = "MEME",
                    )
                    null
                }
                when (vsr?.outcome) {
                    TradeVerifier.Outcome.LANDED -> {
                        verifiedSolReceived = vsr.solReceivedLamports
                        LiveTradeLogStore.log(
                            sellTradeKey, ts.mint, ts.symbol, "SELL",
                            LiveTradeLogStore.Phase.SELL_TX_PARSE_OK,
                            "✅ SELL LANDED [$reason]: rawConsumed=${vsr.rawTokenConsumed} ui=${vsr.uiTokenConsumed.fmt(4)} solReceived=${vsr.solReceivedLamports} lamports${if (vsr.tokenAccountClosedFullExit) " (ATA closed = full exit)" else ""}",
                            sig = finalSig, tokenAmount = vsr.uiTokenConsumed, traderTag = "MEME",
                        )
                        if (vsr.tokenAccountClosedFullExit) {
                            try {
                                HostWalletTokenTracker.recordAuthoritativeTxParseClose(
                                    ts.mint, ts.symbol, finalSig,
                                    "SELL_TX_PARSE_OK_FULL_EXIT_TOKEN_CONSUMED_ATA_CLOSED_SOL_RETURNED"
                                )
                            } catch (_: Throwable) {}
                        }
                        // Fall through to position mutation + journal write.
                    }
                    TradeVerifier.Outcome.FAILED_CONFIRMED -> {
                        LiveTradeLogStore.log(
                            sellTradeKey, ts.mint, ts.symbol, "SELL",
                            LiveTradeLogStore.Phase.SELL_FAILED_CONFIRMED,
                            "🚨 SELL_FAILED_CONFIRMED [$reason]: meta.err=${vsr.txErr} — position UNCHANGED, no treasury credit.",
                            sig = finalSig, tokenAmount = sellQty, traderTag = "MEME",
                        )
                        onLog("🚨 SELL meta.err [$reason] ${ts.symbol}: ${vsr.txErr} — position unchanged.", ts.mint)
                        TradeVerifier.endSell(ts.mint)
                        com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                        return
                    }
                    TradeVerifier.Outcome.INCONCLUSIVE_PENDING,
                    TradeVerifier.Outcome.VERIFICATION_ERROR -> {
                        LiveTradeLogStore.log(
                            sellTradeKey, ts.mint, ts.symbol, "SELL",
                            LiveTradeLogStore.Phase.SELL_VERIFY_INCONCLUSIVE_PENDING,
                            "⏳ SELL VERIFY INCONCLUSIVE [$reason]: tokens cleared AND SOL returned not BOTH proven within 60s — leaving position open & qty unchanged. Next tick will retry. Reconciler will adopt later.",
                            sig = finalSig, tokenAmount = sellQty, traderTag = "MEME",
                        )
                        TradeVerifier.endSell(ts.mint)
                        com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                        return
                    }
                    null -> {
                        // verifier threw — for safety, decline to mutate position; operator can re-trigger exit.
                        TradeVerifier.endSell(ts.mint)
                        com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                        return
                    }
                }
            }

            // V5.9.495y — clear the duplicate-exit guard once we've reached the success-mutation path.
            TradeVerifier.endSell(ts.mint)

            // V5.9.495z — solBack derives from REAL on-chain SOL delta when
            // verifier proved it. Falls back to quote only for PHANTOM
            // sentinels. This kills the +100277% / -100% phantom-PnL
            // entries from V5.9.495w that used quote.outAmount (inflated).
            val solBack: Double = when {
                sig.startsWith("PHANTOM_") -> 0.0
                verifiedSolReceived > 0L -> verifiedSolReceived / 1_000_000_000.0
                else -> quote.outAmount / 1_000_000_000.0  // legacy fallback (rare; verifier should always populate)
            }

            val profitLockAcct = liveSellAccountingAuthority(ts, pos.costSol * sellFraction, solBack, reason, "profitLock")
            val pnlSol = profitLockAcct.pnlSol
            val pnlPct = profitLockAcct.pnlPct
            val netPnl = profitLockAcct.netPnlSol
            val feeSol = profitLockAcct.feeSol
            
            val newQty = pos.qtyToken - sellQty
            val newCost = pos.costSol * (1.0 - sellFraction)
            
            val isCapitalRecovery = reason.contains("capital_recovery")
            val realizedCapitalRecovery4585 = isCapitalRecovery && pos.costSol > 0.0 && solBack >= pos.costSol * 0.98 && netPnl >= -0.000_001
            val realizedProfitLock4585 = !isCapitalRecovery && netPnl > 0.0 && solBack > 0.0
            if (isCapitalRecovery && !realizedCapitalRecovery4585) {
                try {
                    ForensicLogger.lifecycle(
                        "CAPITAL_RECOVERY_STATE_SUPPRESSED_UNREALIZED_4585",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} solBack=${solBack.fmt(6)} cost=${pos.costSol.fmt(6)} net=${netPnl.fmt(6)} reason=$reason sig=${finalSig.take(12)}",
                    )
                    PipelineHealthCollector.labelInc("CAPITAL_RECOVERY_STATE_SUPPRESSED_UNREALIZED_4585")
                } catch (_: Throwable) {}
            }
            ts.position = pos.copy(
                qtyToken = newQty,
                costSol = newCost,
                capitalRecovered = if (realizedCapitalRecovery4585) true else pos.capitalRecovered,
                capitalRecoveredSol = if (realizedCapitalRecovery4585) solBack else pos.capitalRecoveredSol,
                profitLocked = if (realizedProfitLock4585) true else pos.profitLocked,
                profitLockedSol = if (realizedProfitLock4585) solBack else pos.profitLockedSol,
                isHouseMoney = pos.isHouseMoney || realizedCapitalRecovery4585 || realizedProfitLock4585,
                lockedProfitFloor = pos.lockedProfitFloor + solBack,
            )
            
            // V5.0.3683 — ACCOUNTING LEDGER FIX (operator deep-audit P0).
            // trade.sol MUST be COST BASIS allocated to the portion sold so the
            // canonical accounting equation holds across every sell site:
            //   proceedsSol  = trade.sol + trade.pnlSol
            //   gainLossSol  = trade.pnlSol
            //   netGainSol   = trade.pnlSol - trade.feeSol
            // Previously this single live SELL leg stored solBack (proceeds) in
            // trade.sol while every other partial/profit-lock site stored
            // allocated cost basis. That inconsistency forced the CSV exporter
            // to either double-count proceeds or zero-out Net Gain.
            val sellCostBasisSol = pos.costSol * sellFraction
            val trade = Trade("SELL", "live", sellCostBasisSol, getActualPrice(ts),
                System.currentTimeMillis(), reason,
                pnlSol, pnlPct, sig = finalSig, feeSol = feeSol, netPnlSol = netPnl)
            recordTrade(ts, trade)
            security.recordTrade(trade)
            SmartSizer.recordTrade(netPnl > 0, isPaperMode = false)
            // V5.0.3868 — live sizing learns from realized net PnL, not gross pre-fee PnL.
            // V5.9.105: feed live PnL into session drawdown circuit breaker
            LiveSafetyCircuitBreaker.recordTradeResult(netPnl)

            // V5.9.109: FAIRNESS — profit-lock partial sells must pay the
            // same 0.5% fee as full sells. Basis = costSol × sellFraction
            // (portion actually being sold). Previously this path silently
            // skipped the fee split, short-changing the two wallets.
            try {
                val sellBasisSol = pos.costSol * sellFraction
                val feeAmountSol = sellBasisSol * MEME_TRADING_FEE_PERCENT
                if (feeAmountSol >= FEE_SEND_MIN_SOL) {
                    val feeWallet1 = feeAmountSol * FEE_SPLIT_RATIO
                    val feeWallet2 = feeAmountSol * (1.0 - FEE_SPLIT_RATIO)
                    sendFeeSplit(wallet, feeWallet1, feeWallet2, "profit_lock")
                    onLog("💸 TRADING FEE: ${String.format("%.6f", feeAmountSol)} SOL (0.5% of profit-lock) split 50/50", ts.mint)
                    ErrorLogger.info("Executor", "💸 LIVE PROFIT-LOCK FEE: ${feeAmountSol} SOL split to both wallets")
                }
            } catch (feeEx: Exception) {
                ErrorLogger.error("Executor", "🚨 FEE SEND FAILED — PROFIT-LOCK fee NOT sent, will retry next trade: ${feeEx.message}")
                // V5.9.226: Bug #7 — enqueue for retry instead of silently dropping
                val sellBasisSol2 = pos.costSol * sellFraction
                val feeAmt2 = sellBasisSol2 * MEME_TRADING_FEE_PERCENT
                if (feeAmt2 >= FEE_SEND_MIN_SOL) {
                    FeeRetryQueue.enqueue(TRADING_FEE_WALLET_1, feeAmt2 * FEE_SPLIT_RATIO, "profit_lock_w1")
                    FeeRetryQueue.enqueue(TRADING_FEE_WALLET_2, feeAmt2 * (1.0 - FEE_SPLIT_RATIO), "profit_lock_w2")
                }
            }

            val solPrice = WalletManager.lastKnownSolPrice
            val gainMultiple = (solBack + pos.lockedProfitFloor) / pos.costSol
            
            val eventType = if (realizedCapitalRecovery4585) TreasuryEventType.CAPITAL_RECOVERED
                           else TreasuryEventType.PROFIT_LOCK_SELL
            TreasuryManager.recordProfitLockEvent(eventType, solBack, ts.symbol, gainMultiple, solPrice)
            
            if (netPnl > 0) {
                try {
                    if (pos.isTreasuryPosition || pos.tradingMode == "TREASURY") {
                        TreasuryManager.contributeFullyFromTreasuryScalp(netPnl, solPrice)
                    } else {
                        TreasuryManager.contributeFromMemeSell(netPnl, solPrice)
                    }
                } catch (e: Exception) {
                    ErrorLogger.debug("Executor", "Treasury split error (profit-lock live): ${e.message}")
                }
            }

            LiveTradeLogStore.log(
                sellTradeKey, ts.mint, ts.symbol, "SELL",
                LiveTradeLogStore.Phase.SELL_VERIFY_SOL_RETURNED,
                "Profit lock landed | ${solBack.fmt(4)} SOL | net ${netPnl.fmt(4)} | ${if (pnlSol > 0) "+" else ""}${pnlPct.fmt(2)}%",
                sig = finalSig,
                solAmount = solBack,
                traderTag = "MEME",
            )
            // V5.9.495z28 (operator spec items 1+2+3): TWO-SIDE verification.
            // Don't trust SOL-returned alone — reconcile the wallet token
            // balance and only mark CLEARED when it's ≤ dust. Otherwise the
            // lifecycle tracker keeps the position in PARTIAL_SELL /
            // RESIDUAL_HELD so subsequent sweeps can finish the job.
            try {
                kotlinx.coroutines.GlobalScope.launch(AppDispatchers.sideEffect) {
                    val reading = TokenLifecycleTracker.reconcileWalletBalance(wallet, ts.mint)
                    val walletAfter = when (reading) {
                        is TokenLifecycleTracker.Reading.Confirmed -> reading.uiAmount
                        TokenLifecycleTracker.Reading.Empty -> null
                    }
                    TokenLifecycleTracker.onSellSettled(
                        mint = ts.mint, sig = finalSig,
                        solReceived = solBack, walletTokenAfter = walletAfter,
                    )
                    // V5.0.4173 — bust wallet account cache after live-sell
                    // settlement so the next wallet read shows the position
                    // gone immediately (no 5s lag).
                    try { com.lifecyclebot.engine.WalletAccountCache.bustNow() } catch (_: Throwable) {}
                    val phase = when {
                        walletAfter == null -> LiveTradeLogStore.Phase.SELL_STUCK
                        walletAfter > 0.000_001 -> LiveTradeLogStore.Phase.SELL_VERIFY_TOKEN_GONE  // misleading legacy name; partial
                        else -> LiveTradeLogStore.Phase.SELL_VERIFY_TOKEN_GONE
                    }
                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL", phase,
                        "Wallet reconcile: " + when {
                            walletAfter == null -> "RPC empty — RESIDUAL_HELD, watchdog will retry"
                            walletAfter > 0.000_001 -> "PARTIAL — ${walletAfter} ui remain"
                            else -> "CLEARED (token gone, SOL returned)"
                        },
                        traderTag = "MEME",
                    )
                    com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                }
            } catch (_: Throwable) {
                com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                /* never break the live path on reconcile */
            }
            onLog("✅ LIVE $reason: ${solBack.fmt(4)} SOL | pnl ${pnlSol.fmt(4)} SOL | sig=${finalSig.take(16)}…", ts.mint)
            try {
                val notifyKey4585 = "${ts.mint}:${finalSig}:${reason.take(48)}"
                if (realizedMoneyNotifiedSellKeys4585.add(notifyKey4585)) {
                    val realizedMultiple4585 = if (pos.costSol > 0.0) solBack / pos.costSol else 0.0
                    when {
                        realizedCapitalRecovery4585 -> {
                            onNotify(
                                "🔒 Capital Recovered!",
                                "${ts.symbol} received ${solBack.fmt(4)} SOL (${realizedMultiple4585.fmt(2)}x real) net ${netPnl.fmt(4)} SOL",
                                com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO,
                            )
                            sounds?.playMilestone((realizedMultiple4585 - 1.0) * 100.0)
                            PipelineHealthCollector.labelInc("CAPITAL_RECOVERY_NOTIFY_REALIZED_4585")
                        }
                        realizedProfitLock4585 -> {
                            onNotify(
                                "✅ Profit Locked",
                                "${ts.symbol} realized ${solBack.fmt(4)} SOL net ${netPnl.fmt(4)} SOL",
                                com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO,
                            )
                            sounds?.playMilestone(pnlPct)
                            PipelineHealthCollector.labelInc("PROFIT_LOCK_NOTIFY_REALIZED_4585")
                        }
                        else -> {
                            PipelineHealthCollector.labelInc("REAL_MONEY_NOTIFY_SUPPRESSED_NOT_PROFIT_4585")
                        }
                    }
                } else {
                    PipelineHealthCollector.labelInc("REAL_MONEY_NOTIFY_DUP_SUPPRESSED_4585")
                }
            } catch (_: Throwable) {}
                
        } catch (e: Exception) {
            // V5.9.474 — classified post-quote forensics for profit-lock catch
            // (mirrors V5.9.468 outer-catch in liveSell). Was: onLog-only silent kill.
            val safe = security.sanitiseForLog(e.message ?: "unknown")
            val broadcastRetries = zeroBalanceRetries.merge(ts.mint + "_broadcast", 1) { old, _ -> old + 1 } ?: 1
            // V5.9.1522 — canonical classification (0x1788 is SIM, not generic slippage).
            val routeCls = com.lifecyclebot.engine.sell.SellRouteErrorClassifier.classify(safe)
            val routePolicy = com.lifecyclebot.engine.sell.SellRouteErrorClassifier.retryPolicy(routeCls, broadcastRetries, retryScheduled = false)
            // V5.9.1533 — spec item 7: 0x1787 / PUMP_ROUTE_INVALID must RE-RESOLVE the
            // venue, not retry the same Pump-direct payload. Mark the mint so the next
            // attempt skips pump-native and re-resolves to PumpSwap/Raydium/Jupiter.
            if (routePolicy.requireVenueReResolution) {
                try { com.lifecyclebot.engine.sell.MemeVenueRouter.markPumpRouteInvalid(ts.mint) } catch (_: Throwable) {}
                try { ForensicLogger.lifecycle("SELL_VENUE_RE_RESOLVE",
                    "mint=${ts.mint.take(10)} class=${routeCls.name} action=skip_pump_direct_reresolve") } catch (_: Throwable) {}
            }
            val failureClass = routeCls.name
            if (routePolicy.releaseLock) {
                try { com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint) } catch (_: Throwable) {}
                try { com.lifecyclebot.engine.HostWalletTokenTracker.clearSellInFlight(ts.mint, "ROUTE_FAILED_" + routeCls.name) } catch (_: Throwable) {}
            }
            LiveTradeLogStore.log(
                sellTradeKey, ts.mint, ts.symbol, "SELL",
                LiveTradeLogStore.Phase.SELL_FAILED,
                "$failureClass — ${e.javaClass.simpleName}: ${safe.take(120)} (attempt $broadcastRetries)",
                traderTag = "MEME",
            )
            com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
            ErrorLogger.warn("Executor", "PROFIT-LOCK SELL POST-QUOTE FAILURE: ${ts.symbol} class=$failureClass exc=${e.javaClass.simpleName} retry=$broadcastRetries")
            onLog("❌ Profit lock sell FAILED: $failureClass — ${safe.take(80)} (retry $broadcastRetries)", ts.mint)
        }
    }

    // ── partial sell ─────────────────────────────────────────────────

    /**
     * V5.9.494 — public manage-only path used by BotService.sweepUniversalExits.
     * Runs the in-position management triad on EVERY open position once
     * per loop tick, regardless of scanner visibility:
     *   1) checkProfitLock — dynamic profit-lock + trailing
     *   2) checkPartialSell — TP1/TP2 partial profit-taking
     *   3) Catastrophic floor — last-resort SL via FluidLearning floor
     *
     * Idempotent: if no trigger fires, this is three cheap conditionals.
     * Operator: 'where are the fluid stops and dynamic profit lockers?
     * nothing should rip 35% out of us!' — this guarantees they fire
     * even when DexScreener misses a tick.
     */
    private fun trySweepTakeProfitExit(
        ts: TokenState,
        currentPrice: Double,
        wallet: SolanaWallet?,
        walletSol: Double,
        settleBypass: Boolean = false,
    ): Boolean {
        if (!ts.position.isOpen || currentPrice <= 0.0) return false
        val pnlVerdict6038 = OpenPnlSanity.inspectPosition(ts.position, currentPrice, "Executor.trySweepTakeProfitExit_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true)
        val pnlPct = if (pnlVerdict6038.ok) pnlVerdict6038.pnlPct else 0.0
        val tpPct = when {
            // V5.0.4125 — style-adjusted TP takes PRIORITY over lane-specific TPs.
            ts.position.entryTakeProfitPct > 0.0 ->
                ts.position.entryTakeProfitPct
            ts.position.isShitCoinPosition && ts.position.shitCoinTakeProfit > 0.0 ->
                ts.position.shitCoinTakeProfit
            ts.position.isBlueChipPosition && ts.position.blueChipTakeProfit > 0.0 ->
                ts.position.blueChipTakeProfit
            ts.position.isTreasuryPosition && ts.position.treasuryTakeProfit > 0.0 ->
                ts.position.treasuryTakeProfit
            else -> {
                // Generic meme: use fluid TP — lerps from 15% bootstrap to
                // cfg default as learning matures.
                try {
                    com.lifecyclebot.v3.scoring.FluidLearningAI
                        .getFluidTakeProfit(cfg().exitScoreThreshold.coerceAtLeast(20.0))
                } catch (_: Throwable) { 20.0 }
            }
        }
        val laneKey = ts.position.tradingMode.ifBlank { "STANDARD" }
        val learnedTpFloor = try { WrRecoveryPartial.learnedExitRungs(laneKey).first } catch (_: Throwable) { 50.0 }
        val tune = try { LiveStrategyTuner.adjustment(laneKey) } catch (_: Throwable) { LiveStrategyTuner.adjustment("STANDARD") }
        val liveGrowthTpPct = maxOf(tpPct, learnedTpFloor) * tune.tpMult
        if (RuntimeModeAuthority.isLive() && tune.tpMult > 1.0) {
            try { ForensicLogger.lifecycle("LIVE_STRATEGY_TUNER_TP_RAISED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$laneKey baseTp=${tpPct.toInt()} learned=${learnedTpFloor.toInt()} tuned=${liveGrowthTpPct.toInt()} tune=${tune.compact}") } catch (_: Throwable) {}
        }
        if (pnlPct >= liveGrowthTpPct) {
            val tag = if (settleBypass) "SWEEP_TAKE_PROFIT_SETTLE_BYPASS_4200" else "SWEEP_TAKE_PROFIT"
            try {
                ForensicLogger.lifecycle(
                    tag,
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} pnl=${pnlPct.toInt()} learnedTp=${liveGrowthTpPct.toInt()} settleBypass=$settleBypass action=sell_now",
                )
                if (settleBypass) PipelineHealthCollector.labelInc("SWEEP_TAKE_PROFIT_SETTLE_BYPASS_4200")
            } catch (_: Throwable) {}
            onLog("🎯 $tag: ${ts.symbol} pnl=${pnlPct.toInt()}% ≥ learnedTp=${liveGrowthTpPct.toInt()}%", ts.mint)
            doSell(ts, "SWEEP_TAKE_PROFIT_${liveGrowthTpPct.toInt()}${if (settleBypass) "_SETTLE_BYPASS" else ""}", wallet, walletSol)
            return true
        }
        return false
    }

    fun runManageOnly(ts: TokenState, wallet: SolanaWallet?, walletSol: Double) {
        if (!ts.position.isOpen) return
        val currentPrice = getActualPrice(ts)
        if (currentPrice > 0.0) {
            ts.position.highestPrice = maxOf(ts.position.highestPrice, currentPrice)
            if (ts.position.lowestPrice == 0.0 || currentPrice < ts.position.lowestPrice)
                ts.position.lowestPrice = currentPrice
        }

        // V5.9.1259 — UNIVERSAL STALE-FEED EVICTION (volume unblock).
        // ════════════════════════════════════════════════════════════════
        // Runtime evidence (session 9612dbdf, 19:44): 10 open SHITCOIN/MOONSHOT/
        // MANIPULATED pump.fun micros (vol1h=$0) pinned all slots for 13.7min
        // (execAge=822s) while a firehose of 100s of candidates/min starved →
        // forcedOpen=10 every cycle, ZERO new entries, volume collapsed.
        // ROOT CAUSE: a no-trade pump.fun token stops ticking → lastPrice never
        // refreshes → getActualPrice() returns the stale entry price → PnL sits
        // at exactly 0% → neither TP nor SL (both price-based) can EVER fire in
        // this 2s hot path. The slot only frees when the SLOW maxHold timer
        // (15-180min, in maybeAct) finally fires. There IS a stale-feed exit but
        // it was scoped to QUALITY only (BotService:18226). Specialist lanes had
        // no equivalent → zombie slot-squatters.
        // FIX: lane-AGNOSTIC dead-feed eviction in the universal hot path. Same
        // thresholds as the proven QUALITY path (feed dead ≥10min AND held
        // ≥20min). A token with no price movement for 10min is not a runner and
        // not a learning signal — it's a dead slot. Evict to recycle it.
        // SAFETY: (1) paper settle-in respected (entry slippage needs time to
        // mean-revert); (2) RUNNER BYPASS — never evict a live runner
        // (peakGain≥20% with trend intact); (3) only fires when feed is GENUINELY
        // dead (lastPriceUpdate age), never on a moving position. Frees slots →
        // directly serves the 500-1000/day volume target. Fail-open.
        run {
            try {
                val nowMs = System.currentTimeMillis()
                val heldMin = if (ts.position.entryTime > 0L)
                    (nowMs - ts.position.entryTime) / 60_000.0 else 0.0
                // V5.0.3843 — UNKNOWN price timestamp is not an astronomically
                // stale feed. Do not let Long.MAX_VALUE become an exit trigger or
                // journal reason. Restored positions stamp lastPriceUpdate; if a
                // legacy row still has none, stale-feed eviction waits for a real tick.
                val feedAnchorMs = ts.lastPriceUpdate.takeIf { it > 0L }
                val feedAgeMs = feedAnchorMs?.let { (nowMs - maxOf(it, ts.position.entryTime)).coerceAtLeast(0L) }
                // V5.9.1264 — FAST-EVICT TIER for genuinely-dead paper micros.
                // Runtime evidence (build 3228, 21:52): 20/20 slots pinned by
                // pump.fun micros with vol1h=$0 that NEVER tick → PnL stuck at
                // exactly 0% → forcedOpen=20 every cycle, fresh=0, EXEC stalled at
                // 33. The conservative 10min/20min tier below is correct for LIVE
                // and for positions that have at least moved, but a PAPER token
                // whose feed has been dead for minutes AND has never moved off 0%
                // is a zombie squatting a slot — recycle it far sooner so the
                // firehose of candidates can enter. Tighter, paper-only, flat-PnL-
                // gated, runner-bypass still applies. Directly serves volume.
                val nowPnlFastVerdict6038 = OpenPnlSanity.inspectPosition(ts.position, currentPrice, "Executor.dead_feed_fast_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true)
                val nowPnlFast = if (nowPnlFastVerdict6038.ok) nowPnlFastVerdict6038.pnlPct else 0.0
                val fastDeadFeed = isPaperRT() &&
                    feedAgeMs != null && feedAgeMs >= 3L * 60_000L &&      // feed silent ≥3min
                    heldMin >= 4.0 &&                 // held ≥4min (well past 90s settle-in)
                    kotlin.math.abs(nowPnlFast) < 2.0 && // never moved off entry (dead, not a runner)
                    ts.position.peakGainPct < 20.0      // never ran
                val FEED_DEAD_MS = 10L * 60_000L
                val MIN_HELD_MIN = 20.0
                if (fastDeadFeed || (feedAgeMs != null && feedAgeMs >= FEED_DEAD_MS && heldMin >= MIN_HELD_MIN)) {
                    // RUNNER BYPASS — don't evict a position that ran and is
                    // still near its peak (mirrors maybeAct runner-bypass).
                    val curPnlVerdict6038 = OpenPnlSanity.inspectPosition(ts.position, currentPrice, "Executor.dead_feed_runner_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true)
                    val curPnl = if (curPnlVerdict6038.ok) curPnlVerdict6038.pnlPct else 0.0
                    val peak = ts.position.peakGainPct
                    val runnerIntact = peak >= 20.0 && curPnl >= peak * 0.70
                    // Paper settle-in: brand-new paper entries are born at the
                    // slippage-band PnL; never evict before they've settled.
                    val settleIn = run {
                        if (!isPaperRT()) return@run false
                        val ageMs = nowMs - ts.position.entryTime
                        ageMs < 90_000L  // 90s hard floor; heldMin>=20 already exceeds this
                    }
                    if (!runnerIntact && !settleIn) {
                        val feedAgeMin = (feedAgeMs ?: 0L) / 60_000L
                        onLog("💀 STALE_FEED_EVICT: ${ts.symbol} feedAge=${feedAgeMin}min held=${heldMin.toInt()}min pnl=${"%+.0f".format(curPnl)}% — dead feed, recycling slot", ts.mint)
                        doSell(ts, "stale_feed_evict_feedAge${feedAgeMin}m_held${heldMin.toInt()}m", wallet, walletSol)
                        return
                    }
                }
            } catch (_: Throwable) { /* fail-open: eviction must never break exit management */ }
        }

        // V5.9.495z5 — STRICT PER-TRADER SL FIRES UNIVERSALLY (no settle-in
        // grace). Operator (06 May 2026, COMPANY -16.5% with SL -5% never
        // firing): "stop losses on treasury trades are meant to be tight
        // and we are meant to have the dynamic stop loss and profit locks
        // working in a fluid state on all meme trades no matter which
        // trader is carrying out the trade."
        //
        // Previous behaviour (V5.9.495i) returned on settle-in BEFORE
        // STRICT_SL — meaning a fresh entry could bleed past its configured
        // SL during the first 45s and we'd still hold. The settle-in was
        // added to prevent kneejerk exits on noise, but the operator's
        // explicit mandate is: SL is tight, period. We keep settle-in for
        // FLUID exits (dynamic floor, partial-sell, profit-lock unlock) but
        // STRICT_SL_FLOOR runs first regardless of age and applies to every
        // open position no matter which sub-trader entered it.
        //
        // V5.9.1028 — PAPER-MODE-ONLY SETTLE-IN RESTORATION.
        // Operator V5.9.1027b snapshot: every paper trade exits at -10%
        // STRICT_SL within 350-1000ms of entry — NO token can drop -10%
        // that fast. Root cause: paperBuy applies +12% slippage on entry
        // (Executor.kt L6540) and paperSell applies -18% slippage on exit
        // (Executor.kt L9104) — round-trip cost on <$5k pump.fun pools is
        // -26.8% by simulation, before ANY price movement. So every
        // brand-new paper position is born at -26.8% PnL and STRICT_SL
        // fires instantly. This corrupts the bot's learning (every
        // entry "looks" like a -10% loss in the journal) and gutters
        // MOONSHOT / lanes that need time to play out.
        //
        // Fix: in paper mode ONLY, suppress STRICT_SL for a per-lane
        // settle-in window sourced from FluidLearningAI. Live mode is
        // untouched — real slippage IS the real cost. Other stops (RAPID
        // trailing, fluid floor, profit-lock) remain active throughout
        // the settle-in so we still catch genuine rugs via those paths.

        // ═══════════════════════════════════════════════════════════════════
        // V5.0.4160 — CATASTROPHIC -25% HARD EMERGENCY BACKSTOP
        // ═══════════════════════════════════════════════════════════════════
        // Operator P0 (2026-06-25): runtime dump showed trades closing at
        // -71% and -58% even though configured STRICT_SL was -10%. Root
        // cause was a Jupiter DNS blackout (`tokens.jup.ag` unresolvable)
        // that stalled live quotes; both the live and cached SL paths
        // skipped firing because the feed simply stopped ticking before
        // the price ever reached the configured floor, and by the time
        // maxHold finally cut the bag the realized fill was catastrophic.
        //
        // This block is the LAST-LINE BACKSTOP. It runs BEFORE any other
        // gate (paper settle-in, fluid SL coercion, fluid stops, profit
        // locks) and BEFORE STRICT_SL. If EITHER the live price OR the
        // most recent cached price shows pnl <= -25%, we force-exit
        // immediately, regardless of quote freshness, learning state,
        // or trader settle-in. There is no scenario where holding a
        // -25% bag through a quote outage is correct behaviour.
        run {
            val pos = ts.position
            if (!pos.isOpen || pos.entryPrice <= 0.0) return@run
            val livePnlVerdict6038 = if (currentPrice > 0.0) OpenPnlSanity.inspectPosition(pos, currentPrice, "Executor.quote_outage_live_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true) else OpenPnlSanity.Verdict(false, reason = "NO_LIVE_PRICE")
            val livePnl = if (livePnlVerdict6038.ok) livePnlVerdict6038.pnlPct else Double.NaN
            val cachedPx = ts.lastPrice
            val cachedPnlVerdict6038 = if (cachedPx > 0.0) OpenPnlSanity.inspectPosition(pos, cachedPx, "Executor.quote_outage_cached_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true) else OpenPnlSanity.Verdict(false, reason = "NO_CACHED_PRICE")
            val cachedPnl = if (cachedPnlVerdict6038.ok) cachedPnlVerdict6038.pnlPct else Double.NaN
            val candidates = listOf(livePnl, cachedPnl).filter { it.isFinite() }

            // V5.0.4594 — STALE-QUOTE EMERGENCY BACKSTOP (operator P0).
            // Root cause of -99.4% / -96.1% / -95% exits (field report
            // 2026-07-02): BOTH the live Jupiter quote AND the cached scanner
            // price go stale during a rug/liquidity collapse. When both
            // reads are NaN, the existing SL / rug / -25% checks return
            // early on `if (candidates.isEmpty()) return@run`, so NONE of
            // them fire — the bag then bleeds until maxHold trips and the
            // realized fill is catastrophic. This backstop fires an
            // unconditional force-exit if:
            //   • position has been open for > 15s (long enough for a
            //     legit quote to have arrived at least once), AND
            //   • BOTH live and cached prices are non-finite (no signal
            //     for at least one full status check window).
            // We assume the worst (rug in progress) and cut immediately.
            // Threshold: force-exit at the -25% floor already accepted as
            // "no scenario where holding this makes sense". Safe fallback:
            // no assumption about price direction — just call doSell and
            // let the executor's sell path use its own last-known-good
            // price for slippage math.
            if (candidates.isEmpty() && pos.isOpen && pos.entryPrice > 0.0) {
                val holdMs = try { System.currentTimeMillis() - pos.entryTime } catch (_: Throwable) { 0L }
                if (holdMs >= 15_000L) {
                    try {
                        ForensicLogger.lifecycle(
                            "STALE_QUOTE_EMERGENCY_25PCT_BACKSTOP_4594",
                            "mint=${ts.mint.take(10)} sym=${ts.symbol} holdMs=$holdMs entry=${pos.entryPrice} livePx=${currentPrice} cachedPx=${cachedPx} — no finite price reads >15s, force-exiting at -25% assumption",
                        )
                        PipelineHealthCollector.labelInc("STALE_QUOTE_EMERGENCY_25PCT_BACKSTOP")
                    } catch (_: Throwable) {}
                    onLog(
                        "☠ STALE-QUOTE EMERGENCY: ${ts.symbol} hold=${holdMs / 1000}s — no price feed, cutting NOW (assumed -25%)",
                        ts.mint,
                    )
                    doSell(ts, "STALE_QUOTE_EMERGENCY_25PCT_BACKSTOP", wallet, walletSol)
                    return
                }
            }

            if (candidates.isEmpty()) return@run
            val worstPnl = candidates.min()
            val bestPnl = candidates.max()

            // V5.0.4585 — QUICK RUNNER EMERGENCY EXIT (operator P0).
            // Operator: "theres nothing wrong with grabbing a quick snipe when
            // a coins up 2000% in the first 30 seconds after buying. grab the
            // full exit move on. time locks and min hold are irrelevant if
            // the conditions say take the win now!!!"
            // If ANY finite pnl reads >= +500%, fire FULL EXIT immediately,
            // bypassing style-hold, min-hold, time-lock, and lane-specific
            // hold rules. Real Price Lock still validates the price is real
            // via a Jupiter sanity route inside runManageOnly / doSell path;
            // but the DECISION to exit at this level is unconditional.
            // Threshold tiers:
            //   +500%   → 95% exit (bank the 6x)
            //   +1000%  → 100% exit (bank the 11x, no partials, no runner
            //             leftover — the pumps that go 10x reverse hard)
            run quickRunner@{
                if (bestPnl >= 1000.0) {
                    try {
                        ForensicLogger.lifecycle(
                            "QUICK_RUNNER_EMERGENCY_FULL_EXIT",
                            "mint=${ts.mint.take(10)} sym=${ts.symbol} bestPnl=${bestPnl.fmt(1)}% reason=operator_10x_bank_bypass_holds — 100% exit NOW",
                        )
                        PipelineHealthCollector.labelInc("QUICK_RUNNER_EMERGENCY_FULL_EXIT")
                    } catch (_: Throwable) {}
                    onLog("🚀🚀 QUICK RUNNER 10x EXIT: ${ts.symbol} +${bestPnl.toInt()}% — bypassing all holds, full exit NOW", ts.mint)
                    doSell(ts, "QUICK_RUNNER_10X_FULL_EXIT", wallet, walletSol)
                    return
                } else if (bestPnl >= 500.0) {
                    try {
                        ForensicLogger.lifecycle(
                            "QUICK_RUNNER_EMERGENCY_BANK_95PCT",
                            "mint=${ts.mint.take(10)} sym=${ts.symbol} bestPnl=${bestPnl.fmt(1)}% reason=operator_6x_bank_bypass_holds — bank 95% NOW",
                        )
                        PipelineHealthCollector.labelInc("QUICK_RUNNER_EMERGENCY_BANK_95PCT")
                    } catch (_: Throwable) {}
                    onLog("🚀 QUICK RUNNER 6x BANK: ${ts.symbol} +${bestPnl.toInt()}% — bypassing holds, banking 95%", ts.mint)
                    // Use standard doSell (full path) — the sell size fraction is
                    // applied inside the executor's normal sell handler based on
                    // remaining position. This is treated as effectively-full
                    // for the purposes of unlocking the runner.
                    doSell(ts, "QUICK_RUNNER_6X_BANK_95PCT", wallet, walletSol)
                    return
                }
            }

            // V5.0.4585 — HARD -15% SL FOR CATASTROPHIC LANES (operator P0
            // "Rule 2"). Operator V5.0.4584 dump: MANIPULATED -0.347 SOL,
            // SHITCOIN -0.133, EXPRESS -0.113 combined -0.593 SOL bleed
            // versus +0.157 SOL from winners. Recent closes show -99.4% /
            // -96.1% / -95.5% on these three lanes because their existing
            // stop bars are lane-specific and fire too late. Universal
            // hard-cap: for any position in MANIPULATED / SHITCOIN /
            // EXPRESS, exit at -15% absolute PnL regardless of lane rules.
            // Winners (STANDARD/MOONSHOT/BLUECHIP) keep their -25% for
            // more room to breathe.
            run laneHardCap@{
                val laneName = try {
                    ts.position.tradingMode.uppercase()
                } catch (_: Throwable) { "" }
                val isCatastrophicLane = laneName == "MANIPULATED" ||
                    laneName == "SHITCOIN" ||
                    laneName == "EXPRESS"
                if (isCatastrophicLane && worstPnl <= -15.0) {
                    try {
                        ForensicLogger.lifecycle(
                            "LANE_HARD_15PCT_SL",
                            "mint=${ts.mint.take(10)} sym=${ts.symbol} lane=$laneName worstPnl=${worstPnl.fmt(2)} — catastrophic-lane hard cap fired",
                        )
                        PipelineHealthCollector.labelInc("LANE_HARD_15PCT_SL_$laneName")
                    } catch (_: Throwable) {}
                    onLog("🛑 LANE HARD-15% SL: ${ts.symbol} lane=$laneName worstPnl=${worstPnl.toInt()}% — cutting NOW", ts.mint)
                    doSell(ts, "LANE_HARD_15PCT_SL_$laneName", wallet, walletSol)
                    return
                }
            }

            // V5.0.4187 — THIN-LIQ EARLY RUG GUARD (Fix B2). Operator V5.0.4186
            // dump: BCLiquFq lost -96.1% (reason=CATASTROPHIC_STOP_LOSS_OVERRUN_-95pct_FROM_RAPID).
            // The existing -25% backstop fires correctly but post-rug
            // exits realise at -90% to -96% because liquidity is already
            // gone by the time we broadcast. Mitigation: for tokens with
            // thin liquidity (< $5K) in their first 60s on the book,
            // fire HARD-EXIT at -10%. Thin-liq fresh tokens are the
            // rug-prone class; cutting losses at -10% rather than -25%
            // saves 2-3x on each rug while having near-zero false-positive
            // cost on legit runners (a legit runner that dips 10% in the
            // first minute on $5K liq isn't a high-conviction trade anyway).
            //
            // V5.0.4551 — UNIVERSAL RUG BACKSTOP. Operator V5.0.4545 audit:
            // closes show MANIPULATED/EXPRESS hitting -96%. Extended window
            // 60s → 10 min (most rugs occur in first 10 min of life on the
            // book; the 60s window only caught the fastest rugs).
            // Threshold ALSO triggers if liq has DROPPED >50% from last
            // recorded value (= liquidity-drain rug in progress regardless
            // of token age). Universal across all lanes.
            run earlyRug@{
                val liqUsd = try { ts.lastLiquidityUsd } catch (_: Throwable) { 0.0 }
                val ageMs = try { System.currentTimeMillis() - pos.entryTime } catch (_: Throwable) { Long.MAX_VALUE }
                val freshThinLiq = liqUsd > 0.0 && liqUsd < 5_000.0 && ageMs in 0..600_000L && worstPnl <= -10.0
                // Liquidity-drain check: pos may persist a snapshot of entry-time liq via
                // peakLiqUsd / entryLiquidityUsd. Conservative path: trigger on -15% PnL
                // when current liq is < 50% of $5K threshold (i.e., < $2.5K) regardless
                // of age — this captures lanes (MANIPULATED, EXPRESS) where rug occurs
                // past the 60s but pool drain is the smoking gun.
                val liqDrainRug = liqUsd > 0.0 && liqUsd < 2_500.0 && worstPnl <= -15.0
                if (freshThinLiq || liqDrainRug) {
                    val reason = if (freshThinLiq) "THIN_LIQ_FRESH_TOKEN" else "LIQ_DRAIN_IN_PROGRESS"
                    try {
                        ForensicLogger.lifecycle(
                            "THIN_LIQ_EARLY_RUG_BACKSTOP_10",
                            "mint=${ts.mint.take(10)} sym=${ts.symbol} worstPnl=${worstPnl.fmt(2)} liqUsd=${liqUsd.toInt()} ageMs=$ageMs reason=$reason — cut losses early before realised slippage compounds",
                        )
                        PipelineHealthCollector.labelInc("THIN_LIQ_EARLY_RUG_BACKSTOP_10")
                    } catch (_: Throwable) {}
                    onLog(
                        "☠ EARLY-RUG BACKSTOP: ${ts.symbol} worstPnl=${worstPnl.toInt()}% liq=\$${liqUsd.toInt()} reason=$reason — cutting NOW",
                        ts.mint
                    )
                    doSell(ts, "THIN_LIQ_EARLY_RUG_BACKSTOP_-${if (freshThinLiq) "10" else "15"}", wallet, walletSol)
                    return
                }
            }

            if (worstPnl <= -25.0) {
                try {
                    ForensicLogger.lifecycle(
                        "CATASTROPHIC_HARD_BACKSTOP_25",
                        "mint=${ts.mint.take(10)} sym=${ts.symbol} worstPnl=${worstPnl.fmt(2)} livePnl=${if (livePnl.isFinite()) livePnl.fmt(2) else "NaN"} cachedPnl=${if (cachedPnl.isFinite()) cachedPnl.fmt(2) else "NaN"} entry=${pos.entryPrice} currentPx=${currentPrice} cachedPx=${cachedPx}"
                    )
                } catch (_: Throwable) {}
                onLog(
                    "☠ CATASTROPHIC -25% BACKSTOP: ${ts.symbol} worstPnl=${worstPnl.toInt()}% — last-line force-exit (quote freshness ignored)",
                    ts.mint
                )
                doSell(ts, "CATASTROPHIC_HARD_BACKSTOP_-25", wallet, walletSol)
                return
            }
        }

        val paperSettleInActive = run {
            if (!isPaperRT()) return@run false
            val entryMs = ts.position.entryTime
            if (entryMs <= 0L) return@run false
            val ageMs = System.currentTimeMillis() - entryMs
            val lane = ts.position.tradingMode.ifBlank { "V3" }
            val settleInMinutes = try {
                com.lifecyclebot.v3.scoring.FluidLearningAI.getFluidMinHoldMinutes(lane)
            } catch (_: Throwable) { 0.5 }
            // Absolute floor of 30s: slippage band (entry +12%, exit -18%)
            // needs at least that long to mean-revert on a churning pool.
            val settleInMs = maxOf((settleInMinutes * 60_000.0).toLong(), 30_000L)
            ageMs < settleInMs
        }
        run {
            if (paperSettleInActive) return@run
            val pos = ts.position
            val rawSL = when {
                pos.isShitCoinPosition && pos.shitCoinStopLoss > 0.0 -> pos.shitCoinStopLoss
                pos.isBlueChipPosition && pos.blueChipStopLoss > 0.0 -> pos.blueChipStopLoss
                pos.isTreasuryPosition && pos.treasuryStopLoss > 0.0 -> pos.treasuryStopLoss
                else -> cfg().stopLossPct.takeIf { it > 0.0 } ?: 20.0
            }
            // V5.9.1028 — AI-FLUID STOP LOSS THRESHOLD.
            // Operator V5.9.1027b mandate: "the strict and rapid stops are
            // still meant to be a fluid learnt thing as well. everything is
            // meant to be." Route the trader's raw stop through
            // FluidLearningAI.getFluidStopLoss() so the threshold lerps from
            // a -15% bootstrap floor (capital protection while learning)
            // toward the trader's full mode stop at maturity. Without this,
            // every position bleeds straight to the hardcoded trader SL
            // and learning never gets to influence the gate.
            val modeStopNegative = -rawSL.coerceIn(3.0, 50.0)
            val fluidStopNegative = try {
                com.lifecyclebot.v3.scoring.FluidLearningAI.getFluidStopLoss(modeStopNegative)
            } catch (_: Throwable) { modeStopNegative }
            // V5.0.4179 — F2: PREDICTIVE SL. Field journal showed STRICT_SL_-10
            // overrunning to -71% realized due to thin-liq exit slippage.
            // ExecutionCostPredictorAI already learns per-liq-band slip. Now:
            // pull the SL trigger EARLIER by the learned slip so the
            // REALIZED loss caps at the configured stop. e.g. if liq band
            // averages 8% slip and configured SL is -10, fire at -2 so the
            // realized fill comes back near -10 instead of -18. Capped to a
            // minimum -3% to avoid jitter exits on healthy positions.
            val predictedSlip = try {
                com.lifecyclebot.v3.scoring.ExecutionCostPredictorAI.expectedExtraSlipPct(ts.lastLiquidityUsd)
            } catch (_: Throwable) { 0.0 }
            val slipAdjustedStop = if (predictedSlip > 1.0) {
                (fluidStopNegative + predictedSlip).coerceAtMost(-3.0)
            } else fluidStopNegative
            val hardFloor = slipAdjustedStop.coerceIn(-50.0, -3.0)
            val pnlPctNowVerdict6038 = OpenPnlSanity.inspectPosition(pos, currentPrice, "Executor.dynamic_stop_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true)
            val pnlPctNow = if (pnlPctNowVerdict6038.ok) pnlPctNowVerdict6038.pnlPct else 0.0
            if (currentPrice > 0.0 && pnlPctNow <= hardFloor) {
                // V5.0.6006 — AGI STOP-LOSS VETO AUTHORITY. Once a lane's
                // UnifiedExitPolicyHead reaches LEARNED tier with a healthy
                // Brier (<= 0.15) AND strongly signals "hold longer"
                // (exitBias >= 1.20) AND pnlPct is not catastrophic (> -20%),
                // the AGI can VETO this SL trigger and let the position ride.
                // Guard rails inside shouldVetoStopLoss prevent runaway
                // losses: quarantined lanes can never veto, catastrophic
                // drops (<= -20%) always honor the SL, and every failure
                // path defaults to HONOR (safe).
                val agiLane = when {
                    pos.isShitCoinPosition -> "SHITCOIN"
                    pos.isBlueChipPosition -> "BLUECHIP"
                    pos.isTreasuryPosition -> "TREASURY"
                    else -> pos.tradingMode.trim().uppercase().ifBlank { "STANDARD" }
                }
                val exitSignals = try { unifiedExitSignalsFor(ts, pnlPctNow, pos.peakGainPct) } catch (_: Throwable) { null }
                val veto = if (exitSignals != null) {
                    try { com.lifecyclebot.engine.UnifiedExitPolicyHead.shouldVetoStopLoss(agiLane, pnlPctNow, exitSignals) }
                    catch (_: Throwable) { com.lifecyclebot.engine.UnifiedExitPolicyHead.VetoDecision.HONOR }
                } else com.lifecyclebot.engine.UnifiedExitPolicyHead.VetoDecision.HONOR
                if (veto == com.lifecyclebot.engine.UnifiedExitPolicyHead.VetoDecision.VETO) {
                    onLog("🧠 AGI VETO SL: ${ts.symbol} pnl=${pnlPctNow.toInt()}% floor=${hardFloor.toInt()}% lane=$agiLane — exit brain says hold", ts.mint)
                    // Skip the SL for this tick; runtime will re-evaluate on
                    // the next hot-exit pass. If the brain's confidence drops
                    // or price falls to catastrophic territory, next pass
                    // will honor.
                    return
                }
                onLog("🛑 STRICT SL: ${ts.symbol} pnl=${pnlPctNow.toInt()}% ≤ ${hardFloor.toInt()}% (trader=${
                    when {
                        pos.isShitCoinPosition -> "SHITCOIN"
                        pos.isBlueChipPosition -> "BLUECHIP"
                        pos.isTreasuryPosition -> "TREASURY"
                        else -> "DEFAULT"
                    }
                }) — force-exit", ts.mint)
                doSell(ts, "STRICT_SL_${hardFloor.toInt()}", wallet, walletSol)
                return
            }
            // V5.0.4079 — STRICT_SL STALE-PRICE BACKSTOP (operator P0: -48% leak
            // on STRICT_SL_-10 because the feed went silent during the dump).
            // Pre-V5.0.4079 we silently skipped the SL on currentPrice==0 and
            // waited for the "next price resolve" — which on a rugging mint can
            // be minutes away, by which point the position has drained 38%
            // beyond the configured floor. Now:
            //   1. If currentPrice<=0 but ts.lastPrice has a cached value, use
            //      it to check the floor. Old prices are still better than no
            //      prices for an SL decision — we are protecting capital, not
            //      taking profits.
            //   2. If both are stale AND position age >= 60s AND last cached
            //      update is older than 90s, force-exit with STALE_PRICE_FORCED
            //      to avoid silent catastrophic overruns.
            if (currentPrice <= 0.0 && pos.entryPrice > 0.0) {
                val cachedPx = ts.lastPrice
                val cachedAgeMs = (System.currentTimeMillis() - ts.lastPriceUpdate).coerceAtLeast(0L)
                val posAgeMs = (System.currentTimeMillis() - pos.entryTime).coerceAtLeast(0L)
                if (cachedPx > 0.0) {
                    val cachedPnlVerdict6038 = OpenPnlSanity.inspectPosition(pos, cachedPx, "Executor.strict_sl_cached_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true)
                    val cachedPnl = if (cachedPnlVerdict6038.ok) cachedPnlVerdict6038.pnlPct else 0.0
                    if (cachedPnl <= hardFloor) {
                        try { ForensicLogger.lifecycle("STRICT_SL_CACHED_PRICE_BACKSTOP", "mint=${ts.mint.take(10)} sym=${ts.symbol} cachedPx=${cachedPx} entry=${pos.entryPrice} cachedPnl=${cachedPnl.fmt(2)} hardFloor=${hardFloor.fmt(2)} cachedAgeMs=$cachedAgeMs") } catch (_: Throwable) {}
                        onLog("🛑 STRICT SL (cached): ${ts.symbol} cachedPnl=${cachedPnl.toInt()}% ≤ ${hardFloor.toInt()}% — live feed dark, force-exit on cache", ts.mint)
                        doSell(ts, "STRICT_SL_${hardFloor.toInt()}_CACHED", wallet, walletSol)
                        return
                    }
                }
                if (cachedAgeMs > 90_000L && posAgeMs > 60_000L) {
                    try { ForensicLogger.lifecycle("STRICT_SL_STALE_PRICE_FORCED_EXIT", "mint=${ts.mint.take(10)} sym=${ts.symbol} cachedAgeMs=$cachedAgeMs posAgeMs=$posAgeMs entry=${pos.entryPrice} lastCached=${ts.lastPrice}") } catch (_: Throwable) {}
                    onLog("⚠ STRICT SL STALE: ${ts.symbol} feed dark ${cachedAgeMs/1000}s, posAge ${posAgeMs/1000}s — force-exit to prevent overrun", ts.mint)
                    doSell(ts, "STALE_PRICE_FORCED_EXIT_AGE_${cachedAgeMs/1000}s", wallet, walletSol)
                    return
                }
                ErrorLogger.debug(
                    "Executor",
                    "⚠ STRICT SL skipped on ${ts.symbol}: currentPrice=$currentPrice cachedPx=$cachedPx cachedAgeMs=$cachedAgeMs — within stale tolerance, relying on next resolve"
                )
            }
        }

        // ═══════════════════════════════════════════════════════════════════
        // V5.9.940 — STEALTH-MINT RUG EXIT (consumer of BirdeyeMintBurnMonitor).
        //
        // BirdeyeMintBurnMonitor polls /defi/v3/token/mint-burn-txs on
        // a background coroutine and exposes a sync peekAlert(mint). If
        // the alert escalates to CATASTROPHIC_MINT (>10% supply minted
        // post-entry), the dev is rugging via stealth mint authority —
        // force-exit immediately. Same priority as STRICT_SL because
        // waiting for price action to confirm is too slow (dev can
        // dump in the same block).
        //
        // STRONG_MINT (1-10%) is a warning but not auto-exit — relies
        // on existing PnL/distribution detectors to act. MILD_MINT
        // (0.5-1%) ignored (legitimate token emissions sometimes mint
        // small amounts).
        //
        // Fail-open: if BirdeyeMintBurnMonitor isn't reachable or the
        // mint never got registered, peekAlert returns NONE and this
        // block is a no-op.
        // ═══════════════════════════════════════════════════════════════════
        try {
            val mintAlert = com.lifecyclebot.engine.BirdeyeMintBurnMonitor.peekAlert(ts.mint)
            if (mintAlert == com.lifecyclebot.engine.BirdeyeMintBurnMonitor.MintAlert.CATASTROPHIC_MINT) {
                onLog("🚨 STEALTH MINT RUG: ${ts.symbol} — dev minted >10% post-entry, force-exiting", ts.mint)
                doSell(ts, "STEALTH_MINT_RUG_CATASTROPHIC", wallet, walletSol)
                return
            }
        } catch (_: Throwable) { /* fail-open — MintBurn is advisory */ }

        // V5.0.4200 — take-win/profit-lock must bypass settle-in.
        // The 45s settle window exists to prevent fake churn/soft-loss exits,
        // not to hold a winner hostage. Dynamic profit lock and learned take-win
        // are profit-protection actions, so they fire before settle-in exactly
        // like hard safety above. Partial ladder / dead-feed / fluid floor can
        // still wait for the normal post-buy breathing room.
        val posAgeMs = System.currentTimeMillis() - ts.position.entryTime
        val SETTLE_IN_MS = 45_000L
        if (posAgeMs < SETTLE_IN_MS) {
            // V5.0.6063 — SETTLE-IN NO LONGER SHIELDS EXTREME RUNNERS.
            // Operator screenshot: ERMINE peaked +1183% and rocketnigg
            // peaked +1077% both INSIDE the 45s settle window; the give-
            // back lock and MFE-ratcheted floor never ran because they
            // sat outside the settle-bypass and settle returned early.
            // Positions bled to -53.9% and -87.5% respectively before
            // the window expired. Fix: run PeakDrawdownLock's MFE floor
            // + give-back lock BEFORE checkProfitLock inside settle so
            // any position that ever peaked >= +35% cannot be dragged
            // back into red on a rug snap while the bot is 'settling'.
            val curPnlPct: Double = try {
                val ep = ts.position.entryPrice
                if (ep > 0.0 && currentPrice > 0.0) (currentPrice / ep - 1.0) * 100.0 else 0.0
            } catch (_: Throwable) { 0.0 }
            val peakPnlPct: Double = try { ts.position.peakGainPct.coerceAtLeast(curPnlPct) } catch (_: Throwable) { curPnlPct }
            if (PeakDrawdownLock.shouldFloorLock(peakPnlPct, curPnlPct)) {
                try {
                    ForensicLogger.lifecycle("SETTLE_MFE_FLOOR_FIRED_6063",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} peakPct=${peakPnlPct.toInt()} curPct=${curPnlPct.toInt()} ageMs=$posAgeMs reason=peak_gave_back_below_mfe_floor_inside_settle")
                    PipelineHealthCollector.labelInc("SETTLE_MFE_FLOOR_FIRED_6063")
                } catch (_: Throwable) {}
                onLog("🔒 SETTLE_MFE_FLOOR ${ts.symbol}: peak=${peakPnlPct.toInt()}% cur=${curPnlPct.toInt()}% — floor fired inside settle window", ts.mint)
                requestSell(ts, "SETTLE_MFE_FLOOR_PEAK_${peakPnlPct.toInt()}pct", wallet, walletSol)
                return
            }
            if (PeakDrawdownLock.shouldLock(peakPnlPct, curPnlPct)) {
                try {
                    ForensicLogger.lifecycle("SETTLE_PEAK_DRAWDOWN_FIRED_6063",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} peakPct=${peakPnlPct.toInt()} curPct=${curPnlPct.toInt()} ageMs=$posAgeMs reason=give_back_lock_fired_inside_settle")
                    PipelineHealthCollector.labelInc("SETTLE_PEAK_DRAWDOWN_FIRED_6063")
                } catch (_: Throwable) {}
                onLog("🔒 SETTLE_PEAK_DRAWDOWN ${ts.symbol}: peak=${peakPnlPct.toInt()}% cur=${curPnlPct.toInt()}% — give-back lock fired inside settle window", ts.mint)
                requestSell(ts, "SETTLE_PEAK_DRAWDOWN_PEAK_${peakPnlPct.toInt()}pct", wallet, walletSol)
                return
            }
            if (checkProfitLock(ts, wallet, walletSol)) return
            if (trySweepTakeProfitExit(ts, currentPrice, wallet, walletSol, settleBypass = true)) return
            return  // silent grace for softer fluid path — strict SL and take-win already ran
        }

        // V5.9.723 — DEAD_TOKEN_EARLY_EXIT
        // Pump.fun bonding-curve tokens with no live price feed fall back to entryPrice
        // every tick → pnl stays at exactly 0%, peak stays at 0%, position never exits.
        // These ghost positions hold for 60min then exit as MID_FLAT_CHOP, burning
        // the position slot and contributing nothing to learning.
        //
        // Trigger: position open >= 15min AND highest price never exceeded entry + 0.5%
        // (i.e. getActualPrice always resolved to entryPrice via fallback).
        // Exempt: any position that ever moved (highestPrice > entryPrice * 1.005).
        // Exit: force sell via requestSell as DEAD_TOKEN_NO_PRICE_EXIT.
        val pos = ts.position
        if (posAgeMs >= 15 * 60_000L) {
            val entryPx = pos.entryPrice
            val peakPx  = pos.highestPrice
            val isDeadNoFeed = entryPx > 0.0 &&
                currentPrice > 0.0 &&
                currentPrice == entryPx &&           // still at entry — fallback path
                peakPx <= entryPx * 1.005            // never moved more than 0.5%
            if (isDeadNoFeed) {
                ErrorLogger.info("Executor", "🪦 DEAD_TOKEN_NO_PRICE_EXIT: ${ts.symbol} | held=${posAgeMs/60_000}min | peak=${((peakPx/entryPx-1)*100).toInt()}% | freeing slot")
                requestSell(
                    ts       = ts,
                    reason   = "DEAD_TOKEN_NO_PRICE_EXIT",
                    wallet   = wallet,
                    walletSol = walletSol,
                )
                return
            }
        }

        if (checkProfitLock(ts, wallet, walletSol)) return
        // V5.9.1558 — source fix: a partial rung is an exit action for THIS tick.
        // Pre-fix, runManageOnly could partial-sell and then immediately fall
        // through into full TP, so the journal showed terminal TAKE_PROFIT/SL
        // instead of dynamic laddering.
        if (ts.position.isOpen && checkPartialSell(ts, wallet, walletSol)) return
        if (ts.position.isOpen) {
            val pnlVerdict6038 = OpenPnlSanity.inspectPosition(ts.position, currentPrice, "Executor.manage_only_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true)
            val pnlPct = if (pnlVerdict6038.ok) pnlVerdict6038.pnlPct else 0.0

            // V5.9.684 / V5.0.4200 — learned take-profit is now shared with
            // the settle-bypass path above so scanner-missed winners can bank
            // immediately instead of waiting for settle/min-hold.
            if (trySweepTakeProfitExit(ts, currentPrice, wallet, walletSol)) return

            // Fluid stop floor — already wired but make the log more visible
            val floor = try {
                com.lifecyclebot.v3.scoring.FluidLearningAI.getFluidStopLoss(-25.0)
            } catch (_: Throwable) { -25.0 }
            if (pnlPct <= floor && currentPrice > 0.0) {
                onLog("🛑 SWEEP_FLUID_FLOOR: ${ts.symbol} pnl=${pnlPct.toInt()}% ≤ floor=${floor.toInt()}%", ts.mint)
                doSell(ts, "SWEEP_FLUID_FLOOR_${floor.toInt()}", wallet, walletSol)
            }
        }
    }

    fun checkPartialSell(ts: TokenState, wallet: SolanaWallet?, walletSol: Double): Boolean {
        val c   = cfg()
        normalizePositionScaleIfNeeded(ts)
        val pos = ts.position
        if (!c.partialSellEnabled || !pos.isOpen) return false

        val actualPrice = getActualPrice(ts)
        val gainPct = pct(pos.entryPrice, actualPrice)
        val soldPct = pos.partialSoldPct

        val partialLevel = (soldPct / (c.partialSellFraction * 100.0)).toInt()
        val laneKey = pos.tradingMode.ifBlank { if (pos.isShitCoinPosition) "SHITCOIN" else if (pos.isBlueChipPosition) "BLUECHIP" else if (pos.isTreasuryPosition) "TREASURY" else "STANDARD" }
        
        // V5.0.3963 — learned profit-exit ladder. Old WR-recovery lowered
        // partials into +9..+60% scraps. That boosted cosmetic WR but did not
        // cover fees/splits or compound live wallet. Rungs now come from the
        // StrategyTelemetry expectancy table, with a +50% first-profit floor
        // and runner lanes expanding toward +1000%/+10000%.
        val firstTrigger = WrRecoveryPartial.effectiveTrigger(
            normalTrigger      = c.partialSellTriggerPct,
            gainPct            = gainPct,
            partialLevel       = partialLevel,
            profitLockTriggered = pos.profitLocked,
            lane = laneKey,
        )
        val secondTrigger = WrRecoveryPartial.effectiveSecondTrigger(c.partialSellSecondTriggerPct, laneKey)
        val thirdTrigger  = WrRecoveryPartial.effectiveThirdTrigger(c.partialSellThirdTriggerPct, laneKey)
        val milestones = listOf(
            firstTrigger,
            secondTrigger,
            thirdTrigger,
            10000.0,
            50000.0,
        )
        
        val nextMilestone = milestones.getOrNull(partialLevel)
        val shouldPartial = nextMilestone != null && gainPct >= nextMilestone
        if (RuntimeModeAuthority.isLive() && shouldPartial && gainPct < LiveStrategyTuner.livePartialProfitFloorPct()) {
            try { ForensicLogger.lifecycle("PARTIAL_BLOCKED_BELOW_BREAKEVEN", "mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$laneKey gain=${"%.2f".format(gainPct)} floor=${LiveStrategyTuner.livePartialProfitFloorPct()} level=$partialLevel milestone=$nextMilestone") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PARTIAL_BLOCKED_BELOW_BREAKEVEN") } catch (_: Throwable) {}
            return false
        }
        
        val isThirdOrLater = partialLevel >= 2
        if (!shouldPartial) return false
        if (partialLevel == 2 && !c.partialSellThirdEnabled) return false

        // V5.9.796 — operator audit: smaller per-rung fraction when WR recovery
        // is active so each rung leaves a runner instead of dumping a third
        // of the position on the first ladder hit. WrRecoveryPartial returns
        // the operator-configured fraction unchanged when recovery is off.
        val baseFraction = WrRecoveryPartial.effectiveSellFraction(c.partialSellFraction)
        val treasuryAdjustedFraction = try {
            val solPrice = WalletManager.lastKnownSolPrice
            val treasuryUsd = TreasuryManager.treasurySol * solPrice
            val tier = ScalingMode.activeTier(treasuryUsd)
            
            when (tier) {
                ScalingMode.Tier.INSTITUTIONAL -> baseFraction * 0.6
                ScalingMode.Tier.SCALED        -> baseFraction * 0.7
                ScalingMode.Tier.GROWTH        -> baseFraction * 0.8
                ScalingMode.Tier.STANDARD      -> baseFraction * 0.9
                ScalingMode.Tier.MICRO         -> baseFraction
            }
        } catch (_: Exception) { baseFraction }
        
        val sellFraction = treasuryAdjustedFraction
        // V5.9.495z47 P0 — operator spec items C/E (forensics 0508_143519):
        // checkPartialSell is the second partial-sell call site.
        // Replace `pos.qtyToken * sellFraction` ad-hoc math with the verified-
        // remaining clamp from SellAmountAuthority + PartialSellSizer, and
        // capture pre-sell raw / decimals so PartialSellMismatchDetector can
        // verify the post-sell wallet drop.
        var preSellRawForAudit: java.math.BigInteger = java.math.BigInteger.ZERO
        var expectedConsumedRawForAudit: java.math.BigInteger = java.math.BigInteger.ZERO
        var decimalsForAudit: Int = 0
        var liveBalanceSource: com.lifecyclebot.engine.sell.SellAmountAuthority.BalanceSource =
            com.lifecyclebot.engine.sell.SellAmountAuthority.BalanceSource.UNKNOWN
        val sellQty: Double = run {
            if (pos.isPaperPosition) {
                // V5.0.3810 — PAPER partial finality is ledger-authoritative.
                // Do not call SellAmountAuthority / wallet tracker / Helius here:
                // paper has no on-chain token account to prove, and using the live
                // proof path emitted live balance-proof wait labels while valid
                // paper positions were open in the simulator ledger.
                try { ForensicLogger.lifecycle("PAPER_BALANCE_PROOF_BYPASSED_LEDGER_AUTHORITY", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=PARTIAL_TAKE_PROFIT qty=${pos.qtyToken}") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("PAPER_BALANCE_PROOF_BYPASSED_LEDGER_AUTHORITY") } catch (_: Throwable) {}
                if (pos.qtyToken <= 1e-12 || pos.costSol <= 0.0) {
                    try { ForensicLogger.lifecycle("PAPER_PARTIAL_CLOSE_REJECTED_NO_LEDGER_POSITION", "mint=${ts.mint.take(10)} symbol=${ts.symbol} qty=${pos.qtyToken} cost=${pos.costSol}") } catch (_: Throwable) {}
                    try { PipelineHealthCollector.labelInc("PAPER_PARTIAL_CLOSE_REJECTED_NO_LEDGER_POSITION") } catch (_: Throwable) {}
                    return false
                }
                try { ForensicLogger.lifecycle("PAPER_PARTIAL_CLOSE_REQUESTED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} fraction=$sellFraction qty=${pos.qtyToken}") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("PAPER_PARTIAL_CLOSE_REQUESTED") } catch (_: Throwable) {}
                (pos.qtyToken * sellFraction).coerceIn(0.0, pos.qtyToken)
            } else {
                val resolution = try {
                    com.lifecyclebot.engine.sell.SellAmountAuthority.resolveForExit(ts.mint, wallet, "PARTIAL_TAKE_PROFIT")
                } catch (_: Throwable) { null }
                liveBalanceSource = com.lifecyclebot.engine.sell.SellAmountAuthority.balanceSource(resolution)
                val confirmed = resolution as? com.lifecyclebot.engine.sell.SellAmountAuthority.Resolution.Confirmed
                if (confirmed != null) {
                    preSellRawForAudit = confirmed.rawAmount
                    decimalsForAudit = confirmed.decimals
                    val sized = com.lifecyclebot.engine.sell.PartialSellSizer.size(
                        intendedFraction = sellFraction,
                        verifiedRemainingRaw = confirmed.rawAmount,
                    )
                    if (sized != null) {
                        expectedConsumedRawForAudit = sized.rawAmount
                        val ui = java.math.BigDecimal(sized.rawAmount)
                            .movePointLeft(confirmed.decimals).toDouble()
                        onLog("📐 PartialSellSizer ${ts.symbol}: verifiedRaw=${confirmed.rawAmount} " +
                              "fraction=$sellFraction → rawAmount=${sized.rawAmount} (${"%.6f".format(ui)} ui) " +
                              "vs cached pos.qtyToken=${pos.qtyToken}", ts.mint)
                        ui
                    } else {
                        onLog("⏸️ PARTIAL_SELL_WAITING_BALANCE_PROOF: ${ts.symbol} dust-rejected by verified raw amount — no cached qty sell.", ts.mint)
                        try { ForensicLogger.lifecycle("SELL_WAITING_BALANCE_PROOF", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=PARTIAL_DUST_REJECTED") } catch (_: Throwable) {}
                        return false
                    }
                } else {
                    onLog("⏸️ PARTIAL_SELL_WAITING_BALANCE_PROOF: ${ts.symbol} RPC empty/unknown — no cached qty sell.", ts.mint)
                    try { ForensicLogger.lifecycle("SELL_WAITING_BALANCE_PROOF", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=PARTIAL_BALANCE_UNKNOWN") } catch (_: Throwable) {}
                    return false
                }
            }
        }
        val sellSol      = sellQty * actualPrice
        val newSoldPct   = soldPct + sellFraction * 100.0
        val newQty       = pos.qtyToken - sellQty
        val newCost      = pos.costSol * (1.0 - sellFraction)
        val paperPnlSol  = sellQty * actualPrice - pos.costSol * sellFraction
        val triggerPct   = nextMilestone ?: 0.0
        
        val milestoneLabel = when (partialLevel) {
            0 -> "1st partial"
            1 -> "2nd partial"
            2 -> "3rd partial (20x!)"
            3 -> "4th partial (100x MOONSHOT!)"
            4 -> "5th partial (500x MEGA MOON!)"
            else -> "${partialLevel + 1}th partial"
        }

        val wrRecovTag = if (partialLevel == 0) " [${WrRecoveryPartial.statusTag()}]" else ""
        val partialCostBasisEstimate = pos.costSol * sellFraction
        val partialGrossEstimate = sellQty * actualPrice
        val partialNetEstimate = partialGrossEstimate - partialCostBasisEstimate
        val partialPctEstimate = pct(partialCostBasisEstimate, partialGrossEstimate)
        // V5.0.4562 — PARTIAL FINALITY TRUTH.
        // This block used to emit a "💰 partial sold / PnL" notification BEFORE
        // live route selection, wallet-null guard, balance-authority check,
        // broadcast, verification, recordTrade(), journal write and wallet delta.
        // Operator report: open display showed +2000%, five partial-win notices
        // fired, but wallet/journal had nothing. Pre-finality signals are not
        // realized wins. LIVE only gets an armed signal here; sold/PnL notice
        // fires after signature + accounting below. PAPER fires after ledger write.
        if (pos.isPaperPosition) {
            try { ForensicLogger.lifecycle("PAPER_PARTIAL_SIGNAL_ARMED_4562", "mint=${ts.mint.take(10)} symbol=${ts.symbol} milestone=$milestoneLabel triggerPct=$triggerPct estimatePct=${partialPctEstimate.fmtPctPrecise()}") } catch (_: Throwable) {}
        } else {
            onLog("🧭 Partial signal armed: $milestoneLabel ${(sellFraction*100).toInt()}% trigger=+${triggerPct.toInt()}% est=${partialPctEstimate.fmtPctPrecise()} — awaiting live route/finality", ts.mint)
            try {
                ForensicLogger.lifecycle(
                    "LIVE_PARTIAL_SIGNAL_ARMED_NOT_FINAL_4562",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} milestone=$milestoneLabel triggerPct=$triggerPct estPct=${partialPctEstimate.fmtPctPrecise()} estNet=${partialNetEstimate.fmtSignedSol()} action=no_win_notify_until_finality"
                )
                PipelineHealthCollector.labelInc("LIVE_PARTIAL_SIGNAL_ARMED_NOT_FINAL_4562")
            } catch (_: Throwable) {}
        }

        // V5.9.751b — route on position isPaper, not config. Previously a
        // live position with transient wallet=null silently booked a PAPER
        // partial sell here while the real tokens stayed on-chain. Defer
        // and retry next tick when wallet is null on a live position.
        if (!pos.isPaperPosition && wallet == null) {
            ErrorLogger.warn("Executor",
                "🚫 PARTIAL_SELL_DEFERRED: ${ts.symbol} — live position but wallet=null. Will retry next tick.")
            return false
        }
        if (pos.isPaperPosition) {
            val paperDustClosed = newQty <= 1e-12 || newCost <= 0.000_001
            ts.position = if (paperDustClosed) com.lifecyclebot.data.Position() else pos.copy(qtyToken = newQty, costSol = newCost, partialSoldPct = newSoldPct)
            if (paperDustClosed) {
                try { PositionPersistence.removePosition(ts.mint) } catch (_: Throwable) {}
                try { GlobalTradeRegistry.closePosition(ts.mint) } catch (_: Throwable) {}
                try { com.lifecyclebot.v4.meta.PortfolioHeatAI.removePosition(ts.mint) } catch (_: Throwable) {}
                try { PositionCloseLedger.markClosed(ts.mint, "PAPER_PARTIAL_DUST_CLOSED", gainPct.toInt()) } catch (_: Throwable) {}
                try { PaperPositionCloseAuthority.markClosed("PAPER", ts.mint, ts.symbol, "PAPER_PARTIAL_DUST_CLOSED") } catch (_: Throwable) {}
                try { ForensicLogger.lifecycle("PAPER_CLOSE_CONFIRMED_LEDGER_ONLY", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=PARTIAL_DUST") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("PAPER_CLOSE_CONFIRMED_LEDGER_ONLY") } catch (_: Throwable) {}
            }
            val partialCostBasisSol = pos.costSol * sellFraction
            // V5.0.3683 — ACCOUNTING LEDGER FIX — wire feeSol/netPnlSol so the
            // exporter never zeroes Net Gain on paper partials.
            val paperPartialFee = partialCostBasisSol * MEME_TRADING_FEE_PERCENT
            val paperPartialNetPnl = paperPnlSol - paperPartialFee
            val paperPartialReason = if (paperDustClosed || newSoldPct >= 99.9) "FULL_EXIT_100PCT" else "partial_${newSoldPct.toInt().coerceAtMost(100)}pct"
            val trade   = Trade("PARTIAL_SELL", "paper", partialCostBasisSol, actualPrice,
                              System.currentTimeMillis(), paperPartialReason,
                              paperPnlSol, pct(partialCostBasisSol, sellQty * actualPrice),
                              feeSol = paperPartialFee, netPnlSol = paperPartialNetPnl,
                              tradingMode = pos.tradingMode, tradingModeEmoji = pos.tradingModeEmoji, mint = ts.mint)
            recordTrade(ts, trade); security.recordTrade(trade)
            try { ForensicLogger.lifecycle("PAPER_PARTIAL_CLOSE_DONE", "mint=${ts.mint.take(10)} symbol=${ts.symbol} soldQty=$sellQty remaining=${if (paperDustClosed) 0.0 else newQty} dustClosed=$paperDustClosed") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PAPER_PARTIAL_CLOSE_DONE") } catch (_: Throwable) {}
            // V5.9.743 — wire 70/30 treasury siphon onto the AUTONOMOUS partial-
            // sell ladder. Previously only the manual requestPartialSell entry
            // point siphoned (V5.9.428 wired that one). checkPartialSell fires
            // at +200%/+500%/+2000% milestones every monitor tick and is the
            // PRIMARY meme partial path — leaving it un-wired meant Treasury
            // saw 0% of the realised profit on every TP rung until the
            // position fully closed. Operator spec: 'treasury accumulates 30%
            // of all memetrader profit'.
            // Treasury-tagged positions deposit 100% (cash-gen scalp pattern).
            val paperPartialTreasuryShare6041 = if (paperPnlSol > 0.0) {
                try {
                    if (pos.isTreasuryPosition || pos.tradingMode == "TREASURY") {
                        com.lifecyclebot.engine.TreasuryManager.contributeFullyFromTreasuryScalp(
                            paperPnlSol, com.lifecyclebot.engine.WalletManager.lastKnownSolPrice, isPaper = true)
                    } else {
                        com.lifecyclebot.engine.TreasuryManager.contributeFromMemeSell(
                            paperPnlSol, com.lifecyclebot.engine.WalletManager.lastKnownSolPrice, isPaper = true)
                    }
                } catch (e: Exception) {
                    ErrorLogger.debug("Executor", "Treasury split error (checkPartial paper): ${e.message}")
                    0.0
                }
            } else 0.0
            // V5.0.6041 — partial sells are real wallet movements, not only
            // journal annotations. Autonomous paper ladder previously recorded
            // PARTIAL_SELL but never credited the paper wallet, unlike manual
            // partials/full sells/profit locks. Credit principal+P&L less any
            // treasury share so balance, trade count, and journal move together.
            onPaperBalanceChange?.invoke((sellQty * actualPrice) - paperPartialTreasuryShare6041)
            try { ForensicLogger.lifecycle("PARTIAL_SELL_WALLET_CREDITED_6041", "mode=paper mint=${ts.mint.take(10)} symbol=${ts.symbol} gross=${(sellQty * actualPrice).fmtSol()} treasury=${paperPartialTreasuryShare6041.fmtSol()} delta=${((sellQty * actualPrice) - paperPartialTreasuryShare6041).fmtSol()} reason=${trade.reason}") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PARTIAL_SELL_WALLET_CREDITED_6041") } catch (_: Throwable) {}
            try { ForensicLogger.lifecycle("PARTIAL_SELL_ACCOUNTING",
                "mode=paper mint=${ts.mint.take(10)} symbol=${ts.symbol} soldPct=${(sellFraction*100).fmt(1)} cost=${partialCostBasisSol.fmtSol()} gross=${(sellQty * actualPrice).fmtSol()} pnl=${paperPnlSol.fmtSignedSol()} net=${paperPartialNetPnl.fmtSignedSol()} pct=${pct(partialCostBasisSol, sellQty * actualPrice).fmtPctPrecise()} reason=${trade.reason}") } catch (_: Throwable) {}
            onLog("PAPER PARTIAL SELL ${(sellFraction*100).toInt()}% | " +
                  "cost=${partialCostBasisSol.fmtSol()} gross=${(sellQty * actualPrice).fmtSol()} pnl=${paperPnlSol.fmtSignedSol()} (${pct(partialCostBasisSol, sellQty * actualPrice).fmtPctPrecise()})", ts.mint)
            onNotify("💰 $milestoneLabel",
                 "${ts.symbol}: sold ${(sellFraction*100).toInt()}% | PnL ${pct(partialCostBasisSol, sellQty * actualPrice).fmtPctPrecise()} (${paperPartialNetPnl.fmtSignedSol()} SOL net)",
                 com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
            sounds?.playMilestone(gainPct)
        } else {
            beginMemeExecutionStack(
                side = com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Side.SELL,
                ts = ts,
                amountIn = sellFraction,
                amountInRaw = "fraction=$sellFraction",
                slippageBps = com.lifecyclebot.engine.sell.SellSafetyPolicy.initialSlippageBps("PARTIAL_TAKE_PROFIT"),
                reason = "PARTIAL_TAKE_PROFIT",
                urgency = com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Urgency.PARTIAL,
                walletSol = walletSol,
                tokenBalanceAuthority = liveBalanceSource.name,
                callSite = "checkPartialSell",
            )
            // V5.9.751b — wallet guaranteed non-null by PARTIAL_SELL_DEFERRED guard above.
            // Shadow the nullable param with a non-null binding so the rest of
            // this else branch keeps its previous unchanged code (V5.9.495 etc).
            @Suppress("NAME_SHADOWING")
            val wallet: SolanaWallet = wallet!!
            if (!acquirePartialSellLock(ts.mint)) {
                onLog("⏳ Partial sell already in-flight for ${ts.symbol} — skipping duplicate", ts.mint)
                return true
            }
            try {
                if (!security.verifyKeypairIntegrity(wallet.publicKeyB58,
                        c.walletAddress.ifBlank { wallet.publicKeyB58 })) {
                    onLog("🛑 Keypair check failed — aborting partial sell", ts.mint)
                    releasePartialSellLock(ts.mint)
                    return true
                }
                val partialInitialPlan = recalcSellPlanForProcessor(
                    ts = ts,
                    wallet = wallet,
                    processor = "PARTIAL_INITIAL_PLAN",
                    requestedUiQty = sellQty,
                    sellTradeKey = LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                    traderTag = "MEME",
                ) ?: return false
                val sellUnits = partialInitialPlan.rawAmount
                // V5.9.1533 — spec item 5: live partial sell broadcasts ONLY on confirmed balance.
                run {
                    val cb = com.lifecyclebot.engine.sell.SellAmountAuthority.canBroadcastLiveOrEmergency(
                        resolution = try { com.lifecyclebot.engine.sell.SellAmountAuthority.resolveForExit(ts.mint, wallet, "PARTIAL_TAKE_PROFIT") } catch (_: Throwable) { null },
                        reason = "PARTIAL_TAKE_PROFIT",
                        mint = ts.mint,
                        requestedRawAmount = java.math.BigInteger.valueOf(sellUnits),
                    )
                    if (!cb) {
                        try { ForensicLogger.lifecycle("SELL_BROADCAST_BLOCKED_UNCONFIRMED_BALANCE",
                            "mint=${ts.mint.take(10)} symbol=${ts.symbol} balanceSource=$liveBalanceSource phase=partial action=queue_recovery_not_broadcast") } catch (_: Throwable) {}
                        try { com.lifecyclebot.engine.sell.CloseLease.release(ts.mint, "BALANCE_UNKNOWN_NO_SIGNATURE") } catch (_: Throwable) {}
                        try { HostWalletTokenTracker.markSellWaitingBalanceProof(ts.mint, ts.symbol, "BALANCE_UNKNOWN_PARTIAL") } catch (_: Throwable) {}
                        return false
                    }
                }
                val sellSlippage = (c.slippageBps * 2).coerceAtMost(500)

                // V5.9.495 — PUMP-FIRST routing for partial TPs.
                // Try PumpPortal direct FIRST. If it lands, we use the pre-trade
                // mark-to-market estimate as solBack proxy (PumpPortal does not
                // return outAmount; we'd need a balance-delta read which adds
                // ~2s and isn't critical for partial PnL booking — the same
                // approximation `quote.outAmount` already gives is just a
                // forecast, not a settlement).
                val partialJito = c.jitoEnabled
                val partialTip = effectiveJitoTipLamports(c, urgent = false)
                val pumpSig = if (com.lifecyclebot.engine.sell.MemeVenueRouter.isPumpRouteInvalid(ts.mint)) {
                    try { ForensicLogger.lifecycle("PUMP_DIRECT_SKIPPED_RERESOLVE",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} label=PARTIAL reason=pump_route_invalid") } catch (_: Throwable) {}
                    null
                } else tryPumpPortalSell(
                    ts = ts,
                    wallet = wallet,
                    tokenUnits = recalcSellPlanForProcessor(
                        ts = ts,
                        wallet = wallet,
                        processor = "PUMPPORTAL_PARTIAL",
                        requestedUiQty = sellQty,
                        sellTradeKey = LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                        traderTag = "MEME",
                    )?.rawAmount ?: return false,
                    slipPct = 5,  // V5.9.1524 — 5% live sell cap
                    priorityFeeSol = 0.0001,
                    useJito = partialJito,
                    jitoTipLamports = partialTip,
                    sellTradeKey = LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                    traderTag = "MEME",
                    labelTag = "PARTIAL-${(sellFraction*100).toInt()}%",
                )

                val sig: String
                val solBack: Double
                val feeSol: Double
                val netPnl: Double
                val livePnl: Double
                // V5.0.4180/4182 — was `val`, must be `var` because the
                // sell-side phantom guard below may demote liveScore (line ~5842)
                // when an absurd booked pct on a tiny cost basis is detected.
                // CI red on 4181: "Val cannot be reassigned" at Executor.kt:5842.
                var liveScore: Double
                val livePartialReason = if (newSoldPct >= 99.9) "FULL_EXIT_100PCT" else "partial_${newSoldPct.toInt().coerceAtMost(100)}pct"
                if (pumpSig != null) {
                    sig = pumpSig
                    // Estimate solBack from current mark + sold quantity.
                    solBack = sellQty * actualPrice
                    val partialAcct = liveSellAccountingAuthority(ts, pos.costSol * sellFraction, solBack, livePartialReason, "partial.pump")
                    livePnl = partialAcct.pnlSol
                    liveScore = partialAcct.pnlPct
                    netPnl = partialAcct.netPnlSol
                    feeSol = partialAcct.feeSol
                } else {
                    // Fallback: full Jupiter Ultra → Metis ladder (single shot
                    // here; Jupiter dynamicSlippage handles in-route escalation).
                    val partialJupiterPlan = recalcSellPlanForProcessor(
                        ts = ts,
                        wallet = wallet,
                        processor = "JUPITER_ULTRA_METIS_PARTIAL",
                        requestedUiQty = sellQty,
                        sellTradeKey = LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                        traderTag = "MEME",
                    ) ?: return false
                    val quote     = getQuoteWithSlippageGuard(
                        ts.mint, JupiterApi.SOL_MINT, partialJupiterPlan.rawAmount, sellSlippage, isBuy = false)
                    val txResult  = buildTxWithRetry(
                        quote, wallet.publicKeyB58,
                        senderTipLamports = effectiveJitoTipLamports(c, urgent = false),
                    )
                    security.enforceSignDelay()

                    val useJito = c.jitoEnabled && !quote.isUltra
                    val jitoTip = effectiveJitoTipLamports(c, urgent = false)
                    val ultraReqId = if (quote.isUltra) txResult.requestId else null
                    sig = try {
                        wallet.signSendAndConfirm(txResult.txBase64, useJito, jitoTip, ultraReqId, c.jupiterApiKey, txResult.isRfqRoute, txResult.senderCompatible)
                    } catch (jupEx: Exception) {
                        // Jupiter exhausted too — final PumpPortal retry as last resort.
                        val rescue = tryPumpPortalSell(
                            ts = ts,
                            wallet = wallet,
                            tokenUnits = recalcSellPlanForProcessor(
                                ts = ts,
                                wallet = wallet,
                                processor = "PUMPPORTAL_PARTIAL_RESCUE",
                                requestedUiQty = sellQty,
                                sellTradeKey = LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                                traderTag = "MEME",
                            )?.rawAmount ?: return false,
                            slipPct = 5,  // V5.9.1524 — 5% live sell cap
                            priorityFeeSol = 0.0002,
                            useJito = partialJito,
                            jitoTipLamports = partialTip,
                            sellTradeKey = LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                            traderTag = "MEME",
                            labelTag = "PARTIAL-RESCUE-${(sellFraction*100).toInt()}%",
                        )
                        rescue ?: throw jupEx
                    }
                    // V5.9.495k — PHANTOM-aware solBack: zero out fake gains
                    // when the rescue helper returned a PHANTOM_* sentinel sig.
                    solBack = if (sig.startsWith("PHANTOM_")) 0.0 else quote.outAmount / 1_000_000_000.0
                    val partialAcct = liveSellAccountingAuthority(ts, pos.costSol * sellFraction, solBack, livePartialReason, "partial.jupiter")
                    livePnl = partialAcct.pnlSol
                    liveScore = partialAcct.pnlPct
                    netPnl = partialAcct.netPnlSol
                    feeSol = partialAcct.feeSol
                }
                ts.position = pos.copy(qtyToken = newQty, costSol = newCost, partialSoldPct = newSoldPct)
                val livePartialCostBasisSol = pos.costSol * sellFraction
                val liveTrade = Trade("PARTIAL_SELL", "live", livePartialCostBasisSol, actualPrice,
                    System.currentTimeMillis(), livePartialReason,
                    livePnl, liveScore, sig = sig, feeSol = feeSol, netPnlSol = netPnl,
                    mint = ts.mint, tradingMode = pos.tradingMode, tradingModeEmoji = pos.tradingModeEmoji)
                recordTrade(ts, liveTrade); security.recordTrade(liveTrade)
                SmartSizer.recordTrade(netPnl > 0, isPaperMode = false)
                LiveSafetyCircuitBreaker.recordTradeResult(netPnl)  // V5.9.105 session drawdown halt
                // V5.0.6041 — a finalized live partial is landed SOL movement.
                // Do not fake-credit local SOL; force the wallet manager to pull
                // on-chain balance immediately so the dashboard/sizers see the
                // recovered capital/profit instead of waiting for the next slow poll.
                try {
                    GlobalScope.launch(AppDispatchers.sideEffect) {
                        try {
                            val wm6041 = com.lifecyclebot.engine.BotService.walletManager
                            wm6041.refreshBalance(force = true)
                            val fresh6041 = wm6041.state.value.solBalance
                            if (fresh6041 > 0.0) {
                                com.lifecyclebot.engine.BotService.status.walletSol = fresh6041
                                try { LiveSafetyCircuitBreaker.updateBalance(fresh6041) } catch (_: Throwable) {}
                            }
                            try { ForensicLogger.lifecycle("LIVE_PARTIAL_WALLET_REFRESH_FORCED_6041", "mint=${ts.mint.take(10)} symbol=${ts.symbol} sig=${sig.take(16)} fresh=${fresh6041.fmtSol()} net=${netPnl.fmtSignedSol()} reason=${liveTrade.reason}") } catch (_: Throwable) {}
                            try { PipelineHealthCollector.labelInc("LIVE_PARTIAL_WALLET_REFRESH_FORCED_6041") } catch (_: Throwable) {}
                        } catch (_: Throwable) {}
                    }
                } catch (_: Throwable) {}
                // V5.9.109: FAIRNESS — partial sell #1 pays same 0.5% fee
                // (of the portion sold) to both wallets as full sells do.
                try {
                    val feeAmountSol = (pos.costSol * sellFraction) * MEME_TRADING_FEE_PERCENT
                    if (feeAmountSol >= FEE_SEND_MIN_SOL) {
                        val feeWallet1 = feeAmountSol * FEE_SPLIT_RATIO
                        val feeWallet2 = feeAmountSol * (1.0 - FEE_SPLIT_RATIO)
                        sendFeeSplit(wallet, feeWallet1, feeWallet2, "partial_sell")
                        ErrorLogger.info("Executor", "💸 LIVE PARTIAL-SELL FEE: ${feeAmountSol} SOL split to both wallets")
                    }
                } catch (feeEx: Exception) {
                    ErrorLogger.error("Executor", "🚨 FEE SEND FAILED — PARTIAL-SELL fee NOT sent, will retry next trade: ${feeEx.message}")
                    // V5.9.226: Bug #7 — enqueue for retry
                    val feeAmt3 = (pos.costSol * sellFraction) * MEME_TRADING_FEE_PERCENT
                    if (feeAmt3 >= FEE_SEND_MIN_SOL) {
                        FeeRetryQueue.enqueue(TRADING_FEE_WALLET_1, feeAmt3 * FEE_SPLIT_RATIO, "partial_sell_w1")
                        FeeRetryQueue.enqueue(TRADING_FEE_WALLET_2, feeAmt3 * (1.0 - FEE_SPLIT_RATIO), "partial_sell_w2")
                    }
                }
                releasePartialSellLock(ts.mint)
                // V5.9.495z47 — operator P0 (forensics 0508_143519):
                // Verify post-sell wallet drop ≤ expected. If actual > expected
                // by >5%, lock the mint via SellAmountAuditor (executor.liveSell
                // early-returns on locked mints). Skip on PHANTOM_ sentinel
                // sigs and fail-soft so we never block the success path.
                if (!sig.startsWith("PHANTOM_")) {
                    try {
                        if (decimalsForAudit > 0 &&
                            expectedConsumedRawForAudit.signum() > 0 &&
                            preSellRawForAudit.signum() > 0) {
                            com.lifecyclebot.engine.sell.PartialSellMismatchDetector.verifyAndMaybeLock(
                                mint = ts.mint,
                                symbol = ts.symbol,
                                decimals = decimalsForAudit,
                                expectedConsumedRaw = expectedConsumedRawForAudit,
                                preSellWalletRaw = preSellRawForAudit,
                                wallet = wallet,
                            )
                        }
                    } catch (_: Throwable) { /* fail-soft */ }
                }
                try { ForensicLogger.lifecycle("PARTIAL_SELL_ACCOUNTING",
                    "mode=live mint=${ts.mint.take(10)} symbol=${ts.symbol} soldPct=${(sellFraction*100).fmt(1)} cost=${livePartialCostBasisSol.fmtSol()} gross=${solBack.fmtSol()} pnl=${livePnl.fmtSignedSol()} net=${netPnl.fmtSignedSol()} pct=${liveScore.fmtPctPrecise()} reason=${liveTrade.reason} sig=${sig.take(16)}") } catch (_: Throwable) {}
                // V5.0.4180 — F6: SELL-SIDE PHANTOM GUARD.
                // Field notifications showed +210,425% (+6.049 SOL) and +242,342%
                // (+6.966 SOL) "wins" that never landed in the wallet (canonical
                // PnL stayed -0.282 SOL). Root cause: quote.outAmount used as
                // solBack is the OPTIMISTIC Jupiter quote, not the realized
                // post-tx wallet delta. Sandwiches / thin-pool prints / failed
                // routes inflate quote.outAmount → bot books a phantom win →
                // TokenWinMemory + PatternMemory poisoned with ghost data →
                // bot chases the phantom pattern → real fills are dust.
                //
                // Guard: if booked PnL pct is absurd (>1000%) AND the position
                // cost basis was tiny (<0.01 SOL — i.e. real win would be tiny
                // in absolute SOL), demote the booked values. The trade still
                // closes (we can't undo the on-chain swap), but the LEARNING
                // signals get the sanitized values. Sane 10x+ wins on real
                // size are preserved (large position + large pct = legit).
                val isPhantomSuspect = liveScore.toDouble() > 1000.0 &&
                    livePartialCostBasisSol < 0.01
                if (isPhantomSuspect) {
                    try { ForensicLogger.lifecycle("PHANTOM_SELL_DETECTED",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} bookedPct=${liveScore.fmtPctPrecise()} bookedNetSol=${netPnl.fmtSignedSol()} cost=${livePartialCostBasisSol.fmtSol()} reason=ABSURD_PCT_TINY_COST action=demote_for_learning") } catch (_: Throwable) {}
                    try { PipelineHealthCollector.labelInc("PHANTOM_SELL_DETECTED") } catch (_: Throwable) {}
                    // Demote to a sanitised "tiny win" so downstream learning
                    // sees something believable: cap pct at +50% (typical
                    // partial bank), keep the SOL number as-is (audit trail).
                    liveScore = 50.0
                }
                onLog("LIVE PARTIAL SELL ${(sellFraction*100).toInt()}% @ ${liveScore.fmtPctPrecise()} | " +
                      "cost=${livePartialCostBasisSol.fmtSol()} gross=${solBack.fmtSol()} pnl=${livePnl.fmtSignedSol()} net=${netPnl.fmtSignedSol()} | sig=${sig.take(16)}…", ts.mint)
                onNotify("💰 Live Partial Sell",
                    "${ts.symbol}: sold ${(sellFraction*100).toInt()}% | PnL ${liveScore.fmtPctPrecise()} (${netPnl.fmtSignedSol()} SOL net)",
                    com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
                sounds?.playMilestone(gainPct)
                // V5.9.743 — wire 70/30 treasury siphon onto LIVE autonomous
                // partial-sell ladder. Use netPnl (post-fee) — same figure
                // liveSell uses. Treasury-tagged positions deposit 100%.
                // Bookkeeping only in live mode (the SOL has already returned
                // from Jupiter at full face value); a separate on-chain
                // trading→treasury transfer is fired by
                // TreasuryManager.triggerOnChainTransferIfLive.
                if (netPnl > 0.0) {
                    try {
                        if (pos.isTreasuryPosition || pos.tradingMode == "TREASURY") {
                            com.lifecyclebot.engine.TreasuryManager.contributeFullyFromTreasuryScalp(
                                netPnl, com.lifecyclebot.engine.WalletManager.lastKnownSolPrice)
                        } else {
                            com.lifecyclebot.engine.TreasuryManager.contributeFromMemeSell(
                                netPnl, com.lifecyclebot.engine.WalletManager.lastKnownSolPrice)
                        }
                    } catch (e: Exception) {
                        ErrorLogger.debug("Executor", "Treasury split error (checkPartial live): ${e.message}")
                    }
                }
            } catch (e: Exception) {
                releasePartialSellLock(ts.mint)
                onLog("Live partial sell FAILED: ${security.sanitiseForLog(e.message?:"err")} " +
                      "— position NOT updated", ts.mint)
            }
        }
        return true
    }

    private val milestonesHit      = mutableMapOf<String, MutableSet<Int>>()
    // V5.9.753 — Emergent ticket item #5: sell-lock TTL. Previously a stuck
    // pendingVerify sell could hold the in-flight lock forever, spamming
    // SELL_BLOCKED_ALREADY_IN_PROGRESS every monitor tick. Now backed by a
    // timestamped map; cleared automatically after PARTIAL_SELL_LOCK_TTL_MS.
    private val PARTIAL_SELL_LOCK_TTL_MS = 90_000L
    private val partialSellInFlight = java.util.concurrent.ConcurrentHashMap<String, Long>()
    private fun acquirePartialSellLock(mint: String): Boolean {
        val now = System.currentTimeMillis()
        val existing = partialSellInFlight[mint]
        if (existing != null && (now - existing) < PARTIAL_SELL_LOCK_TTL_MS) {
            return false
        }
        if (existing != null) {
            ErrorLogger.warn("Executor",
                "🔓 PARTIAL_SELL_LOCK_EXPIRED mint=${mint.take(10)}… ageMs=${now - existing} — releasing stale lock")
        }
        partialSellInFlight[mint] = now
        return true
    }
    private fun releasePartialSellLock(mint: String) {
        partialSellInFlight.remove(mint)
    }
    // V5.9.756 — Emergent CRITICAL ticket item #3: sell-lock deadlock.
    // Previously `sellInProgress` was `ConcurrentHashMap<String, Boolean>`
    // with no timestamp. If a sell got stuck in pendingVerify or RPC empty-map,
    // the lock held forever — every future sell triggered
    // SELL_BLOCKED_ALREADY_IN_PROGRESS and the position became unsellable
    // (SPARTA/Thucydides/CHING evidence). Now a timestamped map with a 20 s
    // stale-watchdog and `acquire`/`release` helpers. Forensics fire
    // SELL_LOCK_STALE_FORCE_RELEASED on auto-recovery.
    //
    // The full operator-spec state machine (IDLE / SELLING / VERIFYING /
    // RETRY_SCHEDULED / CONFIRMED_SOLD / FAILED_RETRYABLE / FAILED_FINAL /
    // MANUAL_ATTENTION) is the right long-term shape but a multi-day refactor.
    // This patch closes the DEADLOCK symptom today.
    private val SELL_LOCK_STALE_MS = 20_000L
    private val sellInProgress = java.util.concurrent.ConcurrentHashMap<String, Long>()
    private fun acquireSellLock(mint: String): Boolean {
        val now = System.currentTimeMillis()
        val existing = sellInProgress[mint]
        if (existing != null && (now - existing) < SELL_LOCK_STALE_MS) {
            return false
        }
        if (existing != null) {
            ErrorLogger.warn("Executor",
                "🔓 SELL_LOCK_STALE_FORCE_RELEASED mint=${mint.take(10)}… ageMs=${now - existing} — auto-recover, allowing new sell")
            try {
                val tradeKey = LiveTradeLogStore.keyFor(mint, now)
                LiveTradeLogStore.log(
                    tradeKey, mint, mint.take(6), "SELL",
                    LiveTradeLogStore.Phase.INFO,
                    "SELL_LOCK_STALE_FORCE_RELEASED ageMs=${now - existing}",
                    traderTag = "MEME",
                )
                // V5.9.764 — EMERGENT item D forensic counter.
                ForensicLogger.lifecycle(
                    "SELL_LOCK_STALE_FORCE_RELEASED",
                    "mint=${mint.take(10)} ageMs=${now - existing}",
                )
            } catch (_: Throwable) {}
        }
        sellInProgress[mint] = now
        try {
            // V5.9.764 — EMERGENT item D forensic counter.
            ForensicLogger.lifecycle(
                "SELL_LOCK_SET",
                "mint=${mint.take(10)} ts=$now",
            )
        } catch (_: Throwable) {}
        return true
    }
    private fun releaseSellLock(mint: String) {
        val removed = sellInProgress.remove(mint)
        if (removed != null) {
            try {
                // V5.9.764 — EMERGENT item D forensic counter.
                ForensicLogger.lifecycle(
                    "SELL_LOCK_RELEASED",
                    "mint=${mint.take(10)} heldMs=${System.currentTimeMillis() - removed}",
                )
            } catch (_: Throwable) {}
        }
    }
    /** Operator/test diagnostic — number of currently held sell locks. */
    fun sellLockHeldCount(): Int = sellInProgress.size

    fun riskCheck(ts: TokenState, modeConf: AutoModeEngine.ModeConfig? = null): String? {
        normalizePositionScaleIfNeeded(ts)
        val pos   = ts.position
        val price = getActualPrice(ts)
        if (!pos.isOpen || price == 0.0) return null

        // ═══════════════════════════════════════════════════════════════════════
        // V5.9.124 — REFLEX AI (sub-second reflex gate). Runs BEFORE every
        // other exit path so meme snipers get hard-exited on catastrophic
        // red candles / liquidity drains without waiting for the
        // full scan tick. PARTIAL_LOCK is informational here — the
        // milestone-partial-sell layer (checkPartialSell) picks up the 2x
        // move on its own.
        // ═══════════════════════════════════════════════════════════════════════
        try {
            val currentLiq = ts.lastLiquidityUsd
            val reflex = com.lifecyclebot.v3.scoring.ReflexAI.evaluate(ts, price, currentLiq)
            when (reflex) {
                com.lifecyclebot.v3.scoring.ReflexAI.Reflex.ABORT -> {
                    onLog("⚡ REFLEX ABORT: ${ts.symbol} - immediate exit", ts.mint)
                    markForRecoveryScan(ts, pct(pos.entryPrice, price), "reflex_abort")
                    TradeStateMachine.startCooldown(ts.mint)
                    return "reflex_abort"
                }
                com.lifecyclebot.v3.scoring.ReflexAI.Reflex.LIQ_DRAIN -> {
                    onLog("⚡ REFLEX LIQ_DRAIN: ${ts.symbol} - liquidity collapse exit", ts.mint)
                    TradeStateMachine.startCooldown(ts.mint)
                    return "reflex_liq_drain"
                }
                com.lifecyclebot.v3.scoring.ReflexAI.Reflex.PARTIAL_LOCK -> {
                    onLog("⚡ REFLEX PARTIAL_LOCK: ${ts.symbol} +2x fast move (milestone partial will fire)", ts.mint)
                    // fall through — riskCheck does not execute partial sells;
                    // the milestone-partial-sell layer handles the actual sell.
                }
                null -> {}
            }
        } catch (_: Exception) {}

        pos.highestPrice = maxOf(pos.highestPrice, price)
        if (pos.lowestPrice == 0.0 || price < pos.lowestPrice) {
            pos.lowestPrice = price
        }
        val gainPct  = pct(pos.entryPrice, price)
        val heldSecs = (System.currentTimeMillis() - pos.entryTime) / 1000.0
        val peakPctForSymbolic = try {
            val hp = pos.highestPrice.takeIf { it > 0.0 } ?: price
            pct(pos.entryPrice, hp)
        } catch (_: Throwable) { gainPct }
        val symbolicExitAssessment = try {
            SymbolicExitReasoner.assess(
                currentPnlPct = gainPct,
                peakPnlPct = peakPctForSymbolic,
                entryConfidence = pos.entryScore.coerceIn(0.0, 100.0),
                tradingMode = resolveExecutionLane(ts, fallback = "STANDARD"),
                holdTimeSec = heldSecs.toLong(),
                priceVelocity = 0.0,
                volumeRatio = 1.0,
                symbol = ts.symbol,
                mint = ts.mint,
            )
        } catch (_: Throwable) { null }
        fun symbolicWantsPatience(): Boolean {
            val a = symbolicExitAssessment ?: return false
            return a.suggestedAction == SymbolicExitReasoner.Action.HOLD || a.suggestedAction == SymbolicExitReasoner.Action.TIGHTEN
        }
        fun softExitProtectedBySymbolicPatience(reason: String, critical: Boolean = false): Boolean {
            if (critical) return false
            val r = reason.uppercase()
            if (r.contains("REFLEX") || r.contains("LIQUIDITY_COLLAPSE") || r.contains("LIQUIDITY_DRAIN") || r.contains("NO_LIQUIDITY_EXIT") || r.contains("RUG") || r.contains("CATASTROPHIC") || r.contains("EMERGENCY")) return false
            if (gainPct <= -12.0) return false
            if (!symbolicWantsPatience()) return false
            try {
                ForensicLogger.lifecycle(
                    "SYMBOLIC_PATIENCE_SOFT_EXIT_VETO",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${reason.take(80)} pnl=${"%.2f".format(gainPct)} peak=${"%.2f".format(peakPctForSymbolic)} action=${symbolicExitAssessment?.suggestedAction} conviction=${"%.3f".format(symbolicExitAssessment?.conviction ?: 0.0)} primary=${symbolicExitAssessment?.primarySignal ?: "unknown"}",
                )
                PipelineHealthCollector.labelInc("SYMBOLIC_PATIENCE_SOFT_EXIT_VETO")
            } catch (_: Throwable) {}
            return true
        }

        val hitMilestones = milestonesHit.getOrPut(ts.mint) { mutableSetOf() }
        listOf(50, 100, 200).forEach { threshold ->
            if (gainPct >= threshold && !hitMilestones.contains(threshold)) {
                hitMilestones.add(threshold)
                sounds?.playMilestone(gainPct)
                onLog("+${threshold}% milestone on ${ts.symbol}! 🎯", ts.mint)
            }
        }
        if (!pos.isOpen) milestonesHit.remove(ts.mint)

        try {
            if (heldSecs >= 45 && AICrossTalk.isCoordinatedDump(ts.mint, ts.symbol)) {
                val crossTalkSignal = AICrossTalk.analyzeCrossTalk(ts, isOpenPosition = true)
                onLog("🔗🚨 CROSSTALK: ${ts.symbol} COORDINATED DUMP | ${crossTalkSignal.participatingAIs.joinToString("+")} | ${crossTalkSignal.reason}", ts.mint)
                TradeStateMachine.startCooldown(ts.mint)
                return "crosstalk_coordinated_dump"
            }
        } catch (_: Exception) {}
        
        val exitAiState = ExitIntelligence.PositionState(
            mint = ts.mint,
            symbol = ts.symbol,
            entryPrice = pos.entryPrice,
            currentPrice = price,
            highestPrice = pos.highestPrice,
            lowestPrice = pos.lowestPrice,
            pnlPercent = gainPct,
            holdTimeMinutes = (heldSecs / 60.0).toInt(),
            buyPressure = ts.meta.pressScore,
            entryBuyPressure = ts.meta.pressScore,
            volume = ts.meta.volScore,
            volatility = ts.meta.avgAtr,
            isDistribution = ts.phase == "distribution" && ts.meta.pressScore < 30,
            rsi = ts.meta.rsi,
            momentum = ts.entryScore,
            qualityGrade = ts.meta.setupQuality,
        )
        val exitAiDecision = ExitIntelligence.evaluateExit(exitAiState)
        
        when (exitAiDecision.action) {
            ExitIntelligence.ExitAction.EMERGENCY_EXIT -> {
                onLog("🤖🚨 EXIT AI: ${ts.symbol} EMERGENCY | ${exitAiDecision.reasons.firstOrNull()}", ts.mint)
                TradeStateMachine.startCooldown(ts.mint)
                return "ai_emergency_${exitAiDecision.reasons.firstOrNull()?.take(15)?.replace(" ", "_") ?: "exit"}"
            }
            ExitIntelligence.ExitAction.FULL_EXIT -> {
                if (exitAiDecision.urgency == ExitIntelligence.Urgency.HIGH || 
                    exitAiDecision.urgency == ExitIntelligence.Urgency.CRITICAL) {
                    val aiReason = "ai_exit_${exitAiDecision.reasons.firstOrNull()?.take(15)?.replace(" ", "_") ?: "signal"}"
                    if (softExitProtectedBySymbolicPatience(aiReason, critical = exitAiDecision.urgency == ExitIntelligence.Urgency.CRITICAL)) {
                        onLog("🧠 HOLD OVERRIDE: ${ts.symbol} symbolic patience vetoed ExitAI full-exit", ts.mint)
                        return null
                    }
                    onLog("🤖⚠️ EXIT AI: ${ts.symbol} FULL EXIT | ${exitAiDecision.reasons.firstOrNull()}", ts.mint)
                    TradeStateMachine.startCooldown(ts.mint)
                    return aiReason
                }
            }
            else -> {}
        }

        if (!isPaperRT() && gainPct >= 15) {
            try {
                val recentPrices = ts.history.takeLast(10).map { it.priceUsd }
                val geminiAdvice = GeminiCopilot.getExitAdvice(
                    ts = ts,
                    currentPnlPct = gainPct,
                    holdTimeMinutes = heldSecs / 60.0,
                    peakPnlPct = pos.highestPrice.let { if (it > 0) ((it - pos.entryPrice) / pos.entryPrice) * 100 else gainPct },
                    recentPriceAction = recentPrices,
                )
                
                if (geminiAdvice != null) {
                    when (geminiAdvice.exitUrgency) {
                        "IMMEDIATE" -> {
                            if (geminiAdvice.confidenceScore >= 70) {
                                if (softExitProtectedBySymbolicPatience("gemini_immediate_exit", critical = false)) {
                                    onLog("🧠 HOLD OVERRIDE: ${ts.symbol} symbolic patience vetoed Gemini immediate exit", ts.mint)
                                    return null
                                }
                                onLog("🤖🚨 GEMINI EXIT: ${ts.symbol} IMMEDIATE | ${geminiAdvice.reasoning.take(60)}", ts.mint)
                                TradeStateMachine.startCooldown(ts.mint)
                                return "gemini_immediate_exit"
                            }
                        }
                        "SOON" -> {
                            if (geminiAdvice.confidenceScore >= 80 && gainPct >= 30) {
                                if (softExitProtectedBySymbolicPatience("gemini_exit_soon", critical = false)) {
                                    onLog("🧠 HOLD OVERRIDE: ${ts.symbol} symbolic patience vetoed Gemini soon exit", ts.mint)
                                    return null
                                }
                                onLog("🤖⚠️ GEMINI EXIT: ${ts.symbol} SOON | ${geminiAdvice.reasoning.take(60)}", ts.mint)
                                TradeStateMachine.startCooldown(ts.mint)
                                return "gemini_exit_soon"
                            } else {
                                onLog("🤖 GEMINI: ${ts.symbol} suggests exit soon (conf=${geminiAdvice.confidenceScore.toInt()}%)", ts.mint)
                            }
                        }
                        "RIDE" -> {
                            onLog("🤖✨ GEMINI: ${ts.symbol} ride it! target=${geminiAdvice.targetPrice}", ts.mint)
                        }
                        else -> {}
                    }
                }
            } catch (e: Exception) {
                ErrorLogger.debug("Executor", "Gemini exit advice error: ${e.message}")
            }
        }

        val exitSignal = PrecisionExitLogic.evaluate(
            ts = ts,
            currentPrice = price,
            entryPrice = pos.entryPrice,
            history = ts.history.toList(),
            exitScore = ts.exitScore,
            stopLossPct = modeConf?.stopLossPct ?: cfg().stopLossPct,
        )
        
        if (exitSignal.shouldExit) {
            val urgencyEmoji = when (exitSignal.urgency) {
                PrecisionExitLogic.Urgency.CRITICAL -> "🚨"
                PrecisionExitLogic.Urgency.HIGH -> "⚠️"
                PrecisionExitLogic.Urgency.MEDIUM -> "📊"
                else -> "ℹ️"
            }
            val v8Reason = "v8_${exitSignal.reason.lowercase()}"
            if (softExitProtectedBySymbolicPatience(v8Reason, critical = exitSignal.urgency == PrecisionExitLogic.Urgency.CRITICAL)) {
                onLog("🧠 HOLD OVERRIDE: ${ts.symbol} symbolic patience vetoed V8 soft exit | ${exitSignal.reason}", ts.mint)
                return null
            }
            onLog("$urgencyEmoji V8 EXIT: ${ts.symbol} | ${exitSignal.reason} | ${exitSignal.details}", ts.mint)
            TradeStateMachine.startCooldown(ts.mint)
            return v8Reason
        }

        // V5.9.794 — operator audit Item 7 fresh-meme HARD_FLOOR.
        // Fresh meme positions (< 5 minutes old) get a tighter -9% hard
        // floor so an early rug bleeds through much less damage. Matured
        // positions (≥ 5 min) AND non-meme lanes (Quality / BlueChip /
        // Treasury / Sniper / CryptoAlt) keep the prior -15% backstop so
        // a one-off drawdown on a long-running winner doesn't choke them.
        val isMemePosition = pos.isShitCoinPosition ||
            pos.tradingMode.equals("MOONSHOT", ignoreCase = true) ||
            pos.tradingMode.equals("EXPRESS", ignoreCase = true) ||
            pos.tradingMode.equals("PUMP_SNIPER", ignoreCase = true)
        val isFreshMeme = isMemePosition && heldSecs < 300L
        val HARD_FLOOR_STOP_PCT = if (isFreshMeme) 9.0 else 15.0

        // V5.9.807 — P3 predictive exit hook. If this position's
        // (tradingMode × scoreBand) bucket is a danger zone (≥5 losses,
        // ≥75% loss rate in last 2k closes), tighten the hard floor to
        // the recommended SL. ADVISORY + TIGHTENING ONLY: we use
        // minOf(...) so the hard floor can only be MADE TIGHTER, never
        // loosened. Read-only over LosingPatternMemory; no impact on
        // entry sizing, swap scripting, or PrecisionExitLogic.
        val predictiveSlPct: Double? = try {
            com.lifecyclebot.engine.LosingPatternMemory.recommendedSlPct(
                tradingMode = pos.tradingMode,
                v3Score = pos.entryScore.toInt(),
            )
        } catch (_: Throwable) { null }
        val effectiveHardFloorPct: Double = if (predictiveSlPct != null) {
            // recommendedSlPct returns NEGATIVE values (-3.0/-5.0/-7.0);
            // HARD_FLOOR_STOP_PCT is the POSITIVE magnitude. Take the
            // tighter of the two so we never widen an existing backstop.
            minOf(HARD_FLOOR_STOP_PCT, -predictiveSlPct)
        } else {
            HARD_FLOOR_STOP_PCT
        }
        val predictiveTightened = predictiveSlPct != null &&
            effectiveHardFloorPct < HARD_FLOOR_STOP_PCT

        // V5.9.67 ProfitabilityLayer hooks — trailing stop + liquidity drain
        // exit. These run BEFORE the hard floor so in-profit positions get
        // locked in before the −15% emergency cutoff fires.
        ProfitabilityLayer.checkTrailingStop(ts)?.let { reason ->
            onLog("🪢 TRAIL STOP: ${ts.symbol} | $reason", ts.mint)
            TradeStateMachine.startCooldown(ts.mint)
            return reason
        }
        ProfitabilityLayer.checkDrainExit(ts)?.let { reason ->
            onLog("🕳️ DRAIN EXIT: ${ts.symbol} | $reason", ts.mint)
            TradeStateMachine.startCooldown(ts.mint)
            return reason
        }
        // V5.9.1293 — CATASTROPHIC GAP GUARD. Pre-empts the -82% gap-through
        // class: fires on the liquidity-drain rug signature BEFORE price gaps
        // past the -15% floor. Runs here (before the hard floor) so a rugging
        // token is exited on the drain signal rather than after the price has
        // already collapsed. Bypasses min-hold by design (true rug emergency).
        // Does NOT touch the unconditional -15% floor below — additive only.
        ProfitabilityLayer.checkCatastrophicGapGuard(ts)?.let { reason ->
            onLog("🛟 GAP GUARD: ${ts.symbol} | $reason — pre-emptive rug exit", ts.mint)
            markForRecoveryScan(ts, gainPct, "gap_guard")
            TradeStateMachine.startCooldown(ts.mint)
            return reason
        }

        if (gainPct <= -effectiveHardFloorPct) {
            val tag = if (predictiveTightened) "predictive_hard_floor" else "hard_floor"
            val icon = if (predictiveTightened) "🧠🛑" else "🛑"
            onLog("$icon HARD FLOOR STOP ($tag): ${ts.symbol} at ${gainPct.toInt()}% (effective=${effectiveHardFloorPct.toInt()}% pred=${predictiveSlPct?.toInt() ?: 0}%) - EMERGENCY EXIT", ts.mint)
            markForRecoveryScan(ts, gainPct, tag)
            return if (predictiveTightened) "predictive_hard_floor_stop" else "hard_floor_stop"
        }
        
        val peakPnlPct = pos.peakGainPct
        val volatility = ts.volatility ?: 50.0
        
        val dynamicStopPct = try {
            val modeDefault = modeConf?.stopLossPct ?: cfg().stopLossPct
            com.lifecyclebot.v3.scoring.FluidLearningAI.getDynamicFluidStop(
                modeDefaultStop = modeDefault,
                currentPnlPct = gainPct,
                peakPnlPct = peakPnlPct,
                holdTimeSeconds = heldSecs,
                volatility = volatility
            )
        } catch (_: Exception) {
            val modeDefault = modeConf?.stopLossPct ?: cfg().stopLossPct
            try {
                -com.lifecyclebot.v3.scoring.FluidLearningAI.getFluidStopLoss(modeDefault)
            } catch (_: Exception) {
                -(modeConf?.stopLossPct ?: cfg().stopLossPct)
            }
        }
        
        // V5.9.1419 — HARD 30s ENTRY-PROTECT TIME-LOCK (operator directive).
        // This Executor dynamic-stop path had NO settle-in guard, so it kept
        // firing RAPID_ENTRY_PROTECT_STOP on tokens only seconds old even after
        // the BotService warmup was widened — it is a SECOND, independent
        // producer of the entry_protect exit. Operator: "it needs a 30 second
        // time lock where it can't fire on a newly acquired token." Enforce it
        // unconditionally here: no position younger than 30s may be closed by
        // the adaptive/fluid entry-protect or fluid stop. The unconditional
        // -15% hard floor (checked ABOVE at gainPct <= -effectiveHardFloorPct)
        // and the trailing/drain/gap-guard rug exits (also ABOVE) remain fully
        // active inside the lock — only the noise-driven dynamic stop is held.
        // A genuine in-profit trailing exit is unaffected (peak>5% trailing fires
        // through its own ProfitabilityLayer path above, not here).
        val entryLockActive = heldSecs < 40.0  // V5.9.1430 30s->40s: align Executor entry-lock with 1429 BotService settle-in; closes the 30-60s window that booked entry_protect losses at -10..-13%
        // V5.0.4302 — basic crypto invariant: profit-lock beats entry-lock.
        // The time-lock may hold negative entry-protect/fluid-loss exits, but
        // must NOT hold a positive dynamicStopPct produced by a live runner.
        // Instant meme peaks are exactly what the bot is trying to monetize.
        if (entryLockActive && dynamicStopPct <= 0.0 && gainPct <= dynamicStopPct && gainPct > -effectiveHardFloorPct) {
            try {
                com.lifecyclebot.engine.ForensicLogger.lifecycle(
                    "ENTRY_PROTECT_TIMELOCK_HOLD",
                    "symbol=${ts.symbol} pnl=${"%.1f".format(gainPct)}% heldSecs=${"%.1f".format(heldSecs)} dynLimit=${dynamicStopPct.toInt()} floor=-${effectiveHardFloorPct.toInt()} lock=40s"
                )
            } catch (_: Throwable) {}
        } else if (gainPct <= dynamicStopPct) {
            // V5.9.1431 — RAPID ENTRY PROTECT REMOVED (operator directive).
            // The "entry_protect" stop label/concept is gone entirely. A fresh
            // position can no longer be stopped by the dynamic stop during the
            // 40s entry-lock above (only the unconditional -15% hard floor and
            // the rug/gap guards may exit it). Post-lock, every dynamic exit is
            // a normal trailing or fluid stop — there is no early-life special
            // case anymore.
            val stopType = if (peakPnlPct > 5.0) "trailing_fluid" else "fluid_stop"
            onLog("🛑 DYNAMIC STOP ($stopType): ${ts.symbol} at ${gainPct.toInt()}% (dynamic limit=${dynamicStopPct.toInt()}%)", ts.mint)
            markForRecoveryScan(ts, gainPct, stopType)
            return "${stopType}_loss"
        }

        // V5.9.118: REGRESSION GUARD — if a runner gives back >35% of its peak
        // and the dynamic stop above did NOT fire, something is miswired
        // (this was the UGOR +290%→+50% failure mode that kept regressing).
        // WARN at most once per position so the log screams before we ship.
        if (peakPnlPct >= 100.0 && (peakPnlPct - gainPct) >= 35.0 && !pos.profitFloorRegressionLogged) {
            ErrorLogger.warn("Executor",
                "⚠️ PROFIT-FLOOR REGRESSION: ${ts.symbol} peak=+${peakPnlPct.toInt()}% " +
                "now=+${gainPct.toInt()}% (gave back ${(peakPnlPct - gainPct).toInt()}%) " +
                "but dynamicStop=${dynamicStopPct.toInt()}% didn't fire — locks are misconfigured")
            pos.profitFloorRegressionLogged = true
        }

        if (heldSecs < 90.0) return null

        val currentLiq = ts.lastLiquidityUsd
        val entryLiq = pos.entryLiquidityUsd
        if (entryLiq > 0 && currentLiq > 0) {
            val liqDropPct = ((entryLiq - currentLiq) / entryLiq) * 100
            if (liqDropPct > 50) {
                onLog("🚨 LIQ COLLAPSE: ${ts.symbol} liq dropped ${liqDropPct.toInt()}% | exit NOW", ts.mint)
                return "liquidity_collapse"
            }
            if (liqDropPct > 30 && gainPct < 0) {
                onLog("⚠️ LIQ DRAIN: ${ts.symbol} liq dropped ${liqDropPct.toInt()}% while losing | exit", ts.mint)
                return "liquidity_drain"
            }
        }
        
        if (ts.history.size >= 3 && heldSecs >= 30) {
            val recentCandles = ts.history.takeLast(3)
            val totalSells = recentCandles.sumOf { it.sellsH1 }
            val totalBuys = recentCandles.sumOf { it.buysH1 }
            val sellRatio = if (totalBuys + totalSells > 0) totalSells.toDouble() / (totalBuys + totalSells) else 0.0
            
            if (sellRatio > 0.80 && gainPct > 10 && ts.meta.pressScore < -30) {
                onLog("🐋 WHALE DUMP: ${ts.symbol} sell ratio ${(sellRatio*100).toInt()}% | protecting gains", ts.mint)
                return "whale_dump"
            }
            
            val avgVol = recentCandles.map { it.volumeH1 }.average()
            val lastVol = recentCandles.last().volumeH1
            if (lastVol > avgVol * 3 && sellRatio > 0.70 && gainPct < -5) {
                onLog("🚨 DEV DUMP: ${ts.symbol} volume spike ${(lastVol/avgVol).toInt()}x with heavy sells", ts.mint)
                return "dev_dump"
            }
            
            if (recentCandles.size >= 2 && heldSecs >= 45) {
                val priceStart = recentCandles.first().priceUsd
                val priceEnd = recentCandles.last().priceUsd
                if (priceStart > 0 && priceEnd > 0) {
                    val velocityPct = ((priceEnd - priceStart) / priceStart) * 100
                    
                    if (velocityPct < -15.0 && gainPct < -5) {
                        onLog("⚡ VELOCITY EXIT: ${ts.symbol} price dropping ${velocityPct.toInt()}% rapidly | exit before worse", ts.mint)
                        markForRecoveryScan(ts, gainPct, "velocity_dump")
                        return "velocity_dump"
                    }
                    
                    if (velocityPct < -8.0 && gainPct < -12.0) {
                        onLog("⚡ ACCELERATING LOSS: ${ts.symbol} at ${gainPct.toInt()}% and dropping ${velocityPct.toInt()}%/candle", ts.mint)
                        markForRecoveryScan(ts, gainPct, "accelerating_loss")
                        return "accelerating_loss"
                    }
                }
            }
        }

        val effectiveStopPct = modeConf?.stopLossPct ?: cfg().stopLossPct
        if (gainPct <= -effectiveStopPct) {
            onLog("🛑 BACKUP STOP: ${ts.symbol} at ${gainPct.toInt()}%", ts.mint)
            return "stop_loss"
        }
        
        // V5.9.495z15 — operator-mandated unchoke. Pre-fix the trailing
        // stop activated after 60s held OR 5% gain. The 60s clause was
        // the silent killer: every trade that went -1% in the first
        // 90 seconds (the vast majority) tripped it the moment the
        // smartFloor fell just below the current price, producing the
        // "trailing_stop pnl=-1%" exits seen across hundreds of trades.
        // Trailing stops must protect PROFIT, never harvest losses.
        // Now: only activate trailing after meaningful unrealized gain.
        // Bootstrap: 5% gain. Mature: 3% (more aggressive once profitable).
        val trailingActivationPct = run {
            val mature = try {
                com.lifecyclebot.v3.scoring.FluidLearningAI.getLearningProgress() >= 0.6
            } catch (_: Throwable) { false }
            if (mature) 3.0 else 5.0
        }
        val trailingStopActive = gainPct >= trailingActivationPct
        
        val smartFloor = trailingFloor(
            pos = pos,
            current = price,
            modeConf = modeConf,
            emaFanAlignment = ts.meta.emafanAlignment,
            emaFanWidening = ts.meta.emafanAlignment == "BULL_FAN" && ts.meta.volScore >= 55,
            volScore = ts.meta.volScore,
            pressScore = ts.meta.pressScore,
            exhaust = ts.meta.exhaustion,
        )
        
        if (trailingStopActive && price < smartFloor) {
            return "trailing_stop"
        }
        return null
    }

    // ── dispatch ──────────────────────────────────────────────────────

    fun maybeAct(
        ts: TokenState,
        signal: String,
        entryScore: Double,
        walletSol: Double,
        wallet: SolanaWallet?,
        lastPollMs: Long = System.currentTimeMillis(),
        openPositionCount: Int = 0,
        totalExposureSol: Double = 0.0,
        modeConfig: AutoModeEngine.ModeConfig? = null,
        walletTotalTrades: Int = 0,
    ) {
        normalizePositionScaleIfNeeded(ts)

        val isSellAction = (signal in listOf("SELL", "EXIT")) || 
            (ts.position.isOpen && PrecisionExitLogic.quickCheck(
                mint = ts.mint,
                currentPrice = getActualPrice(ts),
                entryPrice = ts.position.entryPrice,
                stopLossPct = cfg().stopLossPct,
                entryTimeMs = ts.position.entryTime,
            )?.shouldExit == true)
        
        val cbState = security.getCircuitBreakerState()
        if (cbState.isHalted && !ts.position.isOpen) {
            onLog("🛑 Halted (no new buys): ${cbState.haltReason}", ts.mint)
            return
        }
        if (cbState.isHalted && ts.position.isOpen) {
            onLog("⚠️ Halted but allowing sell actions for open position", ts.mint)
        }

        if (ts.position.isOpen) {
            ShadowLearningEngine.onPriceUpdate(
                mint = ts.mint,
                currentPrice = getActualPrice(ts),
                liveStopLossPct = cfg().stopLossPct,
                liveTakeProfitPct = 200.0,
            )
            
            val quickExit = PrecisionExitLogic.quickCheck(
                mint = ts.mint,
                currentPrice = getActualPrice(ts),
                entryPrice = ts.position.entryPrice,
                stopLossPct = cfg().stopLossPct,
                entryTimeMs = ts.position.entryTime,
            )
            if (quickExit != null && quickExit.shouldExit) {
                onLog("🚨 V8 QUICK EXIT: ${ts.symbol} | ${quickExit.reason} | ${quickExit.details}", ts.mint)
                doSell(ts, "v8_${quickExit.reason.lowercase()}", wallet, walletSol)
                TradeStateMachine.startCooldown(ts.mint)
                return
            }
        }

        val freshness = security.checkDataFreshness(lastPollMs)
        if (freshness is GuardResult.Block) {
            onLog("⚠ ${freshness.reason}", ts.mint)
            return
        }

        // V5.9.212: Update highestPrice/lowestPrice UNCONDITIONALLY before any exit path
        // (Audit #4 fix: was only updated inside riskCheck — missed when checkProfitLock returned early)
        if (ts.position.isOpen) {
            val _unconditionalPrice = getActualPrice(ts)
            if (_unconditionalPrice > 0.0) {
                ts.position.highestPrice = maxOf(ts.position.highestPrice, _unconditionalPrice)
                if (ts.position.lowestPrice == 0.0 || _unconditionalPrice < ts.position.lowestPrice)
                    ts.position.lowestPrice = _unconditionalPrice
            }
        }

        if (ts.position.isOpen) {
            if (checkProfitLock(ts, wallet, walletSol)) {
                return
            }
        }

        if (ts.position.isOpen && checkPartialSell(ts, wallet, walletSol)) return

        val reason = riskCheck(ts, modeConfig)
        if (reason != null) { doSell(ts, reason, wallet, walletSol); return }
        
        if (ts.position.isOpen) {
            val liqSignal = try { LiquidityDepthAI.getSignal(ts.mint, ts.symbol, isOpenPosition = true) } catch (_: Exception) { null }
            val liquidityCollapsing = liqSignal?.signal in listOf(
                LiquidityDepthAI.SignalType.LIQUIDITY_COLLAPSE,
                LiquidityDepthAI.SignalType.LIQUIDITY_DRAINING
            )
            val depthDangerous = liqSignal?.depthQuality in listOf(
                LiquidityDepthAI.DepthQuality.POOR,
                LiquidityDepthAI.DepthQuality.DANGEROUS
            )
            
            val whaleActivity = ts.meta.velocityScore
            val whalesStopped = whaleActivity < 20 && ts.meta.whaleSummary.isBlank()
            val classification = ModeRouter.classify(ts)
            val copyInvalidated = classification.tradeType.name.contains("COPY") && whalesStopped
            val buyPressureCollapsing = ts.meta.pressScore < 30
            
            val tradingMode = classification.tradeType.name
            
            val shouldForceExit = ToxicModeCircuitBreaker.shouldForceFullExit(
                liquidityCollapsing = liquidityCollapsing,
                depthDangerous = depthDangerous,
                whalesStopped = whalesStopped,
                copyInvalidated = copyInvalidated,
                buyPressureCollapsing = buyPressureCollapsing,
                mode = tradingMode
            )
            
            if (shouldForceExit) {
                onLog("🚨 CIRCUIT BREAKER FORCE EXIT: ${ts.symbol} | mode=$tradingMode | liq=$liquidityCollapsing whale=$whalesStopped copy=$copyInvalidated", ts.mint)
                doSell(ts, "circuit_breaker_force_exit", wallet, walletSol)
                return
            }
        }

        if (signal in listOf("SELL", "EXIT") && ts.position.isOpen) {
            doSell(ts, signal.lowercase(), wallet, walletSol); return
        }
        if (ts.position.isOpen && modeConfig != null) {
            val _held = (System.currentTimeMillis() - ts.position.entryTime) / 60_000.0
            val _tf   = ts.candleTimeframeMinutes.toDouble().coerceAtLeast(1.0)
            // V5.9.822 — MarketRegimeAI.getHoldTimeMultiplier wired on exit
            // timeout. STRONG_BULL = 2.0 (let runners ride), STRONG_BEAR = 0.5
            // (cut losers fast). Clamped [0.5, 2.0] matching Regime enum.
            // Audit ref: TIER 1.2 holdTime — deferred from V5.9.818.
            // WR/profit thesis: bull regimes more often produce runners → longer
            // holds capture them. Bear regimes more often produce death by a
            // thousand cuts → shorter holds bleed less.
            val _regimeHoldMult = try {
                com.lifecyclebot.engine.MarketRegimeAI.getHoldTimeMultiplier().coerceIn(0.5, 2.0)
            } catch (_: Throwable) { 1.0 }
            // V5.0.4125 — Apply AGI style hold multiplier. DH_RUNNER
            // (holdMult=2.80) extends 120min → 336min. EXHAUSTION_QUICK_FLIP
            // (holdMult=0.38) shortens 120min → 45min. This lets the AGI stack
            // control hold time per-trade, not just per-lane.
            val _effectiveMaxHold = modeConfig.maxHoldMins * _tf * _regimeHoldMult * ts.styleHoldMult.coerceIn(0.25, 5.0)
            // V5.9.901 — RUNNER BYPASS for mode_maxhold.
            // PRE-FIX: SNIPE=30min, COPY=20min, DEFENSIVE=45min etc capped
            // every winner at mode-specific time even if +200% and still
            // climbing. Regime mult only goes to ×2 (STRONG_BULL) which
            // SNIPE → 60min still kills any genuine runner.
            // FIX: skip timeout while peakGainPct ≥ 20% AND currentPnl is
            // within 30% of peak (trend intact). Hard ceiling at 4× the
            // effective maxHold to prevent zombies on a runner that died.
            val _curPnl = if (ts.position.entryPrice > 0.0)
                ((getActualPrice(ts) - ts.position.entryPrice) / ts.position.entryPrice) * 100.0
            else 0.0
            val _peakGain = ts.position.peakGainPct
            val _runnerHwGate = _peakGain >= 20.0
            val _runnerTrendIntact = _peakGain > 0.0 && _curPnl >= _peakGain * 0.70
            val _runnerBypass = _runnerHwGate && _runnerTrendIntact
            val _hardCeiling = _effectiveMaxHold * 4.0
            val _shouldForceExit = when {
                _held > _hardCeiling           -> true   // zombie catch
                ts.position.isLongHold         -> false  // V5.0.4125 — long-hold bypasses time exit
                _runnerBypass                  -> false  // keep riding
                _held > _effectiveMaxHold      -> true   // legacy cap
                else                            -> false
            }
            if (_shouldForceExit) {
                // V5.9.676 — surface the actual mode + held time + threshold
                // into the sell reason. V5.9.822 adds regime multiplier so
                // operator can see why a position held longer/shorter than
                // configured maxHold.
                val _utcHour = try {
                    java.util.Calendar.getInstance(java.util.TimeZone.getTimeZone("UTC"))
                        .get(java.util.Calendar.HOUR_OF_DAY)
                } catch (_: Throwable) { -1 }
                val _modeNameLc = modeConfig.mode.name.lowercase()
                val _zombie = if (_held > _hardCeiling) "_zombie" else ""
                val _reason = "mode_maxhold${_zombie}_${_modeNameLc} held=${_held.toInt()}m max=${_effectiveMaxHold.toInt()}m peak=+${_peakGain.toInt()}% pnl=${"%+.0f".format(_curPnl)}% regime×${"%.2f".format(_regimeHoldMult)} utc=${_utcHour}h"
                ErrorLogger.info(
                    "Executor",
                    "🚪 mode_maxhold${_zombie}: ${ts.symbol} mode=${modeConfig.mode.name} held=${_held.toInt()}min > ${_effectiveMaxHold.toInt()}min peak=+${_peakGain.toInt()}% pnl=${"%+.0f".format(_curPnl)}% (regime×${"%.2f".format(_regimeHoldMult)}) utc=${_utcHour}:00"
                )
                doSell(ts, _reason, wallet, walletSol); return
            }
        }

        if (ts.position.isOpen && !ts.position.isLongHold && cfg().longHoldEnabled) {
            val promotionSize = ts.position.costSol
            if (!ts.position.isOpen || promotionSize <= 0.0) {
                ErrorLogger.info("Executor", "[PROMOTION_BLOCKED] ${ts.symbol} | invalid_size_or_closed")
            } else {
                val gainPct   = pct(ts.position.entryPrice, getActualPrice(ts))
                val c         = cfg()
                val holders   = ts.history.lastOrNull()?.holderCount ?: 0
                val existingLH = 0.0

                val meetsConviction = ts.meta.emafanAlignment == "BULL_FAN"
                    && gainPct >= c.longHoldMinGainPct
                    && ts.lastLiquidityUsd >= c.longHoldMinLiquidityUsd
                    && holders >= c.longHoldMinHolders
                    && ts.holderGrowthRate >= c.longHoldHolderGrowthMin
                    && (!c.longHoldTreasuryGate || TreasuryManager.treasurySol >= 0.01)
                    && ts.position.costSol <= walletSol * c.longHoldWalletPct

                if (meetsConviction) {
                    ts.position = ts.position.copy(isLongHold = true)
                    onLog("🔒 LONG HOLD: ${ts.symbol} promoted — " +
                        "BULL_FAN | ${holders} holders (+${ts.holderGrowthRate.toInt()}%) | " +
                        "$${(ts.lastLiquidityUsd/1000).toInt()}K liq | +${gainPct.toInt()}%", ts.mint)
                    onNotify("🔒 Long Hold: ${ts.symbol}",
                        "+${gainPct.toInt()}% | riding trend | max ${c.longHoldMaxDays.toInt()}d",
                        com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
                }
            }
        }

        if (cfg().autoTrade && ts.position.isOpen && ts.meta.topUpReady) {
            val topUpReady = shouldTopUp(
                ts              = ts,
                entryScore      = entryScore,
                exitScore       = ts.exitScore,
                emafanAlignment = ts.meta.emafanAlignment,
                volScore        = ts.meta.volScore,
                exhaust         = ts.meta.exhaustion,
            )
            if (topUpReady) {
                doTopUp(ts, walletSol, wallet, totalExposureSol)
            }
        }

        if (isPaperRT() && ts.position.isOpen && !ts.position.isFullyBuilt) {
            val result = shouldGraduatedAdd(ts.position, getActualPrice(ts), ts.meta.volScore)
            if (result != null) {
                val (addSol, newPhase) = result
                doGraduatedAdd(ts, addSol, newPhase)
            }
        }

        val shouldActOnBuy = isPaperRT() || cfg().autoTrade
        
        if (signal == "BUY") {
            ErrorLogger.debug("Executor", "BUY CHECK: ${ts.symbol} | shouldAct=$shouldActOnBuy | posOpen=${ts.position.isOpen} | autoTrade=${cfg().autoTrade} | paper=${isPaperRT()}")
        }
        
        if (signal == "BUY" && !ts.position.isOpen) {
            ErrorLogger.error("Executor", "🚨 LEGACY BUY PATH BLOCKED: ${ts.symbol} | " +
                "All new entries MUST go through FDG. This is a code architecture bug.")
            onLog("⛔ ${ts.symbol}: Legacy buy path blocked - use FDG flow", ts.mint)
            return
        }
        
        if (false && shouldActOnBuy && signal == "BUY" && !ts.position.isOpen) {
            val isPaper = isPaperRT()
            ErrorLogger.info("Executor", "🔔 BUY signal for ${ts.symbol} | paper=$isPaper | wallet=${walletSol.fmt(4)} | autoTrade=${cfg().autoTrade}")
            
            val severeLossThreshold = -33.0
            val lastExitPnl = ts.lastExitPnlPct
            if (lastExitPnl < severeLossThreshold) {
                ErrorLogger.info("Executor", "🚫 ${ts.symbol} QUARANTINED: Previous exit was ${lastExitPnl.toInt()}% (< $severeLossThreshold%)")
                onLog("💀 ${ts.symbol}: QUARANTINED (rugged ${lastExitPnl.toInt()}%)", ts.mint)
                RuggedContracts.add(ts.mint, ts.symbol, lastExitPnl)
                return
            }
            
            if (RuggedContracts.isBlacklisted(ts.mint)) {
                ErrorLogger.info("Executor", "🚫 ${ts.symbol} BLACKLISTED: Previously rugged")
                onLog("💀 ${ts.symbol}: Blacklisted contract", ts.mint)
                if (!isPaper) livePreAttemptHardReject(ts, 0.0, "LIVE_BUY_REJECTED_HARD_BLOCK_BLACKLIST", "RuggedContracts.maybeAct")
                return
            }
            
            val tradeState = TradeStateMachine.getState(ts.mint)
            val isPaperMode = isPaperRT()
            // V5.0.4021 — proven-edge cooldown leniency is paper-only. Live
            // may size/route from proven edge, but it must not skip cooldown/
            // state-machine safeties and still buy.
            val lenientMode = isPaperMode

            if (!lenientMode && TradeStateMachine.isInCooldown(ts.mint)) {
                val lastTrade = ts.trades.lastOrNull()
                val wasProfit = lastTrade?.let { it.side == "SELL" && (it.pnlPct ?: 0.0) > 0 } ?: false
                val priceDroppedFromExit = lastTrade?.let { getActualPrice(ts) < it.price * 0.85 } ?: false
                val scoreImproved = entryScore >= 50
                
                if (wasProfit && priceDroppedFromExit && scoreImproved) {
                    onLog("🔄 RE-ENTRY: ${ts.symbol} dipped 15%+ from profitable exit, score=$entryScore", ts.mint)
                    TradeStateMachine.clearCooldown(ts.mint)
                } else {
                    onLog("⏸️ ${ts.symbol}: In cooldown, skipping", ts.mint)
                    livePreAttemptHardReject(ts, 0.0, "LIVE_BUY_REJECTED_HARD_BLOCK_COOLDOWN", "TradeStateMachine.maybeAct")
                    return
                }
            }
            
            if (tradeState.state == TradeState.SCAN) {
                TradeStateMachine.setState(ts.mint, TradeState.WATCH, "BUY signal received")
            }
            
            val priceHistory = ts.history.map { it.priceUsd }
            val optimalEntry = if (lenientMode) true else TradeStateMachine.detectEntryPattern(ts.mint, getActualPrice(ts), priceHistory)
            
            val c = cfg()
            val requireOptimalEntry = !lenientMode && c.smallBuySol < 0.1
            
            if (requireOptimalEntry && !optimalEntry && tradeState.entryPattern != EntryPattern.NONE) {
                if (tradeState.entryPattern == EntryPattern.FIRST_SPIKE) {
                    onLog("📈 ${ts.symbol}: Spike detected, waiting for pullback...", ts.mint)
                } else if (tradeState.entryPattern == EntryPattern.PULLBACK) {
                    onLog("📉 ${ts.symbol}: Pullback detected, waiting for re-acceleration...", ts.mint)
                }
                return
            }
            
            if (optimalEntry && !isPaperMode) {
                onLog("🎯 ${ts.symbol}: OPTIMAL ENTRY - Spike→Pullback→ReAccel pattern!", ts.mint)
            }
            
            TradeStateMachine.setState(ts.mint, TradeState.ENTER, "executing buy")
            
            if (ts.position.isOpen) {
                ErrorLogger.debug("Executor", "Skipping ${ts.symbol} - position already open")
                return
            }
            if (cfg().scalingLogEnabled) { val _spx=WalletManager.lastKnownSolPrice; val (_tier,_)=ScalingMode.maxPositionForToken(ts.lastLiquidityUsd,ts.lastFdv,TreasuryManager.treasurySol*_spx,_spx); if(_tier!=ScalingMode.Tier.MICRO) onLog("${_tier.icon} ${_tier.label}: ${ts.symbol}", ts.mint) }
            
            val aiConfidence = try {
                val hist = ts.history.toList()
                val prices = hist.map { it.ref }
                if (hist.size >= 6) {
                    val edgePhase = EdgeOptimizer.detectMarketPhase(hist, prices)
                    val edgeTiming = EdgeOptimizer.checkEntryTiming(edgePhase, hist, prices, ts.meta.pressScore)
                    EdgeOptimizer.calculateConfidence(edgePhase, edgeTiming,
                        EdgeOptimizer.WeightedScore(entryScore, 0.0, emptyMap()))
                } else 50.0
            } catch (e: Exception) { 50.0 }
            
            var walletIntelligenceBlocked = false
            // V5.9.917 — COLD-START CHOKE FIX. The alphaSignals fetch makes
            // 3 parallel network calls (DexScreener + Rugcheck + Solscan).
            // On a fresh install with cold OkHttp DNS / no cached responses,
            // each leg can take 1-3s. With 4 buys queued back-to-back in
            // a single scanner cycle, that's up to 12s blocking the IO
            // worker. The scanner heartbeat then misses, the loop appears
            // frozen, and operator reports "buys 4 tokens then chokes".
            //
            // Two cuts:
            //   (1) In paper mode the result is never CONSUMED (every
            //       block-check below is `if (... !isPaper) {`). Skip the
            //       fetch entirely — pure waste on the cold-start path.
            //   (2) Tighten LIVE timeout 3000 → 1500ms. Wallet-intel is
            //       a soft signal, not the hard gate; we'd rather miss
            //       a marginal bot-farm flag than choke the loop.
            val alphaSignals = if (isPaper) {
                null
            } else try {
                runBlocking {
                    withTimeoutOrNull(1500L) {
                        DataPipeline.getAlphaSignals(ts.mint, cfg()) { msg ->
                            ErrorLogger.debug("DataPipeline", msg)
                        }
                    }
                }
            } catch (e: Exception) {
                ErrorLogger.debug("DataPipeline", "Error fetching alpha signals: ${e.message}")
                null
            }
            
            if (alphaSignals != null && !isPaper) {
                if (alphaSignals.repeatWalletScore > 60.0) {
                    onLog("🤖 WALLET INTEL: Bot farm detected (repeat wallets ${alphaSignals.repeatWalletScore.toInt()}%) — blocking", ts.mint)
                    walletIntelligenceBlocked = true
                }
                if (alphaSignals.volumePriceDivergence > 70.0) {
                    onLog("📉 WALLET INTEL: Distribution detected (vol/price div ${alphaSignals.volumePriceDivergence.toInt()}) — blocking", ts.mint)
                    walletIntelligenceBlocked = true
                }
                if (alphaSignals.whaleRatio > 0.6) {
                    onLog("🐋 WALLET INTEL: Whale concentration too high (${(alphaSignals.whaleRatio * 100).toInt()}%) — blocking", ts.mint)
                    walletIntelligenceBlocked = true
                }
                if (alphaSignals.overallGrade in listOf("D", "F")) {
                    onLog("⚠️ WALLET INTEL: Low grade (${alphaSignals.overallGrade}) — ${DataPipeline.formatAlphaSignals(ts.mint, alphaSignals)}", ts.mint)
                }
            }
            
            if (walletIntelligenceBlocked) {
                ErrorLogger.info("Executor", "❌ ${ts.symbol} blocked by wallet intelligence")
                return
            }
            
            val setupQuality = ts.meta.setupQuality
            val isLowQuality = setupQuality == "C"
            val isUnknownPhase = ts.phase.contains("unknown", ignoreCase = true)
            val isLowConfidence = aiConfidence < 30.0
            
            // V5.9.174 — the user reported that the meme-trader collapsed from
            // thousands of trades/day to <200. This trinity block (C + unknown
            // + low-conf) was killing every fresh-launch candidate even in
            // paper mode. Paper is for LEARNING — hard-kill is wrong here.
            // In paper we now let the fluid size multiplier + FDG confidence
            // floor handle weak setups instead of bailing outright.
            // V5.9.1544 — DON'T HARD-BLOCK THE TRINITY IN LIVE (operator: 55
            // commits stacked over-strict vetoes on working logic). "unknown phase"
            // is the DEFAULT for a fresh launch before phase data resolves, so this
            // C + unknown + low-conf trinity fired on nearly every new LIVE candidate
            // — choking volume. The redFlagCount size-clamp directly below ALREADY
            // shrinks weak setups to 0.25x; that is the correct soft-shape response,
            // and it is strictly safer than a buy at full size. So LIVE now mirrors
            // PAPER: probe at clamped size instead of hard-veto. The unconditional
            // -15% hard-floor SL + FDG + size-cap remain the real risk controls.
            if (isLowQuality && isUnknownPhase && isLowConfidence) {
                ErrorLogger.info("Executor", "🎓 ${ts.symbol} probe-buy: C+unknown+conf${aiConfidence.toInt()}% — size clamped via redFlagCount, NOT blocked${if (isPaper) " [PAPER]" else " [LIVE]"}")
            }
            
            val redFlagCount = listOf(isLowQuality, isUnknownPhase, isLowConfidence).count { it }
            val qualityPenalty = when (redFlagCount) {
                3 -> 0.15   // V5.9.1544 — full trinity (C+unknown+lowconf): smallest probe, NOT full size (was uncapped → 1.0)
                2 -> 0.25
                1 -> 0.60
                else -> 1.0
            }
            
            ErrorLogger.info("Executor", "📊 ${ts.symbol} SIZING: wallet=$walletSol | liq=${ts.lastLiquidityUsd} | mcap=${ts.lastFdv} | conf=$aiConfidence | entry=$entryScore | quality=$setupQuality | redFlags=$redFlagCount")
            // V5.9.718 — derive lane for phase-aware size multiplier
            val _laneMode = try { ModeRouter.classify(ts).tradeType.name } catch (_: Throwable) { ts.source }
            var size = buySizeSol(
                entryScore = entryScore, 
                walletSol = walletSol, 
                currentOpenPositions = openPositionCount, 
                currentTotalExposure = totalExposureSol,
                walletTotalTrades = walletTotalTrades,
                liquidityUsd = ts.lastLiquidityUsd,
                mcapUsd = ts.lastFdv,
                aiConfidence = aiConfidence,
                phase = ts.phase,
                source = ts.source,
                brain = brain,
                setupQuality = setupQuality,
                ts = ts,  // V5.9.69: enable PatternClassifier
                laneMode = _laneMode,
            )
            
            if (qualityPenalty < 1.0) {
                val oldSize = size
                size *= qualityPenalty
                ErrorLogger.info("Executor", "📉 ${ts.symbol} size reduced: ${oldSize.fmt(3)} → ${size.fmt(3)} (penalty=${qualityPenalty}x, redFlags=$redFlagCount)")
            }

            if (c.crossTokenGuardEnabled) {
                val windowMs = (c.crossTokenWindowMins * 60_000.0).toLong()
                val cutoff   = System.currentTimeMillis() - windowMs
                val solPxCG  = WalletManager.lastKnownSolPrice
                val trsUsdCG = TreasuryManager.treasurySol * solPxCG
                val thisTier = ScalingMode.tierForToken(ts.lastLiquidityUsd, ts.lastFdv)
                ts.recentEntryTimes.removeIf { it < cutoff }
                val sameTierCount = BotService.status.openPositions.count { other ->
                    other.mint != ts.mint &&
                    ScalingMode.tierForToken(other.lastLiquidityUsd, other.lastFdv) == thisTier &&
                    (System.currentTimeMillis() - other.position.entryTime) < windowMs
                }
                if (sameTierCount >= c.crossTokenMaxCluster) {
                    size *= c.crossTokenSizePenalty
                    onLog("⚠ Cluster guard (${thisTier.label}): ${sameTierCount} same-tier entries " +
                          "— size ${size.fmt(4)} SOL", ts.mint)
                }
                ts.recentEntryTimes.add(System.currentTimeMillis())
            }
            modeConfig?.let { size = size * it.positionSizeMultiplier }
            
            // V5.9.61: was a live-only `brain.shouldSkipTrade()` block that
            // silently killed trades. Paper didn't apply it, so live was
            // stricter. With V5.9.59's entryThresholdDelta cap at +8 and
            // the drought watchdog, this extra gate is redundant and
            // causes exactly the paper-vs-live divergence users report.
            // Removed entirely — the same brain already influences
            // entryScore / sizing earlier in the pipeline.
            
            if (size < 0.001) {
                ErrorLogger.debug("Executor", "🪫 ${ts.symbol} SIZE TOO SMALL: $size | wallet=$walletSol | paper=$isPaperMode | liq=${ts.lastLiquidityUsd}")
                onLog("Insufficient capacity for new position on ${ts.symbol} (size=$size)", ts.mint)
                if (!isPaperMode) livePreAttemptHardReject(ts, size, "LIVE_ENTRY_REJECTED_SIZE_TOO_THIN_FOR_NON_MICRO_TRADE", "maybeAct.size=$size wallet=$walletSol liq=${ts.lastLiquidityUsd}")
                return
            }
            
            ErrorLogger.info("Executor", "✅ ${ts.symbol} SIZE OK: $size SOL - proceeding to doBuy()")

            ShadowLearningEngine.onTradeOpportunity(
                mint = ts.mint,
                symbol = ts.symbol,
                currentPrice = getActualPrice(ts),
                liveEntryScore = entryScore.toInt(),
                liveEntryThreshold = 42,
                liveSizeSol = size,
                phase = ts.phase,
            )

            doBuy(ts, size, entryScore, wallet, walletSol, null, setupQuality)
        }
    }

    // ══════════════════════════════════════════════════════════════════
    // PRIORITY 2: UNIFIED CANDIDATE DECISION SUPPORT
    // ══════════════════════════════════════════════════════════════════
    
    fun maybeActWithDecision(
        ts: TokenState,
        decision: CandidateDecision,
        walletSol: Double,
        wallet: SolanaWallet?,
        lastPollMs: Long = System.currentTimeMillis(),
        openPositionCount: Int = 0,
        totalExposureSol: Double = 0.0,
        modeConfig: AutoModeEngine.ModeConfig? = null,
        fdgApprovedSize: Double? = null,
        walletTotalTrades: Int = 0,
        tradeIdentity: TradeIdentity? = null,
        fdgApprovalClass: FinalDecisionGate.ApprovalClass? = null,
    ) {
        normalizePositionScaleIfNeeded(ts)
        val identity = tradeIdentity ?: TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
        
        fdgApprovalClass?.let { identity.fdgApprovalClass = it.name }
        
        val cbState = security.getCircuitBreakerState()
        if (cbState.isHalted) {
            onLog("🛑 Halted: ${cbState.haltReason}", identity.mint)
            return
        }

        // ── V5.9.893 — restore checkDataFreshness on maybeActWithDecision path ──
        // The OLDER maybeAct() function (line 4762) calls
        // security.checkDataFreshness(lastPollMs) and blocks trades if the
        // last successful market poll is >60s stale. maybeActWithDecision()
        // was added later (the V3-decision-routed path) and accepts
        // lastPollMs in its signature — but the freshness check was NEVER
        // wired through. Two BotService callers (L13650, L14951) pass
        // lastPollMs correctly, expecting the gate to fire, but the gate
        // was silently absent.
        //
        // Net effect: data-stale (RPC down, network drop, scanner stuck)
        // BUYS could go through on the modern path even though the
        // SecurityGuard had explicitly marked the data as untrustworthy.
        // Classic memory lesson #3.8: when a function gets a sibling, the
        // safety checks don't auto-migrate.
        //
        // This commit restores the original semantic. Block is a soft
        // return (no buy / no sell action) — matches maybeAct behavior
        // exactly. No new veto; this is RESTORING an existing veto that
        // was silently dropped.
        val freshness = security.checkDataFreshness(lastPollMs)
        if (freshness is GuardResult.Block) {
            onLog("⚠ ${freshness.reason}", identity.mint)
            return
        }

        if (ts.position.isOpen) {
            try {
                val currentPnlPct = ((getActualPrice(ts) - ts.position.entryPrice) / ts.position.entryPrice) * 100
                // V5.0.4109 — DEADLOCK FIX. Previously this was a
                // runBlocking { HoldingLogicLayer.evaluatePosition(...) } call
                // that parked the worker thread on a coroutines Mutex inside a
                // suspend function whose body had no real suspension points.
                // With 20+ tokens evaluated concurrently the IO dispatcher
                // drained and the supervisor hung on Unsafe.park. The function
                // is now a regular synchronous fun; call directly.
                val holdEval = HoldingLogicLayer.evaluatePosition(
                    position = ts.position,
                    ts = ts,
                    currentPnlPct = currentPnlPct,
                    isPaperMode = isPaperRT(),
                )
                
                if (holdEval.action == HoldingLogicLayer.HoldAction.SWITCH_MODE && 
                    holdEval.modeSwitchRecommendation?.shouldSwitch == true) {
                    val rec = holdEval.modeSwitchRecommendation
                    val oldMode = ts.position.tradingMode
                    val oldEmoji = ts.position.tradingModeEmoji
                    
                    ts.position.tradingMode = rec.newMode
                    ts.position.tradingModeEmoji = rec.newModeEmoji
                    ts.position.modeHistory = if (ts.position.modeHistory.isEmpty()) {
                        "$oldMode>${rec.newMode}"
                    } else {
                        "${ts.position.modeHistory}>${rec.newMode}"
                    }
                    
                    onLog("🔄 MODE SWITCH: ${identity.symbol} | $oldEmoji $oldMode → ${rec.newModeEmoji} ${rec.newMode} | ${rec.reason}", identity.mint)
                    ErrorLogger.info("HoldingLogic", "Mode switch: ${identity.symbol} $oldMode→${rec.newMode} (conf=${rec.confidence.toInt()}%)")
                }
                
                if (holdEval.urgency == HoldingLogicLayer.Urgency.HIGH || 
                    holdEval.urgency == HoldingLogicLayer.Urgency.CRITICAL) {
                    ErrorLogger.debug("HoldingLogic", "${identity.symbol}: ${holdEval.action} - ${holdEval.reason}")
                }
            } catch (e: Exception) {
                ErrorLogger.debug("HoldingLogic", "Evaluation error for ${identity.symbol}: ${e.message}")
            }
            
            try {
                val currentPnl = ((getActualPrice(ts) - ts.position.entryPrice) / ts.position.entryPrice) * 100
                val mcapChange = if (ts.position.entryMcap > 0) {
                    ((ts.lastMcap - ts.position.entryMcap) / ts.position.entryMcap) * 100
                } else 0.0
                val liquidityChange = if (ts.position.entryLiquidityUsd > 0) {
                    ((ts.lastLiquidityUsd - ts.position.entryLiquidityUsd) / ts.position.entryLiquidityUsd) * 100
                } else 0.0
                val holdTimeMs = System.currentTimeMillis() - ts.position.entryTime
                val tokenAgeMs = System.currentTimeMillis() - ts.addedToWatchlistAt
                
                if (AICrossTalk.shouldCheckModeSwitch(ts.mint, mcapChange, liquidityChange, currentPnl)) {
                    val modeSwitchSignal = AICrossTalk.evaluateModeSwitchCrossTalk(
                        mint = ts.mint,
                        symbol = identity.symbol,
                        currentMode = ts.position.tradingMode,
                        mcap = ts.lastMcap,
                        liquidity = ts.lastLiquidityUsd,
                        ageMs = tokenAgeMs,
                        currentPnlPct = currentPnl,
                        holdTimeMs = holdTimeMs,
                    )
                    
                    if (modeSwitchSignal.shouldSwitch && modeSwitchSignal.confidence >= 70.0) {
                        val oldMode = ts.position.tradingMode
                        val oldEmoji = ts.position.tradingModeEmoji
                        val newEmoji = HoldingLogicLayer.getModeEmoji(modeSwitchSignal.recommendedMode)
                        
                        ts.position.tradingMode = modeSwitchSignal.recommendedMode
                        ts.position.tradingModeEmoji = newEmoji
                        ts.position.modeHistory = if (ts.position.modeHistory.isEmpty()) {
                            "$oldMode>${modeSwitchSignal.recommendedMode}"
                        } else {
                            "${ts.position.modeHistory}>${modeSwitchSignal.recommendedMode}"
                        }
                        
                        onLog("🔗🔄 CROSSTALK SWITCH: ${identity.symbol} | $oldEmoji $oldMode → $newEmoji ${modeSwitchSignal.recommendedMode} | ${modeSwitchSignal.participatingAIs.joinToString("+")} | ${modeSwitchSignal.reason}", identity.mint)
                        ErrorLogger.info("CrossTalk", "Mode switch applied: ${identity.symbol} $oldMode→${modeSwitchSignal.recommendedMode} (conf=${modeSwitchSignal.confidence.toInt()}%)")
                    }
                }
            } catch (e: Exception) {
                ErrorLogger.debug("CrossTalk", "Mode switch eval error for ${identity.symbol}: ${e.message}")
            }
            
            val quickExit = PrecisionExitLogic.quickCheck(
                mint = identity.mint,
                currentPrice = getActualPrice(ts),
                entryPrice = ts.position.entryPrice,
                stopLossPct = cfg().stopLossPct,
                entryTimeMs = ts.position.entryTime,
            )
            if (quickExit != null && quickExit.shouldExit) {
                onLog("🚨 V8 QUICK EXIT: ${identity.symbol} | ${quickExit.reason} | ${quickExit.details}", identity.mint)
                doSell(ts, "v8_${quickExit.reason.lowercase()}", wallet, walletSol, identity)
                TradeStateMachine.startCooldown(identity.mint)
                return
            }
            
            if (checkPartialSell(ts, wallet, walletSol)) return
            
            val reason = riskCheck(ts, modeConfig)
            if (reason != null) {
                doSell(ts, reason, wallet, walletSol, identity)
                return
            }
            
            if (decision.finalSignal in listOf("SELL", "EXIT")) {
                doSell(ts, decision.finalSignal.lowercase(), wallet, walletSol, identity)
                return
            }
            
            if (modeConfig != null) {
                val held = (System.currentTimeMillis() - ts.position.entryTime) / 60_000.0
                val tf = ts.candleTimeframeMinutes.toDouble().coerceAtLeast(1.0)
                // V5.9.822 — same MarketRegimeAI.getHoldTimeMultiplier wire as
                // the primary max-hold gate above. See V5.9.822 block at ~4613.
                val regimeHoldMult2 = try {
                    com.lifecyclebot.engine.MarketRegimeAI.getHoldTimeMultiplier().coerceIn(0.5, 2.0)
                } catch (_: Throwable) { 1.0 }
                // V5.0.4125 — Apply AGI style hold multiplier (sibling of primary path)
                val effectiveMaxHold2 = modeConfig.maxHoldMins * tf * regimeHoldMult2 * ts.styleHoldMult.coerceIn(0.25, 5.0)
                // V5.9.901 — SIBLING-DRIFT FIX (memory #3 rule 8): mirror the
                // runner bypass applied to the primary mode_maxhold gate at
                // ~line 4865. Without this, the v3 decision path would still
                // kill runners while the v8 path correctly let them ride.
                val _curPnl2 = if (ts.position.entryPrice > 0.0)
                    ((getActualPrice(ts) - ts.position.entryPrice) / ts.position.entryPrice) * 100.0
                else 0.0
                val _peakGain2 = ts.position.peakGainPct
                val _runnerHwGate2 = _peakGain2 >= 20.0
                val _runnerTrendIntact2 = _peakGain2 > 0.0 && _curPnl2 >= _peakGain2 * 0.70
                val _runnerBypass2 = _runnerHwGate2 && _runnerTrendIntact2
                val _hardCeiling2 = effectiveMaxHold2 * 4.0
                val _shouldForceExit2 = when {
                    held > _hardCeiling2          -> true
                    ts.position.isLongHold        -> false  // V5.0.4125 — long-hold bypasses time exit
                    _runnerBypass2                -> false
                    held > effectiveMaxHold2      -> true
                    else                           -> false
                }
                if (_shouldForceExit2) {
                    val _utcHour2 = try {
                        java.util.Calendar.getInstance(java.util.TimeZone.getTimeZone("UTC"))
                            .get(java.util.Calendar.HOUR_OF_DAY)
                    } catch (_: Throwable) { -1 }
                    val _zombie2 = if (held > _hardCeiling2) "_zombie" else ""
                    val _reason2 = "mode_maxhold${_zombie2}_${modeConfig.mode.name.lowercase()} held=${held.toInt()}m max=${effectiveMaxHold2.toInt()}m peak=+${_peakGain2.toInt()}% pnl=${"%+.0f".format(_curPnl2)}% regime×${"%.2f".format(regimeHoldMult2)} utc=${_utcHour2}h"
                    ErrorLogger.info(
                        "Executor",
                        "🚪 mode_maxhold(v3)${_zombie2}: ${ts.symbol} mode=${modeConfig.mode.name} held=${held.toInt()}min > ${effectiveMaxHold2.toInt()}min peak=+${_peakGain2.toInt()}% pnl=${"%+.0f".format(_curPnl2)}% (regime×${"%.2f".format(regimeHoldMult2)}) utc=${_utcHour2}:00"
                    )
                    doSell(ts, _reason2, wallet, walletSol, identity)
                    return
                }
            }
            
            if (cfg().autoTrade && decision.meta.topUpReady) {
                val topUpReady = shouldTopUp(
                    ts = ts,
                    entryScore = decision.entryScore,
                    exitScore = decision.exitScore,
                    emafanAlignment = decision.meta.emafanAlignment,
                    volScore = decision.meta.volScore,
                    exhaust = decision.meta.exhaustion,
                )
                if (topUpReady) {
                    doTopUp(ts, walletSol, wallet, totalExposureSol)
                }
            }
            
            if (isPaperRT() && !ts.position.isFullyBuilt) {
                val result = shouldGraduatedAdd(ts.position, getActualPrice(ts), decision.meta.volScore)
                if (result != null) {
                    val (addSol, newPhase) = result
                    doGraduatedAdd(ts, addSol, newPhase)
                }
            }
            
            return
        }
        
        val shouldActOnBuy = isPaperRT() || cfg().autoTrade
        ExecutionRootCauseTrace.buy("DO_EXECUTE_BUY_DECISION", ts, "shouldAct=$shouldActOnBuy autoTrade=${cfg().autoTrade} paper=${isPaperRT()} shouldTrade=${decision.shouldTrade} signal=${decision.signal} final=${decision.finalSignal} score=${decision.entryScore} conf=${decision.aiConfidence} quality=${decision.finalQuality} block=${decision.blockReason.take(80)}")
        if (!shouldActOnBuy) {
            ExecutionRootCauseTrace.buy("BUY_ABORT_AUTO_DISABLED", ts, "autoTrade=${cfg().autoTrade} paper=${isPaperRT()}")
            ErrorLogger.debug("Executor", "📊 ${ts.symbol}: Buy skipped - autoTrade disabled")
            return
        }
        
        if (!decision.shouldTrade) {
            val reason = if (decision.blockReason.isNotEmpty()) decision.blockReason else "legacy_shouldTrade=false"
            ErrorLogger.debug("Executor", "📊 ${ts.symbol}: Legacy would block ($reason) - V3 will evaluate")

            // V5.9.495z33 — executive hook for EntryWaitOverrideGate.
            // Operator directive: "we shouldn't block at 39% confidence —
            // we should wait to see if it changes." When the legacy path
            // would reject and the gate verdict is FDG_DEFER_ENTRY_WAIT,
            // explicitly keep the candidate alive in the watchlist with
            // its TTL refreshed. The V3 engine's own Watch semantic still
            // applies — this just guarantees the rejection branch never
            // silently purges a deferred candidate.
            try {
                val isWait = reason.contains("WAIT", ignoreCase = true) ||
                             reason.contains("entry_wait", ignoreCase = true)
                val isHighRisk = reason.contains("HIGH", ignoreCase = true) ||
                                 reason.contains("risk_high", ignoreCase = true)
                val gate = com.lifecyclebot.engine.EntryWaitOverrideGate.evaluate(
                    entryWait = isWait,
                    riskHigh = isHighRisk,
                    moonshotOverride = false,
                    confidence = decision.aiConfidence.toInt(),
                )
                if (gate.verdict == com.lifecyclebot.engine.EntryWaitOverrideGate.Verdict.FDG_DEFER_ENTRY_WAIT) {
                    com.lifecyclebot.engine.WatchlistTtlPolicy.mark(
                        ts.symbol, decision.aiConfidence.toInt()
                    )
                    com.lifecyclebot.engine.DeferActivityTracker.record(
                        com.lifecyclebot.engine.DeferActivityTracker.Kind.DEFERRED,
                        ts.symbol,
                    )
                    ErrorLogger.info("Executor",
                        "🛡 ${ts.symbol}: ${gate.reason} — kept in watchlist (TTL refreshed)")
                }
            } catch (_: Throwable) { /* best-effort */ }
        }
        
        // V5.9.778 — EMERGENT MEME-ONLY: single source of truth.
        // Operator forensics 5.0.2709: `[MODE] current=PAPER` while live
        // tokens landed on chain and EXEC_LIVE_BUY_OK=1. Root cause was
        // a ConfigStore 2s cache race serving stale paperMode after a
        // PAPER→LIVE flip, producing the impossible `route=PAPER
        // cfgPaper=true walletLoaded=false` pipeline line. Executor now
        // reads from RuntimeModeAuthority (atomic, no cache) — the same
        // authority ConfigStore.save() publishes on every config write.
        val isPaper = isPaperRT()
        // Keep publishing the executor's chosen branch so detectDesync()
        // can still warn the operator if anyone reads a different value.
        com.lifecyclebot.engine.RuntimeModeAuthority.publishExecutorMode(isPaper)
        com.lifecyclebot.engine.HotPathLaneGate.markHotTick()
        ErrorLogger.info("Executor", "🔔 UNIFIED BUY: ${ts.symbol} | " +
            "quality=${decision.finalQuality} | edge=${decision.edgePhase} | " +
            "conf=${decision.aiConfidence.toInt()}% | penalty=${decision.qualityPenalty} | " +
            "paper=$isPaper | autoTrade=${cfg().autoTrade}")

        // V5.0.4009 — SmartChart is advisory in LIVE after FDG/EXEC allow.
        // It may shape/log momentum risk, but it must not silently return before
        // doBuy/liveBuy; otherwise reports show FDG/EXEC allow with BUY 0/0.
        run {
            val bearish = SmartChartCache.getBearishConfidence(ts.mint)
            if (bearish != null && bearish >= 80.0) {
                if (!isPaper) {
                    ErrorLogger.info("Executor", "📉 SMARTCHART_ADVISORY: ${ts.symbol} | bearish=${bearish.toInt()}% — live FDG-approved path continues with downstream hard gates")
                    liveAdvisoryNotTerminal(ts, "MOMENTUM_AVOID", "smartChartBearish=${bearish.toInt()}")
                } else {
                    ErrorLogger.info("Executor", "🚫 SMARTCHART_BLOCK: ${ts.symbol} | bearish=${bearish.toInt()}% — skipping LONG entry")
                    onLog("🚫 ${ts.symbol}: SmartChart ${bearish.toInt()}% bearish — skip entry", ts.mint)
                    return
                }
            }
        }
        
        if (ts.history.size >= 3) {
            val recentCandles = ts.history.takeLast(3)
            val priceStart = recentCandles.first().priceUsd
            val priceEnd = recentCandles.last().priceUsd
            if (priceStart > 0 && priceEnd > 0) {
                val velocityPct = ((priceEnd - priceStart) / priceStart) * 100
                
                if (velocityPct < -5.0) {
                    if (!isPaper) {
                        ErrorLogger.debug("Executor", "⚡ ${ts.symbol} VELOCITY_ADVISORY: Price dropping ${velocityPct.toInt()}% rapidly — live FDG-approved path continues")
                        liveAdvisoryNotTerminal(ts, "MOMENTUM_AVOID", "velocityPct=${velocityPct.fmt(2)}")
                    } else {
                        ErrorLogger.debug("Executor", "⚡ ${ts.symbol} VELOCITY BLOCK: Price dropping ${velocityPct.toInt()}% rapidly")
                        onLog("⚡ ${ts.symbol}: Price dropping ${velocityPct.toInt()}% - waiting for stabilization", ts.mint)
                        return
                    }
                }
            }
        }
        
        if (RuggedContracts.isBlacklisted(ts.mint)) {
            ErrorLogger.info("Executor", "🚫 ${ts.symbol} BLACKLISTED: Previously rugged")
            onLog("💀 ${ts.symbol}: Blacklisted contract", ts.mint)
            if (!isPaper) livePreAttemptHardReject(ts, 0.0, "LIVE_BUY_REJECTED_HARD_BLOCK_BLACKLIST", "RuggedContracts")
            return
        }
        
        if (!isPaper && TradeStateMachine.isInCooldown(ts.mint)) {
            onLog("⏸️ ${ts.symbol}: In cooldown, skipping", ts.mint)
            livePreAttemptHardReject(ts, 0.0, "LIVE_BUY_REJECTED_HARD_BLOCK_COOLDOWN", "TradeStateMachine")
            return
        }
        
        TradeStateMachine.setState(ts.mint, TradeState.ENTER, "executing buy via unified decision")
        
        var size = fdgApprovedSize ?: buySizeSol(
            entryScore = decision.entryScore,
            walletSol = walletSol,
            currentOpenPositions = openPositionCount,
            currentTotalExposure = totalExposureSol,
            walletTotalTrades = walletTotalTrades,
            liquidityUsd = ts.lastLiquidityUsd,
            mcapUsd = ts.lastFdv,
            aiConfidence = decision.aiConfidence,
            phase = decision.phase,
            source = ts.source,
            brain = brain,
            setupQuality = decision.setupQuality,
            ts = ts,  // V5.9.69: enable PatternClassifier
        )
        
        if (fdgApprovedSize == null) {
            if (decision.qualityPenalty < 1.0 && decision.qualityPenalty > 0.0) {
                val oldSize = size
                size *= decision.qualityPenalty
                ErrorLogger.info("Executor", "📉 ${ts.symbol} size reduced: ${oldSize.fmt(3)} → ${size.fmt(3)} " +
                    "(penalty=${decision.qualityPenalty}x, redFlags=${decision.redFlagCount})")
            }
            
            modeConfig?.let { size *= it.positionSizeMultiplier }
        }
        
        if (!isPaper) {
            brain?.let { b ->
                if (b.shouldSkipTrade(decision.phase, decision.meta.emafanAlignment, ts.source, decision.entryScore)) {
                    onLog("🧠 Brain advisory: ${ts.symbol} — risk factors shaped, not terminal", ts.mint)
                    liveAdvisoryNotTerminal(ts, "BRAIN_PATTERN_SUPPRESSED", "phase=${decision.phase} ema=${decision.meta.emafanAlignment} source=${ts.source} score=${decision.entryScore}")
                }
            }
        }
        
        if (size < 0.001) {
            ErrorLogger.debug("Executor", "🪫 ${ts.symbol} SIZE TOO SMALL: $size | quality=${decision.finalQuality}")
            onLog("Insufficient capacity for ${ts.symbol} (size=$size)", ts.mint)
            if (!isPaper) livePreAttemptHardReject(ts, size, "LIVE_ENTRY_REJECTED_SIZE_TOO_THIN_FOR_NON_MICRO_TRADE", "maybeActWithDecision.size=$size")
            return
        }
        
        if (isPaper) {
            ErrorLogger.info("Executor", "📄 ${ts.symbol} PAPER BUY: $size SOL - quality=${decision.finalQuality}")
        } else {
            ErrorLogger.info("Executor", "💰 ${ts.symbol} LIVE BUY ATTEMPT: $size SOL - " +
                "quality=${decision.finalQuality} | wallet=$walletSol | autoTrade=${cfg().autoTrade}")
            onLog("💰 LIVE BUY: ${ts.symbol} | ${size.fmt(4)} SOL | quality=${decision.finalQuality}", ts.mint)
        }
        
        ShadowLearningEngine.onTradeOpportunity(
            mint = ts.mint,
            symbol = ts.symbol,
            currentPrice = getActualPrice(ts),
            liveEntryScore = decision.entryScore.toInt(),
            liveEntryThreshold = 42,
            liveSizeSol = size,
            phase = decision.phase,
        )
        
        val skipGraduated = fdgApprovedSize != null
        doBuy(ts, size, decision.entryScore, wallet, walletSol, identity, decision.setupQuality, skipGraduated)
    }

    // ── top-up (pyramid add) ─────────────────────────────────────────

    fun doTopUp(
        ts: TokenState,
        walletSol: Double,
        wallet: SolanaWallet?,
        totalExposureSol: Double,
    ) {
        normalizePositionScaleIfNeeded(ts)
        val pos  = ts.position
        val c    = cfg()
        val size = topUpSizeSol(pos, walletSol, totalExposureSol)

        if (size < 0.001) {
            onLog("⚠ Top-up skipped: size too small (${size})", ts.mint)
            return
        }

        val gainPct = pct(pos.entryPrice, getActualPrice(ts))
        onLog("🔺 TOP-UP #${pos.topUpCount + 1}: ${ts.symbol} " +
              "+${gainPct.toInt()}% gain | adding ${size.fmt(4)} SOL " +
              "(total will be ${(pos.costSol + size).fmt(4)} SOL)", ts.mint)

        // V5.9.751b — refuse paper fallback when config is live (see A1 note).
        // V5.9.779 — read mode from RuntimeModeAuthority for the canonical
        // single source of truth (config c.paperMode can lag by 2 s).
        if (isPaperRT()) {
            paperTopUp(ts, size)
        } else if (wallet == null) {
            ErrorLogger.error("Executor",
                "🚫 LIVE_TOPUP_REFUSED: ${ts.symbol} — config is LIVE but wallet is NULL. Refusing paperTopUp fallback.")
            onLog("🚫 Live top-up blocked: ${ts.symbol} — wallet disconnected.", ts.mint)
            return
        } else {
            val guard = security.checkBuy(
                mint         = ts.mint,
                symbol       = ts.symbol,
                solAmount    = size,
                walletSol    = walletSol,
                currentPrice = getActualPrice(ts),
                currentVol   = ts.history.lastOrNull()?.vol ?: 0.0,
                liquidityUsd = ts.lastLiquidityUsd,
            )
            when (guard) {
                is GuardResult.Block -> onLog("🚫 Top-up blocked: ${guard.reason}", ts.mint)
                is GuardResult.Allow -> liveTopUp(ts, size, wallet, walletSol)
            }
        }
    }

    private fun paperTopUp(ts: TokenState, sol: Double) {
        // V5.9.779 — EMERGENT MEME-ONLY: defence-in-depth gate. Even if a
        // caller bypasses doTopUp's RuntimeModeAuthority check, paperTopUp
        // refuses to write paper Position mutations when authority=LIVE
        // and shadowPaperEnabled is off.
        if (isLiveRT()) {
            // V5.0.6073 — shadow paper is always-on doctrine; paper mutations in
            // live mode are the shadow book by design.
            val shadowEnabled = true
            if (!shadowEnabled) {
                try {
                    ForensicLogger.lifecycle(
                        "PAPER_TOPUP_IN_LIVE_MODE_BLOCKED",
                        "blocked=true symbol=${ts.symbol} mint=${ts.mint.take(10)} sol=$sol",
                    )
                } catch (_: Throwable) {}
                ErrorLogger.warn("Executor", "🚫 PAPER_TOPUP_IN_LIVE_MODE_BLOCKED: ${ts.symbol} (sol=$sol)")
                return
            }
        }
        val pos   = ts.position
        val price = getActualPrice(ts)
        if (price <= 0) return

        val newQty    = sol / maxOf(price, 1e-12)
        val totalQty  = pos.qtyToken + newQty
        val totalCost = pos.costSol + sol

        ts.position = pos.copy(
            qtyToken       = totalQty,
            entryPrice     = totalCost / totalQty,
            costSol        = totalCost,
            topUpCount     = pos.topUpCount + 1,
            topUpCostSol   = pos.topUpCostSol + sol,
            lastTopUpTime  = System.currentTimeMillis(),
            lastTopUpPrice = price,
        )

        val trade = Trade("BUY", "paper", sol, price,
                          System.currentTimeMillis(), "top_up_${pos.topUpCount + 1}")
        recordTrade(ts, trade)
        security.recordTrade(trade)
        // V5.0.3871 — paper top-ups are BUY legs and must debit available paper cash.
        // Graduated adds and fresh buys already do this; this sibling path mutated
        // position cost without touching the wallet ledger, making cash/equity drift.
        onPaperBalanceChange?.invoke(-sol)

        val gainPct = pct(pos.entryPrice, price)
        onLog("PAPER TOP-UP #${pos.topUpCount + 1} @ ${price.fmt()} | " +
              "${sol.fmt(4)} SOL | running gain was +${gainPct.toInt()}% | " +
              "avg entry now ${ts.position.entryPrice.fmt()}", ts.mint)
        onNotify("🔺 Top-Up #${pos.topUpCount + 1}",
                 "${ts.symbol}  +${gainPct.toInt()}%  adding ${sol.fmt(3)} SOL",
                 com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
        sounds?.playMilestone(gainPct)
    }


    private fun beginMemeExecutionStack(
        side: com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Side,
        ts: TokenState,
        amountIn: Double,
        amountInRaw: String = "",
        slippageBps: Int = 0,
        reason: String = "",
        urgency: com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Urgency = com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Urgency.NORMAL,
        walletSol: Double = 0.0,
        tokenBalanceAuthority: String = "UNKNOWN",
        callSite: String,
    ) {
        try {
            val src = try { ts.source } catch (_: Throwable) { "" }
            val upper = src.uppercase()
            val intel = com.lifecyclebot.engine.execution.MemeExecutionRouteStack.RouteIntelligenceSnapshot(
                birdeyePrice = null,
                coingeckoContext = "",
                dexScreenerPair = if (upper.contains("DEX") || upper.contains("RAYDIUM") || upper.contains("METEORA") || upper.contains("ORCA")) src else "",
                pumpPortalSignal = if (upper.contains("PUMP") || ts.mint.endsWith("pump", ignoreCase = true)) src.ifBlank { "mint_suffix_or_pump_source" } else "",
                pumpFunBondingSignal = ts.mint.endsWith("pump", ignoreCase = true) || upper.contains("PUMP_FUN") || upper.contains("PUMPPORTAL"),
                pumpSwapPoolFound = upper.contains("PUMPSWAP") || upper.contains("GRADUATED") || upper.contains("PUMP_FUN_GRADUATE"),
                raydiumPoolFound = upper.contains("RAYDIUM"),
                meteoraPoolFound = upper.contains("METEORA") || upper.contains("DLMM"),
                orcaPoolFound = upper.contains("ORCA") || upper.contains("WHIRLPOOL"),
                liquidityDepthUsd = try { ts.lastLiquidityUsd } catch (_: Throwable) { 0.0 },
                priceConfidence = 0,
                exitDepthUsd = try { ts.lastLiquidityUsd } catch (_: Throwable) { 0.0 },
                recommendedVenues = src.split(",", "+", "|").map { it.trim() }.filter { it.isNotBlank() }.take(8),
                blockedVenues = emptyList(),
                unsupportedVenues = emptyList(),
            )
            com.lifecyclebot.engine.execution.MemeExecutionRouteStack.start(
                com.lifecyclebot.engine.execution.MemeExecutionRouteStack.ExecutionRouteContext(
                    side = side,
                    mint = ts.mint,
                    symbol = ts.symbol,
                    amountIn = amountIn,
                    amountInRaw = amountInRaw,
                    slippageBps = slippageBps,
                    reason = reason,
                    urgency = urgency,
                    walletSol = walletSol,
                    tokenBalanceAuthority = tokenBalanceAuthority,
                    routeIntelligence = intel,
                    safetyTier = "UNKNOWN",
                    sourceTags = src,
                    callSite = callSite,
                )
            )
        } catch (_: Throwable) {}
    }

    private fun liveTopUp(ts: TokenState, sol: Double,
                           wallet: SolanaWallet, walletSol: Double) {
        val c = cfg()
        beginMemeExecutionStack(
            side = com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Side.BUY,
            ts = ts,
            amountIn = sol,
            amountInRaw = ((sol * 1_000_000_000.0).toLong()).toString(),
            slippageBps = c.slippageBps,
            reason = "TOP_UP",
            urgency = com.lifecyclebot.engine.execution.MemeExecutionRouteStack.Urgency.TOP_UP,
            walletSol = walletSol,
            tokenBalanceAuthority = "WALLET_SOL_PREFLIGHT",
            callSite = "liveTopUp",
        )
        if (!security.verifyKeypairIntegrity(wallet.publicKeyB58,
                c.walletAddress.ifBlank { wallet.publicKeyB58 })) {
            onLog("🛑 Keypair integrity failure — top-up aborted", ts.mint)
            return
        }

        // V5.9.756 — Emergent CRITICAL ticket. liveTopUp was the bypass route:
        // SPARTA / Thucydides / CHING landed live via this path because it
        // routes through tryPumpPortalBuy directly without a safety re-check.
        // A top-up is a fresh live tx on the same mint — it MUST pass the
        // same admission gate as a fresh buy. Same mint can degrade between
        // entry and top-up (LP pulled, dev dumps, freeze authority enabled).
        run {
            val decision = com.lifecyclebot.engine.sell.LiveBuyAdmissionGate.requireApprovedLiveBuy(
                ts = ts,
                callSite = "liveTopUp",
                onLog = onLog,
                onNotify = onNotify,
            )
            if (decision is com.lifecyclebot.engine.sell.LiveBuyAdmissionGate.Decision.Blocked) {
                onLog("🛡 LIVE TOP-UP BLOCKED [${ts.symbol}]: ${'$'}{decision.reasonCode}", ts.mint)
                return
            }
        }
        // V5.9.777 — EMERGENT MEME-ONLY: EXEC_LIVE_ATTEMPT counter wiring on
        // the second live-buy entrypoint (top-ups). Without this the operator
        // sees EXEC=0 even though tryPumpPortalBuy lands a real tx.
        try {
            ForensicLogger.exec(
                "LIVE_BUY_ATTEMPT",
                ts.symbol,
                "mint=${ts.mint.take(10)} sol=${"%.4f".format(sol)} src=liveTopUp",
            )
            ForensicLogger.lifecycle(
                "MEME_LIVE_EXEC_ENTRY",
                "mint=${ts.mint.take(10)} symbol=${ts.symbol} sol=${"%.4f".format(sol)} callSite=liveTopUp",
            )
        } catch (_: Throwable) {}

        val lamports = (sol * 1_000_000_000L).toLong()
        val tradeKey = LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis())
        val pos = ts.position
        try {
            // V5.9.603 — live top-ups must be wallet-delta verified before
            // local qty/cost is inflated. Otherwise a confirmed tx with no
            // token arrival creates a fake larger bag and corrupts PnL/exits.
            val preTopUpQty = try { wallet.getTokenAccountsWithDecimalsBounded()[ts.mint]?.first ?: pos.qtyToken } catch (_: Throwable) { pos.qtyToken }
            // V5.9.495 — PUMP-FIRST routing for top-ups (add-to-position).
            // Same universal-auto routing the entry/exit ladder uses.
            val pumpTopUpPlan = recalcBuyPlanForProcessor(
                ts = ts,
                wallet = wallet,
                processor = "PUMPPORTAL_TOP_UP",
                requestedSol = sol,
                priorityFeeSol = 0.0001,
                jitoTipLamports = effectiveJitoTipLamports(c, urgent = false),
                tradeKey = tradeKey,
                traderTag = "MEME",
            )
            val ppResult = if (pumpTopUpPlan == null) null else tryPumpPortalBuy(
                ts = ts,
                wallet = wallet,
                solAmount = pumpTopUpPlan.solAmount,
                slipPct = 10,
                priorityFeeSol = 0.0001,
                useJito = c.jitoEnabled,
                jitoTipLamports = effectiveJitoTipLamports(c, urgent = false),
                tradeKey = tradeKey,
                traderTag = "MEME",
            )

            val price  = getActualPrice(ts)
            val sig: String
            val newQty: Double
            if (ppResult != null) {
                sig = ppResult.first
                newQty = ppResult.second
                onLog("🔺 LIVE TOP-UP (PUMP-FIRST) #${pos.topUpCount + 1}: ${ts.symbol} | sig=${sig.take(16)}…", ts.mint)
            } else {
                val jupiterTopUpPlan = recalcBuyPlanForProcessor(
                    ts = ts,
                    wallet = wallet,
                    processor = "JUPITER_ULTRA_METIS_TOP_UP",
                    requestedSol = sol,
                    priorityFeeSol = 0.0,
                    jitoTipLamports = effectiveJitoTipLamports(c, urgent = false),
                    tradeKey = tradeKey,
                    traderTag = "MEME",
                ) ?: return
                val quote  = getQuoteWithSlippageGuard(JupiterApi.SOL_MINT, ts.mint,
                                                        jupiterTopUpPlan.lamports, c.slippageBps, jupiterTopUpPlan.solAmount)
                val qGuard = security.validateQuote(quote, isBuy = true, inputSol = jupiterTopUpPlan.solAmount)
                if (qGuard is GuardResult.Block) {
                    onLog("🚫 Top-up quote rejected: ${qGuard.reason}", ts.mint); return
                }
                val txResult = buildTxWithRetry(
                        quote, wallet.publicKeyB58,
                        senderTipLamports = effectiveJitoTipLamports(c, urgent = false),
                    )
                security.enforceSignDelay()

                val useJito = c.jitoEnabled && !quote.isUltra
                val jitoTip = effectiveJitoTipLamports(c, urgent = false)
                val ultraReqId = if (quote.isUltra) txResult.requestId else null

                if (quote.isUltra) {
                    onLog("🚀 Broadcasting top-up via Jupiter Ultra…", ts.mint)
                } else {
                    onLog("Broadcasting top-up tx…", ts.mint)
                }
                sig = wallet.signSendAndConfirm(txResult.txBase64, useJito, jitoTip, ultraReqId, c.jupiterApiKey, txResult.isRfqRoute, txResult.senderCompatible)
                newQty = rawTokenAmountToUiAmount(ts, quote.outAmount, solAmount = jupiterTopUpPlan.solAmount, priceUsd = price)
            }

            val verifiedDelta = try {
                var delta = 0.0
                for (attempt in 0 until 5) {
                    if (attempt > 0) Thread.sleep(2_000)
                    val cur = wallet.getTokenAccountsWithDecimalsBounded()[ts.mint]?.first ?: 0.0
                    delta = (cur - preTopUpQty).coerceAtLeast(0.0)
                    if (delta > 0.0) break
                }
                delta
            } catch (_: Throwable) { 0.0 }

            val effectiveNewQty = if (verifiedDelta > 0.0) verifiedDelta else 0.0
            if (effectiveNewQty <= 0.0) {
                LiveTradeLogStore.log(
                    tradeKey, ts.mint, ts.symbol, "BUY",
                    LiveTradeLogStore.Phase.BUY_FAILED,
                    "⚠️ TOP-UP TX confirmed but wallet token delta not verified — local position NOT inflated",
                    sig = sig, solAmount = sol, traderTag = "MEME",
                )
                onLog("⚠️ LIVE TOP-UP not credited: tx confirmed but token delta not verified", ts.mint)
                return
            }

            ts.position = pos.copy(
                qtyToken       = pos.qtyToken + effectiveNewQty,
                entryPrice     = (pos.costSol + sol) / (pos.qtyToken + effectiveNewQty),
                costSol        = pos.costSol + sol,
                topUpCount     = pos.topUpCount + 1,
                topUpCostSol   = pos.topUpCostSol + sol,
                lastTopUpTime  = System.currentTimeMillis(),
                lastTopUpPrice = price,
            )

            val gainPct = pct(pos.entryPrice, price)
            val trade   = Trade("BUY", "live", sol, price,
                                System.currentTimeMillis(), "top_up_${pos.topUpCount + 1}",
                                sig = sig)
            recordTrade(ts, trade)
            security.recordTrade(trade)
            onLog("LIVE TOP-UP #${pos.topUpCount + 1} @ ${price.fmt()} | " +
                  "${sol.fmt(4)} SOL | +${gainPct.toInt()}% gain | sig=${sig.take(16)}…",
                  ts.mint)
            onNotify("🔺 Live Top-Up #${pos.topUpCount + 1}",
                     "${ts.symbol}  +${gainPct.toInt()}%  ${sol.fmt(3)} SOL",
                     com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
        } catch (e: Exception) {
            onLog("Live top-up FAILED: ${security.sanitiseForLog(e.message ?: "unknown")}", ts.mint)
        }
    }

    // ── buy ───────────────────────────────────────────────────────────

    /**
     * V5.9.1475 (spec item 1/2) — CANONICAL OPEN PREDICATE.
     * doBuy/paperBuy/liveBuy return Unit and have many bail points (LLM veto,
     * PAPER_BUY_BLOCKED_FINALITY, route blocks). Callers historically assumed
     * success after the call returned, which let a BLOCKED/DEFERRED finality
     * still report success=true → stub MEME_EXECUTOR_DONE, fake OPENED hooks,
     * and canonical-learning poisoning. This is the single source of truth a
     * caller checks AFTER doBuy to know whether a real open was actually
     * committed. Mirrors the existing sub-trader predicate (qty>0 || pendingVerify
     * || isOpen): paper open sets qtyToken>0/isOpen; live open sets pendingVerify.
     * A blocked-finality paper buy sets none → returns false.
     */
    fun positionDidOpen(ts: TokenState): Boolean =
        ts.position.qtyToken > 0.0 || ts.position.pendingVerify || ts.position.isOpen

    private fun buyPhase(label: String) {
        try { PipelineHealthCollector.labelInc(label) } catch (_: Throwable) {}
    }

    private fun livePreAttemptHardReject(ts: TokenState, sol: Double, reason: String, detail: String = "") {
        val taxonomy = try { RejectTaxonomy.classify(reason, TradeAuthorizer.BlockLevel.HARD) } catch (_: Throwable) { null }
        ChokeReliefBus.launch("EXECUTOR_PREATTEMPT_REJECT_TAXONOMY_4428", ts.mint) {
            try { if (taxonomy != null) RejectTaxonomyLedger.record(taxonomy, "EXECUTOR_LIVE", reason) } catch (_: Throwable) {}
            try {
                ForensicLogger.lifecycle(
                    "LIVE_PREATTEMPT_HARD_REJECT",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} sol=${"%.4f".format(sol)} reason=$reason ${detail.take(160)} taxonomy=${taxonomy?.category?.name ?: "UNKNOWN"} ledger=RejectTaxonomyLedger".trim(),
                )
                PipelineHealthCollector.labelInc("LIVE_PREATTEMPT_HARD_REJECT_$reason")
                if (taxonomy != null) PipelineHealthCollector.labelInc("EXECUTOR_PREATTEMPT_REJECT_TAXONOMY_4428_${taxonomy.category.name}")
            } catch (_: Throwable) {}
        }
        emitLiveBuyFail(ts, sol, reason, detail)
    }

    private fun liveAdvisoryNotTerminal(ts: TokenState, label: String, detail: String = "") {
        try {
            ForensicLogger.lifecycle(
                "LIVE_ADVISORY_NOT_TERMINAL",
                "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$label ${detail.take(160)} action=continue_to_live_buy",
            )
