    private fun liveBuyDeferred(ts: TokenState, sol: Double, reason: String, detail: String = "") {
        val taxonomy = try { RejectTaxonomy.classify(reason, null) } catch (_: Throwable) { null }
        ChokeReliefBus.launch("EXECUTOR_DEFERRED_BUY_TAXONOMY_4433", ts.mint) {
            try { if (taxonomy != null) RejectTaxonomyLedger.record(taxonomy, "EXECUTOR_DEFERRED", reason) } catch (_: Throwable) {}
            try {
                ForensicLogger.exec(
                    "LIVE_BUY_DEFERRED",
                    ts.symbol,
                    "mint=${ts.mint.take(10)} sol=${"%.4f".format(sol)} reason=$reason ${detail.take(140)} taxonomy=${taxonomy?.category?.name ?: "UNKNOWN"} ledger=RejectTaxonomyLedger".trim(),
                )
                ForensicLogger.lifecycle(
                    "LIVE_BUY_DEFERRED_NON_TERMINAL",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason ${detail.take(160)} no_buy_failed=true no_backoff=true taxonomy=${taxonomy?.category?.name ?: "UNKNOWN"}",
                )
                PipelineHealthCollector.labelInc("LIVE_BUY_DEFERRED_$reason")
                PipelineHealthCollector.labelInc("ENTRY_SUPPRESSOR_$reason")
                if (taxonomy != null) PipelineHealthCollector.labelInc("EXECUTOR_DEFERRED_BUY_TAXONOMY_4433_${taxonomy.category.name}")
            } catch (_: Throwable) {}
        }
    }

    private fun emitLiveBuyFail(ts: TokenState, sol: Double, reason: String, detail: String = "") {
        try {
            val r = reason.uppercase()
            when {
                r.contains("FINALITY") || r.contains("WATCH") -> buyPhase("BUY_FAILED_FINALITY")
                r.contains("STALE") || r.contains("TICKET") || r.contains("TOKEN_STATE_CHANGED") -> buyPhase("BUY_FAILED_STALE_TICKET")
                r.contains("QUOTE") || r.contains("ROUTE") || r.contains("PROVIDER") || r.contains("SWAP") -> buyPhase("BUY_FAILED_ROUTE")
                r.contains("SAFETY") || r.contains("BLACKLIST") || r.contains("RUG") || r.contains("WRONG_TARGET") -> buyPhase("BUY_FAILED_SAFETY")
            }
            ForensicLogger.exec(
                "LIVE_BUY_FAIL",
                ts.symbol,
                "mint=${ts.mint.take(10)} sol=${"%.4f".format(sol)} reason=$reason ${detail.take(140)}".trim(),
            )
            com.lifecyclebot.engine.PipelineHealthCollector.labelInc("LIVE_BUY_FAIL_$reason")
        } catch (_: Throwable) {}
        try {
            LiveTradeLogStore.log(
                LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                ts.mint, ts.symbol, "BUY", LiveTradeLogStore.Phase.BUY_FAILED,
                "LIVE_BUY_FAIL_TELEMETRY reason=$reason ${detail.take(140)}".trim(),
                solAmount = sol,
                traderTag = "MEME",
            )
            PipelineHealthCollector.labelInc("LIVE_TELEMETRY_ROW_BUY_FAIL")
        } catch (_: Throwable) {}
    }

    internal fun doBuy(ts: TokenState, sol: Double, score: Double,
                      wallet: SolanaWallet?, walletSol: Double,
                      identity: TradeIdentity? = null,
                      quality: String = "C",
                      skipGraduated: Boolean = false) {
        val tradeId = identity ?: TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
        // V5.0.4578 — SOURCE FIX for live INVALID_SCORE floods. Runtime 4575
        // showed 26/30 live BUY failures as INVALID_SCORE even though candidates
        // had already passed intake/lane/FDG. That means a caller sentinel
        // (-1/NaN) leaked into doBuy/liveBuy, not that the token was invalid.
        // Normalize once at the executor spine using the TokenState entry score
        // before advisors/sizers/liveBuy consume it. True no-score candidates get
        // a neutral bootstrap score instead of a hard veto; downstream quality,
        // safety, RR, route and cost gates still decide execution.
        val execScore4578 = when {
            score.isFinite() && score >= 0.0 -> score.coerceIn(0.0, 100.0)
            ts.entryScore.isFinite() && ts.entryScore > 0.0 -> ts.entryScore.coerceIn(0.0, 100.0)
            else -> 50.0
        }
        if (execScore4578 != score) {
            try {
                ForensicLogger.lifecycle("LIVE_BUY_SCORE_NORMALIZED_4578", "mint=${ts.mint.take(10)} symbol=${ts.symbol} raw=$score entryScore=${ts.entryScore} normalized=$execScore4578 action=continue_no_invalid_score_veto")
                PipelineHealthCollector.labelInc("LIVE_BUY_SCORE_NORMALIZED_4578")
            } catch (_: Throwable) {}
        }
        val score = execScore4578

        // V5.0.4189 — Sentience pre-trade is ADVISORY ONLY.
        // Cached LLM vetoes were able to return before any live buy, violating the
        // no-hot-path-LLM/no-new-hard-veto doctrine and parking otherwise-executable
        // meme flow. Keep the signal for learning/telemetry; never let it kill entry.
        val sentienceAllowed4189 = try {
            com.lifecyclebot.engine.SentienceHooks.preTradeVeto(
                symbol = ts.symbol, score = score.toInt(), conf = quality.hashCode().rem(100),
                reasons = "src=${ts.source} liq=${ts.lastLiquidityUsd.toInt()}")
        } catch (_: Throwable) { true }
        if (!sentienceAllowed4189) {
            try {
                onLog("🧠 LLM SENTIENCE ADVISORY: ${ts.symbol} veto suggested but ignored for live-throughput doctrine", tradeId.mint)
                com.lifecyclebot.engine.PipelineHealthCollector.labelInc("SENTIENCE_VETO_ADVISORY_4189")
                com.lifecyclebot.engine.ForensicLogger.lifecycle("SENTIENCE_VETO_ADVISORY_4189", "mint=${ts.mint.take(10)} symbol=${ts.symbol} source=${ts.source.take(80)} action=ignored_no_hard_veto")
            } catch (_: Throwable) {}
        }

        // V5.0.4189 — Emergent LLM validation is advisory only. No external LLM
        // may return before a live buy on the hot path; hard safety remains in
        // deterministic gates. Calls are still bounded/fail-open and only feed logs.
        try {
            if (com.lifecyclebot.network.EmergentLlmClient.isEnabled()) {
                val recentPnl = try {
                    val s = com.lifecyclebot.engine.TradeHistoryStore.getStats()
                    // Use 24h win-rate as the "recent performance %" the LLM
                    // sees — directly comparable across sessions, and the
                    // validator prompt uses it as a sanity check on whether
                    // we're on a hot streak vs a losing run.
                    s.winRate24h.toDouble()
                } catch (_: Exception) { 50.0 }
                val verdict = com.lifecyclebot.network.EmergentLlmClient.validateTradeSignal(
                    symbol      = ts.symbol,
                    side        = "BUY",
