        val winnerMaxBoost = if (RuntimeModeAuthority.isLive() && laneEvMult > 1.0) 2.35 else 1.75
        // V5.0.4129 — ABSOLUTE FLOOR + PATTERN GOLDEN GOOSE SIZE OVERRIDE.
