                    )
                    val pendingLiveCommit = try {
                        !ts.position.isPaperPosition && ts.position.pendingVerify && ts.position.qtyToken > 0.0 && ts.position.costSol > 0.0
                    } catch (_: Throwable) { false }
                    if (liveOpened || positionDidOpen(ts) || pendingLiveCommit) {
                        WalletPositionLock.recordOpen("Meme", liveSol)
                        try {
                            ForensicLogger.lifecycle(
                                if (pendingLiveCommit && !positionDidOpen(ts)) "LIVE_BUY_PENDING_COMMIT_ACCEPTED" else "LIVE_OPEN_COMMITTED_LOCK_RECORDED",
                                "symbol=${ts.symbol} mint=${ts.mint.take(10)} size=${liveSol.fmt(4)} result=$liveOpened positionOpen=${positionDidOpen(ts)} pendingLiveCommit=$pendingLiveCommit",
                            )
                            if (pendingLiveCommit && !positionDidOpen(ts)) PipelineHealthCollector.labelInc("LIVE_BUY_PENDING_COMMIT_ACCEPTED")
                        } catch (_: Throwable) {}
                    } else {
                        // V5.0.3900 — do not double-count the outer no-open observation
                        // as the primary LIVE_BUY_FAIL reason. liveBuy() already emits the
                        // real terminal reason (FINALITY_BLOCK, route throw, admission gate,
                        // quote/sim failure, etc.). The old outer fail dominated reports as
                        // NO_OPEN_COMMITTED_AFTER_LIVEBUY=170 and hid the true source.
                        try {
                            ForensicLogger.lifecycle(
                                "NO_OPEN_COMMITTED_LOCK_NOT_RECORDED",
                                "symbol=${ts.symbol} mint=${ts.mint.take(10)} size=${liveSol.fmt(4)} result=$liveOpened positionOpen=${positionDidOpen(ts)} pendingVerify=${ts.position.pendingVerify} action=observe_only_inner_reason_authority",
                            )
                            PipelineHealthCollector.labelInc("NO_OPEN_COMMITTED_AFTER_LIVEBUY_OBSERVED")
                        } catch (_: Throwable) {}
                    }
                    
                    // V5.0.6073 — SHADOW ALWAYS-ON: no toggle gate.
                    runShadowPaperBuy(ts, effSol, score, quality, "parallel", safeWallet, walletSol)
                }
            }
        }
    }
    
    private fun runShadowPaperBuy(ts: TokenState, sol: Double, score: Double, 
                                   quality: String, reason: String,
                                   wallet: SolanaWallet? = null, walletSol: Double = 0.0) {
        try {
            val isMoonshot = cfg().moonshotOverrideEnabled &&
                             score >= 85 && 
                             quality in listOf("A", "B") && 
                             ts.lastLiquidityUsd >= 5000 &&
                             ts.meta.pressScore >= 70
            
            if (isMoonshot && wallet != null && walletSol > 0 && !isPaperRT()) {
                try { ExecutionRouteGuard.recordShadowRouteAllowed() } catch (_: Throwable) {}
                // V5.9.779 — EMERGENT MEME-ONLY: shadow → live shortcut
                // must still pass the canonical LIVE buy chain. We hand
                // off to liveBuy() which now enforces:
                //   - SafetyReadyGate (V5.9.776 sync first-check)
                //   - FinalDecisionGate / LiveBuyAdmissionGate
                //   - MEME_LIVE_BUY_MUTEX (V5.9.778)
                //   - EXEC_LIVE_ATTEMPT counter + MEME_LIVE_EXEC_ENTRY
                //   - HostWalletTokenTracker upsert on confirmation
                // No direct PumpPortal/Jupiter call from this path —
                // liveBuy() is the single executor entry point.
                if (walletSol >= sol * 1.1) {
                    try {
                        ForensicLogger.lifecycle(
                            "SHADOW_TO_LIVE_HANDOFF",
                            "mint=${ts.mint.take(10)} symbol=${ts.symbol} score=${score.toInt()} quality=$quality sol=${"%.4f".format(sol)}",
                        )
                    } catch (_: Throwable) {}
                    onLog("🌙🚀 MOONSHOT in shadow mode! Score=${score.toInt()} Quality=$quality → handing off to liveBuy() (full FDG chain).", ts.mint)
                    onNotify("🌙 Shadow → Live!", "${ts.symbol} moonshot detected!", 
                        com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
                    sounds?.playMilestone(100.0)
                    
                    val tradeId = TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
                    val shadowLiveLane = resolveExecutionLane(ts, tradeId).ifBlank { "MOONSHOT" }
                    liveBuy(
                        ts = ts,
                        sol = sol,
                        score = score,
                        wallet = wallet,
                        walletSol = walletSol,
                        identity = tradeId,
                        quality = quality,
                        layerTag = shadowLiveLane.takeIf { it.isNotBlank() && it != "STANDARD" } ?: "MOONSHOT",
                        layerTagEmoji = "🚀",
                    )
                    return
                }
            }
            
            if (shadowPositions.size >= MAX_SHADOW_POSITIONS) {
                val oldest = shadowPositions.values.minByOrNull { it.entryTime }
                oldest?.let { shadowPositions.remove(it.mint) }
            }
            
            if (shadowPositions.containsKey(ts.mint)) return
            
            val price = getActualPrice(ts)
            if (price <= 0) return
            
            val shadowPos = ShadowPosition(
                mint = ts.mint,
                symbol = ts.symbol,
                entryPrice = price,
                entrySol = sol,
                entryTime = System.currentTimeMillis(),
                quality = quality,
                entryScore = score,
                source = ts.source,
            )
            shadowPositions[ts.mint] = shadowPos
            
            onLog("👻 SHADOW BUY: ${ts.symbol} | $reason | ${sol.toString().take(6)} SOL @ ${price.toString().take(8)} | tracking=${shadowPositions.size}", ts.mint)
            
        } catch (e: Exception) {
            ErrorLogger.debug("Executor", "Shadow paper buy failed: ${e.message}")
        }
    }
    
    fun checkShadowPositions(tokenStates: Map<String, TokenState>) {
        // V5.0.6073 — SHADOW ALWAYS-ON: gate removed (was toggle + live-only).
        val toRemove = mutableListOf<String>()
        val stopLossPct = cfg().stopLossPct
        val takeProfitPct = 50.0
        
        for ((mint, shadow) in shadowPositions) {
            val ts = tokenStates[mint] ?: continue
            val currentPrice = getActualPrice(ts)
            if (currentPrice <= 0) continue
            
            val pnlPct = OpenPnlSanity.inspect(shadow.entryPrice, currentPrice, context = "Executor.shadow_position_6038/${shadow.mint.take(8)}", emit = true).takeIf { it.ok }?.pnlPct ?: 0.0
            val holdTimeMin = (System.currentTimeMillis() - shadow.entryTime) / 60000
            
            val shouldExit = when {
                pnlPct <= -stopLossPct -> "stop_loss"
                pnlPct >= takeProfitPct -> "take_profit"
                holdTimeMin >= 30 -> "timeout_30min"
                else -> null
            }
            
            if (shouldExit != null) {
                val isWin = pnlPct >= 1.0  // V5.9.225: unified 1% threshold
                val pnlSol = pnlPct * shadow.entrySol / 100
                val shadowHoldMins = (System.currentTimeMillis() - shadow.entryTime) / 60_000.0
                
                brain?.learnFromTrade(
                    isWin = isWin,
                    phase = "shadow_${shadow.quality}",
                    emaFan = "FLAT",
                    source = shadow.source,
                    pnlPct = pnlPct,
                    mint = shadow.mint,
                    rugcheckScore = 50,
                    buyPressure = 50.0,
                    topHolderPct = 10.0,
                    liquidityUsd = 10000.0,
                    isLiveTrade = false,
                    approvalClass = "PAPER_EXPLORATION",
                    holdTimeMinutes = shadowHoldMins,
                    maxGainPct = pnlPct.coerceAtLeast(0.0),
                    exitReason = shouldExit,
                    tokenAgeMinutes = 0.0,
                )
                
                brain?.learnThreshold(
                    isWin = isWin,
                    rugcheckScore = 50,
                    buyPressure = 50.0,
                    topHolderPct = 10.0,
                    liquidityUsd = 10000.0,
                    pnlPct = pnlPct,
                )
                
                val emoji = if (isWin) "✅" else "❌"
                onLog("👻 SHADOW EXIT: ${shadow.symbol} | $shouldExit | ${pnlPct.toInt()}% | ${pnlSol.toString().take(6)} SOL | $emoji ${if(isWin) "WIN" else "LOSS"} → LEARNING", mint)
                
                toRemove.add(mint)
            }
        }
        
        toRemove.forEach { shadowPositions.remove(it) }
    }


    private fun shouldSuppressPaperLearningEntry(
        ts: TokenState,
        score: Double,
        layerTag: String,
        identity: TradeIdentity?,
    ): String? {
        val lane = (layerTag.ifBlank { ts.position.tradingMode.ifBlank { identity?.source ?: ts.source } }).uppercase()
        val liq = ts.lastLiquidityUsd.takeIf { it.isFinite() } ?: 0.0
        val dangerBucket = lane.contains("DANGER") || lane.contains("RUG") || lane.contains("HARD_FLOOR")
        val familyStopLoss = try { MemeLossStreakGuard.blockedUntilMs(ts.mint) > System.currentTimeMillis() } catch (_: Throwable) { false }
        return when {
            lane.contains("BLUECHIP") && (score < 70.0 || liq < 25_000.0) -> "BLUECHIP score=${score.toInt()} liq=${liq.toInt()} minScore=70 minLiq=25000"
            lane.contains("EXPRESS") && !dangerBucket && score < 11.0 -> "EXPRESS_S0_10 score=${score.toInt()} danger=$dangerBucket"
            lane.contains("SHITCOIN") && (score < 66.0 || liq < 3_000.0 || familyStopLoss) -> "SHITCOIN score=${score.toInt()} liq=${liq.toInt()} familyStopLoss=$familyStopLoss minScore=66 minLiq=3000"
            else -> null
        }
    }

    private fun buildTradePolicySnapshot(
        ts: TokenState,
        mode: String,
        lane: String,
        style: String,
        score: Double,
        plannedSol: Double,
        finalSol: Double,
        reasons: List<String> = emptyList(),
        extra: String = "",
    ): String {
        val safeLane = normalizeExecutionLane(lane).ifBlank { "STANDARD" }
        val safeStyle = style.ifBlank { safeLane }
        val scannerSource = ts.source.ifBlank { ts.tokenMap.sourceScanner.ifBlank { "UNKNOWN" } }
        val source = ts.lastPriceSource.ifBlank { scannerSource }
        val mult = if (plannedSol > 0.0) (finalSol / plannedSol).coerceIn(0.0, 50.0) else 1.0
        val reasonText = reasons.filter { it.isNotBlank() }.joinToString("|").take(240)
        return listOf(
            "v=4193",
            "mode=$mode",
            "lane=$safeLane",
            "style=$safeStyle",
            "scanner=$scannerSource",
            "source=$source",
            "score=${score.fmt(1)}",
            "planned=${plannedSol.fmt(4)}",
            "final=${finalSol.fmt(4)}",
            "sizeMult=${mult.fmt(3)}",
            "styleTp=${ts.styleTpMult.fmt(2)}",
            "styleHold=${ts.styleHoldMult.fmt(2)}",
            "liq=${ts.lastLiquidityUsd.toInt()}",
            "mcap=${ts.lastMcap.toInt()}",
            "reasons=$reasonText",
            extra.take(200),
        ).filter { it.isNotBlank() }.joinToString(";")
    }

    private fun hydrateMintEntryMarketSnapshotFromCache(ts: TokenState): Boolean {
        val ctx = try { com.lifecyclebot.AATEApp.appContextOrNull() } catch (_: Throwable) { null } ?: return false
        val cached = try { TokenMetaCache.get(ctx).lookup(ts.mint) } catch (_: Throwable) { null } ?: return false
        var changed = false
        if (ts.lastPrice <= 0.0 && cached.lastPrice > 0.0) { ts.lastPrice = cached.lastPrice; changed = true }
        if (ts.lastMcap <= 0.0 && cached.lastMcap > 0.0) { ts.lastMcap = cached.lastMcap; changed = true }
        if (ts.lastLiquidityUsd <= 0.0 && cached.lastLiquidityUsd > 0.0) { ts.lastLiquidityUsd = cached.lastLiquidityUsd; changed = true }
        if (ts.lastFdv <= 0.0 && cached.lastFdv > 0.0) { ts.lastFdv = cached.lastFdv; changed = true }
        if (ts.lastPriceDex.isBlank() && cached.lastPriceDex.isNotBlank()) { ts.lastPriceDex = cached.lastPriceDex; changed = true }
        val cachedPool = cached.lastPricePoolAddr.ifBlank { cached.pairAddress }
        if (ts.lastPricePoolAddr.isBlank() && cachedPool.isNotBlank()) { ts.lastPricePoolAddr = cachedPool; changed = true }
        if (ts.lastPriceSource.isBlank()) {
            when {
                cached.lastPriceSource.isNotBlank() -> { ts.lastPriceSource = cached.lastPriceSource; changed = true }
                cached.lastPrice > 0.0 && cachedPool.isNotBlank() -> { ts.lastPriceSource = "TOKEN_META_CACHE"; changed = true }
            }
        }
        if (changed) {
            ts.lastPriceUpdate = System.currentTimeMillis()
            try {
                ForensicLogger.lifecycle(
                    "MINT_ENTRY_MARKET_SNAPSHOT_CACHE_HYDRATED",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} price=${ts.lastPrice} mcap=${ts.lastMcap} liq=${ts.lastLiquidityUsd} pool=${ts.lastPricePoolAddr.take(16)} source=${ts.lastPriceSource} dex=${ts.lastPriceDex}"
                )
                PipelineHealthCollector.labelInc("MINT_ENTRY_MARKET_SNAPSHOT_CACHE_HYDRATED")
            } catch (_: Throwable) {}
        }
        return changed
    }

    private fun mintEntryMarketSnapshot(ts: TokenState): MintEntryMarketSnapshot? {
        if (ts.lastPrice <= 0.0 || ts.lastLiquidityUsd <= 0.0 || ts.lastPricePoolAddr.isBlank() || ts.lastPriceSource.isBlank()) {
            hydrateMintEntryMarketSnapshotFromCache(ts)
        }
        val price = ts.lastPrice.takeIf { it.isFinite() && it > 0.0 }
            ?: ts.history.lastOrNull { it.priceUsd.isFinite() && it.priceUsd > 0.0 }?.priceUsd
            ?: return null
        val mcap = ts.lastMcap.takeIf { it.isFinite() && it > 0.0 }
            ?: ts.history.lastOrNull { it.marketCap.isFinite() && it.marketCap > 0.0 }?.marketCap
            ?: ts.lastFdv.takeIf { it.isFinite() && it > 0.0 }
            ?: 0.0
        val liq = ts.lastLiquidityUsd.takeIf { it.isFinite() && it > 0.0 } ?: return null
        val source = ts.lastPriceSource.ifBlank { ts.source.ifBlank { "UNKNOWN" } }
        val rawPool = ts.lastPricePoolAddr.ifBlank { ts.pairAddress }
        // V5.0.3983 — do not let optional pool metadata kill real live entries.
        // A mint-level Jupiter route can still execute with price+liquidity+source;
        // the eventual tx/quote is the hard route proof. Stamp an explicit sentinel
        // instead of leaving the field blank so journal/persistence can distinguish
        // "mint route, pool pending" from a lost field.
        val pool = rawPool.ifBlank { "MINT_ROUTE:${ts.mint.take(12)}" }
        val dex = ts.lastPriceDex.ifBlank { if (rawPool.isBlank()) "MINT_ROUTE" else "UNKNOWN" }
        val snap = MintEntryMarketSnapshot(price, mcap, liq, pool, source, dex)
        if (rawPool.isBlank() && snap.valid) {
            try {
                ForensicLogger.lifecycle("MINT_ENTRY_MARKET_SNAPSHOT_POOL_SENTINEL", "mint=${ts.mint.take(10)} symbol=${ts.symbol} price=$price liq=$liq source=$source action=pool_metadata_optional")
                PipelineHealthCollector.labelInc("MINT_ENTRY_MARKET_SNAPSHOT_POOL_SENTINEL")
            } catch (_: Throwable) {}
        }
        return snap.takeIf { it.valid }
    }

    private fun persistMintEntryMarketSnapshot(ts: TokenState, snap: MintEntryMarketSnapshot, reason: String) {
        ts.lastPrice = snap.priceUsd
        if (snap.marketCapUsd > 0.0) ts.lastMcap = snap.marketCapUsd
        ts.lastLiquidityUsd = snap.liquidityUsd
        ts.lastPricePoolAddr = snap.poolAddress
        ts.lastPriceSource = snap.priceSource
        ts.lastPriceDex = snap.dex
        ts.lastPriceUpdate = snap.capturedAtMs
        try {
            val ctx = com.lifecyclebot.AATEApp.appContextOrNull()
            if (ctx != null) TokenMetaCache.get(ctx).register(
                mint = ts.mint,
                symbol = ts.symbol,
                name = ts.name,
                pairAddress = ts.pairAddress.ifBlank { snap.poolAddress },
                pairUrl = ts.pairUrl,
                logoUrl = ts.logoUrl,
                lastPriceSource = snap.priceSource,
                lastPricePoolAddr = snap.poolAddress,
                lastPriceDex = snap.dex,
                lastPrice = snap.priceUsd,
                lastMcap = snap.marketCapUsd.takeIf { it > 0.0 } ?: ts.lastMcap,
                lastLiquidityUsd = snap.liquidityUsd,
                lastFdv = ts.lastFdv.takeIf { it > 0.0 } ?: snap.marketCapUsd,
            )
        } catch (_: Throwable) {}
        try {
            ForensicLogger.lifecycle("MINT_ENTRY_MARKET_SNAPSHOT_STORED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason price=${snap.priceUsd} mcap=${snap.marketCapUsd} liq=${snap.liquidityUsd} pool=${snap.poolAddress.take(16)} source=${snap.priceSource} dex=${snap.dex}")
            PipelineHealthCollector.labelInc("MINT_ENTRY_MARKET_SNAPSHOT_STORED")
            if (snap.marketCapUsd <= 0.0) PipelineHealthCollector.labelInc("MINT_ENTRY_MARKET_SNAPSHOT_MCAP_UNKNOWN")
        } catch (_: Throwable) {}
    }

    private fun requireMintEntryMarketSnapshot(ts: TokenState, reason: String): MintEntryMarketSnapshot? {
        val snap = mintEntryMarketSnapshot(ts)
        if (snap != null) { persistMintEntryMarketSnapshot(ts, snap, reason); return snap }
        try {
            ForensicLogger.lifecycle("ENTRY_MARKET_SNAPSHOT_MISSING_DEFERRED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason price=${ts.lastPrice} mcap=${ts.lastMcap} liq=${ts.lastLiquidityUsd} pool=${ts.lastPricePoolAddr.ifBlank { ts.pairAddress }.take(16)} source=${ts.lastPriceSource.ifBlank { ts.source }} action=no_entry_no_fake_basis")
            ForensicLogger.lifecycle("LIVE_ENTRY_DECISION", "mint=${ts.mint.take(10)} symbol=${ts.symbol} originalLane=UNKNOWN originalStyle=UNKNOWN finalLane=LANE_PROOF_DEFER finalStyle=BASIS_PROOF_WAIT score=0 scoreBand=UNKNOWN sizeSol=0 sizeMultiplier=0 expectedEdgePct=0 requiredEdgePct=999 basisTrusted=false routeTrusted=false holderProof=false rugProof=false liquidityUsd=${ts.lastLiquidityUsd.toInt()} providerProof=${ts.lastPriceSource.isNotBlank()} pivotApplied=true pivotReasons=BASIS_MISSING decision=DEFER")
            PipelineHealthCollector.labelInc("ENTRY_MARKET_SNAPSHOT_MISSING_DEFERRED")
            PipelineHealthCollector.labelInc("LIVE_ENTRY_DECISION")
        } catch (_: Throwable) {}
        return null
    }

    fun paperBuy(ts: TokenState, sol: Double, score: Double, identity: TradeIdentity? = null, 
                 quality: String = "C", skipGraduated: Boolean = false,
                 wallet: SolanaWallet? = null, walletSol: Double = 0.0,
                 layerTag: String = "",            // V5.9.386 — override BUY trade tradingMode for sub-trader journal tagging
                 layerTagEmoji: String = "",
                 finalityPrechecked: Boolean = false,
                 attemptId: String = "",     // V5.9.386 — matching emoji for the sub-trader tag
                 debitPaperWallet: Boolean = true,
                 maxPaperTradeSolOverride: Double? = null) {
        try { PipelineHealthCollector.labelInc("PAPER_BUY_ATTEMPT") } catch (_: Throwable) {}

        fun markPaperBuyNotOpened(reason: String) {
            try { PipelineHealthCollector.labelInc("PAPER_BUY_NOT_OPENED") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PAPER_BUY_NOT_OPENED_$reason") } catch (_: Throwable) {}
            try { FinalExecutionPermit.releaseExecution(ts.mint) } catch (_: Throwable) {}
            try { LaneExecutionCoordinator.releaseIfPrimary(ts.mint, layerTag.ifBlank { ts.position.tradingMode.ifBlank { "PAPER" } }, "BUY_NOT_OPENED_$reason") } catch (_: Throwable) {}
            try { ForensicLogger.lifecycle("PAPER_BUY_NOT_OPENED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} layer=$layerTag reason=$reason attemptId=$attemptId") } catch (_: Throwable) {}
        }

        if (sol <= 0 || sol.isNaN() || sol.isInfinite()) {
            ErrorLogger.warn("Executor", "[EXECUTION/INVALID] Paper buy skipped: invalid size $sol for ${ts.symbol}")
            markPaperBuyNotOpened("INVALID_SIZE")
            return
        }
        if (ts.mint.isBlank() || ts.symbol.isBlank()) {
            ErrorLogger.warn("Executor", "[EXECUTION/INVALID] Paper buy skipped: empty mint/symbol")
            markPaperBuyNotOpened("EMPTY_MINT_OR_SYMBOL")
            return
        }
        if (score < 0 || score.isNaN()) {
            ErrorLogger.warn("Executor", "[EXECUTION/INVALID] Paper buy skipped: invalid score $score for ${ts.symbol}")
            markPaperBuyNotOpened("INVALID_SCORE")
            return
        }

        // V5.0.3928 — PAPER ADVISOR GATE. Operator: 'the entire learning
        // system is basically poisoned currently'. Paper trades that get
        // rugged feed the brain garbage signal-to-outcome pairs (token
        // had no holder data + rug-class characteristics → -100%), which
        // contaminates BotBrain pattern memory, EntryIntelligence weights,
        // and PatternAutoTuner phase/EMA buckets. Run the same advisor
        // chain as live so paper learning trains on the SAME filtered
        // token set live trades on. HardRugPreFilter, ProviderProofWalker
        // liquidity gate, MomentumPredictor, BotBrain learned thresholds,
        // FluidLearningAI floor, EntryIntelligence — all wired identically
        // to live so the learning data isn't contaminated by rug-class
        // outcomes that live wouldn't have taken either.
        val advisor = consultEntryAdvisors(ts, score, layerTag, isPaperMode = true)
        if (!advisor.first) {
            ErrorLogger.warn("Executor",
                "🛡️ PAPER_BUY_ADVISOR_BLOCK ${ts.symbol} layer=$layerTag reason=${advisor.second}")
            try {
                ForensicLogger.lifecycle("PAPER_BUY_ADVISOR_BLOCK",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} layer=$layerTag reason=${advisor.second}")
            } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PAPER_BUY_ADVISOR_BLOCK") } catch (_: Throwable) {}
            markPaperBuyNotOpened("ADVISOR_${advisor.second.substringBefore(':')}")
            return
        }
        shouldSuppressPaperLearningEntry(ts, score, layerTag, identity)?.let { why ->
            try { PipelineHealthCollector.labelInc("PAPER_LEARNING_QUALITY_SUPPRESSED") } catch (_: Throwable) {}
            try { ForensicLogger.lifecycle("PAPER_LEARNING_QUALITY_SUPPRESSED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} layer=$layerTag reason=$why") } catch (_: Throwable) {}
            ErrorLogger.debug("Executor", "🧪 PAPER_LEARNING_QUALITY_SUPPRESSED: ${ts.symbol} | $why")
            markPaperBuyNotOpened("QUALITY_SUPPRESSED")
            return
        }
        // V5.9.1129 — route authority must run before open authority for direct
        // paperBuy() callers. In LIVE mode with shadowPaperEnabled=true this is
        // a SHADOW paper route, not a mixed PAPER/LIVE mode violation. Keep this
        // before EXEC_OPEN_* finality so shadow paper remains a legal explicit mode
        // while ordinary live→paper fallback stays blocked below.
        val routeVerdict = ExecutionRouteGuard.requirePaperRoute(
            ts = ts,
            shadowEnabled = try { cfg().shadowPaperEnabled } catch (_: Throwable) { false },
        )
        if (!routeVerdict.allowed) {
            try {
                ForensicLogger.lifecycle(
                    "PAPER_BUY_IN_LIVE_MODE_BLOCKED",
                    "blocked=true symbol=${ts.symbol} mint=${ts.mint.take(10)} sol=$sol layer=$layerTag reason=${routeVerdict.reason}",
                )
                ForensicLogger.lifecycle(
                    "PAPER_POSITION_BLOCKED_IN_LIVE_MODE",
                    "symbol=${ts.symbol} mint=${ts.mint.take(10)} sol=$sol layer=$layerTag reason=${routeVerdict.reason}"
                )
            } catch (_: Throwable) {}
            ErrorLogger.warn("Executor", "🚫 PAPER_BUY_IN_LIVE_MODE_BLOCKED: ${ts.symbol} (sol=$sol) — ${routeVerdict.reason}")
            markPaperBuyNotOpened("LIVE_MODE_BLOCKED")
            return
        }
        val routeIsShadow = routeVerdict.route == ExecutionRouteGuard.Route.SHADOW

        if (!finalityPrechecked) {
            // V5.9.1331 — prefer the real lane (layerTag → position.tradingMode) and fall
            // back to "STANDARD" not "UNKNOWN" so finality/journal lane attribution is correct.
            val finalityLane = layerTag.ifBlank { ts.position.tradingMode.ifBlank { identity?.source?.takeIf { it.isNotBlank() } ?: "STANDARD" } }
            val executableOpen = ExecutableOpenGate.canOpenExecutablePosition(
                ts = ts,
                mode = if (routeIsShadow) "SHADOW" else "PAPER",
                lane = finalityLane,
                source = "Executor.paperBuy",
                attemptId = attemptId.ifBlank { ExecutableOpenGate.nextAttemptId(ts.mint, finalityLane) },
            )
            if (!executableOpen.allowed) {
                ErrorLogger.warn("Executor", "🚫 PAPER_BUY_BLOCKED_FINALITY: ${ts.symbol} | attemptId=${executableOpen.attemptId} | ${executableOpen.reason}")
                markPaperBuyNotOpened("FINALITY_BLOCKED")
                return
            }
        }

        // V5.9.801 — operator audit Fix D: WR recovery entry-size dampener.
        // When WR recovery is in MODERATE/AGGRESSIVE the bot is bleeding
        // and every entry is statistically more likely to be a loss.
        // Halving (AGGRESSIVE) or three-quartering (MODERATE) the position
        // size shrinks each loss proportionally while still collecting
        // training samples, so the bot can climb out of the deficit
        // without compounding it. FLUID/OFF bands are not touched.
        val wrSizeMult = try { WrRecoveryPartial.entrySizeMultiplier() } catch (_: Throwable) { 1.0 }
        @Suppress("NAME_SHADOWING")
        val sol = run {
            var finalSol = if (wrSizeMult < 1.0) {
                val damped = sol * wrSizeMult
                ErrorLogger.info("Executor", "🩹 WR_RECOVERY_SIZE_DAMP (paper): ${ts.symbol} | sol=${sol.fmt(4)} × ${"%.2f".format(wrSizeMult)} → ${damped.fmt(4)} (band=${WrRecoveryPartial.stateNow().band.name})")
                damped
            } else sol

            // V5.9.1131 — side-effect boundary paper cold-streak cap.
            // SmartSizer has its own cap, but 3098 proved several lane paths can
            // deliver 6-12 SOL directly into paperBuy(). Clamp at the last possible
            // point before wallet/journal mutation so no bypass can create outsized
            // paper losses during a cold WR regime.
            try {
                val stats = TradeHistoryStore.getStatsCached()
                val decisive = stats.totalWins + stats.totalLosses
                val wr = if (decisive > 0) stats.totalWins.toDouble() / decisive * 100.0 else 100.0
                val perf = SmartSizer.getPerformanceContext(walletSol.takeIf { it > 0.0 } ?: finalSol, decisive, isPaperMode = true)
                val coldCapPct = when {
                    decisive >= 25 && (perf.lossStreak >= 10 || wr < 10.0) -> 0.02
                    decisive >= 25 && (perf.lossStreak >= 6  || wr < 20.0) -> 0.035
                    decisive >= 25 && (perf.lossStreak >= 4  || wr < 30.0) -> 0.05
                    else -> 0.0
                }
                if (coldCapPct > 0.0) {
                    val baseWallet = walletSol.takeIf { it > 0.0 } ?: try { FluidLearning.getSimulatedBalance() } catch (_: Throwable) { finalSol }
                    val cap = maxOf(0.01, baseWallet * coldCapPct).coerceAtMost(1.0)
                    if (finalSol > cap) {
                        ErrorLogger.warn("Executor", "🧯 PAPER_BUY_COLD_CAP: ${ts.symbol} ${finalSol.fmt(4)} → ${cap.fmt(4)} SOL | wr=${wr.toInt()}% lossStreak=${perf.lossStreak} trades=$decisive")
                        try { ForensicLogger.lifecycle("PAPER_BUY_COLD_CAP", "symbol=${ts.symbol} mint=${ts.mint.take(10)} from=${finalSol.fmt(4)} to=${cap.fmt(4)} wr=${wr.toInt()} lossStreak=${perf.lossStreak} trades=$decisive") } catch (_: Throwable) {}
                        finalSol = cap
                    }
                }
            } catch (_: Throwable) {}
            clampPaperTradeSol(finalSol, ts.mint, ts.symbol, "paperBuy.pre_mutation", maxPaperTradeSolOverride)
        }
        if (sol <= 0.0) {
            try { ForensicLogger.lifecycle("PAPER_BUY_INVALID_SIZE_REJECTED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} requested=$sol") } catch (_: Throwable) {}
            markPaperBuyNotOpened("SIZE_CLAMP_ZERO")
            return
        }
        
        // V5.9.1586 — canonical EXEC accounting for paper simulator too.
        // TradeHistoryStore journal rows are outcomes; this is the actual executor
        // invocation boundary so the funnel no longer shows EXEC=0 with paper buys.
        try {
            ForensicLogger.exec(
                if (routeIsShadow) "SHADOW_PAPER_BUY" else "PAPER_BUY",
                ts.symbol,
                "mint=${ts.mint.take(10)} sol=${"%.4f".format(sol)} score=${"%.1f".format(score)} q=$quality src=paperBuy.entry",
            )
        } catch (_: Throwable) {}
        PipelineTracer.executorStart(ts.symbol, ts.mint, "PAPER", sol)

        // V5.9.771 — EMERGENT-MEME #4: hard guard against paper buys
        // in LIVE mode. Spec: "if (mode == LIVE && requestedExecutionMode
        // == PAPER && !shadowPaperEnabled) block PAPER_BUY_IN_LIVE_MODE".
        // The existing comment ("only reached when isPaperRT()==true")
        // is correct for the primary doBuy() path, but ~7 other call
        // sites in this file (lines 5279, 5387, 5448, 5542, 5632, etc.)
        // invoke paperBuy() directly from sub-trader fallback paths and
        // some of those wrappers did NOT re-check the global mode. This
        // single gate at the function entry is the canonical fence —
        // even if a future refactor reintroduces a leak, paper buys
        // cannot fire in live mode unless shadowPaperEnabled is on.
        //
        // V5.9.779 — EMERGENT MEME-ONLY: read from RuntimeModeAuthority
        // (atomic, no 2 s cache race) — same single source of truth used
        // by the LIVE buy paths. isPaperRT() is config INPUT only.
        if (routeIsShadow) {
            try {
                ForensicLogger.lifecycle(
                    "SHADOW_PAPER_BUY",
                    "symbol=${ts.symbol} mint=${ts.mint.take(10)} sol=$sol layer=$layerTag mode=SHADOW",
                )
            } catch (_: Throwable) {}
        }

        val tradeId = identity ?: TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)

        normalizePositionScaleIfNeeded(ts)
        val price = getActualPrice(ts)
        if (price <= 0) {
            ErrorLogger.debug("Executor", "Paper buy skipped: no valid price for ${tradeId.symbol}")
            markPaperBuyNotOpened("NO_VALID_PRICE")
            return
        }
        if (ts.position.isOpen) {
            onLog("⚠ Buy skipped: position already open", tradeId.mint); markPaperBuyNotOpened("POSITION_ALREADY_OPEN"); return
        }
        
        val currentLayer = "PAPER"
        if (EmergentGuardrails.shouldBlockMultiLayerEntry(tradeId.mint, currentLayer)) {
            onLog("⚠ Buy skipped: ${tradeId.symbol} already open in different layer", tradeId.mint)
            markPaperBuyNotOpened("MULTI_LAYER_ENTRY_BLOCK")
            return
        }
        
        val actualSol: Double
        val buildPhase: Int
        val targetBuild: Double
        
        if (skipGraduated || quality == "C") {
            actualSol = clampPaperTradeSol(sol, ts.mint, ts.symbol, "paperBuy.actual", maxPaperTradeSolOverride)
            buildPhase = if (quality != "C") 1 else 3
            targetBuild = if (quality != "C") sol / graduatedInitialPct(quality) else 0.0
        } else {
            actualSol = clampPaperTradeSol(graduatedInitialSize(sol, quality), ts.mint, ts.symbol, "paperBuy.graduated", maxPaperTradeSolOverride)
            buildPhase = 1
            targetBuild = sol.coerceAtMost(maxConfiguredPaperTradeSol())
        }
        
        // V5.9.780 — EMERGENT MEME PAPER REALISM (entry side).
        // Same correction as paperSell — live Jupiter slippage on meme
        // dust is 5–15% on the entry side. Old curve was 0.4–3% which
        // gave paper buys an artificial edge that live can't reproduce.
        // V5.9.1436 — REALISTIC PAPER SLIPPAGE (entry side). Operator:
        // "shitcoin stops all seem the same % — data issue with sim slippage.
        // I don't use more than 1% in the real world; cap paper at max 5%."
        // The old 12%/6%/3.5% curve baked a +12% entry tax on every <$5k
        // pump.fun fill, which combined with the -18% exit tax = ~-27%
        // round-trip BEFORE any price move — so every SHITCOIN_STOP_LOSS
        // clustered at the same synthetic values (-10.7/-12.4%) and produced
        // phantom -88/-93% prints. Retuned to the operator's real fill
        // profile: ~1% typical, hard-capped at 5% on the dustiest pools.
        // Tier shape preserved (deeper pool = tighter fill). Live untouched.
        val simulatedSlippagePct = when {
            ts.lastLiquidityUsd < 5_000.0   -> 5.0   // dust pump.fun bonding curve (was 12)
            ts.lastLiquidityUsd < 20_000.0  -> 3.0   // (was 6)
            ts.lastLiquidityUsd < 50_000.0  -> 2.0   // (was 3.5)
            ts.lastLiquidityUsd < 250_000.0 -> 1.0   // (was 1.5)
            else -> 0.5                               // (was 0.8)
        }
        val slippageMultiplier = 1.0 + (simulatedSlippagePct / 100.0)
        val effectivePrice = price * slippageMultiplier
        
        val simulatedFeePct = 0.5
        val effectiveSol = actualSol * (1.0 - simulatedFeePct / 100.0)
        
        val currentMode = try {
            val tokenAgeMs = System.currentTimeMillis() - ts.addedToWatchlistAt
            val hasWhales = ts.meta.whaleSummary.isNotBlank()
            
            val recommendedMode = UnifiedModeOrchestrator.recommendModeForToken(
                liquidity = ts.lastLiquidityUsd,
                mcap = ts.lastMcap,
                ageMs = tokenAgeMs,
                volScore = ts.meta.volScore,
                momScore = ts.meta.momScore,
                source = ts.source,
                emafanAlignment = ts.meta.emafanAlignment,
                holderConcentration = ts.safety.topHolderPct,
                isRevival = ts.source.contains("REVIVAL", ignoreCase = true),
                hasWhaleActivity = hasWhales,
            )
            ErrorLogger.debug("Executor", "Mode selected for ${ts.symbol}: ${recommendedMode.emoji} ${recommendedMode.name}")
            recommendedMode
        } catch (e: Exception) {
            try {
                UnifiedModeOrchestrator.getCurrentPrimaryMode()
            } catch (_: Exception) {
                UnifiedModeOrchestrator.ExtendedMode.STANDARD
            }
        }
        
        // V5.9.969 — z-spec HoldingLogicLayer.recommendInitialMode() revival.
        // Was fully dormant; now consulted when no explicit layerTag is set
        // and currentMode would default to STANDARD. The function picks
        // among PRESALE_SNIPE / PUMP_SNIPER / MICRO_CAP / SLEEPER / REVIVAL /
        // BLUE_CHIP / LONG_HOLD / MOMENTUM_SWING / STANDARD based on
        // (liquidity, mcap, age, volScore, source). The downstream HoldingLogic
        // evaluatePosition path (already wired) uses tradingMode to pick
        // mode-specific TP/SL/trail params — so this finally lights up.
        val smartMode = try {
            com.lifecyclebot.engine.HoldingLogicLayer.recommendInitialMode(
                liquidity = ts.lastLiquidityUsd,
                mcap      = ts.lastMcap,
                age       = System.currentTimeMillis() - ts.addedToWatchlistAt,
                volScore  = ts.meta.volScore,
                source    = ts.source,
            )
        } catch (_: Throwable) { "" }

        val finalMode = when {
            layerTag.isNotBlank()                              -> layerTag
            smartMode.isNotBlank() && smartMode != "STANDARD"  -> smartMode
            else                                               -> currentMode.name
        }
        val finalEmoji = if (layerTagEmoji.isNotBlank()) layerTagEmoji
                         else com.lifecyclebot.engine.HoldingLogicLayer.getModeEmoji(finalMode)

        // V5.9.996 — COPY-TRADE OUTCOME LOOP step 1/2 (Doctrine #4 —
        // genuine learning). Audit found Position.copyWallet has ZERO set
        // sites and ZERO read sites across the whole codebase — it is a
        // phantom field. CopyTradeEngine.recordResult needs a wallet
        // address to attribute the SELL outcome to. Without this stamp
        // the SELL hook (step 2/2 below) has nothing to attribute, the
        // engine's win/loss/PnL stats stay at zero forever, and the
        // auto-pause heuristic (recordResult line 122) never fires —
        // meaning unprofitable copy wallets are followed indefinitely.
        //
        // Read autoMode through BotService.instance (same accessor
        // pattern used by BotViewModel.kt:119). BotMode is nested in
        // AutoModeEngine (verified against ModeSpecificGates.kt:337
        // which uses AutoModeEngine.BotMode.COPY).
        //
        // Fail-open: any exception → blank wallet → no copy attribution
        // (same effect as a non-copy trade), never blocks position open.
        val copyWalletAtEntry: String = try {
            val am = com.lifecyclebot.engine.BotService.instance?.autoMode
            if (am != null
                && am.currentMode == com.lifecyclebot.engine.AutoModeEngine.BotMode.COPY
                && am.copyTriggerMint == ts.mint
            ) am.copyTriggerWallet else ""
        } catch (_: Throwable) { "" }

        val entryMarketSnapshot = mintEntryMarketSnapshot(ts)
        if (entryMarketSnapshot != null) persistMintEntryMarketSnapshot(ts, entryMarketSnapshot, "paperBuy")
        val paperPolicySnapshot = buildTradePolicySnapshot(
            ts = ts,
            mode = "PAPER",
            lane = if (routeIsShadow) "SHADOW_$finalMode" else finalMode,
            style = finalMode,
            score = score,
            plannedSol = sol,
            finalSol = actualSol,
            reasons = listOf("paperBuy", quality.toString(), buildPhase.toString()),
            extra = "entryTp=${ts.styleTpMult.fmt(2)} hold=${ts.styleHoldMult.fmt(2)}",
        )
        ts.lastPolicySnapshot = paperPolicySnapshot
        ts.position = Position(
            qtyToken     = effectiveSol / maxOf(effectivePrice, 1e-12),
            entryPrice   = effectivePrice,
            entryTime    = System.currentTimeMillis(),
            costSol      = actualSol,
            highestPrice = effectivePrice,
            entryPhase   = ts.phase,
            entryScore   = score,
            entryLiquidityUsd = entryMarketSnapshot?.liquidityUsd ?: ts.lastLiquidityUsd,
            entryMcap    = entryMarketSnapshot?.marketCapUsd ?: ts.lastMcap,
            isPaperPosition = true,
            // V5.9.1109 — stamp paper entry pricing basis too. LiveBuy already
            // did this, but paperBuy left entryPriceSource blank; the shared
            // price-basis resolver then could not rebase PAPER entries when
            // PumpFun synthetic quotes graduated to a DEX/Birdeye source. The
            // universal fallback safety path read raw ts.lastPrice and printed
            // fake -24%..-87% orphan losses seconds after BUY. Persisting the
            // source/pool/dex contract here makes paper exits comparable.
            entryPriceSource = entryMarketSnapshot?.priceSource ?: ts.lastPriceSource.ifBlank { "UNKNOWN" },
            entryPoolAddress = entryMarketSnapshot?.poolAddress ?: ts.lastPricePoolAddr.ifBlank { ts.pairAddress },
            entryDex         = entryMarketSnapshot?.dex ?: ts.lastPriceDex.ifBlank { "UNKNOWN" },
            entrySupplyAssumed = if ((entryMarketSnapshot?.priceSource ?: ts.lastPriceSource) == "PUMP_FUN_BC_SYNTHETIC" ||
                                      (entryMarketSnapshot?.priceSource ?: ts.lastPriceSource) == "PUMP_FUN_FRONTEND_API")
                1_000_000_000.0 else 0.0,
            // V5.9.969 — finalMode picks the richer HoldingLogicLayer label
            // when no sub-trader tag is set and would otherwise be STANDARD.
            tradingMode  = if (routeIsShadow) "SHADOW_$finalMode" else finalMode,
            tradingModeEmoji = finalEmoji,
            entryPolicySnapshot = paperPolicySnapshot,
            buildPhase   = buildPhase,
            targetBuildSol = targetBuild,
            // V5.9.996 — copy-trade attribution for CopyTradeEngine.recordResult
            copyWallet   = copyWalletAtEntry,
            // V5.0.4125 — Apply AGI style TP multiplier at position creation.
            // fluidTP * styleTpMult = actual exit target. DH_RUNNER
            // (2.80x) → 42% bootstrap TP instead of 15%. EXHAUSTION_QUICK_FLIP
            // (0.38x) → 5.7% fast scalp TP. This is the bridge between the
            // super-AGI scoring stack and actual exit behavior.
            entryTakeProfitPct = try {
                val baseFluidTp = com.lifecyclebot.v3.scoring.FluidLearningAI
                    .getFluidTakeProfit(cfg().exitScoreThreshold.coerceAtLeast(20.0))
                (baseFluidTp * ts.styleTpMult).coerceIn(5.0, 500.0)
            } catch (_: Throwable) { 0.0 },
        )
        // V5.9.123 — register in CorrelationHedgeAI so other new-entry scoring
        // sees this position as cluster peer pressure.
        try {
            com.lifecyclebot.v3.scoring.CorrelationHedgeAI.registerOpen(
                mint = ts.mint, symbol = ts.symbol, mcapUsd = ts.lastMcap
            )
        } catch (_: Exception) {}
        // V5.9.137 — register in SellOptimizationAI with REAL size so chunk
        // sizing and remainingSizeSol tracking work. Without this the AI
        // used a dummy 0.1◎ fallback and silently broke chunk selling.
        try {
            com.lifecyclebot.v3.scoring.SellOptimizationAI.registerPosition(
                mint = ts.mint, entryPrice = effectivePrice, sizeSol = actualSol
            )
        } catch (_: Exception) {}
        try {
            com.lifecyclebot.v4.meta.PortfolioHeatAI.addPosition(
                id = ts.mint,
                symbol = ts.symbol.ifBlank { ts.mint.take(6) },
                market = "MEME",
                sector = currentLayer,
                direction = "LONG",
                sizeSol = actualSol,
                leverage = 1.0,
                narrative = "${ts.source}:${ts.phase}",
            )
            PipelineHealthCollector.labelInc("PORTFOLIO_HEAT_MEME_POSITION_REGISTERED_4212")
        } catch (_: Throwable) {}
        val trade = Trade(
            side = "BUY", 
            mode = if (routeIsShadow) "shadow" else "paper",
            sol = actualSol, 
            price = price, 
            ts = System.currentTimeMillis(),
            score = score,
            // V5.9.386 — sub-trader tag overrides ExtendedMode when provided
            // so Journal shows SHITCOIN/QUALITY/BLUE_CHIP/MOONSHOT/TREASURY
            // on the BUY leg (SELL leg already correct via ts.position.tradingMode).
            tradingMode = if (layerTag.isNotBlank()) layerTag else currentMode.name,
            tradingModeEmoji = if (layerTagEmoji.isNotBlank()) layerTagEmoji else currentMode.emoji,
        )
        recordTrade(ts, trade)
        security.recordTrade(trade)
        try { PipelineHealthCollector.labelInc("PAPER_BUY_OPENED") } catch (_: Throwable) {}

        EmergentGuardrails.registerPosition(tradeId.mint, tradeId.symbol, currentLayer, actualSol)
        // V5.9.385 — the GHOST POSITION fix. V5.9.369 added a guard in
        // GlobalTradeRegistry.removeFromWatchlist that blocks eviction when
        // `activePositions.containsKey(mint)`. But the guard was a no-op
        // because NO BUY PATH ever called GlobalTradeRegistry.registerPosition
        // (only PositionPersistence on startup did). So `activePositions`
        // was always empty, the guard always returned false, and the
        // scanner evicted mints we held → no price polling → ghost positions
        // that sat in the wallet forever. Reported by user 5× across sessions.
        try {
            com.lifecyclebot.engine.GlobalTradeRegistry.registerPosition(
                mint = tradeId.mint,
                symbol = tradeId.symbol,
                layer = currentLayer,
                sizeSol = actualSol,
            )
        } catch (_: Exception) { /* non-critical */ }
        // V5.9.1470 (spec item 2 corollary) — REOPEN clears any prior close stamp so a
        // legitimately re-bought mint trades again cleanly (the duplicate-suppress guard
        // in paperSell only blocks a SELL while a live close stamp exists; a real new BUY
        // is the signal to clear it).
        try { com.lifecyclebot.engine.PositionCloseLedger.reopen(tradeId.mint) } catch (_: Throwable) {}
        try { com.lifecyclebot.engine.PaperPositionCloseAuthority.reopen("PAPER", tradeId.mint) } catch (_: Throwable) {}
        
        try {
            PositionPersistence.savePosition(ts)
        } catch (e: Exception) {
            ErrorLogger.debug("Executor", "Position persistence save error: ${e.message}")
        }
        
        TradeStateMachine.setState(tradeId.mint, TradeState.MONITOR, "position opened")
        
        tradeId.executed(price, actualSol, isPaper = true)
        tradeId.monitoring()
        
        TradeLifecycle.executed(tradeId.mint, price, actualSol)
        TradeLifecycle.monitoring(tradeId.mint, 0.0)
        
        if (debitPaperWallet) {
            onPaperBalanceChange?.invoke(-actualSol)
        } else {
            try { ForensicLogger.lifecycle("PAPER_BUY_SHARED_WALLET_DEBIT_SKIPPED", "mint=${tradeId.mint.take(10)} symbol=${tradeId.symbol} layer=$layerTag sol=${actualSol.fmt(4)} reason=virtual_book") } catch (_: Throwable) {}
        }
        
        if (cfg().fluidLearningEnabled) {
            FluidLearning.recordPaperBuy(tradeId.mint, actualSol)
            FluidLearning.recordPriceImpact(tradeId.mint, actualSol, ts.lastLiquidityUsd, isBuy = true)
        }
        
        EdgeLearning.recordEntry(
            mint = tradeId.mint,
            symbol = tradeId.symbol,
            buyPct = ts.meta.pressScore,
            volumeScore = ts.meta.volScore,
            phase = ts.phase,
            edgeQuality = quality,
            wasVetoed = false,
            vetoReason = null,
            entryPrice = price,
            isPaperMode = true,
        )
        
        val entryConditions = EntryIntelligence.EntryConditions(
            buyPressure = ts.meta.pressScore,
            volumeScore = ts.meta.volScore,
            priceVsEma = ts.meta.posInRange - 50.0,
            rsi = ts.meta.rsi,
            momentum = ts.entryScore,
            hourOfDay = java.util.Calendar.getInstance(java.util.TimeZone.getTimeZone("UTC")).get(java.util.Calendar.HOUR_OF_DAY),
            volatility = ts.meta.avgAtr,
            liquidityUsd = ts.lastLiquidityUsd,
            topHolderPct = ts.safety.topHolderPct,
            isNearSupport = ts.meta.posInRange < 25.0,
            isNearResistance = ts.meta.posInRange > 75.0,
            candlePattern = "none",
        )
        EntryIntelligence.recordEntry(tradeId.mint, entryConditions)
        
        LiquidityDepthAI.recordEntryLiquidity(tradeId.mint, ts.lastLiquidityUsd)
        
        try {
            val narrative = NarrativeDetectorAI.detectNarrative(ts.symbol, ts.name)
            PortfolioAnalytics.updatePosition(
                mint = tradeId.mint,
                symbol = tradeId.symbol,
                valueSol = actualSol,
                costSol = actualSol,
                narrative = narrative.label,
                entryTime = System.currentTimeMillis(),
            )
            PortfolioAnalytics.recordPrice(tradeId.mint, price)
        } catch (e: Exception) {
            ErrorLogger.debug("PortfolioAnalytics", "Update error: ${e.message}")
        }
        
        sounds?.playBuySound()
        
        val buildInfo = if (buildPhase == 1) " [BUILD 1/3]" else ""
        val buyAttemptLane = if (layerTag.isNotBlank()) layerTag else trade.tradingMode
        try { ForensicLogger.lifecycle("TRADE_HISTORY_BUY_ATTEMPT", "attemptId=$attemptId symbol=${tradeId.symbol} mint=${tradeId.mint.take(10)} mode=PAPER lane=$buyAttemptLane") } catch (_: Throwable) {}
        onLog("PAPER BUY attemptId=$attemptId @ ${price.fmt()} | ${actualSol.fmt(4)} SOL | score=${score.toInt()}$buildInfo", tradeId.mint)
        onNotify("📈 Paper Buy", "${tradeId.symbol}  ${actualSol.fmt(3)} SOL$buildInfo", com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
        
        TradeAlerts.onBuy(cfg(), tradeId.symbol, actualSol, score, 0.0, ts.position.tradingMode, isPaper = true)

        // V5.9.170 — stamp entry reason into the universal learning firehose
        // so EducationSubLayerAI can fold "why we bought" into per-reason
        // win/loss statistics when this position closes.
        try {
            val reason = buildString {
                append(currentMode.name)
                if (ts.phase.isNotBlank()) { append("|phase="); append(ts.phase) }
                append("|q=$quality")
                append("|src=${ts.source.ifBlank { "UNKNOWN" }}")
                if (ts.meta.emafanAlignment.isNotBlank()) { append("|emafan="); append(ts.meta.emafanAlignment) }
                val pressBand = when {
                    ts.meta.pressScore >= 70 -> "HI"
                    ts.meta.pressScore >= 50 -> "MID"
                    else -> "LO"
                }
                append("|press="); append(pressBand)
            }
            com.lifecyclebot.v3.scoring.EducationSubLayerAI.recordEntryReason(
                mint = tradeId.mint,
                traderSource = ts.position.tradingMode.ifEmpty { "MEME" },  // V5.9.320: was hardcoded "Meme"
                reason = reason,
                scoreHint = score,
            )
        } catch (_: Exception) {}
    }
    
    fun v3Buy(
        ts: TokenState,
        sizeSol: Double,
        walletSol: Double,
        v3Score: Int,
        v3Band: String,
        v3Confidence: Double,
        wallet: SolanaWallet?,
        lastSuccessfulPollMs: Long,
        openPositionCount: Int,
        totalExposureSol: Double,
        finalityPrechecked: Boolean = false,
        attemptId: String = "",
    ) {
        // V5.9.778 — EMERGENT MEME-ONLY: single mode authority. The
        // exact log line `MEME_SPINE V3_BUY_ROUTE route=PAPER cfgPaper=true`
        // in the operator's forensic was emitted from here while the
        // user was in LIVE mode (PAPER→LIVE flip + 2s ConfigStore cache
        // race). Now reads from RuntimeModeAuthority, single source.
        val isPaper = isPaperRT()
        val identity = TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
        
        identity.executed(getActualPrice(ts), sizeSol, isPaper)

        // ── V5.9.844 — observability for 3 silently-dropped v3Buy params ──
        // lastSuccessfulPollMs, openPositionCount, totalExposureSol have
        // been parameters since v3Buy shipped, dropped on the floor at
        // every entry. These are the entry-state context numbers an
        // operator needs in the forensic to diagnose why a trade fired:
        //   • pollAgeMs: how stale was the price tick? (>5s = thin venue)
        //   • openPos: how crowded was the book? (correlates with WR)
        //   • exposureSol: portfolio concentration at entry time
        val pollAgeMs = if (lastSuccessfulPollMs > 0L)
            (System.currentTimeMillis() - lastSuccessfulPollMs).coerceAtLeast(0L)
            else -1L
        val pollTag = when {
            pollAgeMs < 0L      -> "BOOT"
            pollAgeMs < 2_500L  -> "FRESH"
            pollAgeMs < 5_000L  -> "OK"
            pollAgeMs < 10_000L -> "STALE"
            else                -> "VERY_STALE"
        }
        val exposurePctOfBank = if (walletSol > 0.0)
            ((totalExposureSol / walletSol) * 100.0).coerceIn(0.0, 999.9)
            else 0.0

        ErrorLogger.info("Executor", "🧬 MEME_SPINE V3_BUY_ROUTE ${ts.symbol} | route=${if (isPaper) "PAPER" else "LIVE_JUPITER"} | authPaper=$isPaper | walletLoaded=${wallet != null} | size=${sizeSol.fmt(4)} | openPos=$openPositionCount | exposure=${totalExposureSol.fmt(3)}SOL(${exposurePctOfBank.toInt()}%) | poll=${pollTag}${if (pollAgeMs >= 0L) "(${pollAgeMs}ms)" else ""}")

        // V5.9.844 — observability-only warnings (no veto, no size mutation).
        // The Executor already passed all FDG / size checks upstream; here
        // we just emit a structured warning so the forensic explorer can
        // surface trades fired during sub-optimal data conditions.
        if (pollAgeMs >= 10_000L) {
            ErrorLogger.warn("Executor", "⏱️ STALE_POLL_AT_ENTRY ${ts.symbol} | pollAge=${pollAgeMs}ms | proceeding (FDG/size already approved)")
        }
        if (exposurePctOfBank >= 80.0 && walletSol > 0.0) {
            ErrorLogger.warn("Executor", "📊 HIGH_EXPOSURE_AT_ENTRY ${ts.symbol} | exposure=${exposurePctOfBank.toInt()}% of bank | openPos=$openPositionCount")
        }
        
        // V5.0.3731 — recover lane-approved finality handoff when caller lost it.
        // Some V3 live paths arrive with blank attemptId even though TradeAuthorizer just
        // approved a specialist lane (MOONSHOT/SHITCOIN/etc). Reuse that approved key so
        // liveBuy does not re-check as STANDARD candidateVersion=0 and emit
        // NO_FINAL_BUY_CANDIDATE.
        val effectiveAttemptId = attemptId.ifBlank { ExecutableOpenGate.recentAllowedAttemptIdAnyLane(ts.mint) ?: "" }
        val effectiveFinalityPrechecked = finalityPrechecked || effectiveAttemptId.isNotBlank()

        // V5.9.1366 — STANDARD-LANE GATE VERDICT. ROOT CAUSE of "parked / 0 open
        // despite V3 EXECUTE": the ExecutableOpenGate EntryState is keyed by MINT and
        // SHARED across every lane. When a meme lane (e.g. SHITCOIN) evaluates a token
        // and records a non-BUY verdict (EXPECTANCY_REJECT / DANGER_BUCKET → WATCH),
        // that WATCH is stamped into the shared state. The V3 spine then reaches a
        // genuine EXECUTE_STANDARD + FDG✓ decision for the SAME mint and calls v3Buy —
        // but it never recorded its OWN pre-FDG BUY verdict for the STANDARD/V3 lane.
        // canOpenExecutablePosition() reads state.preFdgVerdict (=WATCH from the meme
        // lane) → EXEC_OPEN_DROPPED_PRE_FDG_NOT_BUY → every V3 trade silently dropped,
        // book parks at 0 open. Reaching v3Buy means V3 already cleared its own FDG
        // hard-veto upstream (see BotService V3-EXECUTE: FDG is a hard veto there), so
        // stamping a STANDARD BUY here is correct and safe — it does NOT bypass FDG,
        // it records the verdict the V3 path already earned. Real safety context
        // (rug/liq/tier) is passed so genuine hard-no's still convert to HARD_NO_BUY
        // inside recordFdg. This is the missing sibling of the 8 lane recordFdg calls.
        try {
            ExecutableOpenGate.recordFdg(
                ts.mint, ts.symbol, "STANDARD",
                canExecute = true,
                reason = null,
                signal = "BUY",
                rugScore = ts.safety.rugcheckScore,
                safetyTier = ts.safety.tier.name,
                liquidityUsd = ts.lastLiquidityUsd,
                hardNoReasons = ts.safety.hardBlockReasons,
                candidateVersion = effectiveAttemptId.substringAfterLast(":").toLongOrNull()
                    ?: LaneExecutionCoordinator.candidateVersionFor(ts.mint),
                entryScore = v3Score,
                tokenMapRouteStatus = TokenMapAuthority.ensureDiscoveryTokenMap(ts, ts.source).routeStatus,
                tokenMapHydrationComplete = ts.tokenMap.hydrationComplete,
                tokenMapExpectedOut = ts.tokenMap.expectedOutAmount,
                tokenMapProviderAttempts = ts.tokenMap.providerAttempts,
            )
        } catch (_: Throwable) {}

        val openedByV3Buy4462: Boolean = if (isPaper) {
            paperBuy(
                ts = ts,
                sol = sizeSol,
                score = v3Score.toDouble(),
                identity = identity,
                quality = v3Band,
                skipGraduated = true,
                wallet = wallet,
                walletSol = walletSol,
                finalityPrechecked = effectiveFinalityPrechecked,
                attemptId = effectiveAttemptId,
            )
            true
        } else {
            if (wallet == null) {
                ErrorLogger.error("Executor", "[V3] ${ts.symbol} | LIVE_BUY_FAILED | no wallet")
                try { TradeAuthorizer.releasePosition(ts.mint, "V3_LIVE_BUY_NO_WALLET_PREOPEN") } catch (_: Throwable) {}
                try { LaneExecutionCoordinator.releaseIfPrimary(ts.mint, ts.position.tradingMode.ifBlank { "CORE" }, "V3_LIVE_BUY_NO_WALLET_PREOPEN") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("LIVE_BUY_PREOPEN_RELEASE_NO_WALLET") } catch (_: Throwable) {}
                return
            }
            liveBuy(
                ts = ts,
                sol = sizeSol,
                score = v3Score.toDouble(),
                wallet = wallet,
                walletSol = walletSol,
                identity = identity,
                quality = v3Band,
                skipGraduated = true,
                layerTag = resolveExecutionLane(ts, identity).takeIf { it.isNotBlank() && it != "STANDARD" } ?: "",
                finalityPrechecked = effectiveFinalityPrechecked,
                attemptId = effectiveAttemptId,
            )
        }
        if (!openedByV3Buy4462) {
            try { PipelineHealthCollector.labelInc("V3_BUY_NOT_OPENED_SUPPRESS_LEARNING_4462") } catch (_: Throwable) {}
            try { ForensicLogger.lifecycle("V3_BUY_NOT_OPENED_SUPPRESS_LEARNING_4462", "mint=${ts.mint.take(10)} symbol=${ts.symbol} paper=$isPaper lane=${ts.position.tradingMode.ifBlank { v3Band }} attemptId=$effectiveAttemptId") } catch (_: Throwable) {}
            return
        }
        
        try {
            com.lifecyclebot.v3.V3EngineManager.recordEntry(
                mint = ts.mint,
                symbol = ts.symbol,
                entryPrice = getActualPrice(ts),
                sizeSol = sizeSol,
                v3Score = v3Score,
                v3Band = v3Band,
                v3Confidence = v3Confidence,
                source = ts.source,
                liquidityUsd = ts.lastLiquidityUsd,
                isPaper = isPaper
            )
        } catch (e: Exception) {
            ErrorLogger.debug("Executor", "[V3] Learning record error: ${e.message}")
        }
        
        try {
            ErrorLogger.info("Executor", "🌐 [COLLECTIVE] Launching upload for BUY ${ts.symbol}...")
            kotlinx.coroutines.GlobalScope.launch(AppDispatchers.sideEffect) {
                try {
                    // V5.6.21: Log coroutine start to verify it executes
                    ErrorLogger.info("Executor", "🌐 [COLLECTIVE] Coroutine STARTED for BUY ${ts.symbol}")
                    val marketSentiment = ts.meta.emafanAlignment.ifBlank { "NEUTRAL" }
                    com.lifecyclebot.collective.CollectiveLearning.uploadTrade(
                        side = "BUY",
                        symbol = ts.symbol,
                        mint = ts.mint,
                        mode = ts.position.tradingMode.ifBlank { v3Band },
                        source = ts.source.ifBlank { "UNKNOWN" },
                        liquidityUsd = ts.lastLiquidityUsd,
                        marketSentiment = marketSentiment,
                        entryScore = v3Score,
                        confidence = v3Confidence.toInt(),
                        pnlPct = 0.0,
                        holdMins = 0.0,
                        isWin = false,
                        paperMode = isPaper
                    )
                    ErrorLogger.info("Executor", "🌐 [COLLECTIVE] uploadTrade COMPLETED for BUY ${ts.symbol}")
                } catch (e: Exception) {
                    ErrorLogger.error("Executor", "🌐 [COLLECTIVE] Upload coroutine error for ${ts.symbol}: ${e.message}", e)
                }
            }
        } catch (e: Exception) {
            ErrorLogger.debug("Collective", "BUY upload error: ${e.message}")
        }
    }

    // ═══════════════════════════════════════════════════════════════════════
    // V5.9.738 — PAPER-MODE LEAK FIX
    //
    // dipHunterBuy / sniperSell are public router helpers added to plug two
    // historical bugs where the BotService call sites invoked paperBuy() /
    // paperSell() UNCONDITIONALLY, ignoring isPaperRT() entirely. In
    // live mode this caused: (a) paper positions opened against live wallet,
    // (b) operator log saying "LIVE" while the position was stamped
    // isPaperPosition=true, (c) all subsequent sells running through the
    // paper branch — operator wallet never moved.
    //
    // Operator report (Bernard Griffin, messenger 18:43): "its live but
    // making paper trades. nothing should be trading paper if the bot is
    // launched in live."
    //
    // These helpers enforce the same paper-vs-live routing v3Buy already
    // does for the MEME_SPINE path. Single source of truth: isPaperRT().
    // V5.9.1093 — wrapper-level finality preflight.
    // This runs before wrapper PAPER_BUY/LIVE_BUY logs, identity.executed(),
    // wallet mutation, journal writes, learning uploads, or position registration.
    private fun preflightExecutableOpen(
        ts: TokenState,
        isPaper: Boolean,
        lane: String,
        source: String,
        attemptId: String,
    ): ExecutableOpenGate.OpenVerdict {
        return ExecutableOpenGate.canOpenExecutablePosition(
            ts = ts,
            mode = if (isPaper) "PAPER" else "LIVE",
            lane = lane,
            source = source,
            attemptId = attemptId.ifBlank {
                ExecutableOpenGate.recentAllowedAttemptId(ts.mint, lane)
                    ?: ExecutableOpenGate.nextAttemptId(ts.mint, lane)
            },
        )
    }

