    fun dipHunterBuy(
        ts: TokenState,
        sizeSol: Double,
        score: Double,
        wallet: SolanaWallet?,
        walletSol: Double,
        identity: TradeIdentity? = null,
        finalityPrechecked: Boolean = false,
        attemptId: String = "",
    ): Boolean {
        val isPaper = isPaperRT()
        val preflight = if (finalityPrechecked) ExecutableOpenGate.OpenVerdict(true, "prechecked", attemptId = attemptId)
            else preflightExecutableOpen(ts, isPaper, "DIP_HUNTER", "Executor.dipHunterBuy", attemptId)
        if (!preflight.allowed) {
            ErrorLogger.warn("Executor", "🚫 DIP_BUY_BLOCKED_FINALITY: ${ts.symbol} | attemptId=${preflight.attemptId} | ${preflight.reason}")
            return false
        }
        val id = identity ?: TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
        ErrorLogger.info("Executor",
            "📉🎯 DIP_BUY_ROUTE ${ts.symbol} | route=${if (isPaper) "PAPER" else "LIVE_JUPITER"} | " +
            "attemptId=${preflight.attemptId} | cfgPaper=$isPaper | walletLoaded=${wallet != null} | size=${sizeSol.fmt(4)}")
        if (isPaper) {
            paperBuy(
                ts = ts, sol = sizeSol, score = score, identity = id,
                quality = "DIP_HUNTER", skipGraduated = true,
                wallet = wallet, walletSol = walletSol,
                layerTag = "DIP_HUNTER", layerTagEmoji = "📉",
                finalityPrechecked = true, attemptId = preflight.attemptId,
            )
        } else {
            if (wallet == null) {
                ErrorLogger.error("Executor",
                    "📉🎯 DIP ${ts.symbol} | LIVE_BUY_FAILED | no wallet — refusing to fall back to paperBuy")
                return false
            }
            return liveBuy(
                ts = ts, sol = sizeSol, score = score,
                wallet = wallet, walletSol = walletSol,
                identity = id, quality = "DIP_HUNTER", skipGraduated = true,
                layerTag = "DIP_HUNTER", layerTagEmoji = "📉",
                finalityPrechecked = true, attemptId = preflight.attemptId,
            ) || ts.position.qtyToken > 0.0 || ts.position.pendingVerify || ts.position.isOpen
        }
        return ts.position.qtyToken > 0.0 || ts.position.pendingVerify || ts.position.isOpen
    }

    fun sniperSell(
        ts: TokenState,
        reason: String,
        wallet: SolanaWallet?,
        walletSol: Double,
    ): SellResult {
        val isPaper = isPaperRT()
        ErrorLogger.info("Executor",
            "🎯 SNIPER_SELL_ROUTE ${ts.symbol} | route=${if (isPaper) "PAPER" else "LIVE_JUPITER"} | " +
            "cfgPaper=$isPaper | reason=$reason")
        return if (isPaper) {
            paperSell(ts, reason)
        } else {
            // Live route: requestSell branches internally on isPaperPosition,
            // so live-opened positions will correctly fire a Jupiter swap.
            // If the position was somehow opened in paper (e.g. mode flipped
            // mid-position), requestSell still routes via the paper branch
            // honoring isPaperPosition — no spurious live swap on a paper bag.
            requestSell(ts, reason, wallet, walletSol)
        }
    }

    fun treasuryBuy(
        ts: TokenState,
        sizeSol: Double,
        walletSol: Double,
        takeProfitPct: Double,
        stopLossPct: Double,
        wallet: SolanaWallet?,
        isPaper: Boolean,
        finalityPrechecked: Boolean = false,
        attemptId: String = "",
        paperLayerTag: String = "TREASURY",
        paperLayerEmoji: String = "💰",
        debitPaperWallet: Boolean = true,
        maxPaperTradeSolOverride: Double? = null,
    ): Boolean {
        val preflight = if (finalityPrechecked) ExecutableOpenGate.OpenVerdict(true, "prechecked", attemptId = attemptId)
            else preflightExecutableOpen(ts, isPaper, "TREASURY", "Executor.treasuryBuy", attemptId)
        if (!preflight.allowed) {
            ErrorLogger.warn("Executor", "🚫 TREASURY_BUY_BLOCKED_FINALITY: ${ts.symbol} | attemptId=${preflight.attemptId} | ${preflight.reason}")
            return false
        }
        val identity = TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
        
        identity.executed(getActualPrice(ts), sizeSol, isPaper)
        
        ErrorLogger.info("Executor", "💰 [TREASURY] ${ts.symbol} | " +
            "${if (isPaper) "PAPER" else "LIVE"}_BUY | " +
            "attemptId=${preflight.attemptId} | ${sizeSol.fmt(3)} SOL | TP=${takeProfitPct}% SL=${stopLossPct}%")
        
        if (isPaper) {
            paperBuy(
                ts = ts,
                sol = sizeSol,
                score = 80.0,
                identity = identity,
                quality = "TREASURY",
                skipGraduated = true,
                wallet = wallet,
                walletSol = walletSol,
                layerTag = paperLayerTag,        // V5.9.386 — journal tag
                layerTagEmoji = paperLayerEmoji,
                finalityPrechecked = true, attemptId = preflight.attemptId,
                debitPaperWallet = debitPaperWallet,
                maxPaperTradeSolOverride = maxPaperTradeSolOverride,
            )
        } else {
            if (wallet == null) {
                ErrorLogger.error("Executor", "💰 [TREASURY] ${ts.symbol} | LIVE_BUY_FAILED | no wallet")
                return false
            }
            // V5.7.8: Check real wallet balance before live execution
            if (walletSol < sizeSol) {
                ErrorLogger.error("Executor", "💰 [TREASURY] ${ts.symbol} | LIVE_BUY_FAILED | insufficient balance: wallet=${walletSol.fmt(3)} < size=${sizeSol.fmt(3)}")
                return false
            }
            val liveOpened = liveBuy(
                ts = ts,
                sol = sizeSol,
                score = 80.0,
                wallet = wallet,
                walletSol = walletSol,
                identity = identity,
                quality = "TREASURY",
                skipGraduated = true,
                layerTag = "TREASURY",        // V5.9.386
                layerTagEmoji = "💰",
                finalityPrechecked = true, attemptId = preflight.attemptId,
            )
            if (!liveOpened) return false
        }
        val buyOpened = ts.position.qtyToken > 0.0 || ts.position.pendingVerify || ts.position.isOpen
        if (!buyOpened) {
            ErrorLogger.warn("Executor", "💰 [TREASURY] ${ts.symbol} | BUY_NOT_OPENED | attemptId=${preflight.attemptId} | finality/route blocked")
            return false
        }
        
        ts.position.tradingMode = "TREASURY"
        ts.position.tradingModeEmoji = "💰"
        ts.position.isTreasuryPosition = true
        
        ts.position.treasuryTakeProfit = takeProfitPct
        ts.position.treasuryStopLoss = stopLossPct
        
        try {
            ErrorLogger.info("Executor", "🌐 [COLLECTIVE] Launching upload for TREASURY BUY ${ts.symbol}...")
            kotlinx.coroutines.GlobalScope.launch(AppDispatchers.sideEffect) {
                try {
                    val marketSentiment = ts.meta.emafanAlignment.ifBlank { "NEUTRAL" }
                    com.lifecyclebot.collective.CollectiveLearning.uploadTrade(
                        side = "BUY",
                        symbol = ts.symbol,
                        mint = ts.mint,
                        mode = "TREASURY",
                        source = ts.source.ifBlank { "TREASURY_SCAN" },
                        liquidityUsd = ts.lastLiquidityUsd,
                        marketSentiment = marketSentiment,
                        entryScore = 80,
                        confidence = 80,
                        pnlPct = 0.0,
                        holdMins = 0.0,
                        isWin = false,
                        paperMode = isPaper
                    )
                } catch (e: Exception) {
                    ErrorLogger.error("Executor", "🌐 [COLLECTIVE] Treasury upload error: ${e.message}", e)
                }
            }
        } catch (e: Exception) {
            ErrorLogger.debug("Collective", "TREASURY BUY upload error: ${e.message}")
        }
        return true
    }
    
