                wallet = wallet,
                walletSol = walletSol,
                layerTag = "SHITCOIN",          // V5.9.386 — journal tag
                layerTagEmoji = "💩",
                finalityPrechecked = true, attemptId = preflight.attemptId,
            )
        } else {
            if (wallet == null) {
                ErrorLogger.error("Executor", "💩 [SHITCOIN] ${ts.symbol} | LIVE_BUY_FAILED | no wallet")
                return false
            }
            val liveOpened = liveBuy(
                ts = ts,
                sol = sizeSol,
                score = laneScore,
                wallet = wallet,
                walletSol = walletSol,
                identity = identity,
                quality = "SHITCOIN",
                skipGraduated = true,
                layerTag = "SHITCOIN",          // V5.9.386 — journal tag
                layerTagEmoji = "💩",
                finalityPrechecked = true, attemptId = preflight.attemptId,
            )
            if (!liveOpened) return false
        }
        val buyOpened = ts.position.qtyToken > 0.0 || ts.position.pendingVerify || ts.position.isOpen
        if (!buyOpened) {
            ErrorLogger.warn("Executor", "💩 [SHITCOIN] ${ts.symbol} | BUY_NOT_OPENED | attemptId=${preflight.attemptId} | finality/route blocked")
            return false
        }
        
        ts.position.tradingMode = "SHITCOIN"
        ts.position.tradingModeEmoji = "💩"
        ts.position.isShitCoinPosition = true
        
        ts.position.shitCoinTakeProfit = takeProfitPct
        ts.position.shitCoinStopLoss = stopLossPct
        
        try {
            kotlinx.coroutines.GlobalScope.launch(AppDispatchers.sideEffect) {
                val marketSentiment = ts.meta.emafanAlignment.ifBlank { "NEUTRAL" }
                com.lifecyclebot.collective.CollectiveLearning.uploadTrade(
                    side = "BUY",
                    symbol = ts.symbol,
                    mint = ts.mint,
                    mode = "SHITCOIN",
                    source = ts.source.ifBlank { "SHITCOIN_SCAN" },
                    liquidityUsd = ts.lastLiquidityUsd,
                    marketSentiment = marketSentiment,
                    entryScore = entryScore.coerceIn(0, 100),
                    confidence = entryConfidence.coerceIn(0, 100),
                    pnlPct = 0.0,
                    holdMins = 0.0,
                    isWin = false,
                    paperMode = isPaper
                )
            }
        } catch (e: Exception) {
            ErrorLogger.debug("Collective", "SHITCOIN BUY upload error: ${e.message}")
        }
        return true
    }

    fun moonshotBuy(
        ts: TokenState,
        sizeSol: Double,
        walletSol: Double,
        wallet: SolanaWallet?,
        isPaper: Boolean,
        score: Double,
        spaceModeEmoji: String,
        spaceModeName: String,
        finalityPrechecked: Boolean = false,
        attemptId: String = "",
    ): Boolean {
        val preflight = if (finalityPrechecked) ExecutableOpenGate.OpenVerdict(true, "prechecked", attemptId = attemptId)
            else preflightExecutableOpen(ts, isPaper, "MOONSHOT", "Executor.moonshotBuy", attemptId)
        if (!preflight.allowed) {
            ErrorLogger.warn("Executor", "🚫 MOONSHOT_BUY_BLOCKED_FINALITY: ${ts.symbol} | attemptId=${preflight.attemptId} | ${preflight.reason}")
            return false
        }
        val identity = TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
        identity.executed(getActualPrice(ts), sizeSol, isPaper)

        ErrorLogger.info("Executor", "🚀 [MOONSHOT] ${ts.symbol} | " +
            "${if (isPaper) "PAPER" else "LIVE"}_BUY | " +
            "attemptId=${preflight.attemptId} | mcap=\$${(ts.lastMcap/1_000).fmt(1)}K | ${sizeSol.fmt(3)} SOL")

        if (isPaper) {
            paperBuy(ts = ts, sol = sizeSol, score = score, identity = identity,
                quality = spaceModeName, skipGraduated = true, wallet = wallet, walletSol = walletSol,
                layerTag = "MOONSHOT", layerTagEmoji = spaceModeEmoji.ifBlank { "🚀" },
                finalityPrechecked = true, attemptId = preflight.attemptId)  // V5.9.386
        } else {
            if (wallet == null) {
                ErrorLogger.error("Executor", "🚀 [MOONSHOT] ${ts.symbol} | LIVE_BUY_FAILED | no wallet")
                return false
            }
            val liveOpened = liveBuy(ts = ts, sol = sizeSol, score = score, wallet = wallet,
                walletSol = walletSol, identity = identity, quality = spaceModeName, skipGraduated = true,
                layerTag = "MOONSHOT", layerTagEmoji = spaceModeEmoji.ifBlank { "🚀" },
                finalityPrechecked = true, attemptId = preflight.attemptId)  // V5.9.386
            if (!liveOpened) return false
        }
        val buyOpened = ts.position.qtyToken > 0.0 || ts.position.pendingVerify || ts.position.isOpen
        if (!buyOpened) {
            ErrorLogger.warn("Executor", "🚀 [MOONSHOT] ${ts.symbol} | BUY_NOT_OPENED | attemptId=${preflight.attemptId} | finality/route blocked")
            return false
        }

        ts.position.tradingMode = "MOONSHOT"
        try { ForensicLogger.lifecycle("MOONSHOT_SUBSTYLE_CANONICALIZED_4162", "mint=${ts.mint.take(10)} symbol=${ts.symbol} substyle=MOONSHOT_$spaceModeName lane=MOONSHOT") } catch (_: Throwable) {}
        ts.position.tradingModeEmoji = spaceModeEmoji
        return true
    }

    // V5.0.3923 — DORMANT-AI ENTRY ADVISOR GATE. Operator audit (3922)
    // found that EntryIntelligence + MomentumPredictorAI were marked
    // LIVE_ELIGIBLE in the UI but never consulted before live BUYs. This
    // gate runs them on every live buy with PERMISSIVE thresholds (block
    // only on STRONG negative signals; default-allow when learning data
    // is sparse so the bot never chokes itself out). All 9 sub-lane BUY
    // routes flow through liveBuy(), so this single insertion covers
    // SHITCOIN, MOONSHOT, MANIPULATED, EXPRESS, QUALITY, BLUECHIP,
    // TREASURY, DIP_HUNTER, PROJECT_SNIPER. Any internal failure of an
    // advisor returns ALLOW (never choke on the advisor itself).
    //
    // V5.0.3924 — STACK-WIRING EXPANSION. Operator audit confirmed the
    // intelligence stack is BUILT and LEARNING but liveBuy() was ignoring
    // most of it. Wired in the following pre-existing LEARNED signals
    // (NOT new fixed thresholds — these adapt as the bot trades):
    //   • BotBrain.shouldSkipTrade()  — hard-suppressed pattern registry
    //   • BotBrain.learnedRugcheckThreshold  — adaptive (5-40) rug floor
    //   • BotBrain.learnedMinBuyPressure     — adaptive (10-35%) press floor
    //   • BotBrain.learnedMaxTopHolder       — adaptive (40-80%) holder ceiling
    //   • BotBrain.learnedMinLiquidity       — adaptive ($100 default) liq floor
    //   • FluidLearningAI.getExecuteFloor()  — fluid score floor that lerps
    //     from BOOTSTRAP (5) → MATURE (35+) as live trade count grows.
    // The brain reference is the Executor's existing var (line 736). Every
    // check is guarded so that null-brain or sparse-safety-data does NOT
    // choke the bot. Brain returns its own learned safety defaults
    // (intentionally permissive on bootstrap) until experience adjusts them.
    // V5.0.3924 — fluid lane-base score helper. Operator: "the overall
    // scoring for entry isnt meant to be a fixed score anywhere — its
    // meant to be a fluid learnt value in each lane trader or trading
    // tool adjusted thru the learning, brain, education, sentience and
    // intelligence stack." This routes any sub-lane's hard-coded base
    // score through BotBrain's adaptive entry threshold + per-phase +
    // per-source boosts so the value actually moves as the bot learns.
    // Returns the original baseScore unchanged when brain is null
    // (bootstrap / unit-test) so behaviour stays sane on cold start.
    private fun brainAdjustedLaneScore(baseScore: Double, ts: TokenState): Double {
        val b = brain ?: return baseScore
        return try {
            val adjusted = b.effectiveEntryThreshold(baseScore)
            val phaseBoost = b.getPhaseBoost(ts.phase)
            val sourceBoost = b.getSourceBoost(ts.source)
            (adjusted + phaseBoost + sourceBoost).coerceIn(0.0, 100.0)
        } catch (_: Throwable) { baseScore }
    }

    private fun consultEntryAdvisors(ts: TokenState, score: Double, layerTag: String, isPaperMode: Boolean = false): Pair<Boolean, String> {
        // ═══════════════════════════════════════════════════════════════════════
        // V5.0.6044 — PRE-FDG THROUGHPUT DOCTRINE (operator mandate 2026-07-03):
        //   "FDG is meant to be a final safety sanity gate. Trade flows in and
        //    out must align for trade throughput unless explicitly blocked (rugs)."
        //
        // Rule: this function MUST return (true, ...) except when there is an
        // *explicit hard rug* (HardRugPreFilter HARD_FAIL). All other signal
        // concerns — provider blindness, momentum avoid, brain floors, holder
        // ceilings, entry-intel avoid, fluid floors — MUST fire via softAdvisor()
        // ONLY (score penalty / telemetry log). They must NEVER return false.
        //
        // Downstream gates (EXEC_GATE reentry lockout, LiveSafetyCircuitBreaker,
        // FDG final sanity) handle real safety; pre-FDG advisors just SHAPE.
        // Adding a new pre-FDG hard-reject here is a doctrine violation.
        // ═══════════════════════════════════════════════════════════════════════
        return try {
            val mint = ts.mint
            fun softAdvisor(label: String, detail: String = "") {
                try {
                    ForensicLogger.lifecycle(
                        "LIVE_BUY_ADVISOR_SOFT_SHAPE",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} layer=$layerTag reason=$label ${detail.take(120)}".trim(),
                    )
                    PipelineHealthCollector.labelInc("LIVE_BUY_ADVISOR_SOFT_$label")
                } catch (_: Throwable) {}
            }
            // V5.0.3925 — HARD RUG PRE-FILTER on the live buy chokepoint.
            // Operator dump V5.0.3928 still showed live -100% rugs (Insider
            // lane, fresh launches). HardRugPreFilter exists and is called in
            // the scanning pipeline (BotService:15737) but its result is
            // softened by ModeLeniency.useLenientGates for proven-edge live
            // runs — that bypass let rug patterns reach liveBuy(). Force
            // STRICT-mode evaluation here regardless of lenient-mode setting
            // so live buys can never skip the rug pre-filter. HARD_FAIL is
            // a definitive block. SOFT_FAIL still passes (with telemetry).
            try {
                val rugFilter = com.lifecyclebot.engine.HardRugPreFilter.filter(ts, isPaperMode = false)
                if (!rugFilter.pass && rugFilter.severity == com.lifecyclebot.engine.HardRugPreFilter.FilterSeverity.HARD_FAIL) {
                    return false to "RUG_PREFILTER_HARD_FAIL:${rugFilter.reason ?: "unknown"}"
                }
            } catch (_: Throwable) {}
            // V5.0.3929 — PROVIDER PROOF CASCADE. Operator P0 mandate:
            // "theres more than enough free data apis providing g data live
            // it should never have an issue with trading or data flow ...
            // use the whole api stack as its intended for". The walker now
            // iterates the FULL free-API cascade (geckoterminal first,
            // birdeye demoted below pumpportal) and consults EfficiencyLayer
            // snapshot history before declaring UNKNOWN — a single throttled
            // provider can no longer silence the bot. When *every* provider
            // in the cascade is dry we skip the token silently rather than
            // panic-blocking, per operator instruction.
            try {
                val liqProof = com.lifecyclebot.engine.ProviderProofWalker.getBestAvailableProof(
                    ts, com.lifecyclebot.engine.ProviderProofWalker.Field.LIQUIDITY_USD
                )
                if (!liqProof.ok && !isPaperMode) {
                    val walked = liqProof.attempted.size
                    try {
                        ForensicLogger.exec("LIVE_BUY_PREATTEMPT_SUPPRESSED", ts.symbol, "mint=${ts.mint.take(10)} reason=PROVIDER_PROOF_LIQUIDITY_CASCADE_BLIND quality=${liqProof.quality.name} source=${liqProof.source} walked=$walked")
                        PipelineHealthCollector.labelInc("LIVE_BUY_PREATTEMPT_PROVIDER_PROOF_BLIND")
                    } catch (_: Throwable) {}
                    softAdvisor("PROVIDER_PROOF_LIQUIDITY_CASCADE_BLIND", "quality=${liqProof.quality.name} source=${liqProof.source} walked=$walked")
                }
            } catch (_: Throwable) {}
            // MomentumPredictor: shouldAvoid() returns false when there's no
            // data for this mint, so this won't fire on fresh launches.
            if (com.lifecyclebot.engine.MomentumPredictorAI.shouldAvoid(mint)) {
                val pred = com.lifecyclebot.engine.MomentumPredictorAI.getMomentum(mint)?.prediction?.name ?: "UNKNOWN"
                softAdvisor("MOMENTUM_AVOID", pred)
            }
            // BotBrain: hard-suppressed pattern check. shouldSkipTrade() reads
            // the learned suppression registry — patterns that have produced
            // repeated losses are flagged after the brain has observed them.
            // Default-allow when registry is empty (bootstrap).
            val b = brain
            if (b != null) {
                try {
                    if (b.shouldSkipTrade(ts.phase, ts.meta.emafanAlignment, ts.source, score)) {
                        try {
                            ForensicLogger.exec("LIVE_BUY_PREATTEMPT_SUPPRESSED", ts.symbol, "mint=${ts.mint.take(10)} reason=BRAIN_PATTERN_SUPPRESSED phase=${ts.phase} source=${ts.source}")
                            PipelineHealthCollector.labelInc("LIVE_BUY_PREATTEMPT_BRAIN_PATTERN_SUPPRESSED")
                        } catch (_: Throwable) {}
                        softAdvisor("BRAIN_PATTERN_SUPPRESSED", "phase=${ts.phase}|source=${ts.source}")
                    }
                } catch (_: Throwable) {}
                // Learned safety thresholds. Only enforce when the token has
                // a real safety reading (>0) — unknown safety on a brand-new
                // pool is checked elsewhere (HardRugPreFilter / blacklist).
                try {
                    if (ts.safety.rugcheckScore > 0 && ts.safety.rugcheckScore <= b.learnedRugcheckThreshold) {
                        softAdvisor("BRAIN_RUGCHECK_FLOOR", "score=${ts.safety.rugcheckScore}<=${b.learnedRugcheckThreshold}")
                    }
                    if (ts.meta.pressScore > 0.0 && ts.meta.pressScore < b.learnedMinBuyPressure) {
                        softAdvisor("BRAIN_BUY_PRESSURE_FLOOR", "press=${ts.meta.pressScore}<${b.learnedMinBuyPressure}")
                    }
                    // V5.0.3927 — TOP-HOLDER POLARITY-AGNOSTIC GATE. Operator
                    // dump V5.0.3930 showed RICHTROLL bought live despite a
                    // SolanaTrack-style risk page flagging '4 critical
                    // risks: top10 holders >70%, single holder ownership,
                    // unverified, low liquidity'. Internal rugcheckScore=61
                    // (rugcheck.xyz feed) said safe → BRAIN_RUGCHECK_FLOOR
                    // didn't fire. The pre-3927 guard also required
                    // topHolderPct > 0.0 — meaning if Birdeye/Helius hadn't
                    // populated the holder field yet (Birdeye in EMERGENCY
                    // CONSERVATION = 1 call/day), the check SILENTLY skipped
                    // and the token slipped through.
                    //
                    // New semantics: the live BUY chokepoint REQUIRES a
                    // populated topHolderPct value AND that value below the
                    // brain's learned ceiling. UNKNOWN holder concentration
                    // is itself a block reason per doctrine ('live entry
                    // must block or probe-only if holder proof is unknown').
                    // Paper still passes (learning value); the
                    // ProviderProofWalker holder-concentration field will
                    // walk Birdeye → Helius for fallback once per-provider
                    // snapshot provenance lands in a future commit.
                    // V5.0.3929 — HOLDER cascade via ProviderProofWalker.
                    // Walks helius → geckoterminal → dexscreener → birdeye
                    // and cross-checks SafetyReport.topHolderPct (rugcheck.xyz
                    // canonical) so birdeye throttling never silences the bot.
                    val holderProof = try {
                        com.lifecyclebot.engine.ProviderProofWalker.getBestAvailableProof(
                            ts, com.lifecyclebot.engine.ProviderProofWalker.Field.HOLDER_CONCENTRATION_PCT
                        )
                    } catch (_: Throwable) { null }
                    val holderPct = when {
                        holderProof != null && holderProof.ok    -> holderProof.value
                        ts.safety.topHolderPct >= 0.0            -> ts.safety.topHolderPct
                        (ts.topHolderPct ?: -1.0) >= 0.0         -> ts.topHolderPct ?: -1.0
                        else                                      -> -1.0
                    }
                    if (holderPct <= 0.0) {
                        // Full cascade blind → live blocks (real-money risk
                        // demands holder proof), paper learning still passes
                        // through this single gate so the learning loop is
                        // not silenced by data-pipeline gaps (rug pre-filter,
                        // momentum, brain pattern suppression, fluid floor,
                        // and intel still fire — paper isn't poisoned).
                        // V5.0.4595 — HOLDER-CASCADE-BLIND RELAX for proven-
                        // profitable lanes (STANDARD 66%WR, MOONSHOT 56%WR).
                        // If the token has strong liquidity (>= $5K) AND
                        // the lane is a proven winner, don't fire the soft-
                        // advisor. Reason: holder-concentration data is a
                        // *supporting* signal, and strong liq already
                        // implies healthy distribution. Blocking winner
                        // lanes on pipeline gaps was costing 34 trades/sess.
                        val provenWinnerHolderRelax4595 = try {
                            val laneName4595 = when {
                                layerTag.uppercase().contains("STANDARD") -> "STANDARD"
                                layerTag.uppercase().contains("MOONSHOT") -> "MOONSHOT"
                                else -> ""
                            }
                            if (laneName4595.isNotEmpty() && ts.lastLiquidityUsd >= 5_000.0) {
                                val snap = com.lifecyclebot.engine.LiveProbabilityEngine.laneSnapshots().firstOrNull { it.lane == laneName4595 }
                                snap != null && snap.sample >= 5 && snap.wrPct >= 50.0
                            } else false
                        } catch (_: Throwable) { false }
                        // V5.0.6042 — API_LAYER_DEGRADED holder-cascade fail-open.
                        // Operator report 2026-07-03 05:16 showed 21x
                        // PROVIDER_PROOF_HOLDER_CASCADE_BLIND advisor blocks
                        // dominating the funnel when Doctor state=DEGRADED
                        // subsystem=api/providers. Holder-proof data is a
                        // *supporting* signal — when the providers themselves
                        // are down (not the token being manipulated), blocking
                        // every buy is a false-positive choke that starves the
                        // memetrader/crypto lane of volume. Fail-open when:
                        //   (a) Doctor state = DEGRADED api/providers, AND
                        //   (b) liquidity >= $5K (real pool, not a rug shell)
                        // Safety fallback: other gates (LP-lock hard block,
                        // RUGCHECK_FLOOR, PATTERN_SUPPRESSED, EXEC_GATE
                        // reentry-lockout) still enforce live-trade safety.
                        val apiDegradedHolderBypass6042 = try {
                            if (isPaperMode) false
                            else if (ts.lastLiquidityUsd < 5_000.0) false
                            else {
                                val diag = com.lifecyclebot.engine.RuntimeDoctor.currentDiagnosis()
                                diag != null && diag.subsystem == "api/providers" &&
                                    (diag.state == "DEGRADED" || diag.faultCode == "DEGRADED")
                            }
                        } catch (_: Throwable) { false }
                        if (!isPaperMode && !provenWinnerHolderRelax4595 && !apiDegradedHolderBypass6042) {
                            val walked = holderProof?.attempted?.size ?: 0
                            softAdvisor("PROVIDER_PROOF_HOLDER_CASCADE_BLIND", "no_data walked=$walked")
                        } else if (provenWinnerHolderRelax4595) {
                            try {
                                com.lifecyclebot.engine.ForensicLogger.lifecycle(
                                    "HOLDER_CASCADE_BLIND_WINNER_BYPASS_4595",
                                    "mint=${ts.mint.take(10)} sym=${ts.symbol} liq=${ts.lastLiquidityUsd.toInt()} tag=$layerTag — proven-winner lane bypass",
                                )
                                com.lifecyclebot.engine.PipelineHealthCollector.labelInc("HOLDER_CASCADE_BLIND_WINNER_BYPASS_4595")
                            } catch (_: Throwable) {}
                        } else if (apiDegradedHolderBypass6042) {
                            try {
                                com.lifecyclebot.engine.ForensicLogger.lifecycle(
                                    "HOLDER_CASCADE_BLIND_API_DEGRADED_BYPASS_6042",
                                    "mint=${ts.mint.take(10)} sym=${ts.symbol} liq=${ts.lastLiquidityUsd.toInt()} tag=$layerTag — api providers degraded, holder proof fail-open (liq gate + downstream safety still enforced)",
                                )
                                com.lifecyclebot.engine.PipelineHealthCollector.labelInc("HOLDER_CASCADE_BLIND_API_DEGRADED_BYPASS_6042")
                            } catch (_: Throwable) {}
                        }
                    } else if (holderPct > b.learnedMaxTopHolder) {
                        softAdvisor("BRAIN_TOP_HOLDER_CEILING", "top=${holderPct}>${b.learnedMaxTopHolder}")
                    }
                    if (ts.lastLiquidityUsd > 0.0 && ts.lastLiquidityUsd < b.learnedMinLiquidity) {
                        softAdvisor("BRAIN_LIQUIDITY_FLOOR", "liq=${ts.lastLiquidityUsd}<${b.learnedMinLiquidity}")
                    }
                } catch (_: Throwable) {}
            }
            // FluidLearningAI execute floor — adaptive score gate that lerps
            // from bootstrap (~5) to mature (~35+) as the bot accumulates
            // live closes. Stays low during early learning so the bot can
            // still trade; rises as the brain demands stronger signals.
            try {
                val fluidFloor = com.lifecyclebot.v3.scoring.FluidLearningAI.getExecuteFloor().toDouble()
                if (score > 0.0 && score < fluidFloor) {
                    softAdvisor("FLUID_EXECUTE_FLOOR", "score=$score<$fluidFloor")
                }
            } catch (_: Throwable) {}
            // EntryIntelligence: only enforce once the AI has been trained on
            // ≥40 closed trades AND the verdict is AVOID with score < 25.
            // Below 40 trades we don't trust the weights yet. AVOID alone is
            // not enough — we need both labels to align.
            val intelTrades = try { com.lifecyclebot.engine.EntryIntelligence.getTotalTrades() } catch (_: Throwable) { 0 }
            if (intelTrades >= 40) {
                val conditions = com.lifecyclebot.engine.EntryIntelligence.EntryConditions(
                    buyPressure = ts.meta.pressScore,
                    volumeScore = ts.meta.volScore,
                    priceVsEma = ts.meta.posInRange - 50.0,
                    rsi = ts.meta.rsi,
                    momentum = ts.entryScore.toDouble(),
                    hourOfDay = java.util.Calendar.getInstance(java.util.TimeZone.getTimeZone("UTC"))
                        .get(java.util.Calendar.HOUR_OF_DAY),
                    volatility = ts.meta.avgAtr,
                    liquidityUsd = ts.lastLiquidityUsd,
                    topHolderPct = ts.safety.topHolderPct,
                    isNearSupport = ts.meta.posInRange < 25.0,
                    isNearResistance = ts.meta.posInRange > 75.0,
                    candlePattern = "none",
                )
                val intel = com.lifecyclebot.engine.EntryIntelligence.scoreEntry(conditions)
                if (intel.recommendation == com.lifecyclebot.engine.EntryIntelligence.EntryRecommendation.AVOID && intel.score < 25) {
                    softAdvisor("ENTRY_INTEL_AVOID", "score=${intel.score}|${intel.reasons.firstOrNull() ?: ""}")
                }
            }
            true to "ENTRY_ADVISORS_PASS:intelTrades=$intelTrades"
        } catch (e: Throwable) {
            // Any failure → ALLOW (never choke on the advisor itself)
            true to "ENTRY_ADVISORS_SOFT_PASS:${e.javaClass.simpleName}"
        }
    }

    private fun liveBuy(ts: TokenState, sol: Double, score: Double,
                        wallet: SolanaWallet, walletSol: Double,
                        identity: TradeIdentity? = null,
                        quality: String = "C",
                        skipGraduated: Boolean = false,
                        layerTag: String = "",           // V5.9.386 — sub-trader journal tag
                        layerTagEmoji: String = "",
                        finalityPrechecked: Boolean = false,
                        attemptId: String = "",
                        executionContext: ExecutionContext? = null): Boolean {    // V5.9.386 — matching emoji

        // V5.0.3939 — TRUE LIVE ATTEMPT BOUNDARY.
        // Runtime 3938 showed FDG live allow > 0, global EXEC > 0, but
        // LIVE EXEC attempt=0 because the attempt marker lived AFTER advisor,
        // lease, route, invalid-size, and blacklist preflight returns. Entering
        // liveBuy() is the live executor attempt; downstream blocks must report
        // as BUY fail/defer reasons, not disappear as zero attempts.
        try {
            ForensicLogger.exec(
                "LIVE_BUY_ATTEMPT",
                ts.symbol,
                "mint=${ts.mint.take(10)} sol=${"%.4f".format(sol)} score=${"%.1f".format(score)} q=$quality layer=$layerTag src=liveBuy.enter",
            )
            ForensicLogger.lifecycle(
                "MEME_LIVE_EXEC_ENTRY",
                "mint=${ts.mint.take(10)} symbol=${ts.symbol} sol=${"%.4f".format(sol)} layer=$layerTag callSite=liveBuy.enter",
            )
            PipelineHealthCollector.labelInc("LIVE_BUY_ENTERED")
        } catch (_: Throwable) {}

        // V5.0.4578 — same source fix at the final live executor choke. A few
        // direct lane callers bypass doBuy() and can still pass sentinel/NaN
        // scores. Do not hard-fail a route-approved candidate for a missing
        // caller score; normalize to TokenState.entryScore or neutral bootstrap
        // and let safety/route/cost/strategy gates decide.
        val rawLiveScore4578 = score
        val score = when {
            rawLiveScore4578.isFinite() && rawLiveScore4578 >= 0.0 -> rawLiveScore4578.coerceIn(0.0, 100.0)
            ts.entryScore.isFinite() && ts.entryScore > 0.0 -> ts.entryScore.coerceIn(0.0, 100.0)
            else -> 50.0
        }
        if (score != rawLiveScore4578) {
            try {
                ForensicLogger.lifecycle("LIVE_BUY_SCORE_NORMALIZED_AT_CHOKE_4578", "mint=${ts.mint.take(10)} symbol=${ts.symbol} normalized=$score entryScore=${ts.entryScore} action=continue_no_invalid_score_veto")
                PipelineHealthCollector.labelInc("LIVE_BUY_SCORE_NORMALIZED_AT_CHOKE_4578")
            } catch (_: Throwable) {}
        }

        val execCtx = executionContext ?: ExecutionContext(
            execMode = ExecMode.LIVE,
            attemptId = attemptId.ifBlank { "live_${ts.mint.take(8)}_${System.currentTimeMillis()}" },
            source = "Executor.liveBuy.default",
        )

        // V5.0.4151 — BUY DECISION LEASE FRESHNESS.
        // V5.0.4165 — WINDOW BUMPED 5s → 15s.
        // Operator dump on V5.0.4165 (preceding build) showed avg cycle=5827ms
        // with peaks of 21603ms during Jupiter slowness (jupiter avg=3378ms).
        // With cycle times that high, a 5s lease window guaranteed mass
        // EXEC_LEASE_PRUNED_EXPIRED events — 1712 EXEC_GATE allows collapsed
        // to only 10 BUY ok because every decision aged past 5s before the
        // executor could sign it inside the same cycle. troubleshoot_agent
        // RCA confirmed this as the dominant buy-throughput choke. 15s
        // gives ~70% headroom over the worst observed cycle (21.6s) while
        // still rejecting genuinely stale decisions. Route proof older than
        // 8s is still refreshed from local route-truth sources.
        // Statistical timeout/defer is not a strategy loss.
        run {
            val nowLease = System.currentTimeMillis()
            val decisionAgeMs = nowLease - execCtx.createdAtMs
            if (decisionAgeMs > 15_000L) {
                try { PipelineHealthCollector.labelInc("BUY_DECISION_EXPIRED_RESCORE") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("BUY_STALE_LEASE_CANCELLED") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("BUY_TIMEOUT_NOT_STRATEGY_FAILURE") } catch (_: Throwable) {}
                liveBuyDeferred(ts, sol, "BUY_DECISION_EXPIRED_RESCORE", "ageMs=$decisionAgeMs lane=$layerTag attempt=${execCtx.attemptId}")
                return false
            }
            val routeProofAtMs = maxOf(ts.tokenMap.updatedAtMs, ts.lastPriceUpdate)
            if (routeProofAtMs > 0L && nowLease - routeProofAtMs > 8_000L) {
                try { RouteTruthHydrator.hydrate(ts) } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("BUY_ROUTE_REFRESH_BEFORE_SIGN") } catch (_: Throwable) {}
            }
        }

        // V5.0.4161 — EXECUTION-HEALTH BUY GATE.
        // ═════════════════════════════════════════════════════════════════
        // Operator dump 2026-06-26 showed Jupiter sr=0% with DNS-fail
        // (`Unable to resolve host "tokens.jup.ag"`) while two trades bled
        // to -71% / -58% on the sell side. The detect-side STRICT_SL /
        // CATASTROPHIC_HARD_BACKSTOP_-25 (V5.0.4160) fired correctly but
        // the SAME doSell pipeline can't broadcast at a clean price when
        // Jupiter is dead — direct route fills at catastrophic loss.
        //
        // Rule: do NOT acquire new bags we cannot safely unwind. If the
        // execution layer is currently dead, defer the buy. This is
        // VOLUME-PRESERVING — `isJupiterHealthy` flips back to true on
        // the FIRST Jupiter success (sr threshold OR fresh-success window),
        // so the meme trader resumes immediately when execution recovers.
        // Self-correcting, no permanent throttle.
        if (com.lifecyclebot.engine.ExecutionHealthGuard.shouldDeferBuy()) {
            try { PipelineHealthCollector.labelInc("BUY_DEFERRED_JUPITER_DEAD_4161") } catch (_: Throwable) {}
            try {
                ForensicLogger.lifecycle(
                    "BUY_DEFERRED_JUPITER_DEAD",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$layerTag sol=${"%.4f".format(sol)} reason=jupiter_unhealthy_no_safe_unwind"
                )
            } catch (_: Throwable) {}
            liveBuyDeferred(ts, sol, "JUPITER_EXECUTION_LAYER_DEAD", "lane=$layerTag — defer until jupiter recovers (self-clears on next success)")
            return false
        }

        // V5.0.4134 — UNIVERSAL LIVE-BUY DISCIPLINE VETO + DUMP REGIME KILL SWITCH.
        //
        var disciplineRecoverySizeMultiplier4460 = 1.0
        var disciplineRecoveryReason4460 = ""

        // V5.0.4133 added rug-blacklist + discipline veto at doBuy(), but at least one
        // path (MOONSHOT shadow-to-live handoff at Executor.kt:8115) calls liveBuy()
        // directly, bypassing doBuy() entirely. Since the comment above (line 8101) is
        // the project's source-of-truth that "liveBuy() is the single executor entry
        // point [for live]", this is where the universal veto belongs.
        //
        // Additionally — operator's 2026-06-25 dump showed:
        //   regime=DUMP wr=7.9% meanPnl=-68.15% n=45
        //   MOONSHOT: pWin=15% E=-76.5% lane×0.18 (all brains screaming KILL)
        // …yet trades kept firing because LaneExpectancyDamper only SIZES DOWN, the
        // discipline gates were bypassed by GOLD/WINNER goose verdicts, and
        // RugMintBlacklist was unconsulted. Net effect: small size × negative EV =
        // slow, certain bleed. Per operator: "winrate under 20%. unacceptable."
        //
        // The kill switch fires when BOTH are true:
        //   1. RegimeDetector.currentRegime() == DUMP
        //   2. Lane WR (StrategyTelemetry live-terminal leaderboard) < 25% with n≥12
        // …and CANNOT be bypassed by GOLD/WINNER. Pattern verdict is irrelevant when
        // the regime AND retrospective WR both agree this lane is dead.
        run {
            val isLive4134 = try { RuntimeModeAuthority.isLive() } catch (_: Throwable) { false }
            if (!isLive4134) return@run
            val mintShort4134 = ts.mint.take(10)
            val laneRaw4134 = layerTag.ifBlank { ts.position?.tradingMode ?: "STANDARD" }
            val laneTag4134 = laneRaw4134.uppercase()

            // (a) Rug-blacklist — non-negotiable, runs ahead of any pattern bypass.
            val rugBL4134 = try { com.lifecyclebot.engine.RugMintBlacklist.isBlacklisted(ts.mint) } catch (_: Throwable) { false }
            if (rugBL4134) {
                try { ForensicLogger.lifecycle("RUG_BLACKLIST_VETO_V4134", "symbol=${ts.symbol} mint=$mintShort4134 lane=$laneTag4134 path=liveBuy.enter") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("RUG_BLACKLIST_VETO_LIVEBUY") } catch (_: Throwable) {}
                try { emitLiveBuyFail(ts, sol, "RUG_BLACKLIST", "mint blacklisted ≤24h ago") } catch (_: Throwable) {}
                onLog("🛑 LIVE rug-blacklist veto: ${ts.symbol}", "discipline")
                return false
            }

            // (b) DUMP-regime kill switch — pattern-verdict-immune.
            // V5.0.4149 — Operator override: "its not meant to disable its meant
            // to pivot to the right strategy." During DUMP, defensive lanes
            // (DIP_HUNTER, QUALITY, TREASURY, CASHGEN, BLUECHIP) are the
            // CORRECT pivot — let them trade. Only kill DUMP-mismatched degen
            // lanes (MOONSHOT, SHITCOIN, EXPRESS, PROJECT_SNIPER, CYCLIC,
            // MANIPULATED) that are bleeding.
            val defensiveLane4149 = laneTag4134 in setOf("DIP_HUNTER", "QUALITY", "TREASURY", "CASHGEN", "BLUECHIP", "STANDARD")
            val regimeDump4134 = try {
                com.lifecyclebot.engine.RegimeDetector.currentRegime() == com.lifecyclebot.engine.RegimeDetector.Regime.DUMP
            } catch (_: Throwable) { false }
            if (regimeDump4134 && !defensiveLane4149) {
                // Use the same telemetry source LiveProbabilityEngine reads from, so the
                // kill-switch sees identical lane WR to the rest of the brain stack.
                val laneMetric4134 = try {
                    com.lifecyclebot.engine.StrategyTelemetry.computeLiveTerminalLeaderboard(limit = 1_500)
                        .firstOrNull { it.strategy.equals(laneTag4134, ignoreCase = true) }
                } catch (_: Throwable) { null }
                val laneWr4134 = laneMetric4134?.winRatePct ?: 100.0
                val laneN4134 = laneMetric4134?.trades ?: 0
                if (laneN4134 >= 12 && laneWr4134 < 25.0) {
                    // V5.0.4568 — INNER-LANE STRATEGY PIVOT, NOT HARD STOP.
                    // V5.0.4572 — runtime showed learned lane probability acting
                    // like paid-bootstrap tuition / zero-size veto while FDG/EXEC
                    // continued to churn. Operator doctrine:
                    // toxic buckets pivot strategy before purchase; do not simply
                    // disable the lane or buy the same setup as dust. Keep execution
                    // alive, tag the lane-local defensive pivot, and let downstream
                    // style/router/tactic layers tighten entry/exit without returning
                    // false from the live-buy choke point.
                    disciplineRecoverySizeMultiplier4460 = minOf(disciplineRecoverySizeMultiplier4460, 0.35)
                    disciplineRecoveryReason4460 = "DUMP_INNER_LANE_DEFENSIVE_PIVOT"
                    try { ForensicLogger.lifecycle("REGIME_INNER_LANE_PIVOT_4568", "symbol=${ts.symbol} mint=$mintShort4134 lane=$laneTag4134 regime=DUMP laneWr=${"%.1f".format(laneWr4134)} n=$laneN4134 path=liveBuy.enter action=continue_defensive_style sizeMult=0.35") } catch (_: Throwable) {}
                    try { PipelineHealthCollector.labelInc("REGIME_INNER_LANE_PIVOT_4568") } catch (_: Throwable) {}
                    onLog("🧭 LIVE DUMP inner-lane pivot: ${ts.symbol} lane=$laneTag4134 WR=${"%.1f".format(laneWr4134)}%", "discipline")
                }
            } else if (regimeDump4134 && defensiveLane4149) {
                try { ForensicLogger.lifecycle("REGIME_PIVOT_LANE_ADMIT_V4149", "symbol=${ts.symbol} mint=$mintShort4134 lane=$laneTag4134 regime=DUMP path=liveBuy.enter") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("REGIME_PIVOT_LANE_ADMIT") } catch (_: Throwable) {}
            }

            // (c) Standard discipline veto — pause/timeout/scanner. GOLD/WINNER still
            //     bypasses these in non-DUMP regimes (per V5.0.4132 design), but the
            //     rug-blacklist + DUMP kill above are immune to it.
            //
            // V5.0.4148 — TOP-PERFORMING-LANE BYPASS for the GLOBAL pause button.
            // Operator dump (2026-06-25 18:34, build 5.0.4147 +115s uptime):
            //   STANDARD lane: WR=38.5% EV=+5.37%/trade  (PROFITABLE, n=15)
            //   MOONSHOT lane: WR=10.5% EV=-24.44%/trade (BLEEDER, n=117)
            //   Global WR=14.7% (dragged down by MOONSHOT's 117 trades)
            // LivePauseButton.isDefensive() is GLOBAL — when global WR<30%, ALL
            // lanes were vetoed, including the profitable STANDARD lane. With
            // STANDARD locked out, the bot couldn't trade its way out of
            // DEFENSIVE because no new outcomes were being recorded. Deadlock.
            //
            // Fix: when a lane appears in LivePauseButton.topLanes (top-3 by WR
            // with n≥3), it bypasses the GLOBAL pause veto only. LaneTimeoutGate
            // (per-lane), ScannerLaneBridge (per source/lane), the rug-blacklist
            // and the DUMP regime kill switch are unchanged — broken lanes stay
            // blocked. STANDARD now keeps trading and seeds fresh WR data;
            // MOONSHOT stays locked by its own per-lane timeout.
            val pauseDefensive4134 = try { com.lifecyclebot.engine.LivePauseButton.isDefensive() } catch (_: Throwable) { false }
            val laneTopPerformer4148 = try { com.lifecyclebot.engine.LivePauseButton.isTopPerformingLane(laneTag4134) } catch (_: Throwable) { false }
            val effectivePause4148 = pauseDefensive4134 && !laneTopPerformer4148
            val laneTimedOut4134 = try { com.lifecyclebot.engine.LaneTimeoutGate.isTimedOut(laneTag4134) } catch (_: Throwable) { false }
            val srcTag4134 = ts.source.ifBlank { "UNKNOWN" }.uppercase()
            val bridgeToxic4134 = try { !com.lifecyclebot.engine.ScannerLaneBridge.shouldRoute(srcTag4134, laneTag4134) } catch (_: Throwable) { false }
            val gooseVerdict4134 = try { com.lifecyclebot.engine.PatternGoldenGoose.edge(ts.name, ts.symbol).verdict } catch (_: Throwable) { com.lifecyclebot.engine.TokenWinMemory.Verdict.NEUTRAL }
            val isHighEdge4134 = gooseVerdict4134 == com.lifecyclebot.engine.TokenWinMemory.Verdict.GOLD || gooseVerdict4134 == com.lifecyclebot.engine.TokenWinMemory.Verdict.WINNER
            if (!isHighEdge4134 && (effectivePause4148 || laneTimedOut4134 || bridgeToxic4134)) {
                val reasonTag4134 = when {
                    effectivePause4148 -> "LIVE_PAUSE_DEFENSIVE"
                    laneTimedOut4134   -> "LANE_TIMEOUT"
                    else               -> "SCANNER_BRIDGE_VETO"
                }
                disciplineRecoverySizeMultiplier4460 = 0.35
                disciplineRecoveryReason4460 = reasonTag4134
                try { ForensicLogger.lifecycle("DISCIPLINE_RECOVERY_PROBE_4460", "symbol=${ts.symbol} mint=$mintShort4134 lane=$laneTag4134 reason=$reasonTag4134 pause=${pauseDefensive4134} topLane=${laneTopPerformer4148} timeout=${laneTimedOut4134} bridge=${bridgeToxic4134} path=liveBuy.enter sizeMult=0.35 action=continue_to_live_buy") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("DISCIPLINE_RECOVERY_PROBE_$reasonTag4134") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("BUY_TIMEOUT_NOT_STRATEGY_FAILURE") } catch (_: Throwable) {}
                onLog("🛡 LIVE $reasonTag4134 recovery probe: ${ts.symbol} lane=$laneTag4134", "discipline")
            }
            if (pauseDefensive4134 && laneTopPerformer4148) {
                try { ForensicLogger.lifecycle("TOP_LANE_BYPASS_V4148", "symbol=${ts.symbol} mint=$mintShort4134 lane=$laneTag4134 globalPause=DEFENSIVE laneIsTopPerformer=true path=liveBuy.enter") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("TOP_LANE_BYPASS") } catch (_: Throwable) {}
            }
        }

        var liveBuyLastStage = "LIVE_BUY_ENTRY"
        fun liveStage(stage: String, detail: String = "") {
            liveBuyLastStage = stage
            try {
                ForensicLogger.lifecycle(stage, "attemptId=${execCtx.attemptId} execMode=${execCtx.execMode} mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$layerTag $detail".trim())
                PipelineHealthCollector.labelInc(stage)
            } catch (_: Throwable) {}
        }
        fun liveAbortDesync(reason: String): Boolean {
            liveStage("LIVE_BUY_ABORTED", "reason=LIVE_MODE_DESYNC detail=$reason")
            try { emitLiveBuyFail(ts, sol, "LIVE_MODE_DESYNC", reason) } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("LIVE_MODE_DESYNC") } catch (_: Throwable) {}
            return false
        }
        val runtimePaper = try { RuntimeModeAuthority.isPaper() } catch (_: Throwable) { cfg().paperMode }
        if (!runtimePaper && execCtx.execMode != ExecMode.LIVE) return liveAbortDesync("runtime.paperMode=false execMode=${execCtx.execMode}")
        if (execCtx.execMode == ExecMode.LIVE) {
            // V5.0.4017 — pre-open TokenState.position is a placeholder whose
            // Position.isPaperPosition default is true. 4016 incorrectly treated
            // that default as live/paper desync and rejected every live BUY before
            // spend (LIVE_MODE_DESYNC=140, BUY ok=0). Only an already-open
            // position can be authoritative about its mode; fresh entry candidates
            // are governed by ExecutionContext + RuntimeModeAuthority until the
            // live position is stamped after tx confirmation.
            val alreadyOpenPosition = try { ts.position.isOpen && (ts.position.qtyToken > 0.0 || ts.position.costSol > 0.0 || ts.position.entryTime > 0L) } catch (_: Throwable) { false }
            val paperFlag = try { alreadyOpenPosition && ts.position.isPaperPosition } catch (_: Throwable) { false }
            val shadowFlag = try { (alreadyOpenPosition && ts.position.tradingMode.equals("SHADOW", true)) || layerTag.equals("SHADOW", true) } catch (_: Throwable) { false }
            if (runtimePaper || paperFlag || shadowFlag) return liveAbortDesync("mode=LIVE runtimePaper=$runtimePaper alreadyOpen=$alreadyOpenPosition positionPaper=$paperFlag shadow=$shadowFlag")
        }
        liveStage("LIVE_BUY_ENTRY", "sol=${"%.4f".format(sol)} score=${"%.1f".format(score)} quality=$quality")

        // V5.0.3923 — consult dormant entry-quality AIs before any execution
        // work begins. Must run BEFORE ExecutionAttemptLease.acquire below so
        // an advisor-block does not leak a lease. Permissive by design — see
        // consultEntryAdvisors() header for thresholds.
        // V5.0.3924 — score parameter passed through so FluidLearningAI's
        // execute floor can be compared against the actual incoming score.
        val advisor = consultEntryAdvisors(ts, score, layerTag)
        if (!advisor.first) {
            ErrorLogger.warn("Executor",
                "🛡️ LIVE_BUY_ADVISOR_BLOCK ${ts.symbol} layer=$layerTag reason=${advisor.second}")
            try {
                ForensicLogger.lifecycle("LIVE_BUY_ADVISOR_BLOCK",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} layer=$layerTag reason=${advisor.second}")
            } catch (_: Throwable) {}
            try {
                ForensicLogger.lifecycle("LIVE_ENTRY_DECISION", "mint=${ts.mint.take(10)} symbol=${ts.symbol} originalLane=${layerTag.ifBlank { "UNKNOWN" }} originalStyle=${layerTag.ifBlank { "UNKNOWN" }} finalLane=LANE_PROOF_DEFER finalStyle=ADVISOR_BLOCK score=${score.fmt(1)} scoreBand=${LiveStylePivotRouter.scoreBand(score)} sizeSol=${sol.fmt(4)} sizeMultiplier=0.00 expectedEdgePct=0 requiredEdgePct=999 basisTrusted=false routeTrusted=false holderProof=false rugProof=false liquidityUsd=${ts.lastLiquidityUsd.toInt()} providerProof=${ts.lastPriceSource.isNotBlank()} pivotApplied=true pivotReasons=ADVISOR_BLOCK:${advisor.second.take(48)} decision=DEFER")
                PipelineHealthCollector.labelInc("LIVE_ENTRY_DECISION")
            } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("LIVE_BUY_ADVISOR_BLOCK") } catch (_: Throwable) {}
            liveStage("LIVE_BUY_ABORTED", "reason=ADVISOR_BLOCK detail=${advisor.second.take(120)}")
            try { emitLiveBuyFail(ts, sol, "LIVE_BUY_ABORTED", "ADVISOR_BLOCK:${advisor.second}") } catch (_: Throwable) {}
            return false
        }

        val entryMarketSnapshot = requireMintEntryMarketSnapshot(ts, "liveBuy")
        if (entryMarketSnapshot == null) {
            emitLiveBuyFail(ts, sol, "ENTRY_MARKET_SNAPSHOT_MISSING_DEFERRED", "price=${ts.lastPrice} mcap=${ts.lastMcap} liq=${ts.lastLiquidityUsd} pool=${ts.lastPricePoolAddr.ifBlank { ts.pairAddress }.take(16)} source=${ts.lastPriceSource.ifBlank { ts.source }}")
            return false
        }

        val resolvedInputLaneForPivot = resolveExecutionLane(ts, identity).ifBlank { "STANDARD" }
        val originalLaneForPivot = layerTag.ifBlank { ts.position.tradingMode.ifBlank { resolvedInputLaneForPivot } }
        val originalStyleForPivot = originalLaneForPivot
        val liveEntryDecision = LiveStylePivotRouter.route(
            ts = ts,
            originalLaneRaw = originalLaneForPivot,
            originalStyleRaw = originalStyleForPivot,
            score = score,
            plannedSizeSol = sol,
            buySlippageBps = cfg().slippageBps,
            basisTrusted = entryMarketSnapshot.valid,
        )
        fun emitLiveEntryDecision(decisionLabel: String = liveEntryDecision.decision) {
            try {
                ForensicLogger.lifecycle(
                    "LIVE_ENTRY_DECISION",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} originalLane=${liveEntryDecision.originalLane} originalStyle=${liveEntryDecision.originalStyle} finalLane=${liveEntryDecision.finalLane} finalStyle=${liveEntryDecision.finalStyle} score=${score.fmt(1)} scoreBand=${LiveStylePivotRouter.scoreBand(score)} sizeSol=${sol.fmt(4)} sizeMultiplier=${liveEntryDecision.sizeMultiplier.fmt(2)} expectedEdgePct=${liveEntryDecision.expectedEdgePct.fmt(1)} requiredEdgePct=${liveEntryDecision.requiredEdgePct.fmt(1)} basisTrusted=${liveEntryDecision.basisTrusted} routeTrusted=${liveEntryDecision.routeTrusted} holderProof=${liveEntryDecision.holderProof} rugProof=${liveEntryDecision.rugProof} liquidityUsd=${liveEntryDecision.liquidityUsd.toInt()} providerProof=${liveEntryDecision.providerProof} pivotApplied=${liveEntryDecision.pivotApplied} pivotReasons=${liveEntryDecision.reasons.joinToString("|")} decision=$decisionLabel"
                )
                PipelineHealthCollector.labelInc("LIVE_ENTRY_DECISION")
            } catch (_: Throwable) {}
        }
        fun canonicalExecutableLane(raw: String): String {
            val r = raw.uppercase().trim().replace('-', '_').replace(' ', '_')
            return when (r) {
                "BLUE_CHIP" -> "BLUECHIP"
                "SHIT_COIN" -> "SHITCOIN"
                "MANIP" -> "MANIPULATED"
                "DIP" -> "DIP_HUNTER"
                "PROJECT", "SNIPER" -> "PROJECT_SNIPER"
                "CASHGEN", "CASH_GENERATION" -> "TREASURY"
                "CORE", "V3" -> "STANDARD"
                else -> r
            }
        }
        val executableLaneSet = setOf("PROJECT_SNIPER", "MOONSHOT", "SHITCOIN", "EXPRESS", "QUALITY", "BLUECHIP", "TREASURY", "STANDARD", "MANIPULATED", "DIP_HUNTER", "CASHGEN")
        fun observeOnlyLiveEntry(reason: String, laneRaw: String, decisionLabel: String): Boolean {
            try {
                val canon = canonicalExecutableLane(laneRaw)
                ForensicLogger.lifecycle(
                    "LIVE_ENTRY_OBSERVED_ONLY",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason source=${ts.source} requestedLane=$laneRaw canonicalLane=$canon decision=$decisionLabel no_buy_plan=true no_exec_lease=true no_buy_failed=true",
                )
                PipelineHealthCollector.labelInc("LIVE_ENTRY_OBSERVED_ONLY")
                PipelineHealthCollector.labelInc(reason)
            } catch (_: Throwable) {}
            return false
        }
        val stylePivotAdvisory = liveEntryDecision.decision == "DEFER"
        if (stylePivotAdvisory) {
            val pivotReasonBucket = liveEntryDecision.reasons.firstOrNull()
                ?.substringBefore(":")
                ?.uppercase()
                ?.replace(Regex("[^A-Z0-9_]+"), "_")
                ?.take(56)
                ?.ifBlank { null } ?: "UNSPECIFIED"
            try {
                PipelineHealthCollector.labelInc("STYLE_PIVOT_ADVISORY_REASON_$pivotReasonBucket")
                ForensicLogger.lifecycle(
                    "STYLE_PIVOT_ADVISORY",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} originalLane=${liveEntryDecision.originalLane} finalLane=${liveEntryDecision.finalLane} reason=$pivotReasonBucket detail=${liveEntryDecision.reasons.joinToString("|").take(180)} no_live_buy_fail=true no_exec_lease=false observe_only=false action=preserve_executable_lane",
                )
            } catch (_: Throwable) {}
            emitLiveEntryDecision("ADVISORY_SHAPE")
        } else {
            emitLiveEntryDecision()
        }
        val effectiveStyleSizeMultiplier = if (stylePivotAdvisory) 1.0 else liveEntryDecision.sizeMultiplier
        val prePivotExecutableLane = listOf(
            layerTag,
            liveEntryDecision.originalLane,
            originalLaneForPivot,
            ts.position.tradingMode,
            identity?.source ?: "",
        ).map { canonicalExecutableLane(it) }.firstOrNull { it in executableLaneSet }.orEmpty()
        val postPivotExecutableLane = canonicalExecutableLane(liveEntryDecision.finalLane.ifBlank { originalLaneForPivot }).takeIf { it in executableLaneSet }.orEmpty()
        val pivotHasExecutionProof = liveEntryDecision.basisTrusted && liveEntryDecision.routeTrusted && liveEntryDecision.providerProof && liveEntryDecision.liquidityUsd > 0.0
        val innerLaneExecutablePivot = postPivotExecutableLane.isNotBlank() && postPivotExecutableLane == prePivotExecutableLane && pivotHasExecutionProof
        val canonicalRoutedLane = when {
            // V5.0.4545 — advisory style shaping must not reroute to a different
            // executable lane. Preserve the pre-pivot lane and let the lane-local
            // style/tactic carry the re-education.
            stylePivotAdvisory -> prePivotExecutableLane
            else -> postPivotExecutableLane.ifBlank { prePivotExecutableLane }
        }
        if (stylePivotAdvisory && innerLaneExecutablePivot) {
            try {
                ForensicLogger.lifecycle(
                    "STYLE_PIVOT_INNER_LANE_EXECUTABLE",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$prePivotExecutableLane style=${liveEntryDecision.finalStyle} basis=${liveEntryDecision.basisTrusted} route=${liveEntryDecision.routeTrusted} provider=${liveEntryDecision.providerProof} liq=${liveEntryDecision.liquidityUsd.toInt()} action=lane_local_authority",
                )
                PipelineHealthCollector.labelInc("STYLE_PIVOT_INNER_LANE_EXECUTABLE")
            } catch (_: Throwable) {}
        }
        val routedLaneTag = canonicalRoutedLane.ifBlank { if (stylePivotAdvisory) originalLaneForPivot else liveEntryDecision.finalLane.ifBlank { originalLaneForPivot } }
        val routedStyleTag = if (stylePivotAdvisory && canonicalRoutedLane == postPivotExecutableLane && postPivotExecutableLane.isNotBlank()) liveEntryDecision.finalStyle.ifBlank { routedLaneTag } else if (stylePivotAdvisory) originalStyleForPivot else liveEntryDecision.finalStyle.ifBlank { routedLaneTag }
        if (canonicalRoutedLane !in executableLaneSet) {
            return observeOnlyLiveEntry("OBSERVE_ONLY_CANON_LANE_UNRESOLVED", routedLaneTag, liveEntryDecision.decision)
        }
        var commonSenseSizeMultiplier4573 = 1.0
        var laneCapitalSizeMultiplier = 1.0
        run {
            val capitalLane = BleederMemoryRouter.canon(canonicalRoutedLane)
            val st = try { BleederMemoryRouter.statsFor(capitalLane) } catch (_: Throwable) { null }
            val toxicShitcoin = capitalLane == "SHITCOIN" && st != null && st.n50 >= 5 && (st.netPnl50Sol <= 0.0 || st.ev50Pct < 0.0 || st.wr50 < 25.0)
            val toxicPresale = capitalLane == "PRESALE_SNIPE" && st != null && st.n20 >= 3 && (st.wr20 <= 0.0 || st.ev20Pct < 0.0)
            if (toxicShitcoin || toxicPresale) {
                val reason = if (toxicShitcoin) "SHITCOIN_NEGATIVE_EV_SIZE_SHAPED" else "PRESALE_SNIPE_NEGATIVE_EV_SIZE_SHAPED"
                laneCapitalSizeMultiplier = if (toxicShitcoin) 0.35 else 0.25
                try {
