                ForensicLogger.lifecycle(
                    "LIVE_BUY_APPROVED_HANDOFF_RECOVERED",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} layer=$layerTag attemptId=$recoveredLiveAttemptId source=liveBuy.entry",
                )
