            } catch (_: Throwable) {}
        }

        // V5.0.3895 — per-mint/per-side execution lease. The global mutex only
        // serializes wallet spend; it does NOT stop one bad mint from retrying on
        // every scanner/lane pass. This lease makes every BUY plan terminal and
        // applies backoff before route/build/submit work begins.
        val buyLeaseProcessor = canonicalRoutedLane.ifBlank { "MEME_LIVE_BUY" }
        val buyLeaseGeneration = try { BotRuntimeController.currentGeneration() } catch (_: Throwable) { 0L }
        val buyLease = ExecutionAttemptLease.acquire(
            side = "BUY",
            mint = ts.mint,
            symbol = ts.symbol,
            processor = buyLeaseProcessor,
            mode = if (RuntimeModeAuthority.isPaper()) "PAPER" else "LIVE",
            generation = buyLeaseGeneration,
        )
        if (!buyLease.allowed) {
            try {
                ForensicLogger.exec(
                    "LIVE_BUY_DEFERRED", ts.symbol,
                    "mint=${ts.mint.take(10)} sol=$sol reason=${buyLease.reason} backoffMs=${buyLease.backoffMs} processor=$buyLeaseProcessor",
                )
            } catch (_: Throwable) {}
            return false
        }
        var buyTerminalRecorded = false
        fun buyAttemptTrace4576(stage: String, detail: String = "") {
            try {
                ForensicLogger.lifecycle(
                    "BUY_ATTEMPT_TRACE_4576",
                    "attemptId=${execCtx.attemptId} mint=${ts.mint.take(10)} symbol=${ts.symbol} stage=$stage lane=$routedLaneTag lastStage=$liveBuyLastStage detail=${detail.take(180)}",
                )
                PipelineHealthCollector.labelInc("BUY_ATTEMPT_TRACE_4576_$stage")
            } catch (_: Throwable) {}
        }
        fun buyTerminalFail(reason: String) {
            if (!buyTerminalRecorded) {
                buyTerminalRecorded = true
                buyAttemptTrace4576("TERMINAL_FAIL", reason)
                ExecutionAttemptLease.terminalFail(buyLease.key, "BUY", ts.mint, ts.symbol, reason, buyLeaseProcessor)
            }
        }
        fun buyTerminalOk(reason: String) {
            if (!buyTerminalRecorded) {
                buyTerminalRecorded = true
                buyAttemptTrace4576("TERMINAL_OK", reason)
                ExecutionAttemptLease.terminalOk(buyLease.key, "BUY", ts.mint, ts.symbol, reason)
            }
        }
        fun missingTokenMapFields(): String {
            val tm = ts.tokenMap
            val miss = mutableListOf<String>()
            if (tm.canonicalTargetMint.isBlank() && ts.mint.isBlank()) miss += "targetMint"
            if (tm.routeStatus.isBlank() || tm.routeStatus == "LIQUIDITY_UNKNOWN_PENDING_TOKEN_MAP") miss += "routeType"
            if (tm.pairAddress.isBlank() && tm.poolAddress.isBlank() && !tm.pumpFunExecutable) miss += "pairAddress/poolAddress"
            if ((tm.liquidityUsd ?: 0.0) <= 0.0 && ts.lastLiquidityUsd <= 0.0) miss += "liquidityUsd"
            if (!tm.dexRouteOk && !tm.pumpFunExecutable && tm.expectedOutAmount <= 0.0) miss += "executableQuote"
            return miss.distinct().joinToString(",").ifBlank { "route_not_executable" }
        }
        liveStage("TOKEN_MAP_START", "source=${ts.source.take(80)}")
        try { TokenMapAuthority.ensureDiscoveryTokenMap(ts, ts.source) } catch (_: Throwable) {}
        val prePlanRouteOk = try { TokenMapAuthority.executableForLiveBuy(ts) } catch (_: Throwable) { false }
        if (!prePlanRouteOk) {
            val missing = missingTokenMapFields()
            liveStage("LIVE_BUY_FAILED", "reason=TOKEN_MAP_INCOMPLETE missing=$missing route=${ts.tokenMap.routeStatus}")
            emitLiveBuyFail(ts, sol, "TOKEN_MAP_INCOMPLETE", "missing=$missing route=${ts.tokenMap.routeStatus}")
            buyTerminalFail("BUY_TERMINAL_ROUTE_FAIL:TOKEN_MAP_INCOMPLETE_$missing")
            return false
        }
        liveStage("TOKEN_MAP_OK", "route=${ts.tokenMap.routeStatus} pair=${ts.tokenMap.pairAddress.take(12)} pool=${ts.tokenMap.poolAddress.take(12)} expectedOut=${ts.tokenMap.expectedOutAmount}")
        run {
            val commonSense = CommonSenseTradePlaybook.assessPreBuy(
                ts = ts,
                lane = routedLaneTag,
                style = routedStyleTag,
                score = score,
                basisTrusted = entryMarketSnapshot.valid,
                routeTrustedFromStyle = liveEntryDecision.routeTrusted,
            )
            if (!commonSense.allowed) {
                // V5.0.6026 — CommonSense is part of the FDG brain chain, not a
                // blind executor-side obstructor. True hard safety/route/proof
