            emitLiveBuyFail(ts, sol, "EMPTY_MINT_OR_SYMBOL")
            buyTerminalFail("BUY_TERMINAL_NO_EXECUTABLE_ROUTE:EMPTY_MINT_OR_SYMBOL")
            return false
        }

        // V5.9.1502 — UNIVERSAL LIVE BLACKLIST / KNOWN-RUGGER HARD VETO.
