                    liveStage("LIVE_BUY_ABORTED", "reason=OBSERVE_ONLY_NOT_LIVE_EXECUTABLE detail=${executableOpen.reason.take(120)}")
                    emitLiveBuyFail(ts, sol, "LIVE_BUY_ABORTED", executableOpen.reason)
