                    traderTag = "MEME",
                )
            } catch (_: Throwable) {}
            PipelineTracer.executorFailed(ts.symbol, ts.mint, "LIVE", "WRONG_TARGET_MINT")
            emitLiveBuyFail(ts, sol, "WRONG_TARGET_MINT")
            // V5.0.4187 — LEASE ORPHAN FIX (A1). V5.0.4186 dump showed 25+
            // EXEC_LEASE_PRUNED_EXPIRED for BUYs. Each silent early-return
            // after lease acquire holds the slot for 30s, choking volume.
            buyTerminalFail("BUY_TERMINAL_WRONG_TARGET_MINT")
            return false
        }

        if (score < 0 || score.isNaN()) {
            // V5.0.4578 — this should be unreachable after score normalization
            // above. Do not resurrect INVALID_SCORE as a hard live-buy veto; keep
            // the attempt alive and let real safety/route/cost gates decide.
            try {
                ForensicLogger.lifecycle("LIVE_BUY_SCORE_STILL_INVALID_AFTER_NORMALIZE_4578", "mint=${ts.mint.take(10)} symbol=${ts.symbol} score=$score action=continue_no_invalid_score_veto")
                PipelineHealthCollector.labelInc("LIVE_BUY_SCORE_STILL_INVALID_AFTER_NORMALIZE_4578")
            } catch (_: Throwable) {}
        }

        // V5.9.1550 — LIVE restore economics. Stale finality/desync can reduce
        // size, but every live buy must still clear all-in round-trip costs.
        val restorePenalty = run {
            val fromGateRaw = finalityVerdict?.takeIf { it.restoreReason.isNotBlank() && it.restoreReason != "NONE" }?.let {
                LiveRestoreExecutionPolicy.Penalty(
                    scorePenalty = it.scorePenalty,
                    sizeMultiplier = it.sizeMultiplier,
                    reason = it.restoreReason,
                    liquidityOverrideUsd = it.liquidityOverrideUsd,
                )
            } ?: LiveRestoreExecutionPolicy.NONE
            val fromGate = if (LiveRestoreExecutionPolicy.isSlotHealthClean()) LiveRestoreExecutionPolicy.NONE else fromGateRaw
            var p = fromGate.combine(LiveRestoreExecutionPolicy.fromRuntimeDrift(LiveRestoreExecutionPolicy.trustedLiquidityUsd(ts, fromGate.liquidityOverrideUsd)))
            val softText = try { ts.safety.softPenalties.joinToString("|") { it.first } } catch (_: Throwable) { "" }
            // V5.9.1565 — DOCTRINE FIX: live = paper twin. The two penalties below
            // were live-only size caps that paper never bore, and they were the
            // root cause of the 2484-paper-trades vs 57-live-trades disparity in
            // operator dump 5.0.3672. Both shrink size below minExecutable on
            // RugCheck-pending / thin-liq tokens — exactly the fresh-launch state
            // where paper takes the trade and prints +119% mean PnL. Rug risk is
            // already priced into score by CorrelationHedgeAI / LiquidityExitPathAI;
            // a size cap here is double-counting. Break-even economics belong on
            // the SELL side (only sell when realised pnl covers cost + treasury
            // split), not as an entry brake.
            //
            // if (softText.contains("Rugcheck pending", true) || softText.contains("RUGCHECK_UNKNOWN_MAX_SIZE_MULT", true)) {
            //     p = p.combine(LiveRestoreExecutionPolicy.Penalty(scorePenalty = -12, sizeMultiplier = 0.35, reason = "RUGCHECK_PENDING_SIZE_CAP", liquidityOverrideUsd = ts.lastLiquidityUsd))
            // }
            // if (softText.contains("Low but non-zero liquidity", true) || softText.contains("Thin live liquidity", true)) {
            //     p = p.combine(LiveRestoreExecutionPolicy.Penalty(scorePenalty = -10, sizeMultiplier = 0.35, reason = "LOW_LIQUIDITY_SIZE_REDUCED", liquidityOverrideUsd = ts.lastLiquidityUsd))
            // }
            // (softText still consumed downstream for telemetry / safety tier.)
            val _suppressedLiveOnlyPenalties = softText // keep softText referenced
            p
        }
        if (restorePenalty.reason != "NONE") {
            if (!LiveRestoreExecutionPolicy.isSafeOrCaution(ts)) {
                val be = LiveRestoreExecutionPolicy.BreakEven(false, sol, 999.0, 0.0, 999.0, "SKIP_BELOW_BREAK_EVEN")
                LiveRestoreExecutionPolicy.logBreakEven(ts, be, restorePenalty)
                try { ForensicLogger.lifecycle("LIVE_RESTORE_SAFETY_TIER_SKIP", "symbol=${ts.symbol} mint=${ts.mint.take(10)} tier=${ts.safety.tier.name} penalty=${restorePenalty.reason}") } catch (_: Throwable) {}
                emitLiveBuyFail(ts, sol, "RESTORE_SAFETY_TIER_SKIP", restorePenalty.reason)
                // V5.0.4187 — LEASE ORPHAN FIX (A3).
                buyTerminalFail("BUY_TERMINAL_RESTORE_SAFETY_TIER_SKIP:${restorePenalty.reason.take(40)}")
                return false
            }
            if (LiveRestoreExecutionPolicy.mintActuallyOpen(ts.mint, ts)) {
                try { ForensicLogger.lifecycle("TRUE_DUPLICATE_OPEN", "symbol=${ts.symbol} mint=${ts.mint.take(10)} penalty=${restorePenalty.reason}") } catch (_: Throwable) {}
                emitLiveBuyFail(ts, sol, "TRUE_DUPLICATE_OPEN", restorePenalty.reason)
                // V5.0.4187 — LEASE ORPHAN FIX (A4).
                buyTerminalFail("BUY_TERMINAL_TRUE_DUPLICATE_OPEN")
                return false
            }
        }
        // V5.0.3847 — ENTRY BREAK-EVEN BYPASS FOR LIVE MICRO-PROBES.
        // Do NOT process live buy size through break-even / cost expectancy.
        // The entry authority is: wallet/rent, common-sense token safety, and
        // executable buy/sell route quote. Break-even economics remain sell-side
        // via LiveRestoreExecutionPolicy.sellSideBreakEvenOk(), where they can
        // decide whether to bank a positive exit after real PnL exists.
        try {
            ForensicLogger.lifecycle(
                "LIVE_ENTRY_BREAK_EVEN_BYPASSED_TO_SELL",
                "symbol=${ts.symbol} mint=${ts.mint.take(10)} requestedSize=${sol.fmt(4)} penalty=${restorePenalty.reason} liq=${ts.lastLiquidityUsd.toInt()} score=${score.fmt(1)}",
            )
        } catch (_: Throwable) {}
        
        // V5.0.4012 — TokenMap is authoritative before live spend.
        run {
            val routeOk = try { TokenMapAuthority.executableForLiveBuy(ts) } catch (_: Throwable) { false }
            if (!routeOk) {
                val verdict = try { TokenMapAuthority.liquidityVerdict(ts) } catch (_: Throwable) { null }
                if (verdict?.hardZero == true || verdict?.sourceIdentityBad == true) {
                    try {
                        ForensicLogger.lifecycle("EXEC_OPEN_ABORT_TERMINAL", "attemptId=${ts.tokenMap.buyAttemptId} mint=${ts.mint.take(10)} symbol=${ts.symbol} stage=TokenMapAuthority reason=${verdict.status} detail=${verdict.reason.take(120)}")
                        PipelineHealthCollector.labelInc("LIVE_BUY_BLOCKED_${verdict.status}")
                    } catch (_: Throwable) {}
                    emitLiveBuyFail(ts, sol, "PRETRADE_HARD_BLOCK", verdict.status)
                    buyTerminalFail("BUY_TERMINAL_NO_EXECUTABLE_ROUTE:TOKEN_MAP_${verdict.status}")
                    return false
                }
                val missing = missingTokenMapFields()
                liveStage("LIVE_BUY_FAILED", "reason=TOKEN_MAP_INCOMPLETE_LATE missing=$missing route=${ts.tokenMap.routeStatus}")
                emitLiveBuyFail(ts, sol, "TOKEN_MAP_INCOMPLETE", "late missing=$missing route=${ts.tokenMap.routeStatus}")
                buyTerminalFail("BUY_TERMINAL_ROUTE_FAIL:TOKEN_MAP_INCOMPLETE_LATE_$missing")
                return false
            }
        }

        // V5.9.756 — extracted to LiveBuyAdmissionGate (Emergent CRITICAL ticket).
        // The V5.9.753 inline gate was only wired into liveBuy. liveTopUp
        // (which routes through tryPumpPortalBuy at line 4523) bypassed it,
        // letting SPARTA / Thucydides / CHING land live without a safety
        // re-check. All live-buy paths now share one admission gate.
        run {
            val decision = com.lifecyclebot.engine.sell.LiveBuyAdmissionGate.requireApprovedLiveBuy(
                ts = ts,
                callSite = "liveBuy.main",
                onLog = onLog,
                onNotify = onNotify,
            )
            if (decision is com.lifecyclebot.engine.sell.LiveBuyAdmissionGate.Decision.Blocked) {
                // V5.9.1539 — INVARIANT: an EXEC_OPEN_ALLOWED candidate must NOT
                // vanish silently. Emit a TERMINAL abort reason here so the
                // lane-release path is no longer a silent BUY_NOT_OPENED. This
                // makes every gate-blocked live buy traceable (operator spec:
                // EXEC_OPEN_ALLOWED → EXEC_LIVE_ATTEMPT | EXEC_OPEN_ABORT_TERMINAL).
                try {
                    ForensicLogger.lifecycle(
                        "EXEC_OPEN_ABORT_TERMINAL",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} stage=LiveBuyAdmissionGate " +
                        "reason=${decision.reasonCode} detail=${decision.detail.take(80)}",
                    )
                } catch (_: Throwable) {}
                // V5.0.3679 — counter increment (LiveBuyAdmissionGate block).
                try { ForensicLogger.exec(
                    "LIVE_BUY_FAIL", ts.symbol,
                    "mint=${ts.mint.take(10)} sol=$sol reason=ADMISSION_GATE:${decision.reasonCode}",
                ) } catch (_: Throwable) {}
                // V5.0.4187 — LEASE ORPHAN FIX (A7). Admission-gate block is
                // a terminal decision for this attempt; release the lease.
                buyTerminalFail("BUY_TERMINAL_ADMISSION_GATE:${decision.reasonCode.take(40)}")
                return false
            }
        }

        var livePendingProofPenalty = false
        var livePendingProofPenaltyDetail = ""

        // V5.0.3706 — RESTORE FINAL LIVE PRE-BROADCAST RUG DEFENSE.
        // This was added in 3692 and removed by the rollback to 3690 parity.
        // LiveBuyAdmissionGate only proves a safety report exists/fresh/not HARD_BLOCK;
        // it does not block RugCheck pending, holder-data pending, active/unknown
        // mint/freeze authority, exact quarantine, or fatal holder concentration.
        // This gate is immediately before live spend/broadcast and is LIVE-only.
        run {
            val preTrade = PreTradeHardGate.requireLiveBuyAllowed(ts, "Executor.liveBuy.main")
            livePendingProofPenalty = preTrade.allowed && preTrade.detail.contains("pending_penalty", ignoreCase = true)
            if (livePendingProofPenalty) livePendingProofPenaltyDetail = preTrade.detail.take(180)
            if (!preTrade.allowed) {
                if (preTrade.reason == "DEFER_SAFETY_PROOF") {
                    try { SafetyRefreshQueue.request(ts.mint) } catch (_: Throwable) {}
                    val tokenMapPending = preTrade.detail.contains("LIQUIDITY_UNKNOWN_PENDING_TOKEN_MAP", ignoreCase = true) || preTrade.detail.contains("TOKEN_MAP_PENDING", ignoreCase = true)
                    if (tokenMapPending) {
                        try { TokenMapAuthority.ensureDiscoveryTokenMap(ts, ts.source) } catch (_: Throwable) {}
                    }
                    // V5.0.3894 — do NOT zero lastSafetyCheck here. BotService now
                    // consumes SafetyRefreshQueue synchronously before FDG. Resetting
                    // timestamps created SAFETY_NOT_READY_MISSING noise and could route
                    // current-structure live candidates into a missing-safety loop.
                    try {
                        PipelineHealthCollector.labelInc(if (tokenMapPending) "LIVE_BUY_DEFERRED_TOKEN_MAP" else "LIVE_BUY_DEFERRED_SAFETY_PROOF")
                        ForensicLogger.lifecycle(
                            if (tokenMapPending) "EXEC_OPEN_DEFERRED_TOKEN_MAP" else "EXEC_OPEN_DEFERRED_SAFETY_PROOF",
                            "attemptId=${ts.tokenMap.buyAttemptId} mint=${ts.mint.take(10)} symbol=${ts.symbol} stage=PreTradeHardGate detail=${preTrade.detail.take(160)} action=hydrate_then_retry no_live_buy_fail=true",
                        )
                        ForensicLogger.exec(
                            "LIVE_BUY_DEFERRED", ts.symbol,
                            "attemptId=${ts.tokenMap.buyAttemptId} mint=${ts.mint.take(10)} sol=$sol reason=${if (tokenMapPending) "TOKEN_MAP_HYDRATION" else "SAFETY_PROOF_HYDRATION"} detail=${preTrade.detail.take(80)}",
                        )
                    } catch (_: Throwable) {}
                    val abortReason = if (tokenMapPending) "TOKEN_MAP_INCOMPLETE" else "SAFETY_PROOF_INCOMPLETE"
                    liveStage("LIVE_BUY_ABORTED", "reason=$abortReason detail=${preTrade.detail.take(120)}")
                    emitLiveBuyFail(ts, sol, abortReason, preTrade.detail)
                    buyTerminalFail("BUY_TERMINAL_ABORTED:$abortReason")
                    return false
                }
                try {
                    ForensicLogger.lifecycle(
                        "EXEC_OPEN_ABORT_TERMINAL",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} stage=PreTradeHardGate reason=${preTrade.reason} detail=${preTrade.detail.take(80)}",
                    )
                    ForensicLogger.exec(
                        "LIVE_BUY_FAIL", ts.symbol,
                        "mint=${ts.mint.take(10)} sol=$sol reason=PRETRADE:${preTrade.reason} detail=${preTrade.detail.take(80)}",
                    )
                } catch (_: Throwable) {}
                try {
                    LiveTradeLogStore.log(
                        LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis()),
                        ts.mint, ts.symbol, "BUY", LiveTradeLogStore.Phase.BUY_FAILED,
                        "PRETRADE_HARD_BLOCK ${preTrade.reason}: ${preTrade.detail.take(120)}",
                        solAmount = sol, traderTag = "MEME",
                    )
                } catch (_: Throwable) {}
                emitLiveBuyFail(ts, sol, "PRETRADE_HARD_BLOCK", preTrade.reason)
                buyTerminalFail("BUY_TERMINAL_NO_EXECUTABLE_ROUTE:PRETRADE_${preTrade.reason}")
                return false
            }
        }

        if (walletSol <= 0) {
            PipelineTracer.executorFailed(ts.symbol, ts.mint, "LIVE", "WALLET_BALANCE_ZERO")
            PipelineTracer.noBuy(ts.symbol, ts.mint, PipelineTracer.NoBuyReason.WALLET_BALANCE_ZERO, "bal=${walletSol}SOL")
            try { ForensicLogger.exec(
                "LIVE_BUY_FAIL", ts.symbol,
                "mint=${ts.mint.take(10)} sol=$sol reason=WALLET_BALANCE_ZERO bal=$walletSol",
            ) } catch (_: Throwable) {}
            // V5.0.4187 — LEASE ORPHAN FIX (A5). Wallet balance is transient
            // (waiting for sell to settle / refund). Use non-terminal release
            // so the bot can immediately retry once wallet rehydrates instead
            // of orphaning the slot for 30s.
            ExecutionAttemptLease.releaseNonTerminal(buyLease.key, "BUY", ts.mint, ts.symbol, "WALLET_BALANCE_ZERO_TRANSIENT")
            buyTerminalRecorded = true
            return false
        }

        // V5.0.3760 — LIVE BUY SOURCE CLAMP. Runtime 3759 showed valid live
        // candidates failing before broadcast for two opposite sizing errors:
        //   • BULL requested 0.2938 SOL with wallet 0.1716 → rejected as
        //     INSUFFICIENT_BALANCE before the existing wallet-rent clamp could run.
        //   • V3 probes requested 0.0004–0.0006 SOL → below real Solana/Jupiter
        //     min executable, causing RENT_RESERVE_TOO_LOW / NO_OPEN_COMMITTED noise.
        // Fix at the final live authority chokepoint: compute spendable wallet SOL
        // after rent reserve, clamp oversized buys down to spendable, and promote
        // sub-min probes to the minimum executable size when capacity exists. If
        // capacity does not exist, reject once with a truthful low-capacity reason.
        val liveRentReserveSol = 0.012
        val liveCfg = cfg()
        val minNonMicroLiveBuySol = liveCfg.minLiveBuySol.coerceAtLeast(0.0)
        val liveMinExecutableBuySol = if (liveCfg.allowLiveMicroProbe) 0.005 else minNonMicroLiveBuySol
        val maxConfigLiveBuySol = liveCfg.maxLiveBuySol.takeIf { it > 0.0 } ?: Double.MAX_VALUE
        val walletRiskCapSol = (walletSol * liveCfg.maxWalletRiskPerTradePct.coerceIn(0.0, 1.0)).takeIf { it > 0.0 } ?: Double.MAX_VALUE
        val maxSpendableSol = minOf(walletSol - liveRentReserveSol, maxConfigLiveBuySol, walletRiskCapSol)
        if (maxSpendableSol < liveMinExecutableBuySol) {
            onLog("⚠️ ${ts.symbol}: skipping buy — wallet too low for non-micro live ticket (${walletSol.fmt(4)}◎ spendable=${maxSpendableSol.fmt(4)}◎ min=${liveMinExecutableBuySol.fmt(4)}◎)", ts.mint)
            PipelineTracer.executorFailed(ts.symbol, ts.mint, "LIVE", "LIVE_ENTRY_REJECTED_SIZE_TOO_THIN_FOR_NON_MICRO_TRADE")
            PipelineTracer.noBuy(ts.symbol, ts.mint, PipelineTracer.NoBuyReason.WALLET_BALANCE_ZERO, "non_micro_min spendable=${maxSpendableSol}SOL min=${liveMinExecutableBuySol}SOL")
            emitLiveBuyFail(ts, maxOf(maxSpendableSol, 0.0), "LIVE_ENTRY_REJECTED_SIZE_TOO_THIN_FOR_NON_MICRO_TRADE", "walletSol=$walletSol spendable=$maxSpendableSol minLiveBuySol=$liveMinExecutableBuySol allowMicro=${liveCfg.allowLiveMicroProbe}")
            buyTerminalFail("BUY_TERMINAL_MIN_NOTIONAL_AFTER_FEES:SIZE_TOO_THIN_FOR_NON_MICRO_TRADE")
            return false
        }
        if (sol > maxSpendableSol) {
            val old = sol
            sol = maxSpendableSol
            try { ForensicLogger.lifecycle("LIVE_BUY_SIZE_CLAMPED_TO_WALLET", "mint=${ts.mint.take(10)} symbol=${ts.symbol} requested=$old spendable=$maxSpendableSol walletSol=$walletSol rentReserve=$liveRentReserveSol maxConfig=$maxConfigLiveBuySol walletRiskCap=$walletRiskCapSol") } catch (_: Throwable) {}
        }
        if (sol < liveMinExecutableBuySol) {
            val old = sol
            sol = liveMinExecutableBuySol
            try { ForensicLogger.lifecycle("LIVE_BUY_SIZE_RAISED_TO_MIN_NON_MICRO", "mint=${ts.mint.take(10)} symbol=${ts.symbol} requested=$old raised=$sol walletSol=$walletSol spendable=$maxSpendableSol allowMicro=${liveCfg.allowLiveMicroProbe}") } catch (_: Throwable) {}
        }
        if (livePendingProofPenalty) {
            val old = sol
            val shaped = (sol * 0.35).coerceAtMost(maxSpendableSol).coerceAtLeast(0.0)
            sol = if (!liveCfg.allowLiveMicroProbe && shaped < liveMinExecutableBuySol) liveMinExecutableBuySol else shaped
            try {
                ForensicLogger.lifecycle(
                    "LIVE_PENDING_PROOF_LEARNED_RISK_CLAMP",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} requested=$old shaped=$sol detail=${livePendingProofPenaltyDetail.take(120)}"
                )
                PipelineHealthCollector.labelInc("LIVE_PENDING_PROOF_LEARNED_RISK_CLAMP")
            } catch (_: Throwable) {}
        }
        val baseRealisticSol = realisticLiveEntrySize(ts, sol, walletSol, score, layerTag.ifBlank { identity?.source ?: ts.source }, "liveBuy.final")
        // Unknown proof lowers confidence and learned risk until proof arrives;
        // it does not force every live buy into a fixed micro cap.
        val realisticSolRaw = if (livePendingProofPenalty) baseRealisticSol * 0.35 else baseRealisticSol
        val realisticSol = if (!liveCfg.allowLiveMicroProbe && realisticSolRaw < liveMinExecutableBuySol) liveMinExecutableBuySol else realisticSolRaw
        if (livePendingProofPenalty && realisticSol < baseRealisticSol) {
            val old = baseRealisticSol
            sol = realisticSol.coerceAtMost(maxSpendableSol).coerceAtLeast(0.0)
            try { ForensicLogger.lifecycle("LIVE_PENDING_PROOF_REALISTIC_SIZE_RISK_SHAPED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} requested=$old shaped=$sol detail=${livePendingProofPenaltyDetail.take(120)}") } catch (_: Throwable) {}
        } else if (realisticSol > maxSpendableSol) {
            val old = realisticSol
            sol = maxSpendableSol
            try { ForensicLogger.lifecycle("LIVE_REALISTIC_SIZE_CLAMPED_TO_SPENDABLE", "mint=${ts.mint.take(10)} symbol=${ts.symbol} requested=$old spendable=$maxSpendableSol walletSol=$walletSol") } catch (_: Throwable) {}
        } else {
            sol = realisticSol
        }
        val assumedSolUsd = 200.0
        // V5.0.4020 — IMPACT CALC LIQUIDITY CASCADE (operator P0: "stabilise
        // our data providers AND fix this issue at the source"). The previous
        // line read ts.lastLiquidityUsd directly and fell to 999% impact
        // whenever the field was 0/NaN — which is exactly what happens for
        // fresh PumpPortal mints when dexscreener/geckoterminal are in
        // backoff (snapshot: dex sr=0% gt sr=0%). That misclassified every
        // unknown-liquidity token as "SIZE_TOO_THIN_FOR_NON_MICRO_TRADE" and
        // turned 217 of 229 BUY attempts into terminal rejects.
        //
        // Fix: when ts.lastLiquidityUsd is missing/NaN, consult the full
        // ProviderProofWalker cascade (Geckoterminal → DexScreener →
        // PumpPortal → PumpFun → Helius → CoinGecko → Jupiter → Birdeye,
        // cross-checked against EfficiencyLayer fused snapshots). Only fall
        // to 999% when every provider AND the fused history is dry — which
        // is the genuine "we don't know if this is liquid enough" state.
        val tsLiq = ts.lastLiquidityUsd
        val liqForImpact: Double = if (tsLiq > 0.0 && !tsLiq.isNaN() && !tsLiq.isInfinite()) {
            tsLiq
        } else {
            try {
                val proof = com.lifecyclebot.engine.ProviderProofWalker.getBestAvailableProof(
                    ts, com.lifecyclebot.engine.ProviderProofWalker.Field.LIQUIDITY_USD
                )
                val v = proof.value
                if (v > 0.0 && !v.isNaN() && !v.isInfinite()) {
                    try {
                        ForensicLogger.lifecycle(
                            "LIVE_IMPACT_LIQ_CASCADE_RESOLVED",
                            "mint=${ts.mint.take(10)} symbol=${ts.symbol} tsLiq=$tsLiq cascadeLiq=$v source=${proof.source} quality=${proof.quality.name} walked=${proof.attempted.size}"
                        )
                    } catch (_: Throwable) {}
                    v
                } else 0.0
            } catch (_: Throwable) { 0.0 }
        }
        val impactPct = if (liqForImpact > 0.0) ((sol * assumedSolUsd) / liqForImpact) * 100.0 else 999.0
        if (!liveCfg.allowLiveMicroProbe && sol < minNonMicroLiveBuySol) {
            emitLiveBuyFail(ts, sol, "LIVE_ENTRY_REJECTED_SIZE_TOO_THIN_FOR_NON_MICRO_TRADE", "finalSol=$sol minLiveBuySol=$minNonMicroLiveBuySol allowMicro=false")
            buyTerminalFail("BUY_TERMINAL_MIN_NOTIONAL_AFTER_FEES:SIZE_TOO_THIN_FOR_NON_MICRO_TRADE")
            return false
        }
        if (impactPct > liveCfg.maxPoolImpactPct) {
            emitLiveBuyFail(ts, sol, "LIVE_ENTRY_REJECTED_SIZE_TOO_THIN_FOR_NON_MICRO_TRADE", "finalSol=$sol impactPct=${impactPct.fmt(3)} maxPoolImpactPct=${liveCfg.maxPoolImpactPct} liquidityUsd=${ts.lastLiquidityUsd} liqForImpact=$liqForImpact cascadeUsed=${liqForImpact != ts.lastLiquidityUsd}")
            buyTerminalFail("BUY_TERMINAL_MIN_NOTIONAL_AFTER_FEES:POOL_IMPACT_TOO_HIGH_FOR_NON_MICRO_TRADE")
            return false
        }
        try {
            ForensicLogger.lifecycle("LIVE_ENTRY_SIZED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} finalSol=${sol.fmt(4)} minLiveBuySol=${minNonMicroLiveBuySol.fmt(4)} impactPct=${impactPct.fmt(3)} maxImpact=${liveCfg.maxPoolImpactPct.fmt(2)} capitalMode=${liveCfg.capitalMode}")
            PipelineHealthCollector.labelInc("LIVE_ENTRY_SIZED")
        } catch (_: Throwable) {}

        // V5.9.611 — LiveExecutionGate is now settlement-pressure only.
        // Daily quota / concurrent ceiling / min spacing are NOT buy blockers:
        // paper is training for live, so live must express the same fluid gates.
        // V5.9.495z52 — use liveMemeOpenCount() (filters out auto-imported
        // wallet dust ATAs, cross-lane CryptoUniverse / Markets positions,
        // and dust-balance residuals) instead of openCount() which counted
        // all 34 phantom records and falsely tripped concurrent_cap=12.
        val openLive = try { TokenLifecycleTracker.liveMemeOpenCount() } catch (_: Throwable) { 0 }
        when (val decision = LiveExecutionGate.tryAcquireBuy(openLive)) {
            is LiveExecutionGate.Decision.Blocked -> {
                ErrorLogger.warn("Executor",
                    "🚦 GATE_BLOCK ${ts.symbol} ${decision.code} | ${decision.reason}")
                PipelineTracer.executorFailed(ts.symbol, ts.mint, "LIVE", "GATE_${decision.code}")
                emitLiveBuyFail(ts, sol, "LIVE_EXECUTION_GATE_${decision.code}", decision.reason)
                buyTerminalFail("BUY_TERMINAL_NO_EXECUTABLE_ROUTE:EXEC_GATE_${decision.code}")
                return false
            }
            LiveExecutionGate.Decision.Allowed -> { /* proceed */ }
        }

        val effectiveSol = sol

        val tradeId = identity ?: TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)

        val currentLayer = "LIVE"
        if (EmergentGuardrails.shouldBlockMultiLayerEntry(tradeId.mint, currentLayer)) {
            val trulyOpen = LiveRestoreExecutionPolicy.mintActuallyOpen(tradeId.mint, ts)
            if (!trulyOpen) {
                try { ForensicLogger.lifecycle("LIVE_RESTORE_ALREADY_OPEN_CORE_SOFT_ALLOW", "symbol=${tradeId.symbol} mint=${tradeId.mint.take(10)} reason=stale_core_not_wallet_or_canonical") } catch (_: Throwable) {}
            } else {
                onLog("⚠ Buy skipped: ${tradeId.symbol} already open in different layer", tradeId.mint)
                PipelineTracer.noBuy(ts.symbol, ts.mint, PipelineTracer.NoBuyReason.ALREADY_IN_POSITION, "TRUE_DUPLICATE_OPEN")
                emitLiveBuyFail(ts, sol, "MULTILAYER_TRUE_DUPLICATE_OPEN")
                buyTerminalFail("BUY_TERMINAL_DUPLICATE_SUPPRESSED:MULTILAYER_TRUE_DUPLICATE_OPEN")
                return false
            }
        }

        val c = cfg()

        if (!security.verifyKeypairIntegrity(wallet.publicKeyB58,
                c.walletAddress.ifBlank { wallet.publicKeyB58 })) {
            onLog("🛑 Keypair integrity failure — trade aborted", tradeId.mint)
            emitLiveBuyFail(ts, sol, "KEYPAIR_INTEGRITY_FAILURE")
            buyTerminalFail("BUY_TERMINAL_SUBMIT_FAIL:KEYPAIR_INTEGRITY_FAILURE")
            return false
        }

        // V5.0.3910 — final wallet-spend mutex boundary. Every cheap/non-wallet
        // rejection has already run. If the wallet is busy now, this candidate is
        // deferred, not failed: no LIVE_BUY_FAIL, no terminal failure/backoff.
        if (!MEME_LIVE_BUY_MUTEX.tryAcquire(MEME_LIVE_BUY_MUTEX_WAIT_MS, java.util.concurrent.TimeUnit.MILLISECONDS)) {
            ErrorLogger.warn("Executor", "[LIVE_BUY_MUTEX_BUSY] ${ts.symbol} — wallet spend in flight; deferring, not failing")
            try {
                ForensicLogger.exec("LIVE_BUY_DEFERRED", ts.symbol,
                    "mint=${ts.mint.take(10)} sol=${"%.4f".format(sol)} reason=MUTEX_BUSY_DEFERRED")
                ForensicLogger.lifecycle("LIVE_BUY_MUTEX_DEFERRED_NON_TERMINAL",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} sol=${"%.4f".format(sol)} stage=wallet_spend_boundary")
                PipelineHealthCollector.labelInc("LIVE_BUY_MUTEX_DEFERRED_NON_TERMINAL")
            } catch (_: Throwable) {}
            liveBuyDeferred(ts, sol, "MUTEX_BUSY_DEFERRED", "lastStage=$liveBuyLastStage")
            // V5.0.4187 — LEASE ORPHAN FIX (A6). Mutex deferral is transient
            // — non-terminal release lets the bot retry immediately once
            // the current wallet spend completes, instead of 30s orphan.
            ExecutionAttemptLease.releaseNonTerminal(buyLease.key, "BUY", ts.mint, ts.symbol, "MUTEX_BUSY_DEFERRED_TRANSIENT")
            buyTerminalRecorded = true
            return false
        }
        liveBuyMutexAcquired = true

        val lamports = (effectiveSol * 1_000_000_000L).toLong()
        val tradeKey = LiveTradeLogStore.keyFor(ts.mint, System.currentTimeMillis())
        LiveTradeLogStore.log(
            tradeKey, ts.mint, ts.symbol, "BUY",
            LiveTradeLogStore.Phase.INFO,
            "🟢 LIVE BUY START | size=${sol.fmt(4)} SOL | wallet=${walletSol.fmt(4)}",
            solAmount = sol,
            traderTag = "MEME",
        )
        try {
            // V5.9.495 — PUMP-FIRST routing for live buys.
            // PumpPortal Lightning's pool="auto" routes through pump.fun
            // bonding curve, PumpSwap AMM, AND Raydium pools. We try it
            // FIRST for every buy. If it 400s (un-routable mint, deep-
            // graduated to Orca/Meteora only) we fall through to the
            // Jupiter Ultra → Metis ladder.
            val pumpVenue = if (com.lifecyclebot.network.PumpFunDirectApi.isPumpFunMint(ts.mint))
                "pump.fun" else "universal-auto"

            val srcUpperForRoute = ts.source.uppercase()
            // V5.0.4559 — buy-route source fix. Runtime 4538 showed BUY ok=0
            // with top intake SCANNER_DIRECT_RAYDIUM_NEW_POOL and BUY fail reason
            // QUOTE_EXHAUSTED. The comment above says PumpPortal Lightning pool=auto
            // routes pump.fun, PumpSwap AMM AND Raydium pools, but the old policy
            // skipped PumpPortal for every source containing RAYDIUM and went
            // straight to Jupiter. Fresh Raydium/new-pool routes often are not
            // available on Jupiter yet, so that created a no-buy choke. Try
            // PumpPortal auto first for Pump/Raydium/PumpSwap discovery routes;
            // keep deep Orca/Meteora as Jupiter-first.
            val deepUnsupportedAmm4559 = srcUpperForRoute.contains("METEORA") || srcUpperForRoute.contains("ORCA")
            val pumpPortalAutoEligible4559 = !deepUnsupportedAmm4559 && (
                com.lifecyclebot.network.PumpFunDirectApi.isPumpFunMint(ts.mint) ||
                    srcUpperForRoute.contains("PUMP_PORTAL") ||
                    srcUpperForRoute.contains("PUMP_FUN_NEW") ||
                    srcUpperForRoute.contains("PUMP_FUN") ||
                    srcUpperForRoute.contains("PUMPSWAP") ||
                    srcUpperForRoute.contains("RAYDIUM_NEW_POOL") ||
                    srcUpperForRoute.contains("SCANNER_DIRECT_RAYDIUM_NEW_POOL")
            )
            val freshPumpRoute = pumpPortalAutoEligible4559
            val pumpBuyPlan = if (!freshPumpRoute) {
                try { ForensicLogger.lifecycle("PUMP_DIRECT_SKIPPED_ROUTE_POLICY", "mint=${ts.mint.take(10)} symbol=${ts.symbol} src=${ts.source.take(80)} reason=deep_amm_use_jupiter_first pumpPortalAutoEligible4559=false") } catch (_: Throwable) {}
                null
            } else recalcBuyPlanForProcessor(
                ts = ts,
                wallet = wallet,
                processor = "PUMPPORTAL_BUY",
                requestedSol = effectiveSol,
                priorityFeeSol = 0.0001,
                jitoTipLamports = effectiveJitoTipLamports(c, urgent = false),
                tradeKey = tradeKey,
                traderTag = "MEME",
            )
            try { ForensicLogger.lifecycle("BUY_ROUTE_REQUESTED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} route=PUMPPORTAL_FIRST sol=${pumpBuyPlan?.solAmount ?: effectiveSol}") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("BUY_ROUTE_REQUESTED") } catch (_: Throwable) {}
            if (pumpBuyPlan != null) {
                try {
                    ForensicLogger.lifecycle("LIVE_BUY_SUBMITTED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} route=PUMPPORTAL requestedSol=${effectiveSol.fmt(4)} finalSol=${pumpBuyPlan.solAmount.fmt(4)} priorityFee=0.0001 quorumMult=${providerQuorumSizeMultiplier.fmt(2)}")
                    PipelineHealthCollector.labelInc("LIVE_BUY_SUBMITTED")
                } catch (_: Throwable) {}
            }
            val pumpFirstResult: Pair<String, Double>? = if (pumpBuyPlan == null) null else tryPumpPortalBuy(
                ts = ts,
                wallet = wallet,
                solAmount = pumpBuyPlan.solAmount,
                slipPct = 10,
                priorityFeeSol = 0.0001,
                useJito = c.jitoEnabled,
                jitoTipLamports = effectiveJitoTipLamports(c, urgent = false),
                tradeKey = tradeKey,
                traderTag = "MEME",
            )

            // V5.9.495 — Jupiter ladder runs ONLY if PUMP-FIRST failed.
            // V5.9.261 — slippage escalation for buys (was: single c.slippageBps call).
            // Memes/low-liq launches phantom out at the default 1% slippage —
            // Jupiter swap reverts internally on price impact, SOL leaves the wallet
            // (TX fees), tokens never arrive. Now we escalate 200→350→500 bps just
            // like liveSell does, so memes actually fill instead of phantoming.
            val buyBaseSlippage = c.slippageBps.coerceAtLeast(200)
            val slippageLadder = listOf(buyBaseSlippage, 350, 500).distinct()
            var quote: com.lifecyclebot.network.SwapQuote? = null
            var lastQuoteError: Exception? = null
            var txResult: com.lifecyclebot.network.SwapTxResult? = null
            var useJito = false
            var jitoTip = 0L
            if (pumpFirstResult == null) {
            // V5.9.495d — explicit Ultra-first signal for forensics.
            // getQuoteWithSlippageGuard internally tries Jupiter Ultra v2
            // first then falls back to v6 Metis on RFQ rejection — log
            // that intent so the operator can see we're escalating from
            // PUMP-FIRST → JUPITER ULTRA, not silently jumping straight
            // to Metis. Operator: "should always revert to ultra".
            LiveTradeLogStore.log(
                tradeKey, ts.mint, ts.symbol, "BUY",
                LiveTradeLogStore.Phase.INFO,
                "↩ FALLBACK → Jupiter Ultra (v2) primary, v6 Metis secondary | ladder=${slippageLadder.joinToString("/")}bps",
                solAmount = sol, traderTag = "MEME",
            )
            // V5.0.3959 — Jupiter quote must never be silent/disabled. Always try it;
            // transient provider errors fail only this quote attempt/candidate.
            for (slip in slippageLadder) {
                buyPhase("QUOTE_REQUESTED")
                LiveTradeLogStore.log(
                    tradeKey, ts.mint, ts.symbol, "BUY",
                    LiveTradeLogStore.Phase.BUY_QUOTE_TRY,
                    "Quote attempt @ ${slip}bps",
                    slippageBps = slip, solAmount = sol, traderTag = "MEME",
                )
                try {
                    val jupiterBuyPlan = recalcBuyPlanForProcessor(
                        ts = ts,
                        wallet = wallet,
                        processor = "JUPITER_ULTRA_METIS_BUY",
                        requestedSol = effectiveSol,
                        priorityFeeSol = 0.0,
                        jitoTipLamports = effectiveJitoTipLamports(c, urgent = false),
                        tradeKey = tradeKey,
                        traderTag = "MEME",
                    ) ?: throw Exception("BUY_BALANCE_PLAN_UNAVAILABLE")
                    quote = getQuoteWithSlippageGuard(
                        JupiterApi.SOL_MINT, ts.mint, jupiterBuyPlan.lamports,
                        slip.coerceAtMost(500), jupiterBuyPlan.solAmount,
                    )
                    if (quote != null) {
                        if (slip != buyBaseSlippage) onLog("BUY: quote OK at ${slip}bps slippage", ts.mint)
                        buyPhase("QUOTE_OK")
                        LiveTradeLogStore.log(
                            tradeKey, ts.mint, ts.symbol, "BUY",
                            LiveTradeLogStore.Phase.BUY_QUOTE_OK,
                            "Quote OK @ ${slip}bps | impact=${quote.priceImpactPct.fmt(2)}% | router=${quote.router.ifBlank { "?" }}",
                            slippageBps = slip, traderTag = "MEME",
                        )
                        break
                    }
                } catch (e: Exception) {
                    lastQuoteError = e
                    val msg = e.message ?: "unknown"
                    val deterministicProviderFailure = false // Jupiter quote never disables/backoff-rotates; exhaust local ladder only.
                    onLog("BUY: quote ${slip}bps failed — ${msg.take(50)}", ts.mint)
                    LiveTradeLogStore.log(
                        tradeKey, ts.mint, ts.symbol, "BUY",
                        LiveTradeLogStore.Phase.BUY_QUOTE_FAIL,
                        "Quote ${slip}bps FAILED: ${msg.take(80)}${if (deterministicProviderFailure) " | rotate_provider_no_ladder_burn" else ""}",
                        slippageBps = slip, traderTag = "MEME",
                    )
                    Thread.sleep(250)
                }
            }
            if (quote == null) {
                onLog("🚫 BUY ABORTED: all slippage levels failed (${slippageLadder.joinToString()}bps): ${lastQuoteError?.message?.take(80)}", ts.mint)
                LiveTradeLogStore.log(
                    tradeKey, ts.mint, ts.symbol, "BUY",
                    LiveTradeLogStore.Phase.BUY_FAILED,
                    "ABORTED — all ${slippageLadder.size} slippage attempts failed",
                    traderTag = "MEME",
                )
                PipelineTracer.executorFailed(ts.symbol, ts.mint, "LIVE", "QUOTE_EXHAUSTED")
                // V5.0.3679 — counter increment so EXEC_LIVE_BUY_FAIL reflects reality.
                try { com.lifecyclebot.engine.ForensicLogger.exec(
                    "LIVE_BUY_FAIL", ts.symbol,
                    "mint=${ts.mint.take(10)} sol=$sol reason=QUOTE_EXHAUSTED",
                ) } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("JUPITER_QUOTE_FAIL") } catch (_: Throwable) {}
                val terminal = "NO_QUOTE:JUPITER_QUOTE_EXHAUSTED"
                buyTerminalFail("BUY_TERMINAL_ROUTE_FAIL:$terminal")
                return false
            }

            val qGuard = security.validateQuote(quote, isBuy = true, inputSol = sol)
            if (qGuard is GuardResult.Block) {
                onLog("🚫 Quote rejected: ${qGuard.reason}", ts.mint)
                LiveTradeLogStore.log(
                    tradeKey, ts.mint, ts.symbol, "BUY",
                    LiveTradeLogStore.Phase.BUY_FAILED,
                    "Quote rejected by SecurityGuard: ${qGuard.reason}",
                    traderTag = "MEME",
                )
                // V5.0.3679 — counter increment.
                try { com.lifecyclebot.engine.ForensicLogger.exec(
                    "LIVE_BUY_FAIL", ts.symbol,
                    "mint=${ts.mint.take(10)} sol=$sol reason=QUOTE_REJECTED:${qGuard.reason.take(60)}",
                ) } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("JUPITER_QUOTE_REJECTED") } catch (_: Throwable) {}
                buyTerminalFail("BUY_TERMINAL_ROUTE_FAIL:QUOTE_REJECTED_${qGuard.reason.take(40)}")
                return false
            }

            // V5.0.4187 — REAL PRICE LOCK on BUY (Fix B1). Operator V5.0.4186
            // dump: bought BCLiquFq, lost -96.1% on the way out. The quote
            // appeared fine at buy time because PumpPortal/PumpFunDirect
            // does NOT surface priceImpactPct (Executor.kt:11358 explicitly
            // sets it to 0.0 for those routers) — so SecurityGuard's
            // MAX_PRICE_IMPACT_PCT=3% guard is bypassed entirely for the
            // bonding-curve universe where most rugs happen. Mitigation:
            // when the primary quote's router is PumpPortal/PumpFunDirect
            // AND priceImpactPct == 0.0 (unsurfaced), request a Jupiter
            // sanity quote on the same notional. If Jupiter (which DOES
            // surface impact) reports impact > 8% on the same buy, abort —
            // the pool liquidity is thinner than the bonding curve claims.
            run {
                val routerStr = try { quote?.router?.uppercase() ?: "" } catch (_: Throwable) { "" }
                val impactUnsurfaced = (quote?.priceImpactPct ?: 0.0) == 0.0
                val isPumpRouter = routerStr.contains("PUMP")
                if (quote != null && impactUnsurfaced && isPumpRouter) {
                    val lamports = try { (effectiveSol * 1_000_000_000L).toLong() } catch (_: Throwable) { 0L }
                    if (lamports > 0L) {
                        val jupSanityQuote = try {
                            jupiter.getQuote(
                                inputMint = JupiterApi.SOL_MINT,
                                outputMint = ts.mint,
                                amountRaw = lamports,
                                slippageBps = 300,
                            )
                        } catch (_: Throwable) { null }
                        if (jupSanityQuote != null) {
                            val jupImpact = jupSanityQuote.priceImpactPct
                            val pumpOut = (quote?.outAmount ?: 0L).toDouble()
                            val jupOut = jupSanityQuote.outAmount.toDouble()
                            val divergencePct = if (pumpOut > 0.0 && jupOut > 0.0) {
                                kotlin.math.abs(pumpOut - jupOut) / pumpOut * 100.0
                            } else 0.0
                            val impactTooHigh = jupImpact > 8.0
                            val divergedTooFar = divergencePct > 25.0
                            if (impactTooHigh || divergedTooFar) {
                                try {
                                    ForensicLogger.lifecycle(
                                        "REAL_PRICE_LOCK_BUY_REJECT",
                                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} router=$routerStr jupImpact=${jupImpact.fmt(2)}% divergence=${divergencePct.fmt(1)}% reason=${if (impactTooHigh) "IMPACT_>8PCT" else "OUT_DIVERGE_>25PCT"} — refusing rug-prone buy",
                                    )
                                    PipelineHealthCollector.labelInc("REAL_PRICE_LOCK_BUY_REJECT")
                                } catch (_: Throwable) {}
                                onLog("🛡 REAL_PRICE_LOCK BUY: ${ts.symbol} jupImpact=${jupImpact.fmt(1)}% div=${divergencePct.fmt(1)}% — rug-prone, aborting", ts.mint)
                                LiveTradeLogStore.log(
                                    tradeKey, ts.mint, ts.symbol, "BUY",
                                    LiveTradeLogStore.Phase.BUY_FAILED,
                                    "RealPriceLock rejected: jupImpact=${jupImpact.fmt(2)}% divergence=${divergencePct.fmt(1)}%",
                                    traderTag = "MEME",
                                )
                                buyTerminalFail("BUY_TERMINAL_REAL_PRICE_LOCK:${if (impactTooHigh) "IMPACT" else "DIVERGE"}")
                                return false
                            } else {
                                try {
                                    ForensicLogger.lifecycle(
                                        "REAL_PRICE_LOCK_BUY_CONFIRMED",
                                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} router=$routerStr jupImpact=${jupImpact.fmt(2)}% divergence=${divergencePct.fmt(1)}% — gain real, proceeding",
                                    )
                                    PipelineHealthCollector.labelInc("REAL_PRICE_LOCK_BUY_CONFIRMED")
                                } catch (_: Throwable) {}
                            }
                        } else {
                            // Jupiter quote unavailable — can't sanity check.
                            // Failure-soft: allow the buy (consistent with sell-side
                            // RealPriceLock policy). Counter logs for visibility.
                            try { PipelineHealthCollector.labelInc("REAL_PRICE_LOCK_BUY_JUP_UNAVAILABLE") } catch (_: Throwable) {}
                        }
                    }
                }
            }

            val txResultLocal = buildTxWithRetry(
                        quote, wallet.publicKeyB58,
                        senderTipLamports = effectiveJitoTipLamports(c, urgent = false),
                    )
            txResult = txResultLocal
            buyPhase("SWAP_BUILT")
            LiveTradeLogStore.log(
                tradeKey, ts.mint, ts.symbol, "BUY",
                LiveTradeLogStore.Phase.BUY_TX_BUILT,
                "Tx built | router=${txResultLocal.router} | rfq=${txResultLocal.isRfqRoute}",
                traderTag = "MEME",
            )

            val simErr = jupiter.simulateSwap(txResultLocal.txBase64, wallet.rpcUrl)
            if (simErr != null) {
                if (simErr.startsWith("RPC error:") || simErr.startsWith("Simulate failed: null")) {
                    // V5.9.753 — Emergent ticket item #2. PREVIOUSLY this branch
                    // proceeded with the broadcast on RPC simulation failure (the
                    // "Sim RPC unavailable — proceeding" path). Operator forensics
                    // showed real funds being committed on the back of a missing
                    // preflight. Live mode must NEVER skip simulation — abort.
                    onLog("🛑 LIVE BUY ABORTED [${ts.symbol}]: simulation RPC unavailable ($simErr)", ts.mint)
                    ErrorLogger.warn("Executor",
                        "[EXECUTION/LIVE_BUY_BLOCKED_SIM_UNAVAILABLE] ${ts.symbol}: $simErr — refusing to broadcast without preflight")
                    LiveTradeLogStore.log(
                        tradeKey, ts.mint, ts.symbol, "BUY",
                        LiveTradeLogStore.Phase.BUY_SIM_FAIL,
                        "LIVE_BUY_BLOCKED_SIM_UNAVAILABLE — ${simErr.take(80)}",
                        traderTag = "MEME",
                    )
                    onNotify("🛑 Live buy aborted",
                        "${ts.symbol} — simulation RPC unavailable",
                        com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
                    PipelineTracer.executorFailed(ts.symbol, ts.mint, "LIVE", "LIVE_BUY_BLOCKED_SIM_UNAVAILABLE")
                    try { PipelineHealthCollector.labelInc("RPC_SIMULATION_UNAVAILABLE") } catch (_: Throwable) {}
                    throw Exception("LIVE_BUY_BLOCKED_SIM_UNAVAILABLE: $simErr")
                } else {
                    // Actual swap simulation failure (bad accounts, insufficient funds, etc.)
                    onLog("Swap simulation failed: $simErr", ts.mint)
                    LiveTradeLogStore.log(
                        tradeKey, ts.mint, ts.symbol, "BUY",
                        LiveTradeLogStore.Phase.BUY_SIM_FAIL,
                        "Sim FAILED: ${simErr.take(120)}",
                        traderTag = "MEME",
                    )
                    throw Exception(simErr)
                }
            } else {
                LiveTradeLogStore.log(
                    tradeKey, ts.mint, ts.symbol, "BUY",
                    LiveTradeLogStore.Phase.BUY_SIM_OK,
                    "Sim OK",
                    traderTag = "MEME",
                )
            }

            security.enforceSignDelay()

            useJito = c.jitoEnabled && !quote.isUltra
            jitoTip = effectiveJitoTipLamports(c, urgent = false)
            
            if (quote.isUltra) {
                onLog("🚀 Broadcasting via Jupiter Ultra (Beam MEV protection)…", ts.mint)
            } else if (useJito) {
                onLog("⚡ Broadcasting buy tx via Jito MEV protection…", ts.mint)
            } else {
                onLog("Broadcasting buy tx…", ts.mint)
            }
            LiveTradeLogStore.log(
                tradeKey, ts.mint, ts.symbol, "BUY",
                LiveTradeLogStore.Phase.BUY_BROADCAST,
                "Broadcasting | route=${if (quote.isUltra) "ULTRA" else if (useJito) "JITO" else "RPC"}",
                traderTag = "MEME",
            )
            try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BUY_BROADCAST", "mint=${ts.mint.take(10)} symbol=${ts.symbol} route=${if (quote.isUltra) "ULTRA" else if (useJito) "JITO" else "RPC"} sol=$sol") } catch (_: Throwable) {}
            }  // end if (pumpFirstResult == null) — Jupiter pipeline only runs when PUMP-FIRST didn't land
            
            val sig: String
            val qty: Double
            val priceImpactPct: Double
            val routerLabel: String
            if (pumpFirstResult != null) {
                liveStage("TX_SUBMIT_START", "route=PUMPPORTAL")
                // V5.9.495 — PUMP-FIRST landed; skip the entire Jupiter pipeline.
                sig = pumpFirstResult.first
                qty = pumpFirstResult.second
                buyPhase("TX_SIGNED")
                try { ForensicLogger.lifecycle("BUY_TX_SUBMITTED", "attemptId=${execCtx.attemptId} mint=${ts.mint.take(10)} symbol=${ts.symbol} route=PUMPPORTAL sig=${sig.take(16)}") } catch (_: Throwable) {}
                liveStage("TX_SUBMITTED", "route=PUMPPORTAL signature=${sig.take(16)}")
                liveStage("FINALITY_CONFIRMED", "route=PUMPPORTAL signature=${sig.take(16)}")
                try { ForensicLogger.lifecycle("LIVE_BUY_CONFIRMED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} route=PUMPPORTAL signature=${sig.take(16)} finalSol=${effectiveSol.fmt(4)}") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("BUY_TX_SUBMITTED"); PipelineHealthCollector.labelInc("LIVE_BUY_CONFIRMED") } catch (_: Throwable) {}
                buyPhase("TX_SUBMITTED")
                buyPhase("TX_CONFIRMED")
                // V5.9.602 — Pump-first gets the same lifecycle ledger as
                // Jupiter: pending intent, confirmed tx, then HELD only after
                // the verifier proves tokens landed.
                try {
                    TokenLifecycleTracker.onBuyPending(ts.mint, ts.symbol, pumpVenue, effectiveSol)
                    TokenLifecycleTracker.onBuyConfirmed(ts.mint, sig)
                    // V5.0.4173 — bust the wallet account cache so the next
                    // wallet read sees the new bag (cache TTL is 5s; this
                    // bust makes the new position visible immediately).
                    com.lifecyclebot.engine.WalletAccountCache.bustNow()
                    // V5.0.3972 — source fix for LIVE_BUY_CONFIRMED_NOT_VISIBLE.
                    // A confirmed buy is live wallet liability immediately. Do not
                    // wait for later price/journal/verifier branches to create the
                    // host-tracker row; any exception between TX_CONFIRMED and the
                    // old later recordBuyPending left canonicalOpen=1 while
                    // hostTrackerOpen/liveOpen=0.
                    HostWalletTokenTracker.recordBuyPending(ts.mint, ts.symbol, sig)
                    try { PipelineHealthCollector.labelInc("HOST_BUY_PENDING_AT_TX_CONFIRMED") } catch (_: Throwable) {}
                    try { ForensicLogger.lifecycle("HOST_BUY_PENDING_AT_TX_CONFIRMED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} route=PUMPPORTAL sig=${sig.take(16)}") } catch (_: Throwable) {}
                } catch (_: Throwable) {}
                priceImpactPct = 0.0  // PumpPortal does not surface impact
                routerLabel = "PUMP_DIRECT [$pumpVenue]"
                onLog("LIVE BUY (PUMP-FIRST): ${ts.symbol} | sig=${sig.take(16)}…", tradeId.mint)
            } else {
                val q = quote!!
                val tx = txResult!!
                val ultraReqId = if (q.isUltra) tx.requestId else null
                try { PipelineHealthCollector.labelInc("JUPITER_SWAP_BUILD_OK") } catch (_: Throwable) {}
                try {
                    ForensicLogger.lifecycle("LIVE_BUY_SUBMITTED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} route=${q.router} requestedSol=${effectiveSol.fmt(4)} finalSol=${sol.fmt(4)} slippageBps=$buyBaseSlippage priorityFee=0 quorumMult=${providerQuorumSizeMultiplier.fmt(2)}")
                    PipelineHealthCollector.labelInc("LIVE_BUY_SUBMITTED")
                } catch (_: Throwable) {}
                liveStage("TX_SUBMIT_START", "route=${q.router}")
                sig = wallet.signSendAndConfirm(tx.txBase64, useJito, jitoTip, ultraReqId, c.jupiterApiKey, tx.isRfqRoute, tx.senderCompatible)
                buyPhase("TX_SIGNED")
                try { ForensicLogger.lifecycle("BUY_TX_SUBMITTED", "attemptId=${execCtx.attemptId} mint=${ts.mint.take(10)} symbol=${ts.symbol} route=${q.router} sig=${sig.take(16)}") } catch (_: Throwable) {}
                liveStage("TX_SUBMITTED", "route=${q.router} signature=${sig.take(16)}")
                liveStage("FINALITY_CONFIRMED", "route=${q.router} signature=${sig.take(16)}")
                try { ForensicLogger.lifecycle("LIVE_BUY_CONFIRMED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} route=${q.router} signature=${sig.take(16)} finalSol=${sol.fmt(4)}") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("BUY_TX_SUBMITTED"); PipelineHealthCollector.labelInc("LIVE_BUY_CONFIRMED") } catch (_: Throwable) {}
                buyPhase("TX_SUBMITTED")
                try { PipelineHealthCollector.labelInc("JUPITER_CONFIRM_OK") } catch (_: Throwable) {}
                buyPhase("TX_CONFIRMED")
                LiveTradeLogStore.log(
                    tradeKey, ts.mint, ts.symbol, "BUY",
                    LiveTradeLogStore.Phase.BUY_CONFIRMED,
                    "✅ Tx confirmed on-chain — awaiting token-arrival verification",
                    sig = sig, traderTag = "MEME",
                )
                try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BUY_CONFIRMED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} signature=${sig.take(16)} route=${q.router}") } catch (_: Throwable) {}
                // V5.9.495z28 (operator spec item 3): record into authoritative
                // lifecycle ledger keyed by mint. onBuyPending is called BEFORE
                // broadcast (registers the intent); onBuyConfirmed flips it
                // once the tx signature is on-chain. The wallet reconciler
                // then verifies token arrival → onTokenLanded → HELD.
                try {
                    TokenLifecycleTracker.onBuyPending(ts.mint, ts.symbol, "jupiter", sol)
                    TokenLifecycleTracker.onBuyConfirmed(ts.mint, sig)
                    // V5.0.3972 — source fix for LIVE_BUY_CONFIRMED_NOT_VISIBLE.
                    // Jupiter confirmed buys must create host-tracker fresh-buy
                    // liability at the same source point as lifecycle confirmation.
                    HostWalletTokenTracker.recordBuyPending(ts.mint, ts.symbol, sig)
                    try { PipelineHealthCollector.labelInc("HOST_BUY_PENDING_AT_TX_CONFIRMED") } catch (_: Throwable) {}
                    try { ForensicLogger.lifecycle("HOST_BUY_PENDING_AT_TX_CONFIRMED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} route=${q.router} sig=${sig.take(16)}") } catch (_: Throwable) {}
                } catch (_: Throwable) {}
                priceImpactPct = q.priceImpactPct
                routerLabel = q.router
                // qty derived from quote.outAmount AFTER price check below
                qty = -1.0  // sentinel; recalculated below
            }

            val price = getActualPrice(ts)
            if (price <= 0.0) {
                throw Exception("Invalid normalized price for ${ts.symbol}")
            }
            val finalQty: Double = if (pumpFirstResult != null) qty
                else rawTokenAmountToUiAmount(ts, quote!!.outAmount, solAmount = sol, priceUsd = price)

            if (ts.position.isOpen) {
                // V5.0.4576 — SOURCE FIX, not just telemetry. This idempotent
                // success path used to return true before the normal BUY journal /
                // LIVE_POSITION_STAMPED section. That made real confirmed/open buys
                // show up as ok/proofed while missing from journal-derived rows.
                // Backfill exactly one BUY row per signature, then terminal-ok the
                // attempt. This preserves duplicate safety while making the buy real
                // to StrategyTruthLedger / learning / reports.
                onLog("✅ Position opened during confirmation wait — late-confirm success (idempotent)", ts.mint)
                val existingPos4576 = ts.position
                val journalKey4576 = sig.ifBlank { "${ts.mint}:${existingPos4576.entryTime}:${existingPos4576.costSol}" }
                if (liveBuyJournaledSigs4576.add(journalKey4576)) {
                    val recoveredBuy4576 = Trade(
                        side = "BUY",
                        mode = "live",
                        sol = existingPos4576.costSol.takeIf { it > 0.0 } ?: sol,
                        price = existingPos4576.entryPrice.takeIf { it > 0.0 } ?: price,
                        ts = existingPos4576.entryTime.takeIf { it > 0L } ?: System.currentTimeMillis(),
                        score = existingPos4576.entryScore.takeIf { it > 0.0 } ?: score,
                        sig = sig,
                        tradingMode = existingPos4576.tradingMode.ifBlank { routedLaneTag.ifBlank { layerTag.ifBlank { "STANDARD" } } },
                        tradingModeEmoji = existingPos4576.tradingModeEmoji.ifBlank { layerTagEmoji.ifBlank { "📈" } },
                        entryPriceSnapshot = existingPos4576.entryPrice.takeIf { it > 0.0 } ?: price,
                        entryMcapUsd = existingPos4576.entryMcap.takeIf { it > 0.0 } ?: entryMarketSnapshot.marketCapUsd,
                        entryCostSol = existingPos4576.costSol.takeIf { it > 0.0 } ?: sol,
                        entryQtyToken = existingPos4576.qtyToken.takeIf { it > 0.0 } ?: finalQty,
                        remainingQtyToken = existingPos4576.qtyToken.takeIf { it > 0.0 } ?: finalQty,
                        entryPriceSource = existingPos4576.entryPriceSource.ifBlank { entryMarketSnapshot.priceSource },
                        entryPoolAddress = existingPos4576.entryPoolAddress.ifBlank { entryMarketSnapshot.poolAddress },
                        reason = "BUY_ALREADY_OPEN_AT_CONFIRM_BACKFILL_4576",
                    )
                    recordTrade(ts, recoveredBuy4576)
                    security.recordTrade(recoveredBuy4576)
                    liveStage("JOURNAL_WRITE_OK", "alreadyOpenAtConfirm=true signature=${sig.take(16)} lane=${recoveredBuy4576.tradingMode}")
                    try {
                        com.lifecyclebot.engine.PipelineHealthCollector.labelInc("LIVE_BUY_JOURNAL_BACKFILLED_4576")
                        com.lifecyclebot.engine.PipelineHealthCollector.labelInc("LIVE_POSITION_STAMPED")
                        com.lifecyclebot.engine.ForensicLogger.lifecycle(
                            "LIVE_BUY_JOURNAL_BACKFILLED_4576",
                            "attemptId=${execCtx.attemptId} symbol=${ts.symbol} mint=${ts.mint.take(10)} sig=${sig.take(16)} lane=${recoveredBuy4576.tradingMode} sol=${recoveredBuy4576.sol} reason=POSITION_ALREADY_OPEN_AT_CONFIRM"
                        )
                        com.lifecyclebot.engine.ForensicLogger.lifecycle(
                            "LIVE_POSITION_STAMPED",
                            "attemptId=${execCtx.attemptId} mint=${ts.mint.take(10)} symbol=${ts.symbol} finalSol=${recoveredBuy4576.sol.fmt(4)} route=$routerLabel signature=${sig.take(16)} reason=already_open_backfill_4576"
                        )
                    } catch (_: Throwable) { }
                } else {
                    try {
                        com.lifecyclebot.engine.PipelineHealthCollector.labelInc("LIVE_BUY_JOURNAL_BACKFILL_DUP_SUPPRESSED_4576")
                        com.lifecyclebot.engine.ForensicLogger.lifecycle("LIVE_BUY_JOURNAL_BACKFILL_DUP_SUPPRESSED_4576", "mint=${ts.mint.take(10)} symbol=${ts.symbol} sig=${sig.take(16)}")
                    } catch (_: Throwable) { }
                }
                try {
                    com.lifecyclebot.engine.PipelineHealthCollector.labelInc("BUY_OK_LATE_CONFIRMED")
                    com.lifecyclebot.engine.PipelineHealthCollector.labelInc("LIVE_POSITION_ALREADY_OPEN_AT_CONFIRM_4576")
                    com.lifecyclebot.engine.ForensicLogger.lifecycle(
                        "BUY_OK_LATE_CONFIRMED",
                        "attemptId=${execCtx.attemptId} symbol=${ts.symbol} mint=${ts.mint.take(8)} reason=POSITION_ALREADY_OPEN_AT_CONFIRM action=journal_backfilled_terminal_ok"
                    )
                    buyAttemptTrace4576("POSITION_ALREADY_OPEN_AT_CONFIRM", "pendingVerify=${ts.position.pendingVerify} qty=${ts.position.qtyToken}")
                } catch (_: Throwable) { }
                liveStage("POSITION_TRACKED", "alreadyOpenAtConfirm=true signature=${sig.take(16)} pendingVerify=${ts.position.pendingVerify}")
                buyTerminalOk("BUY_TERMINAL_OK:POSITION_ALREADY_OPEN_AT_CONFIRM")
                return true
            }

            val tokenAgeMs = System.currentTimeMillis() - ts.addedToWatchlistAt
            val hasWhales = ts.meta.whaleSummary.isNotBlank()
            val currentMode = try {
                UnifiedModeOrchestrator.recommendModeForToken(
                    liquidity = ts.lastLiquidityUsd,
                    mcap = ts.lastMcap,
                    ageMs = tokenAgeMs,
                    volScore = ts.meta.volScore,
                    momScore = ts.meta.momScore,
                    source = ts.source,
                    emafanAlignment = ts.meta.emafanAlignment,
                    holderConcentration = ts.safety.topHolderPct,
                    isRevival = ts.source.contains("REVIVAL", ignoreCase = true),
                    hasWhaleActivity = hasWhales,
                )
            } catch (e: Exception) {
                try { UnifiedModeOrchestrator.getCurrentPrimaryMode() } 
                catch (_: Exception) { UnifiedModeOrchestrator.ExtendedMode.STANDARD }
            }

            val livePolicySnapshot = buildTradePolicySnapshot(
                ts = ts,
                mode = "LIVE",
                lane = routedLaneTag,
                style = routedStyleTag,
                score = score,
                plannedSol = requestedSolForPolicy,
                finalSol = sol,
                reasons = liveEntryDecision.reasons + listOf(
                    "wr=${wrSizeMult.fmt(2)}",
                    "style=${effectiveStyleSizeMultiplier.fmt(2)}",
                    "provider=${providerQuorumSizeMultiplier.fmt(2)}",
                    "laneCap=${laneCapitalSizeMultiplier.fmt(2)}",
                ),
                extra = "decision=${liveEntryDecision.decision};attempt=${recoveredLiveAttemptId.ifBlank { finalityVerdict?.attemptId ?: "" }}",
            )
            ts.lastPolicySnapshot = livePolicySnapshot
            ts.position = Position(
                qtyToken     = finalQty,
                entryPrice   = price,
                entryTime    = System.currentTimeMillis(),
                costSol      = sol,
                highestPrice = price,
                entryPhase   = ts.phase,
                entryScore   = score,
                entryLiquidityUsd = entryMarketSnapshot.liquidityUsd,
                entryMcap    = entryMarketSnapshot.marketCapUsd,
                isPaperPosition = false,
                // V5.9.386 — sub-trader tag carries through live buy too.
                tradingMode  = routedLaneTag.ifBlank { if (layerTag.isNotBlank()) layerTag else currentMode.name },
                tradingModeEmoji = if (layerTagEmoji.isNotBlank()) layerTagEmoji else currentMode.emoji,
                entryPolicySnapshot = livePolicySnapshot,
                // V5.9.602 — ALL live buys, including Pump-first, remain
                // pending until tx/wallet verification proves token arrival.
                // A submitted/confirmed signature alone is not enough; Solana
                // txs can confirm with no desired token delta or index late.
                pendingVerify = true,
                // V5.9.744 — pricing-context snapshot. See paperBuy for the
                // full diagnosis. For LIVE buys this matters even more: a
                // position opened against a PUMP_FUN_BC_SYNTHETIC quote then
                // measured against a DEXSCREENER_WS pool quote at exit time
                // produces real-money phantom-PnL prints. Snapshot + rebase
                // logic in getActualPrice keeps PnL honest across the BC→pool
                // graduation jump.
                entryPriceSource = entryMarketSnapshot.priceSource,
                entryPoolAddress = entryMarketSnapshot.poolAddress,
                entryDex         = entryMarketSnapshot.dex,
                entrySupplyAssumed = if (entryMarketSnapshot.priceSource == "PUMP_FUN_BC_SYNTHETIC" ||
                                          entryMarketSnapshot.priceSource == "PUMP_FUN_FRONTEND_API")
                    1_000_000_000.0 else 0.0,
                // V5.0.4125 — Apply AGI style TP multiplier at live position creation.
                // Same bridge as paperBuy: fluidTP * styleTpMult = exit target.
                entryTakeProfitPct = try {
                    val baseFluidTp = com.lifecyclebot.v3.scoring.FluidLearningAI
                        .getFluidTakeProfit(cfg().exitScoreThreshold.coerceAtLeast(20.0))
                    (baseFluidTp * ts.styleTpMult).coerceIn(5.0, 500.0)
                } catch (_: Throwable) { 0.0 },
            )
            val trade = Trade(
                side = "BUY", 
                mode = "live", 
                sol = sol, 
                price = price, 
                ts = System.currentTimeMillis(),
                score = score, 
                sig = sig,
                // V5.9.386 — sub-trader tag in journal
                tradingMode = routedLaneTag.ifBlank { if (layerTag.isNotBlank()) layerTag else currentMode.name },
                tradingModeEmoji = if (layerTagEmoji.isNotBlank()) layerTagEmoji else currentMode.emoji,
                entryPriceSnapshot = price,
                entryMcapUsd = entryMarketSnapshot.marketCapUsd,
                entryCostSol = sol,
                entryQtyToken = if (price > 0.0) sol / price else 0.0,
                remainingQtyToken = if (price > 0.0) sol / price else 0.0,
                entryPriceSource = entryMarketSnapshot.priceSource,
                entryPoolAddress = entryMarketSnapshot.poolAddress,
            )
            val normalBuyJournalKey4576 = sig.ifBlank { "${ts.mint}:${trade.ts}:${trade.sol}" }
            if (liveBuyJournaledSigs4576.add(normalBuyJournalKey4576)) {
                recordTrade(ts, trade)
            } else {
                try {
                    ForensicLogger.lifecycle("LIVE_BUY_JOURNAL_DUP_SUPPRESSED_4576", "mint=${ts.mint.take(10)} symbol=${ts.symbol} sig=${sig.take(16)} lane=${trade.tradingMode}")
                    PipelineHealthCollector.labelInc("LIVE_BUY_JOURNAL_DUP_SUPPRESSED_4576")
                } catch (_: Throwable) {}
            }
            liveStage("JOURNAL_WRITE_OK", "signature=${sig.take(16)} lane=${trade.tradingMode}")
            buyAttemptTrace4576("POSITION_STAMPED", "route=$routerLabel signature=${sig.take(16)} lane=${trade.tradingMode}")
            try {
                ForensicLogger.lifecycle("LIVE_POSITION_STAMPED", "attemptId=${execCtx.attemptId} mint=${ts.mint.take(10)} symbol=${ts.symbol} positionId=${trade.positionId.ifBlank { tradeId.mint.take(10) }} finalSol=${sol.fmt(4)} route=$routerLabel signature=${sig.take(16)} policy=${livePolicySnapshot.take(220)}")
                PipelineHealthCollector.labelInc("LIVE_POSITION_STAMPED")
                PipelineHealthCollector.labelInc("TRADE_POLICY_SNAPSHOT_STAMPED_4193")
            } catch (_: Throwable) {}
            buyPhase("BUY_JOURNALED")
            security.recordTrade(trade)

            // V5.9.602 — no route gets inline HELD registration here.
            // Pump-first and Jupiter both create a pending live position, then
            // the common verifier below promotes it only after tx/wallet proof
            // shows tokens actually landed. This prevents ghost positions where
            // a submitted/confirmed tx signature produced no wallet token delta.

            // V5.9.15: PHANTOM GUARD — DO NOT persist or register in guardrails until
            // post-buy verification confirms tokens actually arrived on-chain.
            // Previously these ran immediately, leaking phantoms into UI + persistence.
            
            sounds?.playBuySound()
            
            // V5.7.3: Split trading fee across two wallets (V5.9.1451: 0.5%/side, 1% round-trip)
            try {
                val feeAmountSol = sol * MEME_TRADING_FEE_PERCENT
                if (feeAmountSol >= FEE_SEND_MIN_SOL) {
                    val feeWallet1 = feeAmountSol * FEE_SPLIT_RATIO
                    val feeWallet2 = feeAmountSol * (1.0 - FEE_SPLIT_RATIO)
                    
                    // V5.9.1504 — single resolver call handles BOTH shares,
                    // redirecting any self-addressed fee wallet to the other.
                    sendFeeSplit(wallet, feeWallet1, feeWallet2, "fee")
                    
                    onLog("💸 TRADING FEE: ${String.format("%.6f", feeAmountSol)} SOL (0.5% of $sol) split 50/50", tradeId.mint)
                    ErrorLogger.info("Executor", "💸 LIVE BUY FEE: ${feeAmountSol} SOL split to both wallets")
                }
            } catch (feeEx: Exception) {
                ErrorLogger.error("Executor", "🚨 FEE SEND FAILED — TRADING fee NOT sent, will retry next trade: ${feeEx.message}")
                // V5.9.226: Bug #7 — enqueue for retry
                val feeAmt4 = sol * MEME_TRADING_FEE_PERCENT
                if (feeAmt4 >= FEE_SEND_MIN_SOL) {
                    FeeRetryQueue.enqueue(TRADING_FEE_WALLET_1, feeAmt4 * FEE_SPLIT_RATIO, "buy_fee_w1")
                    FeeRetryQueue.enqueue(TRADING_FEE_WALLET_2, feeAmt4 * (1.0 - FEE_SPLIT_RATIO), "buy_fee_w2")
                }
            }
            
            tradeId.executed(price, sol, isPaper = false, signature = sig)
            try {
                com.lifecyclebot.engine.ForensicLogger.lifecycle(
                    "LIVE_POSITION_CONFIRMED_FROM_SIGNATURE",
                    "symbol=${ts.symbol} mint=${ts.mint.take(10)} sol=$sol price=$price signature=${sig.take(16)}"
                )
            } catch (_: Throwable) {}

            // V5.0.3705 — LIVE BUY MANAGEMENT HANDOFF.
            // Operator 2026-06-15: live buys land in Phantom but bot shows open=0
            // and leaves them unmanaged. Root pattern: the buy signature is confirmed
            // and a BUY journal row is written, but wallet/tx indexers can return empty
            // maps for 60s+. During that window pendingVerify=true makes Position.isOpen
            // false, and the legacy pending-only tracker refuses to track it.
            // Result: real wallet tokens with no exit monitor. Once a live swap returns a
            // non-blank signature and expected token qty/cost, record a pending buy only.
            // The verifier below must produce authoritative owner/mint BalanceProof
            // before the position becomes OPEN_TRACKING / sellable.
            val signatureManagedAtEntry: Boolean = try {
                val provisional = ts.position
                if (!provisional.isPaperPosition && provisional.pendingVerify && provisional.qtyToken > 0.0 && sig.isNotBlank()) {
                    // V5.0.3757 — proof-first live buy doctrine.
                    // A broadcast/confirmed signature is not sell authority. Do not flip
                    // pendingVerify=false, do not OPEN_TRACKING, and do not call legacy
                    // the legacy live final path here. The verifier below must produce an
                    // authoritative BalanceProof and then call recordBuyConfirmedWithProof().
                    try { HostWalletTokenTracker.recordBuyPending(ts.mint, ts.symbol, sig) } catch (_: Throwable) {}
                    try {
                        com.lifecyclebot.engine.ForensicLogger.lifecycle(
                            "BUY_PENDING_BALANCE_PROOF",
                            "mint=${ts.mint.take(10)} symbol=${ts.symbol} sig=${sig.take(16)} reason=SIGNATURE_CONFIRMED_AWAITING_BALANCE_PROOF provisionalQty=${provisional.qtyToken}"
                        )
                    } catch (_: Throwable) {}
                    try { ExecutionRootCauseTrace.authority("BUY", "BUY_CONFIRMED_AWAITING_BALANCE_PROOF", ts, "sig=${sig.take(16)} provisionalQty=${provisional.qtyToken} pendingVerify=${provisional.pendingVerify}") } catch (_: Throwable) {}
                    false
                } else false
            } catch (_: Throwable) { false }
            tradeId.monitoring()
            
            TradeLifecycle.executed(tradeId.mint, price, sol)
            TradeLifecycle.monitoring(tradeId.mint, 0.0)

            EdgeLearning.recordEntry(
                mint = tradeId.mint,
                symbol = tradeId.symbol,
                buyPct = ts.meta.pressScore,
                volumeScore = ts.meta.volScore,
                phase = ts.phase,
                edgeQuality = quality,
                wasVetoed = false,
                vetoReason = null,
                entryPrice = price,
                isPaperMode = false,
            )
            
            val entryConditionsLive = EntryIntelligence.EntryConditions(
                buyPressure = ts.meta.pressScore,
                volumeScore = ts.meta.volScore,
                priceVsEma = ts.meta.posInRange - 50.0,
                rsi = ts.meta.rsi,
                momentum = ts.entryScore,
                hourOfDay = java.util.Calendar.getInstance(java.util.TimeZone.getTimeZone("UTC")).get(java.util.Calendar.HOUR_OF_DAY),
                volatility = ts.meta.avgAtr,
                liquidityUsd = ts.lastLiquidityUsd,
                topHolderPct = ts.safety.topHolderPct,
                isNearSupport = ts.meta.posInRange < 25.0,
                isNearResistance = ts.meta.posInRange > 75.0,
                candlePattern = "none",
            )
            EntryIntelligence.recordEntry(tradeId.mint, entryConditionsLive)
            
            LiquidityDepthAI.recordEntryLiquidity(tradeId.mint, ts.lastLiquidityUsd)
            
            onLog("LIVE BUY  @ ${price.fmt()} | ${sol.fmt(4)} SOL | " +
                  "impact=${priceImpactPct.fmt(2)}% | router=${routerLabel} | sig=${sig.take(16)}…", tradeId.mint)
            onNotify("✅ Live Buy", "${tradeId.symbol}  ${sol.fmt(3)} SOL", com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
            
            TradeAlerts.onBuy(cfg(), tradeId.symbol, sol, score, walletSol, ts.position.tradingMode, isPaper = false)

            // V5.9.170 — stamp entry reason (LIVE mode) into firehose.
            try {
                val reason = buildString {
                    append(ts.position.tradingMode.ifBlank { "LIVE" })
                    if (ts.phase.isNotBlank()) { append("|phase="); append(ts.phase) }
                    append("|q=$quality")
                    append("|src=${ts.source.ifBlank { "UNKNOWN" }}")
                    if (ts.meta.emafanAlignment.isNotBlank()) { append("|emafan="); append(ts.meta.emafanAlignment) }
                }
                com.lifecyclebot.v3.scoring.EducationSubLayerAI.recordEntryReason(
                    mint = tradeId.mint,
                    traderSource = ts.position.tradingMode.ifEmpty { "MEME" },  // V5.9.320: was hardcoded "Meme"
                    reason = reason,
                    scoreHint = score,
                )
            } catch (_: Exception) {}
            
            onToast("✅ LIVE BUY: ${tradeId.symbol}\n${sol.fmt(4)} SOL @ ${price.fmt()}")
            
            GlobalScope.launch(AppDispatchers.sideEffect) {
                try {
                    val aiLayers = mapOf(
                        "Entry Score" to "${score.toInt()}/100",
                        "Phase" to ts.phase,
                        "Quality" to quality,
                        "Buy Pressure" to "${ts.meta.pressScore.toInt()}%",
                        "Volume" to "${ts.meta.volScore.toInt()}%",
                    )
                    val reasoning = GeminiCopilot.explainTrade(
                        ts = ts,
                        action = "BUY",
                        entryScore = score,
                        exitScore = ts.exitScore,
                        aiLayers = aiLayers,
                    )
                    if (reasoning != null) {
                        onLog("🤖 GEMINI: ${reasoning.humanSummary.take(100)}", tradeId.mint)
                    }
                } catch (_: Exception) {}
            }

            // V5.9.15 / V5.9.102: PHANTOM GUARD — verify tokens on-chain BEFORE lifting the
            // pendingVerify flag. UI, persistence, and exit loops skip pending positions.
            // V5.9.102 upgrade: original 8s window was too short on congested
            // Solana RPC and incorrectly wiped real positions as "phantoms"
            // (user's friend ended up with FOF/ASTRA/SWIF tokens on-chain
            // that the bot had forgotten about entirely). Changes:
            //   • Poll 5 times at 6s intervals (up to ~30s total wait).
            //   • If any poll sees the tokens, promote immediately.
            //   • On RPC exception, keep polling — DO NOT wipe the position
            //     (previously a silent debug-level log, position stuck in
            //     pendingVerify forever and invisible to the UI).
            //   • Only declare PHANTOM after all 5 polls return 0 tokens
            //     AND no exception has masked the result.
            val verifyMint = ts.mint
            val verifySymbol = ts.symbol
            val verifyWallet = wallet
            val verifyCurrentLayer = currentLayer
            val verifyTradeMint = tradeId.mint
            val verifyTradeSymbol = tradeId.symbol
            val verifyTradeKey = tradeKey
            val verifySig = sig  // V5.9.265: capture sig for authoritative tx-based verification
            GlobalScope.launch(AppDispatchers.sideEffect) {
                try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BALANCE_PROOF_START", "mint=${verifyMint.take(10)} symbol=$verifySymbol signature=${verifySig.take(16)} owner=${verifyWallet.publicKeyB58.take(8)}") } catch (_: Throwable) {}
                var verifiedQty = 0.0
                var verifiedProof: com.lifecyclebot.engine.sell.BalanceProof? = null
                var anyRpcError = false
                var sigParseConfirmedZero = false  // V5.9.265: only TRUE phantom if tx parse explicitly says 0
                // V5.9.750 — extended verify window. Operator screenshots
                // 23:36 show multiple live buys reaching BUY_CONFIRMED (tx
                // mined on-chain) but never reaching BUY_VERIFIED_LANDED.
                // Tokens DID arrive in the host wallet (Phantom screenshot
                // confirms Fartcoin / 8hPe…pump / 8RT6…TdhL / CwhP…vWdN
                // all present), so the failure mode is RPC indexer lag
                // beyond the original 30s window (5 polls × 6s). pump.fun
                // mints in particular hit indexer lag past 45s during hot
                // scanner storms, AND Helius rate-limit responses cause
                // tx-parse fallback to fail too. Extend to 10 polls × 6s
                // = 60s. Still well under the 90s periodic reconciler so
                // the safety net stays consistent. If verify still fails,
                // the position stays pendingVerify and the V5.9.748
                // RECONCILE-PROMOTE path picks it up at the next 90s tick.
                val pollIntervalMs = 6_000L
                val maxPolls = 10
                for (pollNum in 1..maxPolls) {
                    try {
                        Thread.sleep(pollIntervalMs)

                        // V5.9.265 — AUTHORITATIVE sig-based verification first.
                        // Jupiter Ultra/RFQ swaps deliver tokens but
                        // getTokenAccountsByOwner is often stale for 30+s after
                        // confirmation. The forensics tile proved real tokens
                        // were landing while the ATA poll returned 0. We now
                        // parse postTokenBalances from the tx itself — that's
                        // the on-chain ground truth, no indexer lag.
                        val ownerDeltaProof = try {
                            com.lifecyclebot.engine.sell.SellAmountAuthority.txMetaOwnerDeltaProof(
                                mint = verifyMint,
                                owner = verifyWallet.publicKeyB58,
                                wallet = verifyWallet,
                                sig = verifySig,
                            )
                        } catch (_: Exception) { null }
                        if (ownerDeltaProof != null && ownerDeltaProof.amountRaw.signum() > 0) {
                            verifiedProof = ownerDeltaProof
                            verifiedQty = try { java.math.BigDecimal(ownerDeltaProof.amountRaw).movePointLeft(ownerDeltaProof.decimals).toDouble() } catch (_: Throwable) { 0.0 }
                            LiveTradeLogStore.log(
                                verifyTradeKey, verifyMint, verifySymbol, "BUY",
                                LiveTradeLogStore.Phase.BUY_VERIFY_POLL,
                                "Poll $pollNum/$maxPolls — OWNER_DELTA_PROOF qty=${verifiedQty} raw=${ownerDeltaProof.amountRaw}",
                                tokenAmount = verifiedQty, traderTag = "MEME",
                            )
                            break
                        }
                        val genericSigQty = try { verifyWallet.getTokenAmountFromSig(verifySig, verifyMint) } catch (_: Exception) { null }
                        if (genericSigQty != null && genericSigQty == 0.0) sigParseConfirmedZero = true
                        if (genericSigQty != null && genericSigQty > 0.0) {
                            try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BALANCE_PROOF_REJECTED", "reason=GENERIC_TX_PARSE_NOT_OWNER_FILTERED mint=${verifyMint.take(10)} sig=${verifySig.take(12)}") } catch (_: Throwable) {}
                        }

                        // Fallback: owner token account poll
                        val balances = verifyWallet.getTokenAccountsWithDecimalsBounded()
                        val tokenData = balances[verifyMint]
                        val qty = tokenData?.first ?: 0.0
                        LiveTradeLogStore.log(
                            verifyTradeKey, verifyMint, verifySymbol, "BUY",
                            LiveTradeLogStore.Phase.BUY_VERIFY_POLL,
                            "Poll $pollNum/$maxPolls — wallet qty=${qty.fmt(4)}" +
                                if (ownerDeltaProof == null) " (owner-delta proof not ready yet)" else "",
                            tokenAmount = qty, traderTag = "MEME",
                        )
                        if (qty > 0.0) {
                            verifiedQty = qty
                            val decimals = tokenData?.second ?: 9
                            val raw = try { java.math.BigDecimal(qty).movePointRight(decimals).toBigInteger() } catch (_: Throwable) { java.math.BigInteger.ZERO }
                            verifiedProof = com.lifecyclebot.engine.sell.BalanceProof(
                                mint = verifyMint,
                                owner = verifyWallet.publicKeyB58,
                                ata = null,
                                amountRaw = raw,
                                decimals = decimals,
                                source = com.lifecyclebot.engine.sell.BalanceProofSource.RPC_CONFIRMED_OWNER_TOKEN_ACCOUNT,
                                authoritative = raw.signum() > 0,
                                observedAtMs = System.currentTimeMillis(),
                                signature = null,
                            )
                            break
                        }
                    } catch (e: Exception) {
                        anyRpcError = true
                        ErrorLogger.warn(
                            "Executor",
                            "⚠️ POST-BUY RPC poll $pollNum/$maxPolls failed for $verifySymbol: ${e.message} — will retry"
                        )
                        LiveTradeLogStore.log(
                            verifyTradeKey, verifyMint, verifySymbol, "BUY",
                            LiveTradeLogStore.Phase.BUY_VERIFY_POLL,
                            "Poll $pollNum/$maxPolls — RPC error: ${e.message?.take(80)}",
                            traderTag = "MEME",
                        )
                    }
                }
                fun promoteVerifiedLiveBuy(qtyUi: Double, stage: String) {
                    val promoted = ts.position.copy(
                        qtyToken = qtyUi,
                        pendingVerify = false,
                    )
                    ts.position = promoted
                    // V5.0.3686 — SOURCE FIX: every verified live-buy promotion must
                    // atomically restore the TokenState into BotService.status.tokens.
                    // 3501 worked because the TokenState generally survived the verify
                    // window. Later watchlist/source reapers can evict it while the
                    // side-effect verifier is sleeping. If promotion happens after that,
                    // the wallet holds the token but UI/exits iterate status.tokens and
                    // never see it. This helper is used by ALL promotion branches:
                    // direct tx-parse, last-chance ATA rescue, and TradeVerifier rescue.
                    try {
                        synchronized(com.lifecyclebot.engine.BotService.status.tokens) {
                            com.lifecyclebot.engine.BotService.status.tokens[verifyMint] = ts
                        }
                    } catch (_: Throwable) {}
                    try { PositionPersistence.savePosition(ts) } catch (e: Exception) {
                        ErrorLogger.error("Executor", "💾 persist after $stage failed: ${e.message}", e)
                    }
                    try { WalletTokenMemory.recordBuy(ts) } catch (_: Exception) {}
                    try {
                        ForensicLogger.lifecycle(
                            "LIVE_POSITION_PROMOTED_VISIBLE",
                            "stage=$stage symbol=${verifySymbol} mint=${verifyMint.take(10)} qty=${qtyUi.fmt(4)} inStatusTokens=${try { com.lifecyclebot.engine.BotService.status.tokens.containsKey(verifyMint) } catch (_: Throwable) { false }}"
                        )
                    } catch (_: Throwable) {}
                }

                fun buildOwnerAccountProof(qtyUi: Double, decimals: Int, stage: String): com.lifecyclebot.engine.sell.BalanceProof? {
                    val raw = try { java.math.BigDecimal(qtyUi).movePointRight(decimals.coerceAtLeast(0)).toBigInteger() } catch (_: Throwable) { java.math.BigInteger.ZERO }
                    if (raw.signum() <= 0) return null
                    return com.lifecyclebot.engine.sell.BalanceProof(
                        mint = verifyMint,
                        owner = verifyWallet.publicKeyB58,
                        ata = null,
                        amountRaw = raw,
                        decimals = decimals.coerceAtLeast(0),
                        source = com.lifecyclebot.engine.sell.BalanceProofSource.RPC_CONFIRMED_OWNER_TOKEN_ACCOUNT,
                        authoritative = true,
                        observedAtMs = System.currentTimeMillis(),
                        signature = verifySig,
                    )
                }

                fun completeVerifiedLiveBuyWithProof(proof: com.lifecyclebot.engine.sell.BalanceProof, qtyUi: Double, stage: String): Boolean {
                    if (!proof.authoritative || proof.amountRaw.signum() <= 0 || proof.mint != verifyMint) {
                        try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BUY_PENDING_BALANCE_PROOF", "mint=${verifyMint.take(10)} symbol=$verifySymbol stage=$stage reason=INVALID_PROOF source=${proof.source} raw=${proof.amountRaw}") } catch (_: Throwable) {}
                        try { HostWalletTokenTracker.recordBuyPending(verifyMint, verifySymbol, verifySig) } catch (_: Throwable) {}
                        return false
                    }
                    try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BALANCE_PROOF_OK", "mint=${verifyMint.take(10)} symbol=$verifySymbol source=${proof.source} rawAmount=${proof.amountRaw} decimals=${proof.decimals} sig=${verifySig.take(16)} stage=$stage") } catch (_: Throwable) {}
                    try { com.lifecyclebot.engine.sell.SellAmountAuthority.recordTxParseBalance(verifyMint, proof.amountRaw, proof.decimals, verifySig) } catch (_: Throwable) {}
                    try { com.lifecyclebot.engine.ForensicLogger.lifecycle("SELL_AMOUNT_AUTHORITY_SEEDED", "mint=${verifyMint.take(10)} symbol=$verifySymbol rawAmount=${proof.amountRaw} decimals=${proof.decimals} sig=${verifySig.take(16)} source=${proof.source}") } catch (_: Throwable) {}
                    // V5.0.3777 — LIVE ENTRY PRICE AUTHORITY.
                    // The provisional live position was stamped before token proof using
                    // guide/feed price (ts.lastPrice). Once owner/mint balance proof arrives,
                    // replace that guide basis with the actual economic entry:
                    // (SOL spent / verified UI tokens) × SOL/USD. This prevents false thesis,
                    // bogus stop-loss/TP, and corrupted learning labels from guide prices.
                    val solUsdForBasis = try { WalletManager.lastKnownSolPrice } catch (_: Throwable) { 0.0 }
                    val proofEntryUsd = if (qtyUi > 0.0 && sol > 0.0 && solUsdForBasis > 0.0)
                        (sol / qtyUi) * solUsdForBasis else 0.0
                    if (proofEntryUsd > 0.0 && proofEntryUsd.isFinite()) {
                        val oldEntry = ts.position.entryPrice
                        ts.position = ts.position.copy(
                            entryPrice = proofEntryUsd,
                            highestPrice = proofEntryUsd,
                            lowestPrice = if (ts.position.lowestPrice > 0.0) minOf(ts.position.lowestPrice, proofEntryUsd) else proofEntryUsd,
                            costSol = sol,
                            entryPriceSource = "LIVE_PROOF_COST_BASIS",
                            entrySupplyAssumed = 0.0,
                            priceBasisRescaled = true,
                            priceBasisRescaleFactor = if (oldEntry > 0.0) proofEntryUsd / oldEntry else 1.0,
                        )
                        try { com.lifecyclebot.engine.ForensicLogger.lifecycle("LIVE_ENTRY_PRICE_FROM_PROOF", "mint=${verifyMint.take(10)} symbol=$verifySymbol oldEntry=$oldEntry proofEntryUsd=$proofEntryUsd sol=$sol qty=$qtyUi solUsd=$solUsdForBasis source=${proof.source}") } catch (_: Throwable) {}
                    } else {
                        try { com.lifecyclebot.engine.ForensicLogger.lifecycle("LIVE_ENTRY_PRICE_PROOF_DEFERRED", "mint=${verifyMint.take(10)} symbol=$verifySymbol reason=missing_sol_usd_or_qty sol=$sol qty=$qtyUi solUsd=$solUsdForBasis") } catch (_: Throwable) {}
                    }
                    promoteVerifiedLiveBuy(qtyUi, stage)
                    val beforeOpen = try { HostWalletTokenTracker.getOpenCount() } catch (_: Throwable) { -1 }
                    try { HostWalletTokenTracker.recordBuyConfirmedWithProof(ts, proof, verifySig) } catch (e: Throwable) {
                        ErrorLogger.error("Executor", "🚨 HOST_TRACKER_RECORD_WITH_PROOF_FAILED: $verifySymbol — ${e.javaClass.simpleName}: ${e.message?.take(120)}", e)
                        try { HostWalletTokenTracker.recordBuyPending(verifyMint, verifySymbol, verifySig) } catch (_: Throwable) {}
                        return false
                    }
                    val afterOpen = try { HostWalletTokenTracker.getOpenCount() } catch (_: Throwable) { -1 }
                    val opened = try { HostWalletTokenTracker.hasOpenPosition(verifyMint) } catch (_: Throwable) { false }
                    if (!opened) {
                        try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BUY_PENDING_BALANCE_PROOF", "mint=${verifyMint.take(10)} symbol=$verifySymbol stage=$stage reason=TRACKER_NOT_OPEN_AFTER_PROOF source=${proof.source}") } catch (_: Throwable) {}
                        return false
                    }
                    try { com.lifecyclebot.engine.ForensicLogger.lifecycle("TOKEN_TRACKER_BUY_CONFIRMED_WITH_PROOF", "mint=${verifyMint.take(10)} symbol=$verifySymbol source=${proof.source} rawAmount=${proof.amountRaw} decimals=${proof.decimals} open=$beforeOpen->$afterOpen") } catch (_: Throwable) {}
                    LiveTradeLogStore.log(
                        verifyTradeKey, verifyMint, verifySymbol, "BUY",
                        LiveTradeLogStore.Phase.BUY_VERIFIED_LANDED,
                        "LIVE_BUY_LANDED — proof=${proof.source} raw=${proof.amountRaw} decimals=${proof.decimals} host_tracker open=$beforeOpen→$afterOpen | mint_tracked=$opened",
                        tokenAmount = ts.position.qtyToken, sig = verifySig, traderTag = "MEME",
                    )
                    try { com.lifecyclebot.engine.ForensicLogger.lifecycle("LIVE_BUY_LANDED", "mint=${verifyMint.take(10)} symbol=$verifySymbol source=${proof.source} rawAmount=${proof.amountRaw} decimals=${proof.decimals} sig=${verifySig.take(16)}") } catch (_: Throwable) {}
                    buyAttemptTrace4576("WALLET_PROOF_OK", "stage=$stage proof=${proof.source} qty=$qtyUi sig=${verifySig.take(16)}")
                    return true
                }

                if (verifiedQty > 0.0) {
                    if (ts.position.pendingVerify || signatureManagedAtEntry) {
                        val proof = verifiedProof
                        if (proof == null || !proof.authoritative || proof.amountRaw.signum() <= 0) {
                            try { HostWalletTokenTracker.recordBuyPending(verifyMint, verifySymbol, verifySig) } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BUY_PENDING_BALANCE_PROOF", "mint=${verifyMint.take(10)} symbol=$verifySymbol reason=NO_AUTHORITATIVE_PROOF_AT_DIRECT_VERIFY qty=$verifiedQty") } catch (_: Throwable) {}
                            return@launch
                        }
                        if (!completeVerifiedLiveBuyWithProof(proof, verifiedQty, "DIRECT_VERIFY")) return@launch
                        ErrorLogger.info(
                            "Executor",
                            "✅ POST-BUY OK: $verifySymbol | ${"%.4f".format(verifiedQty)} tokens confirmed with ${proof.source} — position now live"
                        )
                        try {
                            ForensicLogger.exec(
                                "LIVE_BUY_OK",
                                verifySymbol,
                                "mint=${verifyMint.take(10)} qty=${verifiedQty.fmt(4)} sol=${"%.4f".format(sol)} proof=${proof.source}",
                            )
                        } catch (_: Throwable) {}
                        EmergentGuardrails.registerPosition(verifyTradeMint, verifyTradeSymbol, verifyCurrentLayer, sol)
                        try {
                            com.lifecyclebot.engine.GlobalTradeRegistry.registerPosition(
                                mint = verifyTradeMint,
                                symbol = verifyTradeSymbol,
                                layer = verifyCurrentLayer,
                                sizeSol = sol,
                            )
                        } catch (_: Exception) { /* non-critical */ }
                        try {
                            com.lifecyclebot.v3.scoring.SellOptimizationAI.registerPosition(
                                mint = verifyTradeMint,
                                entryPrice = ts.position.entryPrice.takeIf { it > 0.0 && it.isFinite() } ?: price,
                                sizeSol = sol
                            )
                        } catch (_: Exception) {}
                        try {
                            com.lifecyclebot.v4.meta.PortfolioHeatAI.addPosition(
                                id = verifyTradeMint,
                                symbol = verifyTradeSymbol.ifBlank { verifyTradeMint.take(6) },
                                market = "MEME",
                                sector = verifyCurrentLayer,
                                direction = "LONG",
                                sizeSol = sol,
                                leverage = 1.0,
                                narrative = "${ts.source}:${ts.phase}",
                            )
                            PipelineHealthCollector.labelInc("PORTFOLIO_HEAT_MEME_POSITION_REGISTERED_4212")
                        } catch (_: Throwable) {}
                        try { TokenLifecycleTracker.onTokenLanded(verifyMint, verifiedQty) } catch (_: Throwable) {}
                        try {
                            val decimals = proof.decimals
                            val entryRaw = proof.amountRaw
                            val priceSolPerToken = if (verifiedQty > 0.0) sol / verifiedQty else 0.0
                            val priceUsd = priceSolPerToken * (try { WalletManager.lastKnownSolPrice } catch (_: Throwable) { 0.0 })
                            TokenLifecycleTracker.recordEntryMetadata(
                                mint = verifyMint,
                                entryPriceSol = priceSolPerToken,
                                entryPriceUsd = priceUsd,
                                entryDecimals = decimals,
                                entryTokenRawConfirmed = entryRaw,
                                poolLiquidityUsd = ts.lastLiquidityUsd,
                            )
                        } catch (e: Throwable) {
                            ErrorLogger.warn("Executor", "recordEntryMetadata after verify failed (non-fatal): ${e.message}")
                        }
                    }
                } else if (anyRpcError && (ts.position.pendingVerify || signatureManagedAtEntry)) {
                    // All polls returned 0 OR errored. If ANY error masked the
                    // result, we cannot safely conclude phantom — keep the
                    // position pendingVerify so the periodic reconciler /
                    // next restart can adopt it from the on-chain wallet.
                    ErrorLogger.warn(
                        "Executor",
                        "⚠️ POST-BUY INCONCLUSIVE: $verifySymbol — RPC errors during verify; " +
                            "position remains pending balance proof; verifier/reconciler will promote only with proof"
                    )
                    LiveTradeLogStore.log(
                        verifyTradeKey, verifyMint, verifySymbol, "BUY",
                        LiveTradeLogStore.Phase.WARNING,
                        "⚠️ Verification inconclusive — RPC errors during polls. Position remains pending balance proof; reconciler will promote only with proof.",
                        traderTag = "MEME",
                    )
                    buyAttemptTrace4576("WALLET_PROOF_PENDING", "reason=rpc_error_inconclusive sig=${verifySig.take(16)}")
                } else if (!sigParseConfirmedZero && (ts.position.pendingVerify || signatureManagedAtEntry)) {
                    // V5.9.265 — All ATA polls returned 0 BUT the tx-parse never
                    // explicitly returned 0 (it returned null = "tx not yet
                    // indexed"). With Jupiter Ultra/RFQ this is the common case:
                    // tokens really arrived, the indexer just hasn't caught up.
                    // We keep pendingVerify so the StartupReconciler /
                    // WalletTokenMemory adopts the position later instead of
                    // banning the mint and walking away from real on-chain SOL.
                    ErrorLogger.warn(
                        "Executor",
                        "⚠️ POST-BUY INDEXING LAG: $verifySymbol — tx confirmed, ATA poll returned 0 but tx-parse hasn't indexed yet. Leaving pendingVerify."
                    )
                    LiveTradeLogStore.log(
                        verifyTradeKey, verifyMint, verifySymbol, "BUY",
                        LiveTradeLogStore.Phase.WARNING,
                        "⚠️ ATA poll returned 0 but tx not yet indexed — keeping BUY_PENDING_BALANCE_PROOF; reconciler will promote only with proof once tokens index.",
                        traderTag = "MEME",
                    )
                    buyAttemptTrace4576("WALLET_PROOF_PENDING", "reason=tx_not_indexed sig=${verifySig.take(16)}")
                } else if (ts.position.pendingVerify || signatureManagedAtEntry) {
                    // All polls OK and all returned 0 → true phantom
                    // V5.9.495s — operator: "every buy lands as a phaeton".
                    // V5.9.495t — operator triage: "still logging everything
                    // as phantom buys". Root cause: RPC empty-map blip during
                    // verification = "no entries returned for ANY token" ≠
                    // "wallet has no tokens of this mint". Read the WHOLE
                    // map; if it's empty, treat as inconclusive (do NOT
                    // wipe). If non-empty and the mint truly is absent
                    // → real phantom.
                    val lastChanceBalances: Map<String, Pair<Double, Int>>? = try {
                        verifyWallet.getTokenAccountsWithDecimalsBounded()
                    } catch (_: Throwable) { null }
                    val lastChanceQty: Double = lastChanceBalances?.get(verifyMint)?.first ?: 0.0
                    val lastChanceMapEmpty = lastChanceBalances?.isEmpty() == true
                    if (lastChanceQty > 0.0) {
                        val lastChanceDecimals = lastChanceBalances?.get(verifyMint)?.second ?: 9
                        val lastChanceProof = buildOwnerAccountProof(lastChanceQty, lastChanceDecimals, "LAST_CHANCE_ATA_RESCUE")
                        if (lastChanceProof == null || !completeVerifiedLiveBuyWithProof(lastChanceProof, lastChanceQty, "LAST_CHANCE_ATA_RESCUE")) {
                            try { HostWalletTokenTracker.recordBuyPending(verifyMint, verifySymbol, verifySig) } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.ForensicLogger.lifecycle("BUY_PENDING_BALANCE_PROOF", "mint=${verifyMint.take(10)} symbol=$verifySymbol reason=LAST_CHANCE_PROOF_BUILD_FAILED qty=$lastChanceQty") } catch (_: Throwable) {}
                            return@launch
                        }
                        ErrorLogger.warn(
                            "Executor",
                            "🛟 PHANTOM RESCUE: $verifySymbol — last-chance ATA found ${lastChanceQty.fmt(4)} tokens after polls returned 0. Promoting with proof."
                        )
                        LiveTradeLogStore.log(
                            verifyTradeKey, verifyMint, verifySymbol, "BUY",
                            LiveTradeLogStore.Phase.BUY_VERIFIED_LANDED,
                            "🛟 PHANTOM RESCUE: late-indexed buy salvaged with proof=${lastChanceProof.source} | qty=${lastChanceQty.fmt(4)}",
                            tokenAmount = lastChanceQty, sig = verifySig, traderTag = "MEME",
                        )
                        try { TokenLifecycleTracker.onTokenLanded(verifyMint, lastChanceQty) } catch (_: Throwable) {}
                        return@launch
                    }
                    if (lastChanceMapEmpty || lastChanceBalances == null) {
                        ErrorLogger.warn(
                            "Executor",
                            "⚠️ POST-BUY INCONCLUSIVE (RPC-EMPTY): $verifySymbol — last-chance map was empty/null. Position remains pending balance proof; reconciler will promote only with proof later."
                        )
                        LiveTradeLogStore.log(
                            verifyTradeKey, verifyMint, verifySymbol, "BUY",
                            LiveTradeLogStore.Phase.WARNING,
                            "⚠️ POST-BUY: RPC empty-map at end of verify — BUY_PENDING_BALANCE_PROOF kept, no wipe/no sell authority.",
                            traderTag = "MEME",
                        )
                        return@launch
                    }
                    // V5.9.495y — TRADE-VERIFIER FINAL AUTHORITY (spec items 1, 8).
                    // Before destructively wiping a position, ask
                    // TradeVerifier (getSignatureStatuses + getTransaction
                    // tx-parse). LANDED → rescue. FAILED_CONFIRMED → wipe.
                    // INCONCLUSIVE_PENDING → keep position, leave it for
                    // the reconciler.
                    try {
                        val vr = TradeVerifier.verifyBuy(verifyWallet, verifySig, verifyMint, timeoutMs = 30_000L)
                        when (vr.outcome) {
                            TradeVerifier.Outcome.LANDED -> {
                                val rescueProof = com.lifecyclebot.engine.sell.BalanceProof(
                                    mint = verifyMint,
                                    owner = verifyWallet.publicKeyB58,
                                    ata = null,
                                    amountRaw = vr.rawTokenDelta,
                                    decimals = vr.decimals,
                                    source = com.lifecyclebot.engine.sell.BalanceProofSource.TX_META_OWNER_DELTA,
                                    authoritative = vr.rawTokenDelta.signum() > 0,
                                    observedAtMs = System.currentTimeMillis(),
                                    signature = verifySig,
                                )
                                LiveTradeLogStore.log(
                                    verifyTradeKey, verifyMint, verifySymbol, "BUY",
                                    LiveTradeLogStore.Phase.BUY_TX_PARSE_OK,
                                    "🛟 TX-PARSE RESCUE: tokens proven on-chain | rawDelta=${vr.rawTokenDelta} ui=${vr.uiTokenDelta.fmt(4)} dec=${vr.decimals}",
                                    tokenAmount = vr.uiTokenDelta, sig = verifySig, traderTag = "MEME",
                                )
                                if (!completeVerifiedLiveBuyWithProof(rescueProof, vr.uiTokenDelta, "TX_PARSE_RESCUE")) {
                                    try { HostWalletTokenTracker.recordBuyPending(verifyMint, verifySymbol, verifySig) } catch (_: Throwable) {}
                                    return@launch
                                }
                                try { TokenLifecycleTracker.onTokenLanded(verifyMint, vr.uiTokenDelta) } catch (_: Throwable) {}
                                return@launch
                            }
                            TradeVerifier.Outcome.INCONCLUSIVE_PENDING,
                            TradeVerifier.Outcome.VERIFICATION_ERROR -> {
                                LiveTradeLogStore.log(
                                    verifyTradeKey, verifyMint, verifySymbol, "BUY",
                                    LiveTradeLogStore.Phase.SELL_VERIFY_INCONCLUSIVE_PENDING,
                                    "⏳ TRADE-VERIFIER INCONCLUSIVE — BUY_PENDING_BALANCE_PROOF kept, NO wipe/no sell authority until proof.",
                                    sig = verifySig, traderTag = "MEME",
                                )
                                return@launch
                            }
                            TradeVerifier.Outcome.FAILED_CONFIRMED -> {
                                LiveTradeLogStore.log(
                                    verifyTradeKey, verifyMint, verifySymbol, "BUY",
                                    LiveTradeLogStore.Phase.BUY_FAILED,
                                    "🚨 TRADE-VERIFIER FAILED_CONFIRMED — meta.err=${vr.txErr}. Wiping position.",
                                    sig = verifySig, traderTag = "MEME",
                                )
                                // Fall through to wipe block below.
                            }
                        }
                    } catch (vfx: Throwable) {
                        ErrorLogger.warn("Executor", "TradeVerifier.verifyBuy threw, falling back to legacy wipe path: ${vfx.message?.take(80)}")
                    }
                    ErrorLogger.warn(
                        "Executor",
                        "🚨 PHANTOM DETECTED: $verifySymbol — 0 tokens after ${maxPolls * pollIntervalMs / 1000}s + last-chance check (map non-empty, mint absent). Discarding pending position."
                    )
                    onLog("🚨 PHANTOM: $verifySymbol — tx landed but no tokens. Position discarded.", verifyMint)
                    LiveTradeLogStore.log(
                        verifyTradeKey, verifyMint, verifySymbol, "BUY",
                        LiveTradeLogStore.Phase.BUY_PHANTOM,
                        "🚨 PHANTOM — tx confirmed but 0 tokens after ${maxPolls * pollIntervalMs / 1000}s. SOL spent on fees, no tokens received.",
                        traderTag = "MEME",
                    )
                    ts.position = Position()
                    // V5.9.255 FIX: Set lastExitTs so BotService's 300s re-buy cooldown fires.
                    // Without this, the cooldown was never set for phantom cases — only real
                    // sells set lastExitTs. This lets the scanner re-buy instantly.
                    ts.lastExitTs = System.currentTimeMillis()
                    try { PositionPersistence.savePosition(ts) } catch (_: Exception) {}
                    val phantomId = TradeIdentityManager.getOrCreate(verifyMint, verifySymbol, "")
                    phantomId.closed(getActualPrice(ts), -100.0, -sol, "PHANTOM_BUY_NO_TOKENS")
                    // V5.9.199: Mark phantom as scratch — prevents -100% poisoning win rate
                    try { phantomId.classified("PHANTOM_SCRATCH", null) } catch (_: Exception) {}
                    // V5.9.255 FIX: Register a long-lived rejection so the scanner can't
                    // re-discover and re-buy this token immediately after the phantom wipe.
                    // Previously: position wiped → token stays on watchlist → cooldown expires
                    // in 20s → scanner re-finds it → bot buys again → same phantom loop.
                    // Now: token is banned for 10 minutes after a confirmed phantom.
                    // The SOL actually DID leave the wallet (tx landed on-chain) — this is
                    // a real loss, not a failed tx. We must not compound it.
                    try {
                        GlobalTradeRegistry.registerRejection(
                            mint = verifyMint,
                            symbol = verifySymbol,
                            reason = "PHANTOM_BUY: SOL spent but 0 tokens received — banned 10min",
                            rejectedBy = "PHANTOM_GUARD",
                        )
                        ErrorLogger.warn("Executor", "🚫 PHANTOM BAN: $verifySymbol registered in rejection list (10min cooldown)")
                    } catch (_: Exception) {}
                    onNotify(
                        "🚨 Phantom Cleared",
                        "$verifySymbol: tx returned sig but no tokens arrived. Position discarded.",
                        com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO
                    )
                }
            }

            // V5.0.3745 — committed live-open source truth. At this point the
            // route returned a confirmed signature, ts.position was created,
            // the trade was recorded, and verifier/reconciler was queued. Later
            // wallet proof still emits LIVE_BUY_OK or phantom cleanup.
            liveStage("POSITION_TRACKED", "signature=${sig.take(16)} pendingVerify=${ts.position.pendingVerify}")
            buyTerminalOk("BUY_TERMINAL_OK:TX_CONFIRMED_PENDING_WALLET_DELTA")
            return true

        } catch (e: Exception) {
            val safe = security.sanitiseForLog(e.message ?: "unknown")
            // V5.0.3679 — TELEMETRY GAP FIX. Every live-buy throw used to log
            // to ErrorLogger / LiveTradeLogStore but NEVER increment
            // EXEC_LIVE_BUY_FAIL, so operator forensics showed
            // EXEC_LIVE_ATTEMPT=57 with OK=0 AND FAIL=0 (silent drop). Add the
            // ForensicLogger.exec("LIVE_BUY_FAIL", ...) counter here so the
            // catch arm is visible in the per-mode exec funnel.
            try {
                com.lifecyclebot.engine.ForensicLogger.exec(
                    "LIVE_BUY_FAIL",
                    tradeId.symbol,
                    "attemptId=${execCtx.attemptId} execMode=${execCtx.execMode} mint=${tradeId.mint.take(10)} sol=$sol reason=THROWN:${safe.take(80)} lastStage=$liveBuyLastStage exception=${e.javaClass.simpleName}",
                )
            } catch (_: Throwable) {}
            ErrorLogger.error("Trade", "Live buy FAILED for ${tradeId.symbol}: $safe", e)
            onLog("Live buy FAILED: $safe", tradeId.mint)
            LiveTradeLogStore.log(
                tradeKey, tradeId.mint, tradeId.symbol, "BUY",
                LiveTradeLogStore.Phase.BUY_FAILED,
                "❌ Buy threw: ${safe.take(160)}",
                traderTag = "MEME",
            )
            onNotify("⚠️ Buy Failed", "${tradeId.symbol}: ${safe.take(80)}", com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
            onToast("❌ BUY FAILED: ${tradeId.symbol}\n${safe.take(50)}")
            liveStage("LIVE_BUY_FAILED", "reason=THROWN exception=${e.javaClass.simpleName} message=${safe.take(100)} lastStage=$liveBuyLastStage")
            buyTerminalFail("BUY_TERMINAL_SUBMIT_FAIL:THROWN_${safe.take(60)}")
            return false
        }
        } finally {
            if (!buyTerminalRecorded) {
                liveBuyDeferred(ts, sol, "NO_TERMINAL_EVENT_REQUEUED", "lastStage=$liveBuyLastStage")
                buyTerminalRecorded = true
            }
            // V5.9.778/V5.0.3910 — release MEME_LIVE_BUY_MUTEX only if this
            // invocation actually acquired it at the wallet-spend boundary.
            try { if (liveBuyMutexAcquired) MEME_LIVE_BUY_MUTEX.release() } catch (_: Throwable) {}
        }
    }

    // ── sell ──────────────────────────────────────────────────────────

    /**
     * V5.9.1086 — CENTRAL PAPER SOFT-LOSS MIN-HOLD GATE.
     *
     * Regression hunted after V5.9.1085: several exit paths can bypass the
     * lane-specific paper settle-in logic in runManageOnly(), especially
     * BotService → SellOptimizationAI → requestSell("[SELL_OPT] Stop Loss...").
     * In paper mode, entry+exit slippage simulation can make a fresh position
     * appear deeply red before the token has had time to trade, so soft stop
     * exits teach the brain fake instant losses.
     *
     * This gate is intentionally narrow:
     *  - PAPER positions only.
     *  - Loss-making full exits only.
     *  - Soft stop labels only.
     *  - NEVER blocks high-priority rug/catastrophe/stale-price exits.
     *  - NEVER blocks the unconditional -15% hard floor.
     *  - NEVER blocks profit exits, partials, or trailing/profit-lock exits.
     */
    private fun shouldDelayPaperSoftLossExit(ts: TokenState, reason: String): Boolean {
        val pos = ts.position
        if (!pos.isPaperPosition || !pos.isOpen) return false
        val r = reason.uppercase()

        // Explicit immediate-exit whitelist. These preserve the operator's
        // hard safety doctrine and high-priority rug/catastrophe handling.
        val entry = pos.entryPrice
        val current = getActualPrice(ts)
        if (entry <= 0.0 || current <= 0.0) return false
        val pnlPct = ((current - entry) / entry) * 100.0
        val ageMs = System.currentTimeMillis() - pos.entryTime

        val isPaperFullProfitExit = r.contains("RAPID_TAKE_PROFIT") ||
            r.contains("TAKE_PROFIT") ||
            r.contains("FULL_PROFIT")

        val immediateStructural = listOf(
            "RUG_ESCAPE",
            "STALE_PRICE",
            "STALE_LIVE_PRICE",
            "LIQUIDITY_DRAIN",
            "RUG_PULL",
            "BOT_SHUTDOWN",
            "STARTUP_SWEEP",
            "MANUAL",
            "PARTIAL_TAKE",
            "TRAIL",
        )
        val immediatePriceBased = listOf(
            "HARD_FLOOR",
            "CATASTROPHE",
            "DEEP_CATASTROPHE"
        )
        if (immediateStructural.any { r.contains(it) }) return false
        if (immediatePriceBased.any { r.contains(it) }) {
            val rawCurrent = ts.lastPrice
            val rawPnlPct = if (entry > 0.0) ((rawCurrent - entry) / entry) * 100.0 else 0.0
            // V5.9.1410 — prevent simulated paper slippage from triggering "CATASTROPHE" bypasses.
            // In paper mode, simulated slippage makes the PnL appear as -27% immediately. This causes
            // PrecisionExitLogic to emit "v8_catastrophic_loss" within the first 5 seconds. If we just
            // bypass on the word "CATASTROPHE", the position closes instantly for a fake -27% loss.
            // We must verify the RAW market price has actually crashed before allowing a price-based emergency exit.
            if (rawPnlPct <= -9.0) return false 
            // Otherwise, it's a fake catastrophe caused by the paper tax. Fall through and delay.
        }

        // V5.0.4200 — take-win is allowed at any age. This mirrors dynamic
        // profit-lock: once the position is genuinely green enough for a
        // TAKE_PROFIT/FULL_PROFIT/RAPID_TAKE_PROFIT label, paper settle-in is
        // no longer allowed to hold it hostage. Soft red/flat exits below still
        // use settle-in; hard safety and profit protection bypass.
        if (isPaperFullProfitExit && pnlPct > 0.0) {
            try {
                ForensicLogger.lifecycle(
                    "PAPER_TAKE_WIN_MIN_HOLD_BYPASS_4200",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${reason.take(80)} pnl=${"%.1f".format(pnlPct)} ageMs=$ageMs action=sell_now"
                )
            } catch (_: Throwable) {}
            return false
        }
        if (r.contains("PROFIT") && !isPaperFullProfitExit) return false

        // V5.9.1410 — Unconditional raw market hard floor check.
        // If the RAW market price has dropped by 15%, we exit immediately, regardless of label.
        val rawCurrentFloor = ts.lastPrice
        val rawPnlPctFloor = if (entry > 0.0) ((rawCurrentFloor - entry) / entry) * 100.0 else 0.0
        if (rawPnlPctFloor <= -15.0) return false

        // V5.9.1408 — FULL SETTLE-IN CHOKE. Pre-1408 this guard only
        // matched a small set of soft stop labels, so v8_exit_score,
        // BLUECHIP/MOONSHOT stops, fallback sub-trader stops, and other red
        // full-exit routes could still close paper positions inside 5-10s.
        // In paper, any red/flat non-emergency full exit before settle-in is
        // fake churn unless the raw market mark has breached the -15% hard
        // floor above. Delay all such exits, regardless of label.
        if (pnlPct > 0.0) return false
        val lane = pos.tradingMode.ifBlank {
            when {
                pos.isTreasuryPosition -> "TREASURY"
                pos.isShitCoinPosition -> "SHITCOIN"
                pos.isBlueChipPosition -> "BLUECHIP"
                else -> "V3"
            }
        }
        val fluidMinMs = try {
            (com.lifecyclebot.v3.scoring.FluidLearningAI.getFluidMinHoldMinutes(lane) * 60_000.0).toLong()
        } catch (_: Throwable) { 30_000L }
        // Keep the central gate bounded so it doesn't become a throughput choke.
        // Lane learners may recommend minutes, but this central guard's job is
        // only to absorb fake instant paper slippage, not override strategy exits.
        val minHoldMs = fluidMinMs.coerceIn(30_000L, 90_000L)
        if (ageMs >= minHoldMs) return false

        try {
            ForensicLogger.lifecycle(
                "PAPER_SETTLE_IN_EXIT_DELAYED",
                "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${reason.take(80)} pnl=${"%.1f".format(pnlPct)} ageMs=$ageMs minHoldMs=$minHoldMs lane=$lane floor=-15 action=delay"
            )
        } catch (_: Throwable) {}
        try {
            ErrorLogger.info(
                "Executor",
                "⏳ PAPER_SETTLE_IN_EXIT_DELAYED: ${ts.symbol} pnl=${pnlPct.toInt()}% age=${ageMs/1000}s/${minHoldMs/1000}s reason=$reason"
            )
        } catch (_: Throwable) {}
        return true
    }
    
    private data class LiveHoldDelay(val ageMs: Long, val minHoldMs: Long, val lane: String, val rawPnlPct: Double, val styleHint: String)
    private enum class LiveExitSeverity { CHURN, PROFIT, RUNNER_PROTECT, HARD_SAFETY }
    private data class LiveExitIntent(
        val severity: LiveExitSeverity,
        val rawPnlPct: Double,
        val peakGainPct: Double,
        val givebackFromPeak: Double,
        val normalizedReason: String,
        val advancedExitReason: String = "",
        val exitPolicyBias: Double = 1.0,
    )

    private fun unifiedExitLaneFor(ts: TokenState): String {
        return resolveExecutionLane(ts, fallback = ts.position.tradingMode.ifBlank { "STANDARD" })
    }

    private fun unifiedExitSignalsFor(ts: TokenState, rawPnlPct: Double, peakGainPct: Double): UnifiedExitPolicyHead.ExitSignals {
        val pos = ts.position
        val ageMs = (System.currentTimeMillis() - pos.entryTime).coerceAtLeast(0L)
        val (minHoldMs, _) = liveHoldMinMsForPosition(ts)
        val ageNorm = if (minHoldMs > 0L) ageMs.toDouble() / minHoldMs.toDouble() else 0.0
        val liqErode = if (pos.entryLiquidityUsd > 0.0 && ts.lastLiquidityUsd > 0.0) {
            ((pos.entryLiquidityUsd - ts.lastLiquidityUsd) / pos.entryLiquidityUsd).coerceIn(0.0, 1.0)
        } else 0.0
        val momentumDn = (-(ts.momentum ?: ts.meta.momScore.minus(50.0)) / 100.0).coerceIn(0.0, 1.0)
        val sellPressure = maxOf(liqErode, momentumDn, ((ts.meta.pressScore - 50.0) / 100.0).coerceIn(0.0, 1.0))
        return UnifiedExitPolicyHead.ExitSignals(
            pnlPct = (rawPnlPct / 100.0).coerceIn(0.0, 1.0),
            maxPnlPct = (peakGainPct / 100.0).coerceIn(0.0, 1.0),
            ageNorm = ageNorm.coerceIn(0.0, 1.0),
            momentumDn = momentumDn,
            liquidityErode = liqErode,
            sellPressure = sellPressure,
        )
    }

    private fun advancedExitProfileForLane(lane: String): com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitProfile {
        val l = lane.uppercase()
        return when {
            l.contains("SHITCOIN") || l.contains("PRESALE") || l.contains("SNIPER") -> com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitProfile.SHITCOIN
            l.contains("EXPRESS") || l.contains("MANIP") -> com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitProfile.EXPRESS
            l.contains("BLUE") || l.contains("QUALITY") -> com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitProfile.BLUE_CHIP
            l.contains("DIP") -> com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitProfile.DIP_HUNTER
            l.contains("TREASURY") || l.contains("CASH") -> com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitProfile.TREASURY
            l.contains("MOONSHOT") || l.contains("MEME") -> com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitProfile.MOONSHOT
            else -> com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitProfile.V3_STANDARD
        }
    }

    private fun advancedExitAdvisory(ts: TokenState): com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitDecision? {
        val pos = ts.position
        if (!pos.isOpen || pos.entryPrice <= 0.0 || pos.qtyToken <= 0.0) return null
        val px = ts.lastPrice.takeIf { it > 0.0 } ?: return null
        val lane = resolveExecutionLane(ts, fallback = pos.tradingMode.ifBlank { "STANDARD" })
        val holdMinutes = ((System.currentTimeMillis() - pos.entryTime).coerceAtLeast(0L) / 60_000L).toInt()
        return try {
            val decision = com.lifecyclebot.v3.scoring.AdvancedExitManager.evaluateExit(
                profile = advancedExitProfileForLane(lane),
                entryPrice = pos.entryPrice,
                currentPrice = px,
                highWaterMarkPrice = pos.highestPrice.takeIf { it > 0.0 } ?: px,
                holdMinutes = holdMinutes,
                entryScore = pos.entryScore.toInt().coerceIn(0, 100),
                currentMomentum = ts.momentum ?: ts.meta.momScore,
                currentLiquidity = ts.lastLiquidityUsd.takeIf { it > 0.0 } ?: pos.entryLiquidityUsd,
                entryLiquidity = pos.entryLiquidityUsd,
                marketRegime = try { com.lifecyclebot.engine.RegimeDetector.currentRegime().name } catch (_: Throwable) { "UNKNOWN" },
                volatility = ts.volatility ?: 0.0,
                alreadySoldPct = pos.partialSoldPct.toInt().coerceIn(0, 100),
                symbol = ts.symbol,
            )
            if (decision.shouldExit) {
                try {
                    ForensicLogger.lifecycle("ADVANCED_EXIT_MANAGER_ADVISORY_4194", "mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$lane reason=${decision.exitReason} urgency=${decision.urgency} sellPct=${decision.sellPct} msg=${decision.logMessage.take(120)}")
                    PipelineHealthCollector.labelInc("ADVANCED_EXIT_MANAGER_ADVISORY_4194_${decision.exitReason}")
                } catch (_: Throwable) {}
            }
            decision
        } catch (_: Throwable) { null }
    }

    private fun classifyLiveExitIntent(ts: TokenState, reason: String): LiveExitIntent {
        val pos = ts.position
        val entry = pos.entryPrice
        val px = ts.lastPrice.takeIf { it > 0.0 } ?: pos.entryPrice
        val rawPnlPct = if (entry > 0.0 && px > 0.0) ((px - entry) / entry) * 100.0 else 0.0
        val peakGainPct = maxOf(pos.peakGainPct, rawPnlPct)
        val givebackFromPeak = peakGainPct - rawPnlPct
        val r = reason.uppercase()
        val confirmedRugByReason = r.contains("RUGCHECK_CONFIRMED") || r.contains("CONFIRMED_RUG") ||
            r.contains("HONEYPOT") || r.contains("CANNOT_SELL")
        val advanced = advancedExitAdvisory(ts)
        val advancedCritical = advanced?.shouldExit == true && advanced.urgency.ordinal >= com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitUrgency.HIGH.ordinal
        val advancedHardSafety = advancedCritical && (advanced?.exitReason == com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitReason.STOP_LOSS ||
            advanced?.exitReason == com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitReason.LIQUIDITY_EXIT ||
            advanced?.exitReason == com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitReason.MOMENTUM_EXIT)
        val advancedRunnerProtect = advanced?.shouldExit == true && (advanced.exitReason == com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitReason.TRAILING_STOP ||
            advanced.exitReason == com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitReason.TAKE_PROFIT_FULL ||
            advanced.exitReason == com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitReason.TAKE_PROFIT_CHUNK ||
            advanced.exitReason == com.lifecyclebot.v3.scoring.AdvancedExitManager.ExitReason.TIME_EXIT)
        val exitPolicyLane = unifiedExitLaneFor(ts)
        val exitPolicySignals = unifiedExitSignalsFor(ts, rawPnlPct, peakGainPct)
        val exitPolicyBias = try {
            UnifiedExitPolicyHead.stamp(ts.mint, exitPolicyLane, exitPolicySignals)
            UnifiedExitPolicyHead.exitBias(exitPolicyLane, exitPolicySignals)
        } catch (_: Throwable) { 1.0 }
        val exitPolicyBankSoon = exitPolicyBias < 0.85 && rawPnlPct > 0.5
        val exitPolicyLetRun = exitPolicyBias > 1.20 && rawPnlPct >= 0.0 && givebackFromPeak < 10.0
        if (exitPolicyBankSoon || exitPolicyLetRun) {
            try {
                ForensicLogger.lifecycle("UNIFIED_EXIT_POLICY_HEAD_SHAPED_4196", "mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$exitPolicyLane bias=${"%.2f".format(exitPolicyBias)} bankSoon=$exitPolicyBankSoon letRun=$exitPolicyLetRun raw=${"%.1f".format(rawPnlPct)} peak=${"%.1f".format(peakGainPct)} reason=${reason.take(80)}")
                PipelineHealthCollector.labelInc(if (exitPolicyBankSoon) "UNIFIED_EXIT_POLICY_HEAD_BANK_SOON_4196" else "UNIFIED_EXIT_POLICY_HEAD_LET_RUN_4196")
            } catch (_: Throwable) {}
        }
        val hardSafety = rawPnlPct <= -15.0 || confirmedRugByReason || advancedHardSafety ||
            r.contains("CATASTROPHE") || r.contains("HARD_FLOOR") ||
            r.contains("RAPID_HARD_FLOOR") || r.contains("MANUAL_EMERGENCY") ||
            r.contains("EMERGENCY_LIQUIDATE") || r.contains("KILL_SWITCH") ||
            r.contains("WALLET_BALANCE_ZERO") || r.contains("SELL_SIG_CONFIRMED")
        val runnerProtect = (peakGainPct >= 20.0 && givebackFromPeak >= 25.0) || advancedRunnerProtect || exitPolicyBankSoon ||
            r.contains("ULTRA_RUNNER_BANK") || r.contains("PEAK_GIVEBACK") ||
            r.contains("DRAWDOWN_FROM_PEAK") || r.contains("TRAIL_STOP_PEAK") ||
            r.contains("PROFIT_LOCK")
        val profit = !exitPolicyLetRun && (r.contains("TAKE_PROFIT") || r.contains("PROFIT") ||
            r.contains("TRAIL") || r.contains("BANK") || r.contains("PARTIAL"))
        val severity = when {
            hardSafety -> LiveExitSeverity.HARD_SAFETY
            runnerProtect -> LiveExitSeverity.RUNNER_PROTECT
            profit -> LiveExitSeverity.PROFIT
            else -> LiveExitSeverity.CHURN
        }
        return LiveExitIntent(severity, rawPnlPct, peakGainPct, givebackFromPeak, r, advancedExitReason = advanced?.exitReason?.name ?: "", exitPolicyBias = exitPolicyBias)
    }

    private fun liveHoldMinMsForPosition(ts: TokenState): Pair<Long, String> {
        val pos = ts.position
        val lane = pos.tradingMode.ifBlank {
            when {
                pos.isTreasuryPosition -> "TREASURY"
                pos.isShitCoinPosition -> "SHITCOIN"
                pos.isBlueChipPosition -> "BLUECHIP"
                else -> "STANDARD"
            }
        }.uppercase()
        // V5.0.3942 — central style/hold intent. AgenticStyleRouter already
        // selects style/hold×, but most positions do not persist style fields, so
        // exits cannot enforce it. Use lane/archetype as the durable proxy until
        // full style persistence lands. These are MINIMUM anti-churn holds only;
        // hard rug/floor exits still bypass below.
        val movementSignal = try { MovementPatternSignal.from(ts) } catch (_: Throwable) { null }
        val baseMinMs = when {
            lane.contains("TREASURY") || lane.contains("EXPRESS") || lane.contains("MANIP") -> 45_000L
            lane.contains("SHITCOIN") || lane.contains("PRESALE") || lane.contains("SNIPER") -> 75_000L
            lane.contains("MOONSHOT") || lane.contains("QUALITY") || lane.contains("BLUECHIP") || lane.contains("BLUE_CHIP") -> 180_000L
            lane.contains("COPY") || lane.contains("WHALE") || lane.contains("STANDARD") -> 150_000L
            else -> 90_000L
        }
        val minMs = (baseMinMs * (movementSignal?.holdMult ?: 1.0)).toLong().coerceIn(45_000L, 420_000L)
        val styleHint = when {
            movementSignal != null && movementSignal.pattern != "NEUTRAL_STRUCTURE" -> "movement_${movementSignal.pattern.lowercase()}"
            lane.contains("MOONSHOT") || lane.contains("QUALITY") || lane.contains("BLUE") -> "runner_hold"
            lane.contains("TREASURY") || lane.contains("EXPRESS") || lane.contains("MANIP") -> "quick_flip_min_hold"
            lane.contains("SHITCOIN") || lane.contains("SNIPER") -> "degen_snipe_min_hold"
            else -> "standard_min_hold"
        }
        return minMs to styleHint
    }

    private fun liveHoldBypassReason(intent: LiveExitIntent): Boolean {
        // True safety + runner-protection + take-win exits bypass style/min-hold.
        // Min-hold is anti-churn only; it must not override profit lockers,
        // TAKE_PROFIT/full-profit winners, peak-giveback locks, hard floor,
        // confirmed rugs, wallet-zero cleanup, or sell finality cleanup. Tiny
        // profit dust still gets caught earlier by liveProfitDustExitShouldDefer().
        return intent.severity.ordinal >= LiveExitSeverity.RUNNER_PROTECT.ordinal ||
            intent.severity == LiveExitSeverity.PROFIT
    }

    private fun liveHoldDelayIfNeeded(ts: TokenState, reason: String): LiveHoldDelay? {
        if (reason.startsWith("RECONCILER_REQUEUE", ignoreCase = true)) return null
        if (ts.position.isPaperPosition) return null
        val pos = ts.position
        if (pos.entryTime <= 0L || pos.qtyToken <= 0.0) return null
        val now = System.currentTimeMillis()
        val ageMs = (now - pos.entryTime).coerceAtLeast(0L)
        val intent = classifyLiveExitIntent(ts, reason)
        // V5.0.4192 — central severity ladder. Runtime 4189 showed
        // LIVE_STYLE_MIN_HOLD_EXIT_DEFERRED while a position gave back from +2407%
        // to ~0%. The shared classifier makes min-hold subordinate to runner
        // protection and hard-safety across sibling defer paths.
        if (liveHoldBypassReason(intent)) {
            if (intent.severity == LiveExitSeverity.RUNNER_PROTECT) {
                try {
                    ForensicLogger.lifecycle(
                        "LIVE_STYLE_MIN_HOLD_PEAK_GIVEBACK_BYPASS_4192",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${reason.take(80)} rawPnl=${"%.1f".format(intent.rawPnlPct)} peak=${"%.1f".format(intent.peakGainPct)} giveback=${"%.1f".format(intent.givebackFromPeak)} severity=${intent.severity} action=sell_now"
                    )
                    PipelineHealthCollector.labelInc("LIVE_STYLE_MIN_HOLD_PEAK_GIVEBACK_BYPASS_4192")
                } catch (_: Throwable) {}
            }
            return null
        }
        val (minHoldMs, styleHint) = liveHoldMinMsForPosition(ts)
        if (ageMs >= minHoldMs) return null
        val lane = pos.tradingMode.ifBlank { if (pos.isShitCoinPosition) "SHITCOIN" else if (pos.isBlueChipPosition) "BLUECHIP" else if (pos.isTreasuryPosition) "TREASURY" else "STANDARD" }
        return LiveHoldDelay(ageMs, minHoldMs, lane, intent.rawPnlPct, styleHint)
    }

    private fun learnedMinProfitExitPct(ts: TokenState): Double {
        val lane = ts.position.tradingMode.ifBlank { if (ts.position.isShitCoinPosition) "SHITCOIN" else if (ts.position.isBlueChipPosition) "BLUECHIP" else if (ts.position.isTreasuryPosition) "TREASURY" else "STANDARD" }
        return try { WrRecoveryPartial.learnedExitRungs(lane).first } catch (_: Throwable) { 50.0 }
    }

    private fun liveProfitDustExitShouldDefer(ts: TokenState, reason: String): Boolean {
        if (ts.position.isPaperPosition) return false
        val pos = ts.position
        if (!pos.isOpen || pos.entryPrice <= 0.0) return false
        val intent = classifyLiveExitIntent(ts, reason)
        if (intent.severity.ordinal >= LiveExitSeverity.RUNNER_PROTECT.ordinal) return false
        val minProfit = learnedMinProfitExitPct(ts)
        val terminalOrMaintenance = intent.normalizedReason.startsWith("RECONCILER_REQUEUE") ||
            intent.normalizedReason.contains("TAKE_PROFIT") || intent.normalizedReason.contains("PROFIT") ||
            intent.normalizedReason.contains("TRAIL") || intent.normalizedReason == "EXIT" ||
            intent.normalizedReason.contains("EXIT_ROUTE_RETRY")
        return terminalOrMaintenance && intent.rawPnlPct in 0.0..(minProfit - 0.001)
    }

    enum class SellResult {
        CONFIRMED,
        FAILED_RETRYABLE,
        // V5.0.3795 — all providers failed before any broadcast signature. This is
        // not a terminal close (tokens may still be held), but it also must NOT keep
        // a CloseLease or PendingSellQueue entry. A stale blocking retry is exactly
        // what latched LIVE_SELL_NO_FINALITY/noSig and stopped new buys.
        ROUTE_FAILED_NO_SIGNATURE,
        FAILED_FATAL,
        PAPER_CONFIRMED,
        ALREADY_CLOSED,
        NO_WALLET,
        // V5.0.3746 — operator spec items 1, 5, 6: explicit proof-wait outcome.
        // Distinct from FAILED_RETRYABLE so the wrapper does NOT call
        // PendingSellQueue.add() (which would emit SELL_RETRY_TEMPORARY_ONLY)
        // and does NOT emit SELL_NO_CURRENT_HELD_PROOF_NOT_RETRIED. The mint
        // is owned by BalanceProofPoller until proof arrives or zero confirmed.
        WAITING_BALANCE_PROOF,
    }
    
    fun requestSell(ts: TokenState, reason: String, wallet: SolanaWallet?, walletSol: Double): SellResult {
        val requestReason = if (reason.isBlank() || reason.equals("exit", ignoreCase = true)) {
            val trackerStatus = try { HostWalletTokenTracker.getEntry(ts.mint)?.status?.name ?: "UNKNOWN" } catch (_: Throwable) { "UNKNOWN" }
            val closeState = try { com.lifecyclebot.engine.sell.LivePositionCloseAuthority.stateOf(ts.mint)?.name ?: "OPEN" } catch (_: Throwable) { "OPEN" }
            "EXIT_ROUTE_RETRY_${trackerStatus}_${closeState}"
        } else reason
        try { SellDecisionMatrixReport.recordIntent(ts.mint, ts.symbol ?: "?", requestReason, ts.position.isPaperPosition, ts.position.tradingMode.ifBlank { "UNKNOWN" }) } catch (_: Throwable) {}
        val edgeExitPx4532 = try { ts.lastPrice.takeIf { it > 0.0 } ?: ts.position.entryPrice } catch (_: Throwable) { 0.0 }
        val edgeExitPnl4532 = try { if (ts.position.entryPrice > 0.0 && edgeExitPx4532 > 0.0) ((edgeExitPx4532 - ts.position.entryPrice) / ts.position.entryPrice) * 100.0 else 0.0 } catch (_: Throwable) { 0.0 }
        val edgeExitPeak4532 = try { ts.position.peakGainPct.coerceAtLeast(edgeExitPnl4532) } catch (_: Throwable) { edgeExitPnl4532 }
        val edgeExitHoldMs4532 = try { (System.currentTimeMillis() - ts.position.entryTime).coerceAtLeast(0L) } catch (_: Throwable) { 0L }
        val edgeExitLane4532 = try { ts.position.tradingMode.ifBlank { resolveExecutionLane(ts, fallback = "STANDARD") } } catch (_: Throwable) { "STANDARD" }
        try { LearningLifecycleBus.exitDecision("requestSell.intent", edgeExitLane4532, ts.source.ifBlank { ts.lastPriceSource.ifBlank { "UNKNOWN" } }, ts.mint, ts.symbol ?: "?", "INTENT", requestReason, edgeExitPnl4532, edgeExitPeak4532, edgeExitHoldMs4532, ts.lastLiquidityUsd) } catch (_: Throwable) {}
        // V5.0.3801 — PAPER source guard before any executor activity.
        // requestSell() has many upstream callers (main loop, backup sweeps,
        // stale/rug escape paths). If a paper mint already has CLOSE_REQUESTED /
        // CLOSING / CLOSED / ledger closeId, return before TokenLifecycleTracker,
        // sell locks, cooldown re-arm, EXEC_TRACE_SELL, or journal activity.
        if (ts.position.isPaperPosition) {
            val guard = try { PaperPositionCloseAuthority.preSellGuard("PAPER", ts.mint, ts.symbol, requestReason) } catch (_: Throwable) { null }
            if (guard?.blocked == true) {
                return SellResult.ALREADY_CLOSED
            }
        }

        // V5.9.1411 — Settle-in and duplicate-suppress guards moved into doSell()
        // so that direct doSell() calls from riskCheck/UltraFastRugDetector are caught too.
        val isLivePositionEarly = !ts.position.isPaperPosition

        // V5.0.3963 — no scrap-profit terminal sells. This is learned, not a
        // fixed moonshot table: per-lane expectancy/MFE provides the first
        // meaningful-profit floor; hard safety exits bypass.
        if (isLivePositionEarly && liveProfitDustExitShouldDefer(ts, requestReason)) {
            try {
                val px = ts.lastPrice.takeIf { it > 0.0 } ?: ts.position.entryPrice
                val pnl = if (ts.position.entryPrice > 0.0) ((px - ts.position.entryPrice) / ts.position.entryPrice) * 100.0 else 0.0
                ForensicLogger.lifecycle("LIVE_TINY_PROFIT_EXIT_DEFERRED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${requestReason.take(80)} pnl=${"%.1f".format(pnl)} minProfitPct=${"%.1f".format(learnedMinProfitExitPct(ts))} action=no_sell_lock")
                PipelineHealthCollector.labelInc("LIVE_TINY_PROFIT_EXIT_DEFERRED")
            } catch (_: Throwable) {}
            try { SellDecisionMatrixReport.recordPreSellDefer(ts.mint, ts.symbol ?: "?", requestReason, "TINY_PROFIT_DUST") } catch (_: Throwable) {}
            try { LearningLifecycleBus.exitDecision("requestSell.defer", edgeExitLane4532, ts.source.ifBlank { ts.lastPriceSource.ifBlank { "UNKNOWN" } }, ts.mint, ts.symbol ?: "?", "DEFER_TINY_PROFIT_DUST", requestReason, edgeExitPnl4532, edgeExitPeak4532, edgeExitHoldMs4532, ts.lastLiquidityUsd) } catch (_: Throwable) {}
            return SellResult.FAILED_RETRYABLE
        }

        // V5.0.3942 — LIVE STYLE/HOLD ANTI-CHURN GATE. This sits before
        // TokenLifecycleTracker.onSellPending, CloseLease, and PendingSellQueue so a
        // deferred hold does not create sell-only drain mode or lock the mint. Only
        // true catastrophic hard-floor/rug/manual-emergency exits bypass.
        if (isLivePositionEarly) {
            val holdDelay = liveHoldDelayIfNeeded(ts, requestReason)
            if (holdDelay != null) {
                try {
                    ForensicLogger.lifecycle(
                        "LIVE_STYLE_MIN_HOLD_EXIT_DEFERRED",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${requestReason.take(80)} lane=${holdDelay.lane} style=${holdDelay.styleHint} ageMs=${holdDelay.ageMs} minHoldMs=${holdDelay.minHoldMs} rawPnl=${"%.1f".format(holdDelay.rawPnlPct)} action=no_sell_lock",
                    )
                    PipelineHealthCollector.labelInc("LIVE_STYLE_MIN_HOLD_EXIT_DEFERRED")
                    PipelineHealthCollector.labelInc("LIVE_STYLE_MIN_HOLD_${holdDelay.styleHint}")
                } catch (_: Throwable) {}
                try { SellDecisionMatrixReport.recordPreSellDefer(ts.mint, ts.symbol ?: "?", requestReason, "STYLE_MIN_HOLD") } catch (_: Throwable) {}
                try { LearningLifecycleBus.exitDecision("requestSell.defer", edgeExitLane4532, ts.source.ifBlank { ts.lastPriceSource.ifBlank { "UNKNOWN" } }, ts.mint, ts.symbol ?: "?", "DEFER_STYLE_MIN_HOLD", requestReason, edgeExitPnl4532, edgeExitPeak4532, edgeExitHoldMs4532, ts.lastLiquidityUsd) } catch (_: Throwable) {}
                return SellResult.FAILED_RETRYABLE
            }
        }

        // V5.0.3941 — maintenance requeue guard. RECONCILER_REQUEUE is NOT a
        // strategy exit; it is only allowed when tracker state says an exit/recovery
        // lifecycle already exists. A healthy wallet-held live position must be held
        // for its lane/style exit logic, not sold by reconciliation maintenance.
        if (isLivePositionEarly && requestReason.startsWith("RECONCILER_REQUEUE", ignoreCase = true)) {
            val trackerStatus = try { HostWalletTokenTracker.getEntry(ts.mint)?.status?.name ?: "UNKNOWN" } catch (_: Throwable) { "UNKNOWN" }
            val exitLifecycle = trackerStatus in setOf("EXIT_SIGNALLED", "SELL_PENDING", "SELL_VERIFYING", "RECOVERY_SELL_REQUIRED", "SELL_REPRICE_OR_SPLIT_REQUIRED")
            if (!exitLifecycle) {
                try {
                    ForensicLogger.lifecycle("RECONCILER_REQUEUE_SUPPRESSED_HEALTHY_HOLD", "mint=${ts.mint.take(10)} symbol=${ts.symbol} status=$trackerStatus reason=$requestReason")
                    PipelineHealthCollector.labelInc("RECONCILER_REQUEUE_SUPPRESSED_HEALTHY_HOLD")
                } catch (_: Throwable) {}
                try { SellDecisionMatrixReport.recordPreSellDefer(ts.mint, ts.symbol ?: "?", requestReason, "RECONCILER_HEALTHY_HOLD") } catch (_: Throwable) {}
                try { LearningLifecycleBus.exitDecision("requestSell.defer", edgeExitLane4532, ts.source.ifBlank { ts.lastPriceSource.ifBlank { "UNKNOWN" } }, ts.mint, ts.symbol ?: "?", "DEFER_RECONCILER_HEALTHY_HOLD", requestReason, edgeExitPnl4532, edgeExitPeak4532, edgeExitHoldMs4532, ts.lastLiquidityUsd) } catch (_: Throwable) {}
                return SellResult.WAITING_BALANCE_PROOF
            }
        }

        // V5.0.3746 — operator spec items 1, 4, 7: WAITING_BALANCE_PROOF short-circuit.
        // If the mint is already in proof-wait, ExitCoordinator / Universal exit /
        // strict-SL MUST NOT spawn another sell worker. We merge the desired exit
        // reason (highest priority wins) and return WAITING_BALANCE_PROOF — NO lease,
        // NO PendingSellQueue ACTIVE_SELL_READY job, NO duplicate-suppressed metric.
        if (isLivePositionEarly) {
            val closeGuard = try { com.lifecyclebot.engine.sell.LivePositionCloseAuthority.preSellGuard(ts.mint, ts.symbol ?: "?", wallet) } catch (_: Throwable) { null }
            if (closeGuard?.blocked == true) {
                try { ForensicLogger.lifecycle("REQUEST_SELL_SUPPRESSED_CLOSE_AUTHORITY", "mint=${ts.mint.take(10)} symbol=${ts.symbol} guard=${closeGuard.reason} state=${closeGuard.state}") } catch (_: Throwable) {}
                if (closeGuard.state == com.lifecyclebot.engine.sell.LivePositionCloseAuthority.State.CLOSED || closeGuard.state == com.lifecyclebot.engine.sell.LivePositionCloseAuthority.State.CLOSING_CONFIRMED) {
                    try { ts.position = ts.position.copy(qtyToken = 0.0, pendingVerify = false) } catch (_: Throwable) {}
                    return SellResult.ALREADY_CLOSED
                }
                try { SellDecisionMatrixReport.recordPreSellDefer(ts.mint, ts.symbol ?: "?", requestReason, "CLOSE_AUTHORITY_WAIT") } catch (_: Throwable) {}
                return SellResult.WAITING_BALANCE_PROOF
            }
        }
        if (isLivePositionEarly && com.lifecyclebot.engine.sell.BalanceProofWaitState.isWaiting(ts.mint)) {
            val waitProof = try { wallet?.let { com.lifecyclebot.engine.sell.SellAmountAuthority.resolveForExit(ts.mint, it, requestReason) } } catch (_: Throwable) { null }
            val waitConfirmed = waitProof as? com.lifecyclebot.engine.sell.SellAmountAuthority.Resolution.Confirmed
            if (waitConfirmed != null && waitConfirmed.rawAmount.signum() > 0) {
                ExecutionRootCauseTrace.authority("SELL", "REQUEST_SELL_BALANCE_WAIT_PROOF_READY", ts, "reason=$requestReason raw=${waitConfirmed.rawAmount} decimals=${waitConfirmed.decimals} source=${waitConfirmed.source} action=clear_wait_and_sell")
                try { com.lifecyclebot.engine.sell.BalanceProofWaitState.clear(ts.mint, "PROOF_READY_REQUESTSELL") } catch (_: Throwable) {}
                // Fall through to acquire the normal sell lease and route now.
            } else {
                val waitProofTrace = waitProof?.javaClass?.simpleName ?: "none"
                ExecutionRootCauseTrace.authority("SELL", "REQUEST_SELL_BALANCE_WAIT_MERGE", ts, "reason=$requestReason alreadyWaiting=true proof=$waitProofTrace action=merge_no_new_lease")
                com.lifecyclebot.engine.sell.BalanceProofWaitState.markWaiting(
                    ts.mint, ts.symbol ?: "?", requestReason,
                    runtimeGeneration = try { BotRuntimeController.currentGeneration() } catch (_: Throwable) { 0L },
                )
                try { SellDecisionMatrixReport.recordPreSellDefer(ts.mint, ts.symbol ?: "?", requestReason, "BALANCE_PROOF_WAIT_MERGE") } catch (_: Throwable) {}
                return SellResult.WAITING_BALANCE_PROOF
            }
        }

        // V5.9.495z28 (operator spec items 1+3): mark the lifecycle record
        // as SELL_PENDING the moment any sell is requested. The downstream
        // SOL+token verification path (post-broadcast) flips it to CLEARED
        // / PARTIAL_SELL / RESIDUAL_HELD based on the wallet reading.
        try { TokenLifecycleTracker.onSellPending(ts.mint) } catch (_: Throwable) {}

        // V5.9.1527 — SELL SOURCE FIX (spec item 3): canonical per-mint CLOSE
        // LEASE. Live sells acquire the lease here; duplicate sell starts for the
        // same mint are suppressed (no second SELL_START) and counted. The lease
        // also de-pollutes the retry reason (no recursive PENDING_RETRY_n nesting)
        // and is released on any terminal SellResult. Paper sells are sim-only and
        // are NOT leased.
        val isLivePosition = !ts.position.isPaperPosition
        if (isLivePosition) {
            val lease = com.lifecyclebot.engine.sell.CloseLease.acquire(ts.mint, ts.symbol ?: "?", requestReason)
            if (lease == null) {
                // A fresh close is already in flight for this mint — suppress the
                // duplicate. The owning close job will complete or terminally fail.
                return SellResult.FAILED_RETRYABLE
            }
            // V5.9.1539 — ROOT FIX (operator spec item C): before retrying a sell
            // under an existing lease, short-circuit if the wallet is CONCLUSIVELY
            // empty. MARS looped forever broadcasting the stale tracker-derived
            // amount (984443.7) at 5% slippage while the wallet balance was already
            // 0 — every 503 was classed RETRYABLE so the lease never released. A
            // confirmed-zero (RPC_CONFIRMED / WALLET_SCAN_CONFIRMED Resolution.Zero)
            // means there is nothing to sell: treat as ALREADY_CLOSED, release the
            // lease, and let the reconciler stamp the ledger. We do NOT act on an
            // UNKNOWN/empty-map RPC blip — only a genuine confirmed zero.
            run {
                val res = try { com.lifecyclebot.engine.sell.SellAmountAuthority.resolve(ts.mint, wallet) } catch (_: Throwable) { null }
                if (res is com.lifecyclebot.engine.sell.SellAmountAuthority.Resolution.Zero) {
                    try { ForensicLogger.lifecycle("SELL_ABORT_WALLET_CONFIRMED_ZERO",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} — confirmed-empty wallet, releasing lease (no stale TX_PARSE sell)") } catch (_: Throwable) {}
                    com.lifecyclebot.engine.sell.CloseLease.release(ts.mint, "WALLET_CONFIRMED_ZERO")
                    return SellResult.ALREADY_CLOSED
                }
            }
            // Sell under the lease using the CANONICAL (de-polluted) reason so the
            // forensic phases + any requeue carry a clean, non-nesting reason.
            val canonicalReason = lease.originalExitReason
            return try {
                val r = doSell(ts, canonicalReason, wallet, walletSol)
                when (r) {
                    // Terminal outcomes → release the lease.
                    SellResult.CONFIRMED, SellResult.PAPER_CONFIRMED,
                    SellResult.ALREADY_CLOSED, SellResult.FAILED_FATAL,
                    SellResult.ROUTE_FAILED_NO_SIGNATURE -> {
                        com.lifecyclebot.engine.sell.CloseLease.release(ts.mint, r.name)
                        if (r == SellResult.ROUTE_FAILED_NO_SIGNATURE) {
                            try { PendingSellQueue.remove(ts.mint) } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.HostWalletTokenTracker.clearSellInFlight(ts.mint, "ROUTE_FAILED_NO_SIGNATURE_NO_BLOCKING_RETRY") } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.sell.SellFailureHistory.record(
                                mint = ts.mint,
                                symbol = ts.symbol,
                                kind = com.lifecyclebot.engine.sell.SellFailureHistory.Kind.ROUTE_FAILED_NO_SIGNATURE,
                                reason = "requestSell released CloseLease; no blocking retry queue",
                                sig = null,
                            ) } catch (_: Throwable) {}
                        }
                    }
                    // NO_WALLET is terminal for THIS attempt (wallet gone) — release
                    // so a reconnect can re-acquire cleanly rather than starving.
                    SellResult.NO_WALLET ->
                        com.lifecyclebot.engine.sell.CloseLease.release(ts.mint, r.name)
                    // V5.0.3746 — WAITING_BALANCE_PROOF is NOT a route failure. The
                    // mint has been handed to BalanceProofPoller; the lease MUST be
                    // released (no blocking lease, no in-flight, no duplicate
                    // suppression for the poller's future re-entry).
                    SellResult.WAITING_BALANCE_PROOF ->
                        com.lifecyclebot.engine.sell.CloseLease.release(ts.mint, "WAITING_BALANCE_PROOF")
                    // Retryable → keep the lease, record the attempt (de-pollutes reason).
                    SellResult.FAILED_RETRYABLE ->
                        com.lifecyclebot.engine.sell.CloseLease.recordRetry(ts.mint, "RETRYABLE")
                }
                r
            } catch (t: Throwable) {
                // Never leak the lease on an unexpected throw.
                com.lifecyclebot.engine.sell.CloseLease.recordRetry(ts.mint, "EXCEPTION:${t.message?.take(40)}")
                throw t
            }
        }
        try { SellDecisionMatrixReport.recordDoSellHandoff(ts.mint, ts.symbol ?: "?", requestReason, ts.position.isPaperPosition) } catch (_: Throwable) {}
        return doSell(ts, requestReason, wallet, walletSol)
    }
    
    fun requestPartialSell(
        ts: TokenState, 
        sellPercentage: Double, 
        reason: String, 
        wallet: SolanaWallet?, 
        walletBalance: Double
    ) {
        val pct = sellPercentage.coerceIn(0.0, 1.0)
        if (pct <= 0) return
        
        // V5.9.475 — rehydrate ts.position from sub-trader maps if empty.
        // Without this, partial-sell would compute originalHolding = 0
        // because sub-traders keep positions in private maps and don't
        // mirror back to ts.position.qtyToken.
        rehydratePositionFromSubTraders(ts)

        val originalHolding = ts.position.qtyToken
        val sellAmount = originalHolding * pct
        val remainingAmount = originalHolding - sellAmount
        
        // CRITICAL FIX: Use position mode, NOT config mode!
        // A LIVE position must ALWAYS execute LIVE sells regardless of current config.
        val isPaper = ts.position.isPaperPosition
        normalizePositionScaleIfNeeded(ts)
        val currentPrice = getActualPrice(ts)
        val pnlVerdict6038 = OpenPnlSanity.inspectPosition(ts.position, currentPrice, "Executor.partial_ladder_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true)
        val pnlPct = if (pnlVerdict6038.ok) pnlVerdict6038.pnlPct else 0.0

        // V5.9.1515 — P0 FIX 3: NEVER partial-ladder a deeply red position.
        // Operator audit: snapshot showed partial_10/20/30pct sells firing at
        // -50% to -80%, dripping a loser out in slices instead of one clean cut —
        // the exact opposite of what partials are for (capturing UPSIDE). Once a
        // position has fallen past the -15% canonical floor, a partial is just a
        // slow bleed that leaves the rump exposed to further downside. Collapse it
        // into a single FULL risk exit. The only partials allowed below entry are
        // EXPLICIT forced-risk/liquidity cuts (reason carries RISK/LIQUIDITY/
        // STOP/RUG/RECOVERY) — those are deliberate, not laddering.
        run {
            val r = reason.uppercase()
            val isForcedRiskCut = r.contains("RISK") || r.contains("LIQUIDITY") ||
                r.contains("STOP") || r.contains("RUG") || r.contains("RECOVERY") ||
                r.contains("CATASTROPHE") || r.contains("DRAIN")
            if (!isPaper && pnlPct < LiveStrategyTuner.livePartialProfitFloorPct() && !isForcedRiskCut) {
                try { ForensicLogger.lifecycle("PARTIAL_BLOCKED_BELOW_BREAKEVEN",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} pnl=${"%.2f".format(pnlPct)} floor=${LiveStrategyTuner.livePartialProfitFloorPct()} reqPct=${(pct*100).toInt()} reason=$reason action=hold_runner") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("PARTIAL_BLOCKED_BELOW_BREAKEVEN") } catch (_: Throwable) {}
                return
            }
            if (pnlPct <= -15.0 && !isForcedRiskCut) {
                try { ForensicLogger.lifecycle("PARTIAL_COLLAPSED_TO_RISK_EXIT",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} pnl=${pnlPct.toInt()}% reqPct=${(pct*100).toInt()} reason=$reason") } catch (_: Throwable) {}
                requestSell(ts, "PARTIAL_LADDER_COLLAPSED_RISK_EXIT_${pnlPct.toInt()}", wallet, walletBalance)
                return
            }
        }

        onLog("📊 PARTIAL SELL: ${ts.symbol} | ${(pct * 100).toInt()}% of position | " +
            "sell=$sellAmount remain=$remainingAmount | pnl=${pnlPct.toInt()}% | $reason", ts.mint)
        
        if (isPaper) {
            val pos = ts.position
            try { ForensicLogger.lifecycle("PAPER_BALANCE_PROOF_BYPASSED_LEDGER_AUTHORITY", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=REQUEST_PARTIAL_SELL qty=${pos.qtyToken}") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PAPER_BALANCE_PROOF_BYPASSED_LEDGER_AUTHORITY") } catch (_: Throwable) {}
            if (pos.qtyToken <= 1e-12 || pos.costSol <= 0.0) {
                try { ForensicLogger.lifecycle("PAPER_PARTIAL_CLOSE_REJECTED_NO_LEDGER_POSITION", "mint=${ts.mint.take(10)} symbol=${ts.symbol} qty=${pos.qtyToken} cost=${pos.costSol}") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("PAPER_PARTIAL_CLOSE_REJECTED_NO_LEDGER_POSITION") } catch (_: Throwable) {}
                return
            }
            try { ForensicLogger.lifecycle("PAPER_PARTIAL_CLOSE_REQUESTED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} pct=$pct qty=${pos.qtyToken}") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PAPER_PARTIAL_CLOSE_REQUESTED") } catch (_: Throwable) {}
            val soldValueSol = pos.costSol * pct
            val profitSol = soldValueSol * (pnlPct / 100.0)
            val newSoldPct = pos.partialSoldPct + (pct * 100.0)

            // Update position state to reflect the partial sell so that subsequent
            // exits operate on the correct remaining size, not the full original.
            // V5.9.1328 — ROOT FIX A: Ghost-hold leak.
            // When cumulative partials cross 99% (rounding) or the residual qty
            // is below dust, finalize the position the same way paperSell does:
            // ts.position = Position() + remove from PositionPersistence +
            // close in GlobalTradeRegistry. Otherwise the entry stays in the
            // internal token map with qtyToken > 0 forever and AntiChoke has
            // to ghost-clear it every cycle.
            val cumulativeSoldPct = newSoldPct
            val residualQty = pos.qtyToken * (1.0 - pct)
            val residualSol = pos.costSol * (1.0 - pct)
            val fullyExited = cumulativeSoldPct >= 99.0 || residualQty <= 1e-9 || residualSol <= 0.000_001
            if (fullyExited) {
                ts.position = Position()
                ts.lastExitTs = System.currentTimeMillis()
                ts.lastExitPrice = currentPrice
                ts.lastExitPnlPct = pnlPct
                ts.lastExitWasWin = pnlPct >= 1.0
                try { PositionPersistence.removePosition(ts.mint) } catch (_: Exception) {}
                try { GlobalTradeRegistry.closePosition(ts.mint) } catch (_: Exception) {}
                try { com.lifecyclebot.v4.meta.PortfolioHeatAI.removePosition(ts.mint) } catch (_: Throwable) {}
                try { BotService.recentlyClosedMs[ts.mint] = System.currentTimeMillis() } catch (_: Throwable) {}
                try { ForensicLogger.lifecycle("PAPER_SELL_POSITION_CLOSED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} pnlPct=${pnlPct.toInt()} reason=partial_finalize_${cumulativeSoldPct.toInt()}pct stage=partial_cumulative persisted=removed") } catch (_: Throwable) {}
            } else {
                ts.position = pos.copy(
                    qtyToken       = residualQty,
                    costSol        = residualSol,
                    partialSoldPct = newSoldPct,
                )
            }

            // Record the partial sell as a proper Trade entry in the journal
            // V5.0.3683 — ACCOUNTING LEDGER FIX — populate feeSol/netPnlSol.
            val partialSellFee = soldValueSol * MEME_TRADING_FEE_PERCENT
            val partialSellNetPnl = profitSol - partialSellFee
            val trade = Trade(
                side             = "PARTIAL_SELL",
                mode             = "paper",
                sol              = soldValueSol,
                price            = currentPrice,
                ts               = System.currentTimeMillis(),
                reason           = if (newSoldPct >= 99.9) "FULL_EXIT_100PCT" else "partial_${newSoldPct.toInt().coerceAtMost(100)}pct",
                pnlSol           = profitSol,
                pnlPct           = pnlPct.coerceAtLeast(-100.0),
                feeSol           = partialSellFee,
                netPnlSol        = partialSellNetPnl,
                tradingMode      = pos.tradingMode,
                tradingModeEmoji = pos.tradingModeEmoji,
                mint             = ts.mint,
            )
            recordTrade(ts, trade)
            try { ForensicLogger.lifecycle("PAPER_PARTIAL_CLOSE_DONE", "mint=${ts.mint.take(10)} symbol=${ts.symbol} soldValue=$soldValueSol remaining=${if (fullyExited) 0.0 else residualQty} fullyExited=$fullyExited") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PAPER_PARTIAL_CLOSE_DONE") } catch (_: Throwable) {}
            // V5.9.428 — treasury split on partial sells too (same model as
            // full paperSell): meme wins 70/30, treasury scalps 100%, losers
            // contribute nothing. soldValueSol includes principal+profit share
            // of the sold slice; we deduct treasuryShare before crediting.
            val partialTreasuryShare = if (profitSol > 0) {
                try {
                    if (pos.isTreasuryPosition || pos.tradingMode == "TREASURY") {
                        com.lifecyclebot.engine.TreasuryManager.contributeFullyFromTreasuryScalp(
                            profitSol, com.lifecyclebot.engine.WalletManager.lastKnownSolPrice, isPaper = true)
                    } else {
                        com.lifecyclebot.engine.TreasuryManager.contributeFromMemeSell(
                            profitSol, com.lifecyclebot.engine.WalletManager.lastKnownSolPrice, isPaper = true)
                    }
                } catch (e: Exception) {
                    ErrorLogger.debug("Executor", "Treasury split error (partial paper): ${e.message}")
                    0.0
                }
            } else 0.0
            onPaperBalanceChange?.invoke((soldValueSol + profitSol) - partialTreasuryShare)

            try { ForensicLogger.lifecycle("PARTIAL_SELL_ACCOUNTING",
                "mode=paper mint=${ts.mint.take(10)} symbol=${ts.symbol} soldPct=${(pct*100).fmt(1)} cost=${soldValueSol.fmtSol()} gross=${(soldValueSol + profitSol).fmtSol()} pnl=${profitSol.fmtSignedSol()} net=${partialSellNetPnl.fmtSignedSol()} pct=${pnlPct.fmtPctPrecise()} reason=${trade.reason}") } catch (_: Throwable) {}
            ErrorLogger.info("Executor", "📄 PAPER PARTIAL SELL: ${ts.symbol} | " +
                "sold=${(pct * 100).toInt()}% @ ${pnlPct.fmtPctPrecise()} | cost=${soldValueSol.fmtSol()} gross=${(soldValueSol + profitSol).fmtSol()} profit=${profitSol.fmtSignedSol()}SOL net=${partialSellNetPnl.fmtSignedSol()}SOL | " +
                "remaining=${((1-pct) * 100).toInt()}%")

            onNotify("📊 Partial Profit (PAPER)",
                "${ts.symbol}: sold ${(pct * 100).toInt()}% | PnL ${pnlPct.fmtPctPrecise()} (${profitSol.fmtSignedSol()} SOL)",
                com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)

        } else {
            // LIVE partial sell - need wallet
            var activeWallet = wallet
            
            if (activeWallet == null) {
                ErrorLogger.error("Executor", "🚨 LIVE PARTIAL SELL: Wallet NULL for ${ts.symbol} - attempting reconnect...")
                
                try {
                    val reconnectedWallet = WalletManager.attemptReconnect()
                    if (reconnectedWallet != null) {
                        ErrorLogger.info("Executor", "✅ Wallet reconnected for partial sell!")
                        activeWallet = reconnectedWallet
                    }
                } catch (e: Exception) {
                    ErrorLogger.error("Executor", "🚨 Wallet reconnect failed: ${e.message}")
                }
                
                if (activeWallet == null) {
                    ErrorLogger.error("Executor", "🚨 PARTIAL SELL BLOCKED: No wallet for ${ts.symbol}")
                    onNotify("🚨 Partial Sell Blocked!", 
                        "Cannot partial-sell ${ts.symbol} - wallet not connected!",
                        com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
                    return
                }
            }
            
            ErrorLogger.info("Executor", "🔄 LIVE PARTIAL SELL: ${ts.symbol} | " +
                "${(pct * 100).toInt()}% of holdings")
            
            if (pct >= 0.9) {
                doSell(ts, "[PARTIAL→FULL] $reason", activeWallet, walletBalance)
            } else {
                val lockTradeKeyPre = LiveTradeLogStore.keyFor(ts.mint, ts.position.entryTime)
                if (blockIfSellInFlight(ts, reason, lockTradeKeyPre)) return
                if (!com.lifecyclebot.engine.sell.SellExecutionLocks.tryAcquire(ts.mint)) {
                    // V5.9.967 — z43-D SellSpamGuard wrap.
                    if (com.lifecyclebot.engine.sell.SellSpamGuard.shouldLogBlocked(ts.mint, reason))
                        LiveTradeLogStore.log(lockTradeKeyPre, ts.mint, ts.symbol, "SELL",
                            LiveTradeLogStore.Phase.SELL_VERIFY_INCONCLUSIVE_PENDING,
                            "SELL_BLOCKED_ALREADY_IN_PROGRESS partial reason=$reason", traderTag = "MEME")
                    return
                }
                // V5.6.27: Implement actual partial sell for LIVE mode
                try {
                    val c = cfg()
                    val pos = ts.position
                    val requestedSellQty = pos.qtyToken * pct
                    val sellTradeKey = LiveTradeLogStore.keyFor(ts.mint, pos.entryTime)
                    val partialPlan = ProcessorAmountPlanner.planSell(
                        ts = ts,
                        wallet = activeWallet,
                        processor = "JupiterPartial",
                        requestedUiQty = requestedSellQty,
                        exitReason = reason,
                        fraction = pct,
                        sellTradeKey = sellTradeKey,
                        traderTag = "MEME",
                    ) ?: run {
                        com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                        onLog("🛑 PARTIAL SELL BLOCKED: ${ts.symbol} BALANCE_UNKNOWN — refusing cached qty broadcast", ts.mint)
                        return
                    }
                    val sellQty = partialPlan.uiAmount
                    val newQty = (pos.qtyToken - sellQty).coerceAtLeast(0.0)
                    val newCost = pos.costSol * (newQty / pos.qtyToken.coerceAtLeast(0.000000001))
                    val newSoldPct = pos.partialSoldPct + (pct * 100)
                    var sellUnits = partialPlan.rawAmount
                    val sellSlippage = com.lifecyclebot.engine.sell.SellSafetyPolicy.initialSlippageBps(reason)
                    val broadcastSlipLadder = com.lifecyclebot.engine.sell.SellSafetyPolicy.ladder(reason)
                    val isDrainExit = com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason) > 1200 &&
                                      (com.lifecyclebot.engine.sell.SellSafetyPolicy.isHardRug(reason) ||
                                       com.lifecyclebot.engine.sell.SellSafetyPolicy.isManualEmergency(reason))

                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_START,
                        "requestPartialSell LIVE: ${(pct*100).toInt()}% | qty=$sellUnits | slip=${sellSlippage}bps | ladder=${broadcastSlipLadder.joinToString(",")}${if (isDrainExit) " [DRAIN-EXIT]" else ""}",
                        tokenAmount = sellQty,
                        slippageBps = sellSlippage,
                        traderTag = "MEME",
                    )
                    
                    onLog("📊 LIVE PARTIAL: Getting quote for $sellUnits units @ ${sellSlippage}bps slippage", ts.mint)
                    
                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_QUOTE_TRY,
                        "Quote try @ ${sellSlippage}bps",
                        slippageBps = sellSlippage,
                        traderTag = "MEME",
                    )
                    val manualJupiterPlan = recalcSellPlanForProcessor(
                        ts = ts,
                        wallet = activeWallet,
                        processor = "JUPITER_ULTRA_METIS_MANUAL_PARTIAL",
                        requestedUiQty = sellQty,
                        sellTradeKey = sellTradeKey,
                        traderTag = "MEME",
                    ) ?: run {
                        com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                        return
                    }
                    sellUnits = manualJupiterPlan.rawAmount
                    var quote = getQuoteWithSlippageGuard(
                        ts.mint, JupiterApi.SOL_MINT, sellUnits, sellSlippage, isBuy = false,
                        sellTaker = activeWallet.publicKeyB58)
                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_QUOTE_OK,
                        "Quote OK | out=${quote.outAmount} | impact=${"%.2f".format(quote.priceImpactPct)}% | router=${quote.router}${if (quote.isRfqRoute) " (RFQ)" else ""}${if (quote.ultraRejectedReason.isNotBlank()) " ⚠ Ultra REJECTED → Metis fallback (${quote.ultraRejectedReason.take(60)})" else ""}",
                        slippageBps = sellSlippage,
                        traderTag = "MEME",
                    )

                    // V5.9.479 — IN-LINE broadcast escalation loop (mirrors V5.9.478 in liveSell).
                    var sig: String? = null
                    var lastBroadcastException: Exception? = null
                    var broadcastAttempts = 0
                    for (currentSlip in broadcastSlipLadder) {
                        broadcastAttempts++
                        try {
                            if (broadcastAttempts > 1) {
                                LiveTradeLogStore.log(
                                    sellTradeKey, ts.mint, ts.symbol, "SELL",
                                    LiveTradeLogStore.Phase.SELL_QUOTE_TRY,
                                    "⚡ ESCALATION re-quote @ ${currentSlip}bps (attempt $broadcastAttempts)${if (isDrainExit) " [DRAIN-EXIT]" else ""}",
                                    slippageBps = currentSlip, traderTag = "MEME",
                                )
                                try {
                                    val manualLadderPlan = recalcSellPlanForProcessor(
                                        ts = ts,
                                        wallet = activeWallet,
                                        processor = "JUPITER_ULTRA_METIS_MANUAL_PARTIAL_LADDER",
                                        requestedUiQty = sellQty,
                                        sellTradeKey = sellTradeKey,
                                        traderTag = "MEME",
                                    ) ?: run {
                                        com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                                        return
                                    }
                                    sellUnits = manualLadderPlan.rawAmount
                                    quote = getQuoteWithSlippageGuard(
                                        ts.mint, JupiterApi.SOL_MINT, sellUnits, currentSlip,
                                        isBuy = false, sellTaker = activeWallet.publicKeyB58)
                                    // V5.9.495u — show Ultra status on each escalation
                                    LiveTradeLogStore.log(
                                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                                        LiveTradeLogStore.Phase.SELL_QUOTE_OK,
                                        "Re-quote OK @ ${currentSlip}bps | out=${quote.outAmount} | router=${quote.router}${if (quote.isRfqRoute) " (RFQ)" else ""}${if (quote.ultraRejectedReason.isNotBlank()) " ⚠ Ultra REJECTED → Metis (${quote.ultraRejectedReason.take(60)})" else if (quote.isUltra) " ✅ ULTRA accepted" else ""}",
                                        slippageBps = currentSlip, traderTag = "MEME",
                                    )
                                } catch (qex: Exception) {
                                    lastBroadcastException = qex
                                    LiveTradeLogStore.log(
                                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                                        LiveTradeLogStore.Phase.SELL_QUOTE_FAIL,
                                        "Re-quote ${currentSlip}bps FAILED: ${qex.message?.take(80) ?: "?"}",
                                        slippageBps = currentSlip, traderTag = "MEME",
                                    )
                                    continue
                                }
                            }
                            val dynSlipCap = com.lifecyclebot.engine.sell.SellSafetyPolicy.maxSlippageBps(reason).coerceAtLeast(currentSlip)
                            val txResult = buildTxWithRetry(
                                quote, activeWallet.publicKeyB58, dynamicSlippageMaxBps = dynSlipCap,
                                senderTipLamports = effectiveJitoTipLamports(c, urgent = isDrainExit),
                            )
                            LiveTradeLogStore.log(
                                sellTradeKey, ts.mint, ts.symbol, "SELL",
                                LiveTradeLogStore.Phase.SELL_TX_BUILT,
                                "Tx built | router=${txResult.router} rfq=${txResult.isRfqRoute} | slip=${currentSlip}bps (attempt $broadcastAttempts)" + (if (txResult.dynSlipPickedBps >= 0) " | dyn-slip picked=${txResult.dynSlipPickedBps}bps incurred=${txResult.dynSlipIncurredBps}bps" else ""),
                                traderTag = "MEME",
                            )
                            security.enforceSignDelay()

                            val useJito = c.jitoEnabled && !quote.isUltra
                            // V5.9.483 — dynamic Jito tip (see JitoTipFetcher).
                            val jitoTip = effectiveJitoTipLamports(c, urgent = isDrainExit)
                            val ultraReqId = if (quote.isUltra) txResult.requestId else null

                            onLog("📊 LIVE PARTIAL: Signing and broadcasting @ ${currentSlip}bps (attempt $broadcastAttempts)...", ts.mint)
                            LiveTradeLogStore.log(
                                sellTradeKey, ts.mint, ts.symbol, "SELL",
                                LiveTradeLogStore.Phase.SELL_BROADCAST,
                                "Broadcasting @ ${currentSlip}bps | route=${if (quote.isUltra) "ULTRA" else if (useJito) "JITO" else "RPC"} (attempt $broadcastAttempts)",
                                traderTag = "MEME",
                            )
                            sig = activeWallet.signSendAndConfirm(txResult.txBase64, useJito, jitoTip, ultraReqId, c.jupiterApiKey, txResult.isRfqRoute, txResult.senderCompatible)
                            LiveTradeLogStore.log(
                                sellTradeKey, ts.mint, ts.symbol, "SELL",
                                LiveTradeLogStore.Phase.SELL_CONFIRMED,
                                "✅ Sig confirmed @ ${currentSlip}bps (attempt $broadcastAttempts): ${sig.take(20)}…",
                                sig = sig, traderTag = "MEME",
                            )
                            break
                        } catch (broadcastEx: Exception) {
                            lastBroadcastException = broadcastEx
                            val safe = security.sanitiseForLog(broadcastEx.message ?: "unknown")
                            val isSlippage = safe.contains("0x1788", ignoreCase = true) ||
                                             safe.contains("TooLittleSolReceived", ignoreCase = true) ||
                                             safe.contains("Slippage", ignoreCase = true) ||
                                             safe.contains("SlippageToleranceExceeded", ignoreCase = true)
                            if (!isSlippage) throw broadcastEx
                            val brc = zeroBalanceRetries.merge(ts.mint + "_broadcast_partial", 1) { old, _ -> old + 1 } ?: 1
                            LiveTradeLogStore.log(
                                sellTradeKey, ts.mint, ts.symbol, "SELL",
                                LiveTradeLogStore.Phase.SELL_FAILED,
                                "SLIPPAGE @ ${currentSlip}bps (in-line attempt $broadcastAttempts) — escalating${if (isDrainExit) " [DRAIN-EXIT]" else ""} (lifetime=$brc)",
                                slippageBps = currentSlip, traderTag = "MEME",
                            )
                        }
                    }
                    if (sig == null) {
                        throw lastBroadcastException ?: RuntimeException(
                            "${ts.symbol}: partial-sell in-line broadcast retries exhausted at ${broadcastSlipLadder.last()}bps")
                    }
                    zeroBalanceRetries.remove(ts.mint + "_broadcast_partial")
                    // V5.9.479 — capture non-null sig for downstream Trade record + log calls
                    val finalSig: String = sig!!
                    // V5.9.495y — register with TradeVerifier dedupe guard.
                    if (!finalSig.startsWith("PHANTOM_")) TradeVerifier.beginSell(ts.mint, finalSig, "partial_${(pct*100).toInt()}pct")

                    // V5.9.495y/z — TRADE-VERIFIER AUTHORITATIVE PARTIAL-SELL
                    // VERIFY (spec items 6, 8). Replaces V5.9.495s wallet-poll
                    // heuristic. Requires BOTH tokens cleared AND SOL received
                    // (operator: "I still want the sell verified and that the
                    // tokens clear the wallet and return the sol").
                    var verifiedSolReceived: Long = -1L
                    run {
                        if (finalSig.startsWith("PHANTOM_")) return@run
                        val sellQtyHere = pos.qtyToken * pct
                        val vsr = try {
                            TradeVerifier.verifySell(activeWallet, finalSig, ts.mint, timeoutMs = 60_000L)
                        } catch (vfx: Throwable) {
                            LiveTradeLogStore.log(
                                sellTradeKey, ts.mint, ts.symbol, "SELL",
                                LiveTradeLogStore.Phase.WARNING,
                                "⚠ TradeVerifier threw (${vfx.message?.take(60)}) — leaving position pending",
                                sig = finalSig, traderTag = "MEME",
                            )
                            null
                        }
                        when (vsr?.outcome) {
                            TradeVerifier.Outcome.LANDED -> {
                                verifiedSolReceived = vsr.solReceivedLamports
                                LiveTradeLogStore.log(
                                    sellTradeKey, ts.mint, ts.symbol, "SELL",
                                    LiveTradeLogStore.Phase.SELL_TX_PARSE_OK,
                                    "✅ PARTIAL LANDED: rawConsumed=${vsr.rawTokenConsumed} ui=${vsr.uiTokenConsumed.fmt(4)} solReceived=${vsr.solReceivedLamports} lamports",
                                    sig = finalSig, tokenAmount = vsr.uiTokenConsumed, traderTag = "MEME",
                                )
                            }
                            TradeVerifier.Outcome.FAILED_CONFIRMED -> {
                                LiveTradeLogStore.log(
                                    sellTradeKey, ts.mint, ts.symbol, "SELL",
                                    LiveTradeLogStore.Phase.SELL_FAILED_CONFIRMED,
                                    "🚨 PARTIAL_FAILED_CONFIRMED: meta.err=${vsr.txErr} — position UNCHANGED.",
                                    sig = finalSig, tokenAmount = sellQtyHere, traderTag = "MEME",
                                )
                                onLog("🚨 PARTIAL SELL meta.err ${ts.symbol}: ${vsr.txErr} — position unchanged.", ts.mint)
                                TradeVerifier.endSell(ts.mint)
                                return
                            }
                            TradeVerifier.Outcome.INCONCLUSIVE_PENDING,
                            TradeVerifier.Outcome.VERIFICATION_ERROR -> {
                                LiveTradeLogStore.log(
                                    sellTradeKey, ts.mint, ts.symbol, "SELL",
                                    LiveTradeLogStore.Phase.SELL_VERIFY_INCONCLUSIVE_PENDING,
                                    "⏳ PARTIAL VERIFY INCONCLUSIVE: tokens-clear AND SOL-return not BOTH proven within 60s — leaving position open & qty unchanged. Reconciler will adopt later.",
                                    sig = finalSig, tokenAmount = sellQtyHere, traderTag = "MEME",
                                )
                                TradeVerifier.endSell(ts.mint)
                                return
                            }
                            null -> {
                                TradeVerifier.endSell(ts.mint)
                                return
                            }
                        }
                    }
                    TradeVerifier.endSell(ts.mint)
                    
                    val solBack: Double = when {
                        finalSig.startsWith("PHANTOM_") -> 0.0
                        verifiedSolReceived > 0L -> verifiedSolReceived / 1_000_000_000.0
                        else -> quote.outAmount / 1_000_000_000.0
                    }
                    val livePnl = solBack - pos.costSol * pct
                    val liveScore = pct(pos.costSol * pct, solBack)
                    val (netPnl, feeSol) = slippageGuard.calcNetPnl(livePnl, pos.costSol * pct)
                    
                    // Update position
                    ts.position = pos.copy(qtyToken = newQty, costSol = newCost, partialSoldPct = newSoldPct)
                    
                    val livePartialCostBasisSol = pos.costSol * pct
                    val liveTrade = Trade("PARTIAL_SELL", "live", livePartialCostBasisSol, currentPrice,
                        System.currentTimeMillis(), if (newSoldPct >= 99.9) "FULL_EXIT_100PCT" else "partial_${newSoldPct.toInt().coerceAtMost(100)}pct",
                        livePnl, liveScore, sig = finalSig, feeSol = feeSol, netPnlSol = netPnl,
                        mint = ts.mint, tradingMode = pos.tradingMode, tradingModeEmoji = pos.tradingModeEmoji)
                    
                    recordTrade(ts, liveTrade)
                    security.recordTrade(liveTrade)
                    SmartSizer.recordTrade(netPnl > 0, isPaperMode = false)
                    LiveSafetyCircuitBreaker.recordTradeResult(netPnl)  // V5.9.105 session drawdown halt
                    // V5.9.109: FAIRNESS — partial sell #2 pays same 0.5% fee.
                    try {
                        val feeAmountSol = (pos.costSol * pct) * MEME_TRADING_FEE_PERCENT
                        if (feeAmountSol >= FEE_SEND_MIN_SOL) {
                            val feeWallet1 = feeAmountSol * FEE_SPLIT_RATIO
                            val feeWallet2 = feeAmountSol * (1.0 - FEE_SPLIT_RATIO)
                            sendFeeSplit(activeWallet, feeWallet1, feeWallet2, "partial_sell_v2")
                            ErrorLogger.info("Executor", "💸 LIVE PARTIAL-SELL FEE (v2): ${feeAmountSol} SOL split to both wallets")
                        }
                    } catch (feeEx: Exception) {
                        ErrorLogger.error("Executor", "🚨 FEE SEND FAILED — PARTIAL-SELL FEE (v2) failed: ${feeEx.message}")
                        // V5.9.226: Bug #7 — enqueue for retry
                        val feeAmt5 = (pos.costSol * pct) * MEME_TRADING_FEE_PERCENT
                        if (feeAmt5 >= 0.0001) {
                            FeeRetryQueue.enqueue(TRADING_FEE_WALLET_1, feeAmt5 * FEE_SPLIT_RATIO, "partial_sell_v2_w1")
                            FeeRetryQueue.enqueue(TRADING_FEE_WALLET_2, feeAmt5 * (1.0 - FEE_SPLIT_RATIO), "partial_sell_v2_w2")
                        }
                    }

                    LiveTradeLogStore.log(
                        sellTradeKey, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_VERIFY_SOL_RETURNED,
                        "Partial sold ${(pct*100).toInt()}% | got ${solBack.fmt(4)} SOL | net ${netPnl.fmt(4)}",
                        sig = finalSig,
                        solAmount = solBack,
                        traderTag = "MEME",
                    )
                    com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)

                    // V5.9.743 — wire 70/30 treasury siphon onto the LIVE branch
                    // of the manual requestPartialSell entry point. The PAPER
                    // branch of this same function already siphons (V5.9.428);
                    // the LIVE branch was missing the call, so any external
                    // partial-close request (UI button / API) deposited 0%
                    // to Treasury in live mode. Use netPnl (post-fee).
                    if (netPnl > 0.0) {
                        try {
                            if (pos.isTreasuryPosition || pos.tradingMode == "TREASURY") {
                                com.lifecyclebot.engine.TreasuryManager.contributeFullyFromTreasuryScalp(
                                    netPnl, com.lifecyclebot.engine.WalletManager.lastKnownSolPrice)
                            } else {
                                com.lifecyclebot.engine.TreasuryManager.contributeFromMemeSell(
                                    netPnl, com.lifecyclebot.engine.WalletManager.lastKnownSolPrice)
                            }
                        } catch (e: Exception) {
                            ErrorLogger.debug("Executor", "Treasury split error (reqPartial live): ${e.message}")
                        }
                    }

                    // V5.9.1161 — no synthetic zero-price PARTIAL_SELL row here.
                    // liveTrade above is the canonical partial outcome and trains
                    // through TradeHistoryStore → CanonicalOutcomeBus when valid.

                    try { ForensicLogger.lifecycle("PARTIAL_SELL_ACCOUNTING",
                        "mode=live mint=${ts.mint.take(10)} symbol=${ts.symbol} soldPct=${(pct*100).fmt(1)} cost=${livePartialCostBasisSol.fmtSol()} gross=${solBack.fmtSol()} pnl=${livePnl.fmtSignedSol()} net=${netPnl.fmtSignedSol()} pct=${liveScore.fmtPctPrecise()} reason=${liveTrade.reason} sig=${finalSig.take(16)} source=requestPartialSell") } catch (_: Throwable) {}
                    onLog("✅ LIVE PARTIAL SELL ${(pct*100).toInt()}% @ ${liveScore.fmtPctPrecise()} | " +
                          "cost=${livePartialCostBasisSol.fmtSol()} gross=${solBack.fmtSol()} pnl=${livePnl.fmtSignedSol()} net=${netPnl.fmtSignedSol()} | sig=${finalSig.take(16)}…", ts.mint)
                    
                    onNotify("💰 Live Partial Sell",
                        "${ts.symbol}: sold ${(pct*100).toInt()}% | PnL ${liveScore.fmtPctPrecise()} (${netPnl.fmtSignedSol()} SOL net)",
                        com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
                        
                } catch (e: Exception) {
                    // V5.9.474 — classified post-quote forensics for partial-sell catch
                    val sellTradeKey2 = LiveTradeLogStore.keyFor(ts.mint, ts.position.entryTime)
                    val safe = security.sanitiseForLog(e.message ?: "unknown")
                    val broadcastRetries = zeroBalanceRetries.merge(ts.mint + "_broadcast_partial", 1) { old, _ -> old + 1 } ?: 1
                    // V5.9.1522 — canonical classification (0x1788 is SIM, not generic slippage).
            val routeCls = com.lifecyclebot.engine.sell.SellRouteErrorClassifier.classify(safe)
            val routePolicy = com.lifecyclebot.engine.sell.SellRouteErrorClassifier.retryPolicy(routeCls, broadcastRetries, retryScheduled = false)
            // V5.9.1533 — spec item 7: 0x1787 / PUMP_ROUTE_INVALID must RE-RESOLVE the
            // venue, not retry the same Pump-direct payload. Mark the mint so the next
            // attempt skips pump-native and re-resolves to PumpSwap/Raydium/Jupiter.
            if (routePolicy.requireVenueReResolution) {
                try { com.lifecyclebot.engine.sell.MemeVenueRouter.markPumpRouteInvalid(ts.mint) } catch (_: Throwable) {}
                try { ForensicLogger.lifecycle("SELL_VENUE_RE_RESOLVE",
                    "mint=${ts.mint.take(10)} class=${routeCls.name} action=skip_pump_direct_reresolve") } catch (_: Throwable) {}
            }
            val failureClass = routeCls.name
            if (routePolicy.releaseLock) {
                try { com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint) } catch (_: Throwable) {}
                try { com.lifecyclebot.engine.HostWalletTokenTracker.clearSellInFlight(ts.mint, "ROUTE_FAILED_" + routeCls.name) } catch (_: Throwable) {}
            }
                    LiveTradeLogStore.log(
                        sellTradeKey2, ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_FAILED,
                        "$failureClass — ${e.javaClass.simpleName}: ${safe.take(120)} (partial-sell attempt $broadcastRetries)",
                        traderTag = "MEME",
                    )
                    com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
                    ErrorLogger.error("Executor", "❌ LIVE PARTIAL SELL FAILED: ${ts.symbol} | class=$failureClass | ${e.message}")
                    onLog("❌ Live partial sell FAILED: $failureClass — ${safe.take(80)} (retry $broadcastRetries)", ts.mint)
                }
            }
        }
    }

    private fun isNonRouteSellWait(ts: TokenState): Boolean {
        return try {
            com.lifecyclebot.engine.sell.BalanceProofWaitState.isWaiting(ts.mint) ||
                TradeVerifier.activeSellSig(ts.mint) != null ||
                com.lifecyclebot.engine.sell.SellFailureHistory.shouldBlockNextRetry(ts.mint) ||
                HostWalletTokenTracker.sellBlockReason(ts.mint) != null ||
                com.lifecyclebot.engine.sell.LivePositionCloseAuthority.isTerminalOrClosing(ts.mint)
        } catch (_: Throwable) { false }
    }

    internal fun doSell(ts: TokenState, reason: String,
                       wallet: SolanaWallet?, walletSol: Double,
                       identity: TradeIdentity? = null): SellResult {
        val paperCloseAuthorityActive = ts.position.isPaperPosition
        if (paperCloseAuthorityActive) {
            val guard = PaperPositionCloseAuthority.preSellGuard("PAPER", ts.mint, ts.symbol, reason)
            if (guard.blocked) {
                return SellResult.ALREADY_CLOSED
            }
            PaperPositionCloseAuthority.markCloseRequested("PAPER", ts.mint, ts.symbol, reason)
        }
        ExecutionRootCauseTrace.sell("DO_SELL_ENTRY", ts, "reason=$reason walletLoaded=${wallet != null} walletSol=$walletSol identity=${identity?.source ?: "-"} posQty=${ts.position.qtyToken} entry=${ts.position.entryPrice} high=${ts.position.highestPrice}")
        // V5.9.1411 — Move paper settle-in delay guard directly into doSell.
        // This ensures exits originating from riskCheck (like v8_catastrophic_loss)
        // or UltraFastRugDetector are caught by the settle-in delay if they are fake soft losses.
        if (ts.position.isPaperPosition) {
            val reasonUpper = reason.uppercase()
            val hardFloorOrEmergency = reasonUpper.contains("HARD_FLOOR") ||
                reasonUpper.contains("RAPID_HARD_FLOOR") ||
                reasonUpper.contains("STARTUP_SWEEP_HARD_FLOOR") ||
                reasonUpper.contains("RUG_SAFETY") ||
                reasonUpper.contains("MANUAL")
            val closedAgoMs = System.currentTimeMillis() - (BotService.recentlyClosedMs[ts.mint] ?: 0L)
            if (!hardFloorOrEmergency && closedAgoMs in 0L..60_000L) {
                try { ForensicLogger.lifecycle("PAPER_SELL_DUPLICATE_SUPPRESSED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason closedAgoMs=$closedAgoMs stage=pre_sell_lock") } catch (_: Throwable) {}
                return SellResult.ALREADY_CLOSED
            }
            // V5.0.3702 — close-ledger duplicate suppression must happen before
            // acquireSellLock(). 3700 dump showed SELL_LOCK_SET=413 and
            // PAPER_SELL_DUPLICATE_SUPPRESSED=367 because doSell acquired the
            // general lock, then paperSell discovered the mint was already CLOSED.
            // Duplicate closed rows are not sell attempts; never churn sell locks.
            val existingCloseId = try { com.lifecyclebot.engine.PositionCloseLedger.closeIdOf(ts.mint) } catch (_: Throwable) { null }
            if (existingCloseId != null) {
                try { ForensicLogger.lifecycle("PAPER_SELL_DUPLICATE_SUPPRESSED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} originalCloseId=$existingCloseId reason=$reason stage=pre_sell_lock") } catch (_: Throwable) {}
                return SellResult.ALREADY_CLOSED
            }
            if (shouldDelayPaperSoftLossExit(ts, reason)) return SellResult.FAILED_RETRYABLE
        } else {
            if (blockIfSellInFlight(ts, reason)) return SellResult.FAILED_RETRYABLE
        }

        val tradeId = identity ?: TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)

        // Atomic guard: only ONE sell can proceed per mint at a time.
        // V5.9.756 — TTL-backed acquire (20 s stale-release watchdog).
        if (!acquireSellLock(ts.mint)) {
            onLog("⚠️ SELL SKIPPED: sell already in-progress for ${ts.symbol}", tradeId.mint)
            return SellResult.ALREADY_CLOSED
        }

        try {

        // V5.9.475 — REHYDRATE before the isOpen check so sub-trader positions
        // (Treasury, ShitCoin, Quality, BlueChip, Moonshot) that never wrote
        // back to ts.position can still be sold. Was the primary cause of
        // 'meme sells never reach the host wallet': sub-traders kept positions
        // in private maps, ts.position.isOpen=false, doSell returned
        // ALREADY_CLOSED, swap never fired.
        rehydratePositionFromSubTraders(ts)
        // V5.9.491 — final on-chain fallback: if no sub-trader had it but
        // the wallet on-chain DOES hold the mint, rehydrate from there.
        // Operator forensics: 'wrong the tokens are in my wallets' — the
        // bot was aborting sells with qty=0 while the bag was sitting in
        // the wallet. This guarantees the sell pipeline can ALWAYS dump
        // any token the wallet actually owns.
        if (ts.position.qtyToken <= 0.0) {
            rehydratePositionFromWallet(ts, wallet)
        }

        val isPaper = ts.position.isPaperPosition
        val hasWallet = wallet != null

        // V5.9.290 FIX: doSell guard — same pendingVerify force-clear as BotService + liveSell.
        // If qtyToken > 0 but pendingVerify=true for > 120s, clear it so isOpen becomes true
        // and the sell is not incorrectly rejected here.
        if (ts.position.pendingVerify && ts.position.qtyToken > 0.0) {
            val pendingAgeMs = System.currentTimeMillis() - ts.position.entryTime
            if (pendingAgeMs >= 120_000L) {
                ErrorLogger.warn("Executor",
                    "⚠️ [DOSELL_VERIFY_STUCK] ${ts.symbol} | ${pendingAgeMs / 1000}s — force-clearing pendingVerify in doSell.")
                synchronized(ts) {
                    ts.position = ts.position.copy(pendingVerify = false)
                }
            }
        }
        if (!ts.position.isOpen) {
            if (paperCloseAuthorityActive) {
                PaperPositionCloseAuthority.markClosed("PAPER", ts.mint, ts.symbol, "POSITION_ALREADY_CLOSED:$reason")
            }
            onLog("⚠️ SELL SKIPPED: Position already closed for ${ts.symbol} (qty=${ts.position.qtyToken} pendingVerify=${ts.position.pendingVerify})", tradeId.mint)
            return SellResult.ALREADY_CLOSED
        }
        
        val configMode = if (isPaperRT()) "paper" else "live"
        val positionMode = if (isPaper) "paper" else "LIVE"
        onLog("📤 doSell: ${ts.symbol} | positionMode=$positionMode | configMode=$configMode | hasWallet=$hasWallet | reason=$reason", tradeId.mint)
        
        if (!isPaper && isPaperRT()) {
            ErrorLogger.warn("Executor", "⚠️ LIVE position sell while config is PAPER - executing LIVE sell anyway!")
            onLog("⚠️ LIVE position ${ts.symbol} must be sold LIVE even though config is paper", tradeId.mint)
        }
        
        if (!isPaper && wallet == null) {
            ErrorLogger.error("Executor", "🚨 CRITICAL: Live mode sell attempted but WALLET IS NULL!")
            ErrorLogger.error("Executor", "🚨 Token ${ts.symbol} - attempting wallet reconnect...")
            
            try {
                val reconnectedWallet = WalletManager.attemptReconnect()
                if (reconnectedWallet != null) {
                    ErrorLogger.info("Executor", "✅ Wallet reconnected! Proceeding with sell...")
                    onLog("✅ Wallet reconnected - proceeding with ${ts.symbol} sell", tradeId.mint)
                    return liveSell(ts, reason, reconnectedWallet, reconnectedWallet.getSolBalance(), tradeId)
                }
            } catch (e: Exception) {
                ErrorLogger.error("Executor", "🚨 Wallet reconnect failed: ${e.message}")
            }
            
            ErrorLogger.error("Executor", "🚨 Token ${ts.symbol} QUEUED FOR RETRY - reconnect wallet!")
            onLog("🚨 SELL QUEUED: ${ts.symbol} | Wallet disconnected - will retry", tradeId.mint)
            onNotify("🚨 Wallet Disconnected!", 
                "Cannot sell ${ts.symbol} - wallet is NULL! Queued for retry. Reconnect wallet!",
                com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
            onToast("🚨 Reconnect wallet to sell ${ts.symbol}!")
            
            PendingSellQueue.add(ts.mint, ts.symbol, reason)
            return SellResult.NO_WALLET
        }
        
        if (isPaper) {
            onLog("📄 Routing to paperSell (paperMode=$isPaper)", tradeId.mint)
            return paperSell(ts, reason, tradeId)
        } else if (wallet == null) {
            ErrorLogger.error("Executor", "🚨 LIVE MODE SELL BLOCKED: Wallet is NULL!")
            onLog("🚨 LIVE SELL BLOCKED: ${ts.symbol} | No wallet - position NOT cleared", tradeId.mint)
            onNotify("🚨 Sell Blocked!",
                "Cannot sell ${ts.symbol} - wallet not connected. Position still open!",
                com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
            onToast("🚨 Cannot sell ${ts.symbol} - reconnect wallet!")
            return SellResult.NO_WALLET
        } else {
            if (blockIfSellInFlight(ts, reason, LiveTradeLogStore.keyFor(ts.mint, ts.position.entryTime))) {
                return SellResult.FAILED_RETRYABLE
            }
            if (!com.lifecyclebot.engine.sell.SellExecutionLocks.tryAcquire(ts.mint)) {
                // V5.9.967 — z43-D SellSpamGuard wrap.
                if (com.lifecyclebot.engine.sell.SellSpamGuard.shouldLogBlocked(ts.mint, reason))
                    LiveTradeLogStore.log(
                        LiveTradeLogStore.keyFor(ts.mint, ts.position.entryTime), ts.mint, ts.symbol, "SELL",
                        LiveTradeLogStore.Phase.SELL_VERIFY_INCONCLUSIVE_PENDING,
                        "SELL_BLOCKED_ALREADY_IN_PROGRESS full reason=$reason", traderTag = "MEME")
                return SellResult.FAILED_RETRYABLE
            }
            onLog("💰 Routing to liveSell", tradeId.mint)
            val result = liveSell(ts, reason, wallet, walletSol, tradeId)
            // V5.7.7 FIX: Auto-requeue on retryable failure so SL/TP never gets silently dropped
            if (result == SellResult.FAILED_RETRYABLE) {
                val nonRouteWait = isNonRouteSellWait(ts)
                if (nonRouteWait) {
                    onLog("⏸️ Sell retry suppressed for ${ts.symbol}: existing finality/proof worker owns this mint; no PendingSellQueue/no noSig.", tradeId.mint)
                    try { ForensicLogger.lifecycle("SELL_RETRY_SUPPRESSED_NON_ROUTE_WAIT", "mint=${ts.mint.take(12)} symbol=${ts.symbol} reason=$reason proofWait=${com.lifecyclebot.engine.sell.BalanceProofWaitState.isWaiting(ts.mint)} activeSig=${TradeVerifier.activeSellSig(ts.mint)?.take(12) ?: "none"}") } catch (_: Throwable) {}
                } else {
                    PendingSellQueue.add(ts.mint, ts.symbol, reason)
                    onLog("🔄 Sell auto-queued for retry: ${ts.symbol} | reason=$reason", tradeId.mint)
                    ErrorLogger.warn("Executor", "🔄 SELL REQUEUED: ${ts.symbol} — will retry when wallet/RPC recovers")
                    // V5.0.4029 — generic retryable sells are NOT sell-finality
                    // corruption. Pre-broadcast route exhaustion/dust/no-wallet-route
                    // must never emit SELL_NO_CURRENT_HELD_PROOF_NOT_RETRIED because
                    // the doctor interprets that as a missing/corrupt landed sell.
                    // Typed route failures are handled inside liveSell() as
                    // ROUTE_FAILED_NO_SIGNATURE and are non-blocking/non-closing.
                    try {
                        ForensicLogger.lifecycle(
                            "SELL_RETRY_ENQUEUED_NO_FINALITY_FAULT",
                            "mint=${ts.mint.take(12)} symbol=${ts.symbol} reason=$reason no_close=true retry=true noSig=false"
                        )
                        PipelineHealthCollector.labelInc("SELL_RETRY_ENQUEUED_NO_FINALITY_FAULT")
                    } catch (_: Throwable) {}
                }
            }
            // V5.0.3746 — operator spec items 1, 5, 6: WAITING_BALANCE_PROOF is a
            // proof wait, NEVER an active sell. Skip PendingSellQueue.add (no
            // SELL_RETRY_TEMPORARY_ONLY emission) and skip
            // SELL_NO_CURRENT_HELD_PROOF_NOT_RETRIED (no route was actually
            // attempted). The BalanceProofPoller takes over from here.
            if (result == SellResult.WAITING_BALANCE_PROOF) {
                onLog("⏸️ SELL WAITING BALANCE PROOF: ${ts.symbol} — owned by BalanceProofPoller, no requeue/no blocking lease.", tradeId.mint)
            }
            return result
        }

        } finally {
            // Always release the sell guards after the sell/verify lifecycle returns.
            releaseSellLock(ts.mint)
            com.lifecyclebot.engine.sell.SellExecutionLocks.release(ts.mint)
        }
    }

    /**
     * V5.9.780 — EMERGENT MEME PAPER REALISM helper.
     * Parse the strategy's intended exit threshold from the sell reason
     * label so paperSell can clamp the exit price to a realistic band.
     * Returns (lowPct, highPct) relative to entryPrice, or (null, null)
     * for unknown labels (no clamp applied).
     */
    private fun parsePaperExitClamp(reason: String): Pair<Double?, Double?> {
        val r = reason.uppercase()
        val strictSl = Regex("""STRICT_SL_(-?\d+(?:\.\d+)?)""").find(r)
        if (strictSl != null) {
            val pct = strictSl.groupValues[1].toDoubleOrNull()
            // V5.9.801 — operator audit Fix C: tightened paper realism on
            // STRICT_SL exits. Pre-V5.9.801 used `pct - 5.0` → STRICT_SL_-10
            // booked in [-15%, -10%]. Operator forensics on the deep
            // performance report showed paper STRICT_SL exits routinely
            // booking near -15% while live cannot reproduce that drift on
            // a -10% trigger. Cap the band at 2% beyond the strategy's
            // stated threshold so [-12%, -10%] on STRICT_SL_-10 etc.
            if (pct != null) return Pair(pct - 2.0, pct)
        }
        val tp = Regex("""RAPID_TAKE_PROFIT_(\d+(?:\.\d+)?)""").find(r)
        if (tp != null) {
            val pct = tp.groupValues[1].toDoubleOrNull()
            if (pct != null) return Pair(pct - 5.0, pct)
        }
        if (r.contains("RAPID_ENTRY_PROTECT_STOP")) return Pair(-13.0, -8.0)
        // V5.9.1089 — paper realism for stop labels that do not encode a
        // numeric threshold. 5.0.3056 still journaled TREASURY_STOP_LOSS_SWEEP
        // at -75%/-90% and CASHGEN_STOP_LOSS at -72% because these labels fell
        // through unclamped to stale/raw prices. These are soft stop labels, not
        // rug/catastrophe labels; train the brain on the intended trigger band.
        if (r.contains("TREASURY_STOP_LOSS") || r.contains("TREASURY_SL")) return Pair(-17.0, -15.0)
        // V5.9.1225 — SELL_OPT stop labels were falling through unclamped.
        // Runtime 5.0.3192 journaled [SELL_OPT] Stop Loss exits at -53/-61/-79%,
        // training the brain on stale/raw paper prices even though SellOptimizationAI
        // triggers its soft SL around -6..-10%. Clamp to the intended soft-stop band.
        if (r.contains("SELL_OPT") && (r.contains("STOP_LOSS") || r.contains("STOP LOSS"))) return Pair(-12.0, -6.0)
        if (r.contains("CASHGEN_STOP_LOSS") || r.contains("SHITCOIN_STOP_LOSS") || r.contains("QUALITY_STOP_LOSS") || r.contains("BLUECHIP_STOP_LOSS") || r.contains("MOONSHOT_STOP_LOSS")) return Pair(-12.0, -6.0)
        // V5.9.1432 — MANIPULATED_STOP_LOSS was MISSING from the matcher, so every
        // MANIP soft-stop fell through to Pair(null,null) = NO CLAMP = raw gap-through.
        // Recent-Outcomes was full of MANIPULATED LOSS -84.5%/-92.0% — impossible under
        // the -15% floor — crushing MANIP WR/net to 9%/-0.114 and poisoning learning.
        if (r.contains("MANIPULATED_STOP_LOSS") || r.contains("MANIP_STOP_LOSS") || r.contains("DIP_HUNTER_STOP_LOSS") || r.contains("PROJECT_SNIPER_STOP_LOSS") || r.contains("CYCLIC_STOP_LOSS") || r.contains("CYCLIC_SL")) return Pair(-12.0, -6.0)
        // V5.9.1086 — align paper hard-floor accounting with the operator's
        // unconditional -15% floor. Old [-20,-9] made hard-floor exits look
        // materially better/worse than the actual trigger band.
        if (r.contains("RAPID_HARD_FLOOR_STOP") || r.contains("HARD_FLOOR")) return Pair(-17.0, -15.0)
        // V5.9.795 — operator audit (build-2733 dump): catastrophe trigger
        // was tightened from -25% to -14% in V5.9.791, but the paper clamp
        // band was left at [-30%, -15%] — meaning every RAPID_CATASTROPHE
        // exit was booking -15% to -30% realised even though the strategy
        // pulled the trigger at -14%. Trade journal showed uniform -30.7%
        // catastrophe exits, which was the paper sim lying to the AI
        // layers about edge. V5.9.795 aligned to [-19%, -14%].
        // V5.9.801 — operator audit Fix C: tightened further to [-16%, -14%].
        // The deep-performance report still showed catastrophe paper
        // exits booking ~-19% on a -14% trigger, a 5pp paper-vs-live
        // drift. Live execution catastrophe drift is empirically 0–2pp;
        // matching that ends the paper-edge fantasy entirely.
        if (r.contains("RAPID_CATASTROPHE_STOP")) return Pair(-16.0, -14.0)
        if (r.contains("TREASURY_TAKE_PROFIT")) return Pair(+5.0, +15.0)
        if (r.contains("FLAT_EXIT") || r.contains("SCRATCH")) return Pair(-3.0, +3.0)
        if (r.contains("TRAILING_STOP") || r.contains("TRAIL_STOP")) return Pair(-10.0, +5.0)
        // V5.9.1432 — GENERIC SOFT-STOP FALLBACK. Any *_STOP_LOSS / *_SL label not
        // matched above must NOT fall through unclamped (the structural hole that let
        // -90% gap-throughs into the journal). A soft stop can never realistically book
        // worse than the -15% hard floor; bound any remaining stop label to the floor
        // band. Rug/catastrophe/gap-guard labels are matched explicitly above.
        if (r.endsWith("_STOP_LOSS") || r.endsWith("_SL") || r.contains("STOP_LOSS")) return Pair(-15.0, -6.0)
        return Pair(null, null)
    }

    /**
     * V5.9.780 — EMERGENT MEME PAPER REALISM helper.
     * Is this paper trade reason a zero-information SCRATCH/FLAT that
     * should be excluded from learning counts? (RunTracker30D will use
     * this to avoid counting flat exits toward the bootstrap milestone.)
     */
    internal fun isPaperScratchTrade(reason: String, pnlPct: Double): Boolean {
        val r = reason.uppercase()
        if (kotlin.math.abs(pnlPct) <= 1.5) return true
        return r.contains("SCRATCH") || r.contains("FLAT_EXIT")
    }

    private fun maxConfiguredPaperTradeSol(): Double {
        return try {
            val c = cfg()
            val legacyMax = maxOf(c.smallBuySol, c.maxPositionSol).takeIf { it.isFinite() && it > 0.0 } ?: 0.15
            // V5.0.3873 — ALL PAPER ENTRIES must train at live-transfer size, not
            // legacy micro-probe size. SmartSizer can compute realistic paper sizes,
            // but this final executor clamp used to crush every normal paper lane
            // back to maxPositionSol (default 0.15 SOL). That makes paper PnL/impact
            // too small to teach live sizing. Use 10% of configured paper bankroll as
            // the universal paper-learning cap, bounded to a sane 2 SOL ceiling.
            maxOf(legacyMax, (c.paperSimulatedBalance * 0.10).coerceIn(legacyMax, 2.0))
        } catch (_: Throwable) { 1.0 }
    }

    private fun minConfiguredPaperTradeSol(): Double {
        return try {
            val c = cfg()
            val legacyMin = c.smallBuySol.takeIf { it.isFinite() && it > 0.0 } ?: 0.05
            // V5.0.3873 — live-transfer floor. A 0.01/0.03 SOL paper row is useful
            // for route smoke, but not for learned live sizing. Default paper bankroll
            // 11.76 SOL => min ≈0.1176 SOL, still small enough for high throughput.
            maxOf(legacyMin, (c.paperSimulatedBalance * 0.01).coerceIn(0.05, 0.15))
        } catch (_: Throwable) { 0.10 }
    }

    private fun clampPaperTradeSol(requested: Double, mint: String = "", symbol: String = "", source: String = "paper", maxOverrideSol: Double? = null): Double {
        val minSol = minConfiguredPaperTradeSol()
        val configuredMax = maxOverrideSol?.takeIf { it.isFinite() && it > 0.0 } ?: maxConfiguredPaperTradeSol()
        val maxSol = configuredMax.coerceAtLeast(minSol)
        if (!requested.isFinite() || requested <= 0.0) return 0.0
        val clamped = requested.coerceIn(minSol, maxSol)
        if (kotlin.math.abs(clamped - requested) > 0.0000001) {
            try {
                ForensicLogger.lifecycle(
                    "PAPER_BUY_SIZE_CLAMPED",
                    "mint=${mint.take(10)} symbol=$symbol source=$source requested=${requested.fmt(6)} clamped=${clamped.fmt(6)} min=${minSol.fmt(6)} max=${maxSol.fmt(6)}"
                )
                PipelineHealthCollector.labelInc("PAPER_BUY_SIZE_CLAMPED")
            } catch (_: Throwable) {}
        }
        return clamped
    }


    fun paperSell(ts: TokenState, reason: String, identity: TradeIdentity? = null): SellResult {
        val tradeId = identity ?: TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
        
        val pos   = ts.position
        val price = getActualPrice(ts)
        if (!pos.isOpen) {
            PaperPositionCloseAuthority.markClosed("PAPER", ts.mint, ts.symbol, "PAPER_SELL_NOT_OPEN:$reason")
            return SellResult.ALREADY_CLOSED
        }
        if (price == 0.0) {
            PaperPositionCloseAuthority.markFailed("PAPER", ts.mint, ts.symbol, "PAPER_SELL_NO_PRICE:$reason")
            return SellResult.FAILED_RETRYABLE
        }
        // V5.9.1470 (spec item 2) — CLOSE IDEMPOTENCY. If this mint already has a live
        // close stamp, a previous paperSell already finalized it. Suppress the duplicate
        // SELL: do NOT journal, train, or re-occupy the slot. Fixes the same-mint
        // multi-sell storm (Fsnx8Y / 7AUvsp) the operator observed.
        run {
            val existingCloseId = com.lifecyclebot.engine.PositionCloseLedger.closeIdOf(ts.mint)
            if (existingCloseId != null) {
                PaperPositionCloseAuthority.markClosed("PAPER", ts.mint, ts.symbol, "LEDGER_ALREADY_CLOSED:$reason", existingCloseId)
                try { ForensicLogger.lifecycle("PAPER_SELL_DUPLICATE_SUPPRESSED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} originalCloseId=$existingCloseId reason=$reason") } catch (_: Throwable) {}
                return SellResult.ALREADY_CLOSED
            }
        }
        // V5.9.719: acquire paper sell lock to prevent double-exit race.
        // If another sell request is already in-flight for this mint, reject this one.
        if (!acquirePaperSellLock(ts.mint)) {
            ErrorLogger.debug("Executor", "🔒 PAPER_DOUBLE_SELL_BLOCKED: ${ts.symbol} reason=$reason already selling")
            return SellResult.ALREADY_CLOSED
        }
        PaperPositionCloseAuthority.markClosing("PAPER", ts.mint, ts.symbol, reason)
        // V5.9.720: try/finally ensures lock is ALWAYS released — even on exception.
        // Without this, a crash mid-sell leaves the lock set forever, causing
        // bot-stop closeAllPositions() to see ALREADY_CLOSED and skip the position.
        try {
        try { ForensicLogger.lifecycle("PAPER_SELL_START", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason") } catch (_: Throwable) {}
        // FIX: these were missing and caused your compile failure
        // V5.9.83: guard against unset entryTime (would make holdTime = now-epoch = 56 yrs).
        val entryTimeSafe = if (pos.entryTime > 1_000_000_000_000L) pos.entryTime else System.currentTimeMillis()
        val holdTimeMins = (System.currentTimeMillis() - entryTimeSafe) / 60_000.0
        val holdMinutes = holdTimeMins
        
        // V5.9.780 — EMERGENT MEME PAPER REALISM.
        // Operator forensics: STRICT_SL_-10 exits booked at -94%; +30% TP
        // exits booked at +8234%. Paper sim was using getActualPrice(ts)
        // verbatim with no clamp + only 0.5–4% slippage. Live execution
        // CANNOT reproduce those returns — Jupiter slippage on meme dust
        // is 8–25%. So paper has been LYING to the AI layers about edge,
        // sending the bot into LIVE with a fantasy +37%/trade prior.
        //
        // Six corrections applied below:
        //  (1) realistic slippage curve based on liquidity tier
        //  (2) exit-price clamp around the strategy's stated threshold
        //      so STRICT_SL_-10 books in [-10%, -15%], not -94%
        //      and RAPID_TAKE_PROFIT_30 books in [+25%, +30%], not +8234%
        //  (3) liquidity-aware return cap (single trade pnl bounded by
        //      `liq / costSol * 0.5` — you can't extract +8000% from a
        //      $4k pool with a $1 position because exit liquidity is
        //      capped by the same pool)
        //  (5) SCRATCH/FLAT exits flagged so RunTracker30D can exclude
        //      them from learning counts (zero-information trades were
        //      inflating the bootstrap milestone).
        // V5.9.1436 — REALISTIC PAPER SLIPPAGE (exit side). See entry-side
        // note: the old 18%/10%/6% exit tax was the dominant driver of the
        // identical SHITCOIN_STOP_LOSS loss clusters and phantom catastrophe
        // prints in the journal. Capped at the operator's real 5% worst-case
        // (typical ~1%). Tier shape preserved. Live execution untouched —
        // real Jupiter slippage IS the real cost there.
        val simulatedSlippagePct = when {
            ts.lastLiquidityUsd < 5_000.0   -> 5.0   // dust pump.fun bonding curve (was 18)
            ts.lastLiquidityUsd < 20_000.0  -> 3.0   // small post-grad pool (was 10)
            ts.lastLiquidityUsd < 50_000.0  -> 2.0   // (was 6)
            ts.lastLiquidityUsd < 250_000.0 -> 1.0   // (was 3)
            else -> 0.5                               // (was 1.5)
        }
        val slippageMultiplier = 1.0 - (simulatedSlippagePct / 100.0)
        var effectivePrice = price * slippageMultiplier

        // (2) EXIT PRICE CLAMP — derive the strategy's intended exit band
        // from the reason label. We honour the label rather than letting
        // a stale price take us 100x past it.
        // V5.9.1430 — realized-pct band bounds used only when entryPrice is
        // missing (set by the no-entry branch below). null = no override.
        var paperBandFloorPct: Double? = null
        var paperBandCeilPct: Double? = null
        val (clampLowPct, clampHighPct) = parsePaperExitClamp(reason)
        if (pos.entryPrice > 0.0 && clampLowPct != null && clampHighPct != null) {
            val low  = pos.entryPrice * (1.0 + clampLowPct / 100.0)
            val high = pos.entryPrice * (1.0 + clampHighPct / 100.0)
            val clamped = effectivePrice.coerceIn(minOf(low, high), maxOf(low, high))
            if (clamped != effectivePrice) {
                try {
                    ForensicLogger.lifecycle(
                        "PAPER_EXIT_PRICE_CLAMPED",
                        "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason fromPrice=${"%.10f".format(effectivePrice)} toPrice=${"%.10f".format(clamped)} entry=${"%.10f".format(pos.entryPrice)} band=[${clampLowPct}%,${clampHighPct}%]",
                    )
                } catch (_: Throwable) {}
                effectivePrice = clamped
            }
        } else if (pos.entryPrice <= 0.0 && clampLowPct != null && clampHighPct != null) {
            // V5.9.1430 — ENTRY-PRICE-MISSING GAP-THROUGH GUARD. When entryPrice
            // is 0/missing the price-band clamp above is SKIPPED, so a stale paper
            // quote books the raw gap (this is how FINDER SHITCOIN_STOP_LOSS booked
            // -50.7% even though the SHITCOIN stop band is [-12%,-6%], and how a
            // hard-floor exit could book past the unconditional -15% floor).
            // Synthesise a valid entry from the current price + the band so the
            // clamp can still apply: pin effectivePrice to the band's worst edge,
            // honouring the strategy's stated trigger instead of the phantom gap.
            // Hard-floor/HARD bands are [-17,-15] so this also re-enforces the
            // operator's unconditional -15% floor on the gap-through case.
            val worstPct = minOf(clampLowPct, clampHighPct)
            val bestPct  = maxOf(clampLowPct, clampHighPct)
            // Mark so the realized-pct clamp below knows to bound to [worst,best].
            paperBandFloorPct = worstPct
            paperBandCeilPct  = bestPct
            try {
                ForensicLogger.lifecycle(
                    "PAPER_EXIT_BAND_NO_ENTRY",
                    "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason band=[${worstPct}%,${bestPct}%] — entryPrice missing, clamping realized pct to band",
                )
            } catch (_: Throwable) {}
        }

        // V5.0.3868 — executable-live paper friction.
        // Report: live MemeTrader buys/sells flow, but paper edge doesn't transfer;
        // bot runs about even/slightly under live. Root cause: terminal paper sells
        // only charged 0.5%, while live meme round-trip drag is ≈1.6% plus route/
        // liquidity slippage. Train paper on executable net edge, not optimistic
        // gross paper edge, so readiness/lane memory promote only trades that can
        // survive real fees/slip.
        val expectedRouteSlipPct = try {
            com.lifecyclebot.v3.scoring.ExecutionCostPredictorAI.expectedExtraSlipPct(ts.lastLiquidityUsd)
        } catch (_: Throwable) { 0.0 }
        val simulatedFeePct = (1.6 + expectedRouteSlipPct.coerceIn(0.0, 8.0)).coerceIn(1.6, 9.6)

        val priceDerivedPnlPct = run {
            val base = pct(pos.entryPrice, effectivePrice).coerceIn(-100.0, 1000.0)
            // V5.9.1430 — when entryPrice was missing, pct() is meaningless
            // (division by ~0). Bound the realized pct to the strategy's stated
            // band so a gap-through cannot book -50% on a [-12,-6] stop, nor
            // breach the unconditional -15% floor on a hard-floor label.
            if (paperBandFloorPct != null && paperBandCeilPct != null) {
                base.coerceIn(paperBandFloorPct!!, paperBandCeilPct!!)
            } else base
        }
        val rawValue = pos.costSol * (1.0 + priceDerivedPnlPct / 100.0) * (1.0 - simulatedFeePct / 100.0)
        // (3) Cost-basis paper proceeds — paper has no real token balance. Do
        // NOT book proceeds from qtyToken * price; a stale qty or source-basis
        // mismatch creates impossible million-SOL rows. We already have the
        // correct comparable entry/exit price after getActualPrice() rebase and
        // optional reason clamp, so proceeds are cost basis × price return.
        val cappedValue = run {
            val solPriceUsd = WalletManager.lastKnownSolPrice
            if (ts.lastLiquidityUsd > 0.0 && solPriceUsd > 0.0) {
                val maxValueSol = (ts.lastLiquidityUsd * 0.5) / solPriceUsd
                if (rawValue > maxValueSol) {
                    try {
                        ForensicLogger.lifecycle(
                            "PAPER_PNL_LIQUIDITY_CAPPED",
                            "mint=${ts.mint.take(10)} symbol=${ts.symbol} rawValueSol=${"%.6f".format(rawValue)} capSol=${"%.6f".format(maxValueSol)} liqUsd=${"%.0f".format(ts.lastLiquidityUsd)}",
                        )
                    } catch (_: Throwable) {}
                    maxValueSol
                } else rawValue
            } else rawValue
        }
        val value = cappedValue.coerceAtLeast(0.0)
        val grossNoFrictionValue = (pos.costSol * (1.0 + priceDerivedPnlPct / 100.0)).coerceAtLeast(0.0)
        val simulatedFeeSol = (grossNoFrictionValue - value).coerceAtLeast(0.0)
        val pnl   = value - pos.costSol
        val pnlP  = pct(pos.costSol, value)
        val trade = Trade(
            side = "SELL", 
            mode = "paper", 
            // V5.9.1018c — operator triage bug: this was `sol = pos.costSol`,
            // which records the COST BASIS (with all top-ups summed in) as
            // the SELL row's `sol` field. Every other SELL constructor in
            // this file — live sells, partial sells, profit-lock, capital
            // recovery — uses GROSS PROCEEDS. The mismatch made operator
            // see `BUY sol=0.685` → `SELL sol=1.370 pnl=-1.115` (a buy that
            // top-upped to 1.370 cost basis then dumped) and read it as
            // "98% loss in seconds for no reason". It also fed cost basis
            // into CanonicalLearning.exitSol = trade.sol — corrupt learning.
            sol = value,
            price = price,
            ts = System.currentTimeMillis(),
            reason = reason,
            pnlSol = pnl,
            pnlPct = pnlP,
            // V5.9.1205 — close rows must preserve entry score for
            // LosingPatternMemory. Default 0 made normal ShitCoin/Quality
            // closes look like S0-10 death-bucket samples.
            score = pos.entryScore,
            feeSol = simulatedFeeSol,
            netPnlSol = pnl,
            tradingMode = pos.tradingMode,
            tradingModeEmoji = pos.tradingModeEmoji,
        )
        // V5.9.1011 — PAPER SELL FAST PATH.
        // Snapshot before closing the real position, then move canonical journal
        // + security + ML/learning fanout off this sell thread. V5.9.1010
        // proved paperSell was stalling between PAPER_SELL_START and
        // PAPER_SELL_JOURNAL_DONE, i.e. inside synchronous recordTrade()/
        // TradeHistoryStore/SecurityGuard work. Closing the position and
        // releasing locks must not wait for that fanout.
        val tradeSnap = if (trade.mint.isBlank()) trade.copy(mint = ts.mint) else trade
        val tsLearningSnap = try {
            ts.copy(
                position = pos.copy(),
                trades = mutableListOf(),
                recentEntryTimes = ts.recentEntryTimes.toMutableList(),
            )
        } catch (_: Throwable) { ts }
        try { ts.trades.add(tradeSnap) } catch (_: Throwable) {}
        kotlinx.coroutines.GlobalScope.launch(AppDispatchers.sideEffect) {
            try {
                recordTrade(tsLearningSnap, tradeSnap)
                try { security.recordTrade(tradeSnap) } catch (_: Throwable) {}
                try { ForensicLogger.lifecycle("PAPER_SELL_JOURNAL_DONE", "mint=${tradeSnap.mint.take(10)} symbol=${tsLearningSnap.symbol} pnlPct=${tradeSnap.pnlPct.toInt()} reason=${tradeSnap.reason}") } catch (_: Throwable) {}
                // V5.0.3680 — TELEMETRY GAP. EXEC_PAPER_SELL_OK was always 0
                // despite EXEC_SELL=67 in journal. Same gap pattern as the
                // V5.0.3679 LIVE_BUY_FAIL telemetry fix. Increment the per-
                // mode exec counter so the operator dashboard reflects the
                // 67 paper sells actually happening.
                try { ForensicLogger.exec(
                    "PAPER_SELL_OK",
                    tsLearningSnap.symbol,
                    "mint=${tradeSnap.mint.take(10)} pnlPct=${tradeSnap.pnlPct.toInt()} reason=${tradeSnap.reason.take(40)}",
                ) } catch (_: Throwable) {}
            } catch (t: Throwable) {
                ErrorLogger.warn("Executor", "paperSell async journal error: ${t.message}")
                try { ForensicLogger.lifecycle("PAPER_SELL_JOURNAL_ASYNC_ERR", "mint=${tradeSnap.mint.take(10)} err=${t.message?.take(80)}") } catch (_: Throwable) {}
                // V5.0.3680 — exec FAIL counter increment on the paper async path.
                try { ForensicLogger.exec(
                    "PAPER_SELL_FAIL",
                    tsLearningSnap.symbol,
                    "mint=${tradeSnap.mint.take(10)} reason=ASYNC_ERR:${t.message?.take(60)}",
                ) } catch (_: Throwable) {}
            }
        }
        try { ForensicLogger.lifecycle("PAPER_SELL_LEARNING_ASYNC_QUEUED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=$reason") } catch (_: Throwable) {}
        
        EmergentGuardrails.unregisterPosition(tradeId.mint)
        // V5.9.385 — match the BUY-side registerPosition by closing the
        // GlobalTradeRegistry.activePositions entry here. After this call
        // the scanner eviction guard releases and the mint can be removed
        // from the watchlist normally (or kept around via cooldown as before).
        try {
            com.lifecyclebot.engine.GlobalTradeRegistry.closePosition(tradeId.mint)
        } catch (_: Exception) { /* non-critical */ }
        try { com.lifecyclebot.v4.meta.PortfolioHeatAI.removePosition(tradeId.mint) } catch (_: Throwable) {}
        // V5.9.1470 (spec item 1) — ATOMIC CLOSE STAMP. Record the canonical close
        // identity so every later exit pass / slot tracker / forcedOpen scan sees this
        // mint as CLOSED and cannot re-sell it or hold its slot. Stamped here, inside
        // the sell-lock try-block, the instant the registry close fires. Metadata only —
        // never touches qtyToken, balances, or P&L.
        try {
            val pnlPctForLedger = try { OpenPnlSanity.inspectPosition(pos, price, "Executor.close_ledger_stamp_6038/${ts.symbol}/${ts.mint.take(8)}", emit = true).takeIf { it.ok }?.pnlPct?.toInt() ?: 0 } catch (_: Throwable) { 0 }
            val cid = com.lifecyclebot.engine.PositionCloseLedger.markClosed(tradeId.mint, reason, pnlPctForLedger)
            PaperPositionCloseAuthority.markClosed("PAPER", tradeId.mint, ts.symbol, reason, cid)
            ForensicLogger.lifecycle("POSITION_CLOSE_LEDGER_STAMPED", "mint=${tradeId.mint.take(10)} closeId=$cid reason=$reason")
        } catch (_: Throwable) {}

        // V5.9.428 — treasury split BEFORE wallet credit (was double-counting).
        // Previously: wallet got `value` (principal + 100% profit) AND treasury
        // got 30% on top — inflating both balances and leaving treasury a
        // phantom counter. Now: compute treasuryShare first, credit wallet
        // with (value - treasuryShare) so capital accounting is honest.
        //   • Losing/scratch sells           → treasuryShare = 0 (unchanged)
        //   • Treasury-scalp wins            → 100% of profit → treasury
        //   • All other meme wins            → 30% of profit  → treasury
        val treasuryShare = if (pnl > 0) {
            try {
                if (pos.isTreasuryPosition || pos.tradingMode == "TREASURY") {
                    TreasuryManager.contributeFullyFromTreasuryScalp(pnl, WalletManager.lastKnownSolPrice, isPaper = true)
                } else {
                    TreasuryManager.contributeFromMemeSell(pnl, WalletManager.lastKnownSolPrice, isPaper = true)
                }
            } catch (e: Exception) {
                ErrorLogger.debug("Executor", "Treasury split error (paper): ${e.message}")
                0.0
            }
        } else 0.0

        val cyclicVirtualPaperClose = pos.tradingMode.equals("CYCLIC", true) || reason.startsWith("CYCLIC_", true)
        if (cyclicVirtualPaperClose) {
            try { ForensicLogger.lifecycle("PAPER_SELL_SHARED_WALLET_CREDIT_SKIPPED", "mint=${tradeId.mint.take(10)} symbol=${tradeId.symbol} mode=${pos.tradingMode} reason=$reason value=${value.fmt(4)} virtual_book=CYCLIC") } catch (_: Throwable) {}
        } else {
            onPaperBalanceChange?.invoke(value - treasuryShare)
        }
        
        if (cfg().fluidLearningEnabled) {
            FluidLearning.recordPaperSell(tradeId.mint, pos.costSol, pnl)
            FluidLearning.recordPriceImpact(tradeId.mint, pos.costSol, ts.lastLiquidityUsd, isBuy = false)
            FluidLearning.clearPriceImpact(tradeId.mint)
        }
        
        onLog("PAPER SELL @ ${price.fmt()} | $reason | pnl ${pnl.fmt(4)} SOL (${pnlP.fmtPct()})", tradeId.mint)
        onNotify("📉 Paper Sell", "${tradeId.symbol}  $reason  PnL ${pnlP.fmtPct()}", com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO)
        
        TradeAlerts.onSell(cfg(), tradeId.symbol, pnl, pnlP, reason, isPaper = true)
        
        if (pnl > 0) sounds?.playCashRegister() else sounds?.playWarningSiren()
        if (pnl > 0) sounds?.playMilestone(pnlP)
        SmartSizer.recordTrade(pnl > 0, isPaperMode = true)

        // V5.9.400 — feed ExecutionCostPredictorAI in paper mode so its
        // per-liq-band history accumulates samples (was 100% zero / DEAD).
        // Synthetic slip = sqrt(size/liq) basis-point model — rough but
        // teaches the layer the relationship between size, liquidity and
        // realized cost. Layer can then refine when live trades run.
        try {
            val liqUsdSlip = ts.lastLiquidityUsd
            val sizeUsd = pos.costSol * WalletManager.lastKnownSolPrice
            if (liqUsdSlip > 0 && sizeUsd > 0) {
                val slipFrac = kotlin.math.sqrt(sizeUsd / liqUsdSlip).coerceAtMost(0.10)
                val quoted = ts.lastPrice
                val realized = quoted * (1.0 - slipFrac)
                com.lifecyclebot.v3.scoring.ExecutionCostPredictorAI.learn(
                    liqUsd = liqUsdSlip,
                    quotedPxUsd = quoted,
                    realizedPxUsd = realized,
                )
            }
        } catch (_: Exception) {}

        // V5.9.399 / V5.9.428 — treasury split moved above and integrated with
        // wallet credit so accounting is honest (no double-counting). Losing
        // sells still contribute nothing.

        if (pnl > 0) {
            try {
                val drawdownPct = SmartSizer.getCurrentDrawdownPct(isPaper = true)
                val allocation = AutoCompoundEngine.processWin(pnl, drawdownPct)
                
                if (allocation.toTreasury > 0) {
                    com.lifecyclebot.v3.scoring.CashGenerationAI.addToTreasury(allocation.toTreasury, isPaper = true)
                }
                
                ErrorLogger.info("Executor", "🔄 AUTO-COMPOUND [PAPER]: ${pnl.fmt(4)} SOL profit → " +
                    "Treasury: ${allocation.toTreasury.fmt(3)} | " +
                    "Compound: ${allocation.toCompound.fmt(3)} | " +
                    "Wallet: ${allocation.toWallet.fmt(3)} | " +
                    "Size mult: ${allocation.newSizeMultiplier.fmt(2)}x")
            } catch (e: Exception) {
                ErrorLogger.debug("Executor", "AutoCompound error (paper): ${e.message}")
            }
        }

        try {
            val isWin = pnlP >= 1.0  // V5.9.226: 1% floor — pnl>0 includes fee-wash near-zeros
            
            val treasurySignal = if (isWin) {
                com.lifecyclebot.v3.scoring.CashGenerationAI.ExitSignal.TAKE_PROFIT
            } else {
                com.lifecyclebot.v3.scoring.CashGenerationAI.ExitSignal.STOP_LOSS
            }
            com.lifecyclebot.v3.scoring.CashGenerationAI.closePosition(ts.mint, price, treasurySignal)
            
            val shitcoinSignal = if (isWin) {
                com.lifecyclebot.v3.scoring.ShitCoinTraderAI.ExitSignal.TAKE_PROFIT
            } else {
                com.lifecyclebot.v3.scoring.ShitCoinTraderAI.ExitSignal.STOP_LOSS
            }
            com.lifecyclebot.v3.scoring.ShitCoinTraderAI.closePosition(ts.mint, price, shitcoinSignal)
            
            val bluechipSignal = if (isWin) {
                com.lifecyclebot.v3.scoring.BlueChipTraderAI.ExitSignal.TAKE_PROFIT
            } else {
                com.lifecyclebot.v3.scoring.BlueChipTraderAI.ExitSignal.STOP_LOSS
            }
            com.lifecyclebot.v3.scoring.BlueChipTraderAI.closePosition(ts.mint, price, bluechipSignal)

            // V5.9.963 — UNIVERSAL SUB-TRADER CLOSE (paperSell win/loss path).
            // Pre-fix only CashGen/ShitCoin/BlueChip got closePosition() here.
            // The other 6 sub-traders (Moonshot, Quality, Manipulated, DipHunter,
            // ProjectSniper, ShitCoinExpress) retained the entry in their private
            // activePositions map forever. After ts.position was zeroed below,
            // rapidStopLossMonitor's V5.9.721 sub-trader sweep kept finding the
            // zombie entry, fired requestSell -> acquireSellLock -> ALREADY_CLOSED
            // -> releaseSellLock at ~3 calls/sec for 2+ minutes per dead mint.
            // V5.9.962 forensics: 417 SELL_LOCK_SET for 3 real sells.
            try {
                val mEx = if (isWin) com.lifecyclebot.v3.scoring.MoonshotTraderAI.ExitSignal.TAKE_PROFIT
                          else com.lifecyclebot.v3.scoring.MoonshotTraderAI.ExitSignal.STOP_LOSS
                com.lifecyclebot.v3.scoring.MoonshotTraderAI.closePosition(ts.mint, price, mEx)
            } catch (_: Exception) {}
            try {
                val qEx = if (isWin) com.lifecyclebot.v3.scoring.QualityTraderAI.ExitSignal.TAKE_PROFIT
                          else com.lifecyclebot.v3.scoring.QualityTraderAI.ExitSignal.STOP_LOSS
                com.lifecyclebot.v3.scoring.QualityTraderAI.closePosition(ts.mint, price, qEx)
            } catch (_: Exception) {}
            try {
                val manEx = if (isWin) com.lifecyclebot.v3.scoring.ManipulatedTraderAI.ManipExitSignal.TAKE_PROFIT
                            else com.lifecyclebot.v3.scoring.ManipulatedTraderAI.ManipExitSignal.STOP_LOSS
                com.lifecyclebot.v3.scoring.ManipulatedTraderAI.closePosition(ts.mint, price, manEx)
            } catch (_: Exception) {}
            try {
                val dipEx = if (isWin) com.lifecyclebot.v3.scoring.DipHunterAI.DipExitSignal.RECOVERY_TARGET
                            else com.lifecyclebot.v3.scoring.DipHunterAI.DipExitSignal.STOP_LOSS
                com.lifecyclebot.v3.scoring.DipHunterAI.closeDip(ts.mint, price, dipEx)
            } catch (_: Exception) {}
            try {
                val snEx = com.lifecyclebot.v3.scoring.ProjectSniperAI.ExitSignal(
                    shouldExit = true,
                    exitPct = 100,
                    reason = if (isWin) "TAKE_PROFIT" else "STOP_LOSS",
                    rank = com.lifecyclebot.v3.scoring.ProjectSniperAI.SniperRank.PENDING,
                )
                com.lifecyclebot.v3.scoring.ProjectSniperAI.completeMission(ts.mint, price, snEx)
            } catch (_: Exception) {}
            try {
                val expEx = if (isWin) com.lifecyclebot.v3.scoring.ShitCoinExpress.ExitSignal.TAKE_PROFIT_30
                            else com.lifecyclebot.v3.scoring.ShitCoinExpress.ExitSignal.STOP_LOSS
                com.lifecyclebot.v3.scoring.ShitCoinExpress.exitRide(ts.mint, price, expEx)
            } catch (_: Exception) {}

            ErrorLogger.debug("Executor", "✅ Closed all 9 sub-trader positions for ${ts.symbol}")
        } catch (e: Exception) {
            ErrorLogger.error("Executor", "Error closing layer positions: ${e.message}")
        }

        // V5.9.1133 — close paper position state before heavy learning fanout.
        // 3100 showed ghost-looking open positions after sells while the code kept
        // ts.position open until after bad-observation/brain/memory work. The
        // async journal already uses tsLearningSnap, and later learning can read
        // immutable `pos`, so clear live state now to stop exit sweeps/re-entry
        // guards from seeing a closed paper trade as still open.
        ts.position = Position()
        ts.lastExitTs = System.currentTimeMillis()
        ts.lastExitPrice = price
        ts.lastExitPnlPct = pnlP
        ts.lastExitWasWin = pnlP >= 1.0
        try { PositionPersistence.removePosition(ts.mint) } catch (_: Exception) {}
        try { ForensicLogger.lifecycle("PAPER_SELL_POSITION_CLOSED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} pnlPct=${pnlP.toInt()} reason=$reason stage=early_close persisted=removed") } catch (_: Throwable) {}
        // V5.9.1369 — GHOST FIX (lifecycle tracker). The lifecycle ledger only reaches
        // a TERMINAL state (CLEARED) when onSellSettled sees walletTokenAfter<=dust. In
        // PAPER mode there is NO live wallet to reconcile, so the old live-wallet-driven
        // settle returned null -> RESIDUAL_HELD (non-terminal) and openCount() kept the
        // sold paper position forever. UI showed inflated "24 open" vs 7 real. A paper
        // sell IS the truth (the sim fully exits), so settle deterministically with
        // walletTokenAfter=0.0 -> CLEARED. Closes the lifecycle-tracker ghost class.
        try {
            TokenLifecycleTracker.onSellSettled(
                mint = ts.mint,
                sig = "PAPER:${reason}",
                solReceived = pos.costSol.coerceAtLeast(0.0),
                walletTokenAfter = 0.0,
            )
        } catch (_: Throwable) {}
        try { BotService.recentlyClosedMs[ts.mint] = System.currentTimeMillis() } catch (_: Throwable) {}
        try { GlobalTradeRegistry.closePosition(tradeId.mint) } catch (_: Exception) {}
        try { EmergentGuardrails.unregisterPosition(tradeId.mint) } catch (_: Exception) {}
        try { com.lifecyclebot.v4.meta.PortfolioHeatAI.removePosition(tradeId.mint) } catch (_: Throwable) {}
        
        try {
            TradeAuthorizer.releasePosition(
                mint = ts.mint,
                reason = "SELL_$reason",
                book = TradeAuthorizer.ExecutionBook.CORE
            )
            ErrorLogger.debug("Executor", "🔓 CORE LOCK RELEASED: ${ts.symbol}")
        } catch (e: Exception) {
            ErrorLogger.debug("Executor", "Failed to release CORE lock: ${e.message}")
        }

        val maxGainPct = if (pos.entryPrice > 0 && pos.highestPrice > 0) {
            ((pos.highestPrice - pos.entryPrice) / pos.entryPrice) * 100.0
        } else 0.0
        
        val tokenAgeMins = if (ts.addedToWatchlistAt > 0) {
            (pos.entryTime - ts.addedToWatchlistAt) / 60_000.0
        } else 0.0
        
        // V5.9.720: BOT-SHUTDOWN FAST PATH.
        // For bot_shutdown sells, skip all 44-layer AI learning — it's a forced
        // exit, not a real signal. The position is closed and wallet is credited
        // above; learning from a shutdown sell is pure noise and takes 2-4s/position.
        // With 17+ open positions this was causing the 60-90s freeze on restart.
        if (reason == "bot_shutdown") {
            val shutdownCostSol = pos.costSol  // capture BEFORE position reset
            tradeId.closed(price, pnlP, pnl, reason)
            try { GlobalTradeRegistry.closePosition(tradeId.mint) } catch (_: Exception) {}
            try { EmergentGuardrails.unregisterPosition(tradeId.mint) } catch (_: Exception) {}
            try { com.lifecyclebot.v4.meta.PortfolioHeatAI.removePosition(tradeId.mint) } catch (_: Throwable) {}
            ts.position      = Position()
            ts.lastExitTs    = System.currentTimeMillis()
            ts.lastExitPrice = price
            ts.lastExitPnlPct = pnlP
            ts.lastExitWasWin = pnlP >= 1.0
            try { PositionPersistence.removePosition(ts.mint) } catch (_: Exception) {}
            try { PaperPositionCloseAuthority.markClosed("PAPER", ts.mint, ts.symbol, "bot_shutdown") } catch (_: Throwable) {}
            // V5.9.1369 — same deterministic paper lifecycle settle on the shutdown fast path.
            try {
                TokenLifecycleTracker.onSellSettled(
                    mint = ts.mint, sig = "PAPER:bot_shutdown",
                    solReceived = shutdownCostSol.coerceAtLeast(0.0), walletTokenAfter = 0.0,
                )
            } catch (_: Throwable) {}
            try { WalletPositionLock.recordClose("Meme", shutdownCostSol) } catch (_: Exception) {}
            try { TradeAuthorizer.releasePosition(ts.mint, "SELL_$reason", TradeAuthorizer.ExecutionBook.CORE) } catch (_: Exception) {}
            onLog("🛑 SHUTDOWN CLOSE: ${ts.symbol} @ ${pnlP.toInt()}% (learning skipped)", tradeId.mint)
            return SellResult.PAPER_CONFIRMED
        }

        // V5.9.363 — SYMMETRIC SCRATCH ZONE.
        // Old: WIN ≥ +2.0%, LOSS ≤ -3.0%. The asymmetric -3% loss threshold
        // meant winners that retraced from +50% back to +1% got hidden as
        // SCRATCH while -2% losses still showed up as 'real'. With 1960
        // scratches / 209 wins / 581 losses, this asymmetry was distorting
        // the learning signal AND the WR display. Symmetric ±1.5% gives
        // both sides equal weight — fewer scratches, fairer brain training.
        val tradeClassification = when {
            pnlP >= 1.5 -> "WIN"
            pnlP <= -1.5 -> "LOSS"
            else -> "SCRATCH"
        }
        
        val isScratchTrade = tradeClassification == "SCRATCH"
        val shouldLearnAsLoss = tradeClassification == "LOSS"
        val shouldLearnAsWin = tradeClassification == "WIN"
        
        ErrorLogger.info("Executor", "📊 ${tradeId.symbol} CLASSIFIED: $tradeClassification | " +
            "pnl=${pnlP.toInt()}% | hold=${holdTimeMins.toInt()}min | " +
            "learn=${if(isScratchTrade) "NO (scratch)" else "YES"}")
        
        if (shouldLearnAsLoss) {
            val fanName = ts.meta.emafanAlignment
            val ph      = pos.entryPhase
            val src     = ts.source.ifBlank { "UNKNOWN" }

            tradeDb?.recordBadObservation(
                featureKey    = "phase=${ph}+ema=${fanName}",
                behaviourType = "ENTRY_SIGNAL",
                description   = "Loss on $ph + $fanName — pnl=${pnlP.toInt()}%",
                lossPct       = pnlP,
            )
            if (src != "UNKNOWN") tradeDb?.recordBadObservation(
                featureKey    = "source=${src}",
                behaviourType = "SOURCE",
                description   = "Loss from source $src",
                lossPct       = pnlP,
            )
            tradeDb?.recordBadObservation(
                featureKey    = "exit_reason=${reason}",
                behaviourType = "EXIT_PATTERN",
                description   = "Exit via $reason resulted in loss",
                lossPct       = pnlP,
            )
            val scoreRange = when {
                pos.entryScore >= 80 -> "high_80+"
                pos.entryScore >= 65 -> "medium_65-79"
                pos.entryScore >= 50 -> "low_50-64"
                else -> "very_low_<50"
            }
            tradeDb?.recordBadObservation(
                featureKey    = "entry_score_range=${scoreRange}",
                behaviourType = "SCORE_QUALITY",
                description   = "Loss with entry score ${pos.entryScore.toInt()} ($scoreRange)",
                lossPct       = pnlP,
            )
            
            brain?.let { b ->
                val shouldBlacklist = b.learnFromTrade(
                    isWin = false, 
                    phase = ph, 
                    emaFan = fanName, 
                    source = src, 
                    pnlPct = pnlP,
                    mint = ts.mint,
                    rugcheckScore = ts.safety.rugcheckScore,
                    buyPressure = ts.meta.pressScore,
                    topHolderPct = ts.safety.topHolderPct,
                    liquidityUsd = ts.lastLiquidityUsd,
                    isLiveTrade = false,
                    approvalClass = tradeId.fdgApprovalClass.ifEmpty { "PAPER_BENCHMARK" },
                    holdTimeMinutes = holdTimeMins,
                    maxGainPct = maxGainPct,
                    exitReason = reason,
                    tokenAgeMinutes = tokenAgeMins,
                )
                if (shouldBlacklist) {
                    // V5.0.3844 — repeated losses are learning pressure, not
                    // malicious mint proof. They may reduce score/size or trigger
                    // short cooldown/pivot logic, but must never write a hard
                    // blacklist that diverts future live candidates into shadow.
                    try {
                        ForensicLogger.lifecycle(
                            "BUY_GATE_DECISION",
                            "mint=${ts.mint.take(10)} symbol=${ts.symbol} decision=PENALTY_ONLY reason=2+_losses source=Executor.paperLearning liveEligible=true",
                        )
                    } catch (_: Throwable) {}
                    try { PipelineHealthCollector.labelInc("BUY_GATE_PENALTY_ONLY_REPEATED_LOSS") } catch (_: Throwable) {}
                    onLog("🧠 PENALTY_ONLY: ${ts.symbol} repeated losses — score/size/cooldown pressure only, no blacklist", ts.mint)
                }
            }
            
            TradingMemory.learnFromBadTrade(
                mint = ts.mint,
                symbol = ts.symbol,
                lossPct = pnlP,
                phase = ph,
                emaFan = fanName,
                source = src,
                liquidity = ts.lastLiquidityUsd,
                mcap = ts.lastMcap,
                ageHours = (System.currentTimeMillis() - (ts.history.firstOrNull()?.ts ?: System.currentTimeMillis())) / 3_600_000.0,
                hadSocials = false,
                isPumpFun = ts.source.contains("pump", ignoreCase = true),
                volumeToLiqRatio = if (ts.lastLiquidityUsd > 0) ts.history.lastOrNull()?.vol?.div(ts.lastLiquidityUsd) ?: 0.0 else 0.0,
            )
            onLog("🤖 AI LEARNED: Loss on ${ts.symbol} | phase=$ph ema=$fanName | Pattern recorded", ts.mint)
            
            if (pnlP <= -15.0) {
                kotlinx.coroutines.GlobalScope.launch(AppDispatchers.sideEffect) {
                    try {
                        com.lifecyclebot.collective.CollectiveLearning.broadcastHotToken(
                            mint = ts.mint,
                            symbol = ts.symbol,
                            pnlPct = pnlP,
                            confidence = 0,
                            liquidityUsd = ts.lastLiquidityUsd,
                            mode = pos.tradingMode.ifBlank { "PAPER" },
                            reason = "AVOID_${(-pnlP).toInt()}%_LOSS"
                        )
                        ErrorLogger.info("Executor", "⚠️ BROADCAST AVOID: ${ts.symbol} ${pnlP.toInt()}% → Network warned!")
                    } catch (e: Exception) {
                        ErrorLogger.debug("Executor", "Broadcast avoid error: ${e.message}")
                    }
                }
            }
        } else if (shouldLearnAsWin) {
            val fanName = ts.meta.emafanAlignment
            val ph      = pos.entryPhase
            val src     = ts.source.ifBlank { "UNKNOWN" }
            tradeDb?.recordGoodObservation("phase=${ph}+ema=${fanName}")
            tradeDb?.recordGoodObservation("source=${src}")
            
            brain?.let { b ->
                b.learnFromTrade(
                    isWin = true, 
                    phase = ph, 
                    emaFan = fanName, 
                    source = src, 
                    pnlPct = pnlP,
                    mint = ts.mint,
                    rugcheckScore = ts.safety.rugcheckScore,
                    buyPressure = ts.meta.pressScore,
                    topHolderPct = ts.safety.topHolderPct,
                    liquidityUsd = ts.lastLiquidityUsd,
                    isLiveTrade = false,
