                else -> "LOW"
            }
            
            val marketSentiment = when {
                ts.meta.emafanAlignment.contains("BULL") -> "BULL"
                ts.meta.emafanAlignment.contains("BEAR") -> "BEAR"
                else -> "NEUTRAL"
            }
            
            BehaviorLearning.recordTrade(
                entryScore = ts.position.entryScore.toInt(),
