                    ts.position.entryScore >= 90 -> "A+"
                    ts.position.entryScore >= 80 -> "A"
                    ts.position.entryScore >= 70 -> "B"
                    else -> "C"
                },
                tradingMode = ts.position.tradingMode.ifEmpty { "SMART_SNIPER" },
                marketSentiment = marketSentiment,
